// Polyfill structuredClone for older WebViews (prevents blank screen on mobile).
// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore
if (typeof globalThis.structuredClone !== 'function') {
  (globalThis as any).structuredClone = (val: any) => JSON.parse(JSON.stringify(val));
}

// Safe ResizeObserver fallback for old WebViews.
// eslint-disable-next-line @typescript-eslint/ban-ts-comment
// @ts-ignore
const SafeResizeObserver: typeof ResizeObserver = typeof ResizeObserver !== 'undefined'
  ? ResizeObserver
  : class {
      constructor(_cb: ResizeObserverCallback) {}
      observe() {}
      disconnect() {}
    };
const resolveDefaultMpWsUrl = () => {
  // Highest priority: explicit build-time override.
  const env = (import.meta.env.VITE_MP_WS_URL as string | undefined)?.trim();
  if (env) return env;

  const isHttp = typeof window !== 'undefined' && window.location.protocol === 'http:';
  const scheme = isHttp ? 'ws' : 'wss';

  // Local dev keeps the standalone relay on port 3001.
  if (import.meta.env.DEV) {
    const hostname = typeof window !== 'undefined' ? (window.location.hostname || 'localhost') : 'localhost';
    return `${scheme}://${hostname}:3001`;
  }

  // Production fallback: use the dedicated multiplayer worker endpoint.
  return `${scheme}://drawaspell-ws.game-blk.workers.dev/ws`;
};
const CLIENT_ROOM_CODE_ALPHABET = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
const generateClientRoomCode = (len = 6): string => {
  let out = '';
  for (let i = 0; i < len; i += 1) {
    out += CLIENT_ROOM_CODE_ALPHABET[Math.floor(Math.random() * CLIENT_ROOM_CODE_ALPHABET.length)];
  }
  return out;
};
