function readStoredLayoutMode(): UiLayoutMode {
  if (typeof window === 'undefined') return 'landscape';
  try {
    const raw = window.localStorage.getItem(UI_LAYOUT_MODE_STORAGE_KEY);
    return raw === 'portrait' ? 'portrait' : 'landscape';
  } catch {
    return 'landscape';
  }
}

function readStoredSoundEnabled(): boolean {
  if (typeof window === 'undefined') return true;
  try {
    const raw = window.localStorage.getItem(SOUND_ENABLED_STORAGE_KEY);
    if (raw == null) return true;
    return raw !== '0';
  } catch {
    return true;
  }
}

let rubbleCardMeta: { text?: string; image?: string } = {};
function downloadTextFile(filename: string, content: string, mime = 'text/plain') {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

function escapeRtf(text: string) {
  return text
    .replace(/\\/g, '\\\\')
    .replace(/{/g, '\\{')
    .replace(/}/g, '\\}')
    .replace(/\n/g, '\\par ');
}

function exportLog(log: string[], format: 'txt' | 'rtf' = 'txt') {
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  if (format === 'txt') {
    downloadTextFile(`sorcery-log-${ts}.txt`, log.join('\n'), 'text/plain;charset=utf-8');
  } else {
    const rtf = `{\rtf1\ansi ${escapeRtf(log.join('\n'))}}`;
    downloadTextFile(`sorcery-log-${ts}.rtf`, rtf, 'application/rtf');
  }
}


