// Fits the board to the available viewport by auto-scaling so it is never clipped.
// If the board is smaller than the viewport, it is centered.
function BoardFitViewport({ children, bottomInset = 0 }: { children: React.ReactNode; bottomInset?: number }) {
  const outerRef = useRef<HTMLDivElement | null>(null);
  const innerRef = useRef<HTMLDivElement | null>(null);
  const [fitScale, setFitScale] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });

  const recompute = useCallback(() => {
    const outer = outerRef.current;
    const inner = innerRef.current;
    if (!outer || !inner) return;

    const o = outer.getBoundingClientRect();

    // Natural content size (not affected by transforms)
    const contentW = inner.scrollWidth || inner.getBoundingClientRect().width;
    const contentH = inner.scrollHeight || inner.getBoundingClientRect().height;

    // Safety padding to avoid tiny right/bottom clipping due to rounding/borders.
    const pad = 16;
    const reservedBottom = Math.max(0, bottomInset);
    const usableHeight = Math.max(1, o.height - reservedBottom);
    const availW = Math.max(1, o.width - pad * 2);
    const availH = Math.max(1, usableHeight - pad * 2);

    if (!contentW || !contentH) return;

    // Scale down to fit; never scale up above 1.
    const next = Math.min(1, availW / contentW, availH / contentH);

    const drawW = contentW * next;
    const drawH = contentH * next;

    // Center the scaled content.
    const cx = Math.round((o.width - drawW) / 2);
    const cy = Math.round((usableHeight - drawH) / 2);

    setFitScale(next);
    setOffset({ x: cx, y: cy });
  }, [bottomInset]);

  useLayoutEffect(() => {
    recompute();

    const outer = outerRef.current;
    const inner = innerRef.current;
    if (!outer || !inner) return;

    const ro = new SafeResizeObserver(() => {
      recompute();
    });

    ro.observe(outer);
    ro.observe(inner);

    window.addEventListener('resize', recompute);
    return () => {
      ro.disconnect();
      window.removeEventListener('resize', recompute);
    };
  }, [recompute]);

  return (
    <div
      ref={outerRef}
      style={{
        position: 'relative',
        width: '100%',
        height: '100%',
        overflow: 'hidden',
        borderRadius: 14,
        background: 'transparent',
        boxShadow: 'none',
      }}
      aria-label="Board fit viewport"
    >
      <div
        style={{
          position: 'absolute',
          left: 0,
          top: 0,
          transform: `translate(${offset.x}px, ${offset.y}px) scale(${fitScale})`,
          transformOrigin: 'top left',
          willChange: 'transform',
        }}
      >
        <div ref={innerRef} style={{ display: 'inline-block' }}>
          {children}
        </div>
      </div>
    </div>
  );
}
