function advKey(x:number,y:number){ return `${x},${y}`; }
function adjacentsOf(x:number,y:number, w:number,h:number){
  return [{x,y},{x:x-1,y},{x:x+1,y},{x,y:y-1},{x,y:y+1}]
    .filter(p=>p.x>=0&&p.y>=0&&p.x<w&&p.y<h);
}

const adventureTileFrom = (g: Game, x: number, y: number): AdventureTile | null => {
  const adv: AdventureRuntime | undefined = (g as any)._adventure;
  if (!adv || !adv.enabled || !adv.scenario) return null;
  const key = advKey(x, y);
  return adv.scenario.tiles[key] ?? null;
};

