// ===== Adventure Mode: runtime recompute (fog, unveil, flip facedown) =====
function applyAdventureFogAndTriggers(g:any){
  const adv: AdventureRuntime | undefined = (g as any)._adventure;
  if (!adv || !adv.enabled || !adv.scenario) return;
  const sc = adv.scenario;

  // Ensure tile defaults exist
  for(let y=0;y<sc.size.h;y++){
    for(let x=0;x<sc.size.w;x++){
      const k = advKey(x,y);
      sc.tiles[k] = sc.tiles[k] || { cards:[], fog:false, entered:false, starting:false };
      sc.tiles[k].fog = false;
    }
  }
}

function handleAdventureTileEntry(g: Game, x: number, y: number, tile: AdventureTile, units: Unit[]) {
  const firstEntry = !tile.entered;
  if (firstEntry) {
    tile.entered = true;
    tile.fog = false;
    g.log?.unshift?.(`${tileLabel(g, x, y)} unveiled.`);
  }
  if (units.length > 0) {
    revealAdventureTileCards(g, x, y, tile, units);
  }
}

function revealAdventureTileCards(g: Game, x: number, y: number, tile: AdventureTile, units: Unit[]) {
  const occupantUnit = units.find(u => {
    const owner = (u as any).player as PlayerId | undefined;
    return owner === 1 || owner === 2;
  });
  const occupantPid = (occupantUnit ? (occupantUnit as any).player : 1) as PlayerId;
  for (const stub of tile.cards) {
    if (adventureStubIsSite(stub)) {
      placeAdventureSiteFromStub(g, occupantPid, x, y, stub);
    }
    if (stub.faceDown) stub.faceDown = false;
  }
  const villainPid = ensureAdventureVillain(g);
  (g as any)._adventureVillainActive = true;
  const cell = cellOf(g, x, y);
  const remaining: AdventureCardStub[] = [];
  for (const stub of tile.cards) {
    hydrateAdventureCardStub(stub);
    const card = stub.card;
    const hostile = (stub.alignment ?? 'neutral') === 'hostile';
    if (!hostile || !card) {
      remaining.push(stub);
      continue;
    }
    if (card.kind === 'Unit' || card.kind === 'Avatar') {
      const inst = newCardInstance(card) as unknown as Unit;
      (inst as any).player = villainPid;
      (inst as any).x = x;
      (inst as any).y = y;
      (inst as any).region = 'surface';
      (inst as any)._adventureHostile = true;
      cell.units.push(inst);
      g.log?.unshift?.(`[Adventure] Hostile ${inst.name} emerges at ${tileLabel(g, x, y)}.`);
      continue;
    }
    const hostileKind = (card as any).kind;
    if (hostileKind === 'Artifact' || hostileKind === 'Relic' || hostileKind === 'Monument') {
      const art = structuredClone(card) as unknown as Artifact;
      art.id = art.id ?? `adv_art_${uid()}`;
      art.carriedBy = null;
      art.x = x;
      art.y = y;
      art.region = 'surface';
      (art as any).player = villainPid;
      (art as any)._adventureHostile = true;
      cell.artifacts.push(art);
      g.log?.unshift?.(`[Adventure] Hostile ${art.name} stands at ${tileLabel(g, x, y)}.`);
      continue;
    }
    remaining.push(stub);
  }
  tile.cards = remaining;
}
function ensureModalManager(): (req: ModalRequest) => void {
  if (!enqueueModalRequest) throw new Error('Modal system not initialised yet.')
  return enqueueModalRequest
}

function getMpBridgeSafe(): MpBridge | null {
  try {
    return getMultiplayerBridge?.() ?? null
  } catch {
    return null
  }
}

function reactNodeToPlainText(node: React.ReactNode): string {
  if (node == null || node === false) return ''
  if (typeof node === 'string' || typeof node === 'number') return String(node)
  if (Array.isArray(node)) return node.map(reactNodeToPlainText).join('')
  if (React.isValidElement(node)) return reactNodeToPlainText((node as any).props?.children)
  return ''
}

function cpuAutoResolveModal(): { enabled: boolean; pid?: PlayerId } {
  const g = getLatestGameState?.();
  if (!g || !isCpuMatch(g)) return { enabled: false };
  const cpuPids = ((g as any)._cpuPlayerIds as PlayerId[] | undefined) ?? [];
  const pid = cpuPids.find((p) => p === g.turn) as PlayerId | undefined;
  return pid ? { enabled: true, pid } : { enabled: false };
}

function cpuAutoResolveModalForPid(pid: PlayerId | null | undefined): { enabled: boolean; pid?: PlayerId } {
  const g = getLatestGameState?.();
  if (!g || pid == null) return { enabled: false };
  if (!isCpuPlayer(g, pid)) return { enabled: false };
  return { enabled: true, pid };
}

function pickFirstEnabled<T>(options: Array<{ value: T; disabled?: boolean }>): T | null {
  const enabled = options.filter(opt => !opt.disabled);
  return enabled.length > 0 ? enabled[0].value : null;
}

function nextModalId(): number {
  modalRequestId += 1
  return modalRequestId
}

export async function uiSelectOne<T>(params: {
  title: string
  message?: React.ReactNode
  options: Array<{ label: string; value: T; disabled?: boolean; description?: string }>
  allowCancel?: boolean
  cancelLabel?: string
}): Promise<T | null> {
  const auto = cpuAutoResolveModal();
  if (auto.enabled) {
    const choice = pickFirstEnabled(params.options);
    return Promise.resolve(choice as T | null);
  }

  // Multiplayer: if the authoritative host needs input from the remote player, forward a modal request.
  const bridge = getMpBridgeSafe();
  const g = getLatestGameState?.();
  if (bridge && bridge.session.role === 'host' && bridge.session.status === 'inGame' && g) {
    const controllerPid = courtesanControllerFor(g, g.turn as PlayerId);
    if (controllerPid === bridge.session.peerPid) {
      const idx = await bridge.requestRemoteModal({
        id: `m_${Date.now()}_${Math.random().toString(36).slice(2)}`,
        pid: controllerPid,
        kind: 'single',
        title: params.title,
        message: params.message ? reactNodeToPlainText(params.message) : undefined,
        options: params.options.map((opt) => ({
          label: opt.label,
          description: opt.description,
          disabled: opt.disabled,
        })),
        allowCancel: params.allowCancel ?? true,
        cancelLabel: params.cancelLabel,
      });
      if (idx == null) return null;
      if (typeof idx !== 'number') return null;
      if (idx < 0 || idx >= params.options.length) return null;
      return params.options[idx].value;
    }
  }
  return new Promise<T | null>((resolve) => {
    ensureModalManager()({
      id: nextModalId(),
      kind: 'single',
      title: params.title,
      message: params.message,
      options: params.options.map(opt => ({ ...opt })),
      allowCancel: params.allowCancel ?? true,
      cancelLabel: params.cancelLabel,
      resolve: (value) => resolve(value as T | null),
    })
  })
}

