export async function uiSelectMany<T>(params: {
  title: string
  message?: React.ReactNode
  options: Array<{ label: string; value: T; disabled?: boolean; description?: string }>
  initialSelected?: T[]
  allowEmpty?: boolean
  confirmLabel?: string
  cancelLabel?: string
}): Promise<T[] | null> {
  const auto = cpuAutoResolveModal();
  if (auto.enabled) {
    const initial = params.initialSelected;
    if (initial && initial.length > 0) return Promise.resolve(initial);
    const first = pickFirstEnabled(params.options);
    if (first == null) return Promise.resolve(params.allowEmpty === false ? null : []);
    return Promise.resolve([first]);
  }

  const bridge = getMpBridgeSafe();
  const g = getLatestGameState?.();
  if (bridge && bridge.session.role === 'host' && bridge.session.status === 'inGame' && g) {
    const controllerPid = courtesanControllerFor(g, g.turn as PlayerId);
    if (controllerPid === bridge.session.peerPid) {
      const initialSelected = (params.initialSelected ?? [])
        .map((v) => params.options.findIndex((o) => o.value === v))
        .filter((idx) => idx >= 0);
      const idxs = await bridge.requestRemoteModal({
        id: `m_${Date.now()}_${Math.random().toString(36).slice(2)}`,
        pid: controllerPid,
        kind: 'multi',
        title: params.title,
        message: params.message ? reactNodeToPlainText(params.message) : undefined,
        options: params.options.map((opt) => ({
          label: opt.label,
          description: opt.description,
          disabled: opt.disabled,
        })),
        initialSelected,
        allowEmpty: params.allowEmpty ?? true,
        confirmLabel: params.confirmLabel,
        cancelLabel: params.cancelLabel,
      });
      if (idxs == null) return null;
      if (!Array.isArray(idxs)) return null;
      const values: T[] = [];
      for (const idx of idxs) {
        if (typeof idx !== 'number') continue;
        if (idx < 0 || idx >= params.options.length) continue;
        values.push(params.options[idx].value);
      }
      if ((params.allowEmpty ?? true) === false && values.length === 0) return null;
      return values;
    }
  }
  return new Promise<T[] | null>((resolve) => {
    ensureModalManager()({
      id: nextModalId(),
      kind: 'multi',
      title: params.title,
      message: params.message,
      options: params.options.map(opt => ({ ...opt })),
      initialSelected: params.initialSelected ?? [],
      allowEmpty: params.allowEmpty ?? true,
      confirmLabel: params.confirmLabel,
      cancelLabel: params.cancelLabel,
      resolve: (value) => resolve((value ?? null) as T[] | null),
    })
  })
}

