export async function uiPrompt(params: {
  title: string
  message?: React.ReactNode
  defaultValue?: string
  placeholder?: string
  confirmLabel?: string
  cancelLabel?: string
  allowEmpty?: boolean
}): Promise<string | null> {
  const auto = cpuAutoResolveModal();
  if (auto.enabled) {
    const val = params.defaultValue ?? '';
    if (params.allowEmpty === false && val.trim() === '') return Promise.resolve(null);
    return Promise.resolve(val);
  }

  const bridge = getMpBridgeSafe();
  const g = getLatestGameState?.();
  if (bridge && bridge.session.role === 'host' && bridge.session.status === 'inGame' && g) {
    const controllerPid = courtesanControllerFor(g, g.turn as PlayerId);
    if (controllerPid === bridge.session.peerPid) {
      const text = await bridge.requestRemoteModal({
        id: `m_${Date.now()}_${Math.random().toString(36).slice(2)}`,
        pid: controllerPid,
        kind: 'prompt',
        title: params.title,
        message: params.message ? reactNodeToPlainText(params.message) : undefined,
        defaultValue: params.defaultValue,
        placeholder: params.placeholder,
        confirmLabel: params.confirmLabel,
        cancelLabel: params.cancelLabel,
        allowEmpty: params.allowEmpty ?? true,
      });
      const val = typeof text === 'string' ? text : null;
      if ((params.allowEmpty ?? true) === false && (val ?? '').trim() === '') return null;
      return val;
    }
  }
  return new Promise<string | null>((resolve) => {
    ensureModalManager()({
      id: nextModalId(),
      kind: 'input',
      title: params.title,
      message: params.message,
      defaultValue: params.defaultValue,
      placeholder: params.placeholder,
      confirmLabel: params.confirmLabel,
      cancelLabel: params.cancelLabel,
      allowEmpty: params.allowEmpty ?? true,
      resolve,
    })
  })
}

const CardHoverContext = React.createContext<HoverCtx | null>(null)

function CardHoverProvider({ children }: { children: React.ReactNode }) {
  const [hover, setHover] = useState<HoverState>(null)
  const hoverSrcs = useMemo(() => buildAssetFallbacks(hover?.src), [hover?.src]);
  const visibleHover = useMemo(() => {
    if (!hover || typeof window === 'undefined') return hover;
    const portraitWidth = (hover.baseWidth ?? 220) * (hover.zoom ?? 1);
    const portraitHeight = portraitWidth * 1.4;
    const displayWidth = hover.rotate90 ? portraitHeight : portraitWidth;
    const displayHeight = hover.rotate90 ? portraitWidth : portraitHeight;
    const maxX = Math.max(12, window.innerWidth - displayWidth - 12);
    const maxY = Math.max(displayHeight / 2 + 12, window.innerHeight - displayHeight / 2 - 12);
    return {
      ...hover,
      x: Math.max(12, Math.min(hover.x, maxX)),
      y: Math.max(displayHeight / 2 + 12, Math.min(hover.y, maxY)),
    };
  }, [hover]);

  const ctx = useMemo<HoverCtx>(() => ({
    show: (s) => setHover(s),
    move: (x, y) => setHover(h => (h ? { ...h, x, y } : h)),
    hide: () => setHover(null),
  }), [])

  return (
    <CardHoverContext.Provider value={ctx}>
      {children}
      {visibleHover && (
        <div
          style={{
            position: 'fixed',
            left: visibleHover.x,
            top: visibleHover.y,
            zIndex: 6200,
            pointerEvents: 'none',
            filter: 'drop-shadow(0 10px 24px rgba(0,0,0,.35))',
            transform: 'translateY(-50%)',
            willChange: 'transform',
          }}
        >
          <img
            src={hoverSrcs[0] ?? visibleHover.src}
            data-fallbacks={hoverSrcs.slice(1).join('|')}
            alt={visibleHover.name ?? ''}
            onError={advanceImageFallback}
            style={{
              width: (visibleHover.baseWidth ?? 220) * (visibleHover.zoom ?? 1),
              height: 'auto',
              borderRadius: 10,
              display: 'block',
              background: '#111',
              transform: visibleHover.rotate90 ? 'rotate(90deg)' : undefined,
              transformOrigin: 'center center',
            }}
            draggable={false}
          />
        </div>
      )}
    </CardHoverContext.Provider>
  )
}

function CodexModal({
  open,
  onClose,
  pages,
  page,
  onPageChange,
  search,
  onSearch,
  loading,
  variant = 'modal',
}: {
  open: boolean;
  onClose: () => void;
  pages: CodexEntry[][];
  page: number;
  onPageChange: (next: number) => void;
  search: string;
  onSearch: (val: string) => void;
  loading: boolean;
  variant?: 'modal' | 'page';
}) {
  const hoverCtx = React.useContext(CardHoverContext);
  const pageEntries = pages[page] ?? [];
  const pageCount = Math.max(1, pages.length || 1);
  const [preview, setPreview] = useState<{ title: string; src: string } | null>(null);
  const previewSrcs = useMemo(() => buildAssetFallbacks(preview?.src), [preview?.src]);

  const renderRichText = (text: string, keyBase: string) => {
    const parts: React.ReactNode[] = [];
    const regex = /\[\[([^\]]+)\]\]/g;
    let lastIndex = 0;
    let match: RegExpExecArray | null;
    while ((match = regex.exec(text)) !== null) {
      const [full, name] = match;
      if (match.index > lastIndex) {
        parts.push(<span key={`${keyBase}-txt-${lastIndex}`}>{text.slice(lastIndex, match.index)}</span>);
      }
      const src = codexImageForName(name) ?? '/assets/Sorcery_Spellbook.png';
      const handleShow = (x: number, y: number) => {
        if (!src) return;
        if (hoverCtx) {
          hoverCtx.show({
            src,
            name,
            x: x + 16,
            y,
            baseWidth: 220,
            zoom: 1.05,
          });
          return;
        }
        setPreview({ title: name, src });
      };
      const handleMove = (x: number, y: number) => {
        if (hoverCtx) hoverCtx.move(x + 16, y);
      };
      const handleActivate = (x: number, y: number) => {
        handleShow(x, y);
      };
      const handleLeave = () => {
        setPreview(null);
        hoverCtx?.hide();
      };
      parts.push(
        <span
          key={`${keyBase}-card-${match.index}`}
          style={{ color: '#1f6db5', cursor: 'pointer', fontWeight: 600 }}
          role="button"
          tabIndex={0}
          onPointerEnter={(e) => handleShow(e.clientX, e.clientY)}
          onPointerMove={(e) => handleMove(e.clientX, e.clientY)}
          onPointerLeave={handleLeave}
          onClick={(e) => handleActivate(e.clientX, e.clientY)}
          onKeyDown={(e) => {
            if (e.key !== 'Enter' && e.key !== ' ') return;
            e.preventDefault();
            const rect = e.currentTarget.getBoundingClientRect();
            handleActivate(rect.left + rect.width / 2, rect.top + rect.height / 2);
          }}
          onTouchStart={(e) => {
            const touch = e.touches[0];
            if (touch) handleShow(touch.clientX, touch.clientY);
          }}
          onTouchEnd={handleLeave}
        >
          {name}
        </span>
      );
      lastIndex = match.index + full.length;
    }
    if (lastIndex < text.length) {
      parts.push(<span key={`${keyBase}-tail`}>{text.slice(lastIndex)}</span>);
    }
    return parts;
  };

  if (!open) return null;

  const outerStyle: React.CSSProperties =
    variant === 'modal'
      ? {
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.7)',
          zIndex: 9998,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 12,
        }
      : {
          position: 'relative',
          minHeight: '100vh',
          background: '#0b1116',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 18,
        };

  return (
    <div style={outerStyle}>
      <div
        style={{
          width: variant === 'modal' ? 'min(94vw, 920px)' : 'min(94vw, 1080px)',
          height: variant === 'modal' ? 'min(92vh, 780px)' : 'min(94vh, 860px)',
          background: '#f8f1e3',
          border: '1px solid rgba(56,38,26,0.35)',
          borderRadius: 16,
          boxShadow: '0 18px 48px rgba(0,0,0,0.55)',
          overflow: 'hidden',
          display: 'grid',
          gridTemplateRows: 'auto 1fr auto',
        }}
      >
        <div style={{ padding: '12px 16px', display: 'flex', alignItems: 'center', gap: 8, justifyContent: 'space-between', background: '#efe5d0', borderBottom: '1px solid rgba(56,38,26,0.25)' }}>
          <div style={{ fontFamily: '"Cinzel", "Georgia", serif', letterSpacing: '0.12em', textTransform: 'uppercase', color: '#3a2418' }}>
            Sorcery Codex
          </div>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            <input
              value={search}
              onChange={(e) => onSearch(e.target.value)}
              placeholder="Search terms, cards, or rules..."
              style={{
                background: '#fff8ec',
                color: '#2d1b12',
                border: '1px solid rgba(56,38,26,0.35)',
                borderRadius: 8,
                padding: '6px 10px',
              }}
            />
            <button className="btn" onClick={onClose}>{variant === 'page' ? 'Back' : 'Close'}</button>
          </div>
        </div>
        <div
          style={{
            position: 'relative',
            padding: '20px 22px',
            background: 'linear-gradient(180deg, #f8f1e3 0%, #f4e4c4 100%)',
            overflowY: 'auto',
          }}
        >
          {loading && (!pages || pages.length === 0) ? (
            <div style={{ color: '#5a3c2c', fontSize: 14 }}>Loading codex…</div>
          ) : (
            <div style={{ display: 'flex', justifyContent: 'center', position: 'relative' }}>
              <div
                style={{
                  background: 'linear-gradient(180deg, rgba(248,239,223,0.98), rgba(243,229,198,0.98))',
                  color: '#1f120b',
                  padding: '22px 24px',
                  borderRadius: 10,
                  boxShadow: 'inset 0 0 24px rgba(0,0,0,0.08), 0 10px 24px rgba(0,0,0,0.25)',
                  width: '100%',
                  maxWidth: variant === 'modal' ? 760 : 880,
                  minHeight: 420,
                  fontFamily: '"Cormorant Garamond", "Georgia", serif',
                  textAlign: 'left',
                }}
              >
                {pageEntries.length === 0 ? (
                  <div style={{ color: '#5a3c2c' }}>No entries.</div>
                ) : (
                  pageEntries.map((entry, idx) => (
                    <article
                      key={`${entry.title}-${idx}`}
                      style={{
                        paddingBottom: idx === pageEntries.length - 1 ? 0 : 22,
                        marginBottom: idx === pageEntries.length - 1 ? 0 : 22,
                        borderBottom: idx === pageEntries.length - 1 ? 'none' : '1px solid rgba(88,62,40,0.18)',
                      }}
                    >
                      <h2
                        style={{
                          margin: 0,
                          marginBottom: 10,
                          fontFamily: '"Cinzel", "Georgia", serif',
                          fontSize: 22,
                          lineHeight: 1.2,
                          color: '#3a2418',
                          letterSpacing: '0.02em',
                        }}
                      >
                        {entry.title}
                      </h2>
                      {entry.paragraphs.map((paragraph, pIdx) => (
                        <p
                          key={`${entry.title}-p-${pIdx}`}
                          style={{
                            margin: 0,
                            marginBottom: 12,
                            fontSize: 18,
                            lineHeight: 1.55,
                            color: '#24150d',
                            textIndent: pIdx === 0 ? 20 : 0,
                          }}
                        >
                          {renderRichText(paragraph, `${idx}-p-${pIdx}`)}
                        </p>
                      ))}
                      {entry.subsections.map((section, sIdx) => (
                        <section
                          key={`${entry.title}-sub-${sIdx}`}
                          style={{
                            marginTop: 8,
                            padding: '10px 12px',
                            borderRadius: 8,
                            border: '1px solid rgba(90,72,50,0.22)',
                            background: 'rgba(255,248,232,0.56)',
                          }}
                        >
                          <div
                            style={{
                              marginBottom: 8,
                              fontFamily: '"Cinzel", "Georgia", serif',
                              textTransform: 'uppercase',
                              letterSpacing: '0.08em',
                              color: '#5b3927',
                              fontSize: 12,
                              fontWeight: 700,
                            }}
                          >
                            {section.title}
                          </div>
                          {section.paragraphs.map((paragraph, subIdx) => (
                            <p
                              key={`${entry.title}-sub-${sIdx}-${subIdx}`}
                              style={{
                                margin: 0,
                                marginBottom: subIdx === section.paragraphs.length - 1 ? 0 : 9,
                                fontSize: 16,
                                lineHeight: 1.45,
                                color: '#2f1f15',
                              }}
                            >
                              {renderRichText(paragraph, `${idx}-s-${sIdx}-p-${subIdx}`)}
                            </p>
                          ))}
                        </section>
                      ))}
                    </article>
                  ))
                )}
              </div>
              {preview && (
                <div
                  className="codexCardPreview"
                  style={{
                    position: 'absolute',
                    inset: 0,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    pointerEvents: 'none',
                  }}
                >
                  <div
                    style={{
                      background: 'rgba(0,0,0,0.7)',
                      padding: 12,
                      borderRadius: 12,
                      border: '1px solid rgba(255,255,255,0.18)',
                      boxShadow: '0 16px 30px rgba(0,0,0,0.4)',
                      pointerEvents: 'none',
                      display: 'grid',
                      gap: 6,
                      justifyItems: 'center',
                    }}
                  >
                    <div style={{ color: '#f6edd9', fontSize: 14, fontWeight: 600 }}>{preview.title}</div>
                    <img
                      className="codexCardImg"
                      src={previewSrcs[0] ?? preview.src}
                      data-fallbacks={previewSrcs.slice(1).join('|')}
                      alt={preview.title}
                      onError={advanceImageFallback}
                      style={{ width: 220 * HOVER_PREVIEW_SCALE, height: 'auto', borderRadius: 10, boxShadow: '0 12px 24px rgba(0,0,0,0.35)' }}
                    />
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
        <div style={{ padding: '10px 14px', borderTop: '1px solid rgba(56,38,26,0.25)', background: '#efe5d0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <button className="btn" onClick={() => onPageChange(Math.max(0, page - 1))} disabled={page === 0}>Prev</button>
          <span style={{ color: '#3a2418', fontSize: 12, letterSpacing: '0.08em' }}>
            Page {page + 1} / {pageCount}
          </span>
          <button className="btn" onClick={() => onPageChange(Math.min(pageCount - 1, page + 1))} disabled={page >= pageCount - 1}>Next</button>
        </div>
      </div>
    </div>
  );
}

function useHoverBindingsForCard(opts: {
  src?: string
  name?: string
  rotate90?: boolean
  cardKind?: Card['kind']
  offset?: { x: number; y: number }
  zoom?: number
  baseWidth?: number
  side?: 'left' | 'right'
  context?: 'hand' | 'default'
}) {
  const ctx = React.useContext(CardHoverContext)
  const hoverSrc = React.useMemo(() => buildAssetFallbacks(opts.src)[0], [opts.src]);
  const effectiveZoom = (opts.zoom ?? 1) * HOVER_PREVIEW_SCALE
  const shouldRotate = opts.rotate90 ?? opts.cardKind === 'Site'
  const defaultOffsetY =
    opts.offset?.y ??
    (opts.context === 'hand'
      ? (opts.baseWidth ?? 220) * effectiveZoom * 0.7
      : 24)
  const offset = opts.offset ?? { x: 24, y: defaultOffsetY }
  const previewW = (opts.baseWidth ?? 220) * effectiveZoom
  const side = opts.side ?? 'right'
  const touchPreviewTimeout = React.useRef<number | null>(null)
  const lastPayload = React.useRef<(CardHoverData & { x: number; y: number }) | null>(null)
  const xPos = (e: { clientX: number }) =>
    side === 'left' ? e.clientX - previewW - offset.x : e.clientX + offset.x
  const yPos = (e: { clientY: number }) => e.clientY - offset.y
  const clearTouchPreview = () => {
    if (touchPreviewTimeout.current != null) {
      window.clearTimeout(touchPreviewTimeout.current)
      touchPreviewTimeout.current = null
    }
  }
  const hide = () => {
    clearTouchPreview()
    lastPayload.current = null
    ctx?.hide()
  }
  React.useEffect(() => () => {
    clearTouchPreview()
  }, [])
  const showFromPointer = (e: { clientX: number; clientY: number }) => {
    if (!ctx || !hoverSrc) return
    const payload = {
      src: hoverSrc,
      name: opts.name,
      x: xPos(e),
      y: yPos(e),
      rotate90: shouldRotate,
      zoom: effectiveZoom,
      baseWidth: opts.baseWidth ?? 220,
    }
    lastPayload.current = payload
    ctx.show(payload)
  }
  const showFromRect = (el: HTMLElement) => {
    if (!ctx || !hoverSrc) return
    const rect = el.getBoundingClientRect()
    const baseWidth = opts.baseWidth ?? 220
    const zoom = effectiveZoom
    const width = baseWidth * zoom
    const x =
      side === 'left'
        ? rect.left - offset.x - width
        : rect.right + offset.x
    const y = rect.top + rect.height / 2 - offset.y
    const payload = {
      src: hoverSrc,
      name: opts.name,
      x,
      y,
      rotate90: shouldRotate,
      zoom,
      baseWidth,
    }
    lastPayload.current = payload
    ctx.show(payload)
  }
  return {
    onPointerEnter: (e?: React.PointerEvent) => {
      if (e) showFromPointer({ clientX: e.clientX, clientY: e.clientY });
    },
    onPointerMove: (e: React.PointerEvent) => {
      if (!ctx || !lastPayload.current) return
      ctx.move(xPos(e), yPos(e))
    },
    onPointerLeave: () => {
      hide()
    },
    onPointerDown: (e: React.PointerEvent) => {
      if (!ctx || !hoverSrc) return
      const cx = e.clientX;
      const cy = e.clientY;
      clearTouchPreview()
      touchPreviewTimeout.current = window.setTimeout(() => {
        showFromPointer({ clientX: cx, clientY: cy })
      }, 180);
    },
    onPointerUp: (e?: React.PointerEvent) => {
      clearTouchPreview();
      hide()
    },
    onPointerCancel: () => {
      clearTouchPreview()
      hide()
    },
    onFocus: (e: React.FocusEvent<HTMLElement>) => {
      clearTouchPreview()
      showFromRect(e.currentTarget)
      e.currentTarget.style.outline = '2px solid #7dd3fc'
      e.currentTarget.style.outlineOffset = '2px'
    },
    onBlur: (e: React.FocusEvent<HTMLElement>) => {
      e.currentTarget.style.outline = ''
      e.currentTarget.style.outlineOffset = ''
      hide()
    },
  }
}

export type Elem = 'Air' | 'Earth' | 'Fire' | 'Water'
export type PlayerId = 1 | 2

function opposingPlayer(pid: PlayerId): PlayerId {
  return pid === 1 ? 2 : 1;
}

function imperialRoadResolutionDepth(g: Game): number {
  const raw = Number((g as any)._imperialRoadPendingDepth ?? 0);
  return Number.isFinite(raw) && raw > 0 ? Math.floor(raw) : 0;
}

function hasImperialRoadResolutionPending(g: Game): boolean {
  return imperialRoadResolutionDepth(g) > 0;
}

function beginImperialRoadResolution(g: Game): void {
  (g as any)._imperialRoadPendingDepth = imperialRoadResolutionDepth(g) + 1;
}

function endImperialRoadResolution(g: Game): void {
  const next = imperialRoadResolutionDepth(g) - 1;
  if (next > 0) (g as any)._imperialRoadPendingDepth = next;
  else delete (g as any)._imperialRoadPendingDepth;
}

function courtesanControllerFor(g: Game, pid: PlayerId): PlayerId {
  const map = (g as any)._courtesanActive as Record<PlayerId, PlayerId> | undefined;
  return map?.[pid] ?? pid;
}

function isCpuMatch(g: Game): boolean {
  return (g as any)._opponentType === 'cpu';
}

function tileNumberFrom(state: { width: number; board?: { length: number }[] }, x: number, y: number): number {
  const width = typeof state.width === 'number' ? state.width : state.board?.[0]?.length ?? 0;
  return y * width + x + 1;
}

function tileLabel(state: { width: number; board?: { length: number }[] }, x: number, y: number): string {
  return `Tile ${tileNumberFrom(state, x, y)}`;
}

function formatTileText(state: { width: number; board?: { length: number }[] }, value: string): string {
  return value.replace(/\((\d+)\s*,\s*(\d+)\)/g, (_, xs: string, ys: string) => {
    const x = Number(xs) - 1;
    const y = Number(ys) - 1;
    if (!Number.isFinite(x) || !Number.isFinite(y)) return _;
    return tileLabel(state, x, y);
  });
}

type SwivenIntelEntry = { unitId: string; name: string; owner: PlayerId; scoutLocation: string };

function recomputeSwivenScoutIntel(g: Game): void {
  const prev = (g as any)._swivenIntel as Record<PlayerId, SwivenIntelEntry[]> | undefined;
  const prevActive: Record<PlayerId, boolean> = { 1: false, 2: false };
  const prevFirst = prev?.[1];
  if (Array.isArray(prevFirst)) prevActive[1] = prevFirst.length > 0;
  const prevSecond = prev?.[2];
  if (Array.isArray(prevSecond)) prevActive[2] = prevSecond.length > 0;

  const intel: Record<PlayerId, SwivenIntelEntry[]> = { 1: [], 2: [] };
  const scouts = g.board
    .flat()
    .flatMap(cell => cell.units)
    .filter(
      (unit): unit is Token =>
        unit.kind !== 'Avatar' && /^Swiven Scout$/i.test(unit.name ?? '')
    );

  for (const scout of scouts) {
    const owner = scout.player as PlayerId | undefined;
    if (owner == null) continue;
    const enemy: PlayerId = owner === 1 ? 2 : 1;
    const region = ((scout as any).region ?? 'surface') as Region;

    const reachable = new Set<string>();
    reachable.add(`${scout.x},${scout.y},${region}`);
    for (const pos of neighborsFor(scout, g)) {
      reachable.add(`${pos.x},${pos.y},${pos.region}`);
    }

    const avatar = g.avatars[enemy];
    if (!avatar) continue;
    const avatarRegion = avatar.region ?? 'surface';
    const avatarKey = `${avatar.x},${avatar.y},${avatarRegion}`;
    if (!reachable.has(avatarKey)) continue;

    intel[enemy].push({
      unitId: scout.id,
      name: scout.name ?? 'Swiven Scout',
      owner,
      scoutLocation: tileLabel(g, scout.x, scout.y),
    });
  }

  (g as any)._swivenIntel = intel;

  const nowActive: Record<PlayerId, boolean> = {
    1: intel[1].length > 0,
    2: intel[2].length > 0,
  };

  let changed = false;
  for (const pid of [1, 2] as PlayerId[]) {
    if (prevActive[pid] === nowActive[pid]) continue;
    changed = true;
    if (nowActive[pid]) g.log.unshift(`Swiven Scouts reveal Player ${pid}'s hand.`);
    else g.log.unshift(`Swiven Scouts lose sight of Player ${pid}'s hand.`);
  }

  if (changed) requestGameSync?.();
}

function handleWayfaringPilgrimCorner(g: Game, token: Token): void {
  const pid = token.player as PlayerId | undefined;
  if (pid == null) return;
  const tokenId = String((token as any).id ?? '');
  const region = ((token as any).region ?? 'surface') as Region;
  if (region !== 'surface') return;
  const x = token.x;
  const y = token.y;
  const atCorner =
    (x === 0 || x === g.width - 1) &&
    (y === 0 || y === g.height - 1);
  if (!atCorner) return;
  const record: string[] = Array.isArray((token as any)._pilgrimCornersVisited)
    ? (token as any)._pilgrimCornersVisited
    : ((token as any)._pilgrimCornersVisited = []);
  const key = `${x},${y}`;
  if (record.includes(key)) return;
  record.push(key);

  const auto = (g as any)._opponentType === 'cpu' && pid === 2;
  if (auto) {
    const deckChoice =
      g.decks[pid].spellbook.length > 0
        ? 'spells'
        : g.decks[pid].atlas.length > 0
          ? 'atlas'
          : null;
    if (deckChoice) {
      draw(g, pid, deckChoice, 1);
      g.log.unshift(
        `Wayfaring Pilgrim reaches a new corner and draws a card from the ${
          deckChoice === 'spells' ? 'spellbook' : 'atlas'
        }.`,
      );
    } else {
      g.log.unshift('Wayfaring Pilgrim reaches a new corner but there are no cards left to draw.');
    }
    return;
  }

  void (async () => {
    const atlasLeft = g.decks[pid].atlas.length;
    const spellsLeft = g.decks[pid].spellbook.length;
    const options: Array<{ label: string; value: 'atlas' | 'spells'; disabled?: boolean }> = [
      {
        label: formatTileText(g, `Spellbook (${spellsLeft} card${spellsLeft === 1 ? '' : 's'} remaining)`),
        value: 'spells',
        disabled: spellsLeft === 0,
      },
      {
        label: formatTileText(g, `Atlas (${atlasLeft} card${atlasLeft === 1 ? '' : 's'} remaining)`),
        value: 'atlas',
        disabled: atlasLeft === 0,
      },
    ];

    const want = await uiSelectOne<'atlas' | 'spells'>({
      title: 'Wayfaring Pilgrim',
      message: formatTileText(g, 'Draw a card for visiting this corner? Choose a deck.'),
      options,
      allowCancel: true,
      cancelLabel: 'Decline',
    });

    if (want == null) {
      const live = getLatestGameState?.() ?? g;
      live.log.unshift('Wayfaring Pilgrim declines the corner boon.');
    } else {
      const live = getLatestGameState?.() ?? g;
      const liveLocated = tokenId ? findTokenOnBoard(live, tokenId) : null;
      const liveToken = (liveLocated?.token ?? null) as Token | null;
      const livePid = ((liveToken?.player ?? pid) as PlayerId);
      const liveAtlasLeft = live.decks[livePid]?.atlas?.length ?? 0;
      const liveSpellsLeft = live.decks[livePid]?.spellbook?.length ?? 0;
      if (want === 'atlas' && liveAtlasLeft === 0) {
        live.log.unshift('Wayfaring Pilgrim tries to draw from the atlas, but it is empty.');
      } else if (want === 'spells' && liveSpellsLeft === 0) {
        live.log.unshift('Wayfaring Pilgrim tries to draw from the spellbook, but it is empty.');
      } else {
        draw(live, livePid, want, 1);
        live.log.unshift(
        `Wayfaring Pilgrim reaches a new corner and draws a card from the ${
          want === 'spells' ? 'spellbook' : 'atlas'
        }.`,
      );
      }
    }
    requestGameSync?.();
  })();
}

function stateHasPendingSpellTargeting(state: Game): boolean {
  return Boolean(
    (state as any)._pendingPlay ||
    (state as any)._pendingOrbCopy ||
    (state as any)._pendingWhirling ||
    (state as any)._pendingBlink ||
    (state as any)._chainLightning
  );
}

function stateHasPendingBoardAction(state: Game): boolean {
  const hasPendingMove = pendingMoveStateForGame(state) != null;
  return (
    stateHasPendingSpellTargeting(state) ||
    hasPendingMove ||
    Boolean(
      (state as any)._pendingUnitMode ||
      (state as any)._pendingSiteMode ||
      (state as any)._pendingUnitShoot ||
      (state as any)._pendingPayloadTrebuchet ||
      (state as any)._pendingFireball ||
      (state as any)._pendingWaypointPortal ||
      (state as any)._pendingTeleport
    )
  );
}

type MoveAttackIntent = 'attack' | 'abstain';
type PendingMoveTargetSelection = {
  pendingMoveIntent?: MoveAttackIntent;
  pendingMoveTargetUnitId?: string;
  pendingMoveRegion?: Region;
  clearPendingMoveOnly?: boolean;
};

type PendingMoveModeState = {
  pid: PlayerId;
  unitId: string;
  forceAbstain?: boolean;
};

type PendingTargetOverlay = {
  active: boolean;
  legalTiles: Set<string>;
  softTiles: Set<string>;
  sourceTile: { x: number; y: number } | null;
  sourceUnitId?: string | null;
  pendingMove?: PendingMoveModeState | null;
};

const pendingTileKey = (x: number, y: number): string => `${x},${y}`;

const pendingRegionIntentLabel = (unit: Unit | null | undefined, region: Region): string => {
  if (region === 'surface') return 'Surface';
  if (region === 'underground') return unit && !!(unit as any).burrowing ? 'Burrow' : 'Underground';
  if (region === 'underwater') return unit && !!(unit as any).submerge ? 'Submerge' : 'Underwater';
  if (region === 'void') return 'Void';
  return String(region);
};

const pendingSourceFromPid = (g: Game, pid: PlayerId | undefined): { x: number; y: number } | null => {
  if (pid == null) return null;
  const av = g.avatars[pid];
  if (!av) return null;
  if (!inside(g, av.x, av.y)) return null;
  return { x: av.x, y: av.y };
};

function pendingPlayCard(g: Game, pending: PendingPlayState): Card | null {
  const source = pending.source ?? 'hand';
  const pid = pending.pid;
  if (source === 'hand') {
    return (g.handSpells[pid] ?? []).find((card) => card.id === pending.cardId) ?? null;
  }
  if (source === 'cemetery') {
    return (g.cemetery[pid] ?? []).find((card) => card.id === pending.cardId) ?? null;
  }
  if (source === 'morgana') {
    if (!pending.morganaId) return null;
    const located = locateMorganaSpellCard(g, pending.morganaId, pending.cardId);
    return located ? located.hand[located.index] : null;
  }
  if (source === 'algor') {
    if (!pending.algorId) return null;
    const art = findAlgorArtifactById(g, pending.algorId);
    if (!art) return null;
    const hand = getAlgorHand(art);
    return hand?.find((card) => card.id === pending.cardId) ?? null;
  }
  return null;
}

function pendingPlaySourceTile(g: Game, pending: PendingPlayState): { x: number; y: number } | null {
  if (pending.forcedCasterId) {
    const caster = findUnitById(g, pending.forcedCasterId);
    if (caster) {
      const x = Number((caster as any).x);
      const y = Number((caster as any).y);
      if (Number.isFinite(x) && Number.isFinite(y) && inside(g, x, y)) return { x, y };
    }
  }
  if (pending.source === 'algor' && pending.algorId) {
    const art = findAlgorArtifactById(g, pending.algorId);
    if (art && inside(g, art.x, art.y)) return { x: art.x, y: art.y };
  }
  if (pending.source === 'morgana' && pending.morganaId) {
    const data = findMorganaHandData(g, pending.morganaId);
    if (data) {
      const x = Number((data.token as any).x);
      const y = Number((data.token as any).y);
      if (Number.isFinite(x) && Number.isFinite(y) && inside(g, x, y)) return { x, y };
    }
  }
  return pendingSourceFromPid(g, pending.pid);
}

function pendingPlaySourceUnitId(g: Game, pending: PendingPlayState): string | null {
  if (pending.forcedCasterId) {
    const caster = findUnitById(g, pending.forcedCasterId);
    if (caster) return (caster as any).id ?? null;
  }
  if (pending.source === 'morgana' && pending.morganaId) {
    const data = findMorganaHandData(g, pending.morganaId);
    if (data?.token) return (data.token as any).id ?? null;
  }
  if (pending.source === 'algor' && pending.algorId) {
    return `ALG_${pending.algorId}`;
  }
  return null;
}

function buildPendingTargetOverlay(g: Game): PendingTargetOverlay {
  const legalTiles = new Set<string>();
  const softTiles = new Set<string>();
  const addLegal = (x: number, y: number) => {
    if (!inside(g, x, y)) return;
    legalTiles.add(pendingTileKey(x, y));
  };
  const addSoft = (x: number, y: number) => {
    if (!inside(g, x, y)) return;
    softTiles.add(pendingTileKey(x, y));
  };
  const fillSoftBoard = () => {
    for (let yy = 0; yy < g.height; yy += 1) {
      for (let xx = 0; xx < g.width; xx += 1) addSoft(xx, yy);
    }
  };
  const anyG = g as any;

  // Movement intent should always drive the overlay if active.
  // This prevents stale pending spell states from hijacking magnet targeting visuals.
  const pendingMove = pendingMoveStateForGame(g);
  if (pendingMove) {
    for (const entry of pendingMove.options) {
      addLegal(entry.x, entry.y);
      if ((pendingMove.unit as any).size2x2 && entry.region === 'surface') {
        addLegal(entry.x + 1, entry.y);
        addLegal(entry.x, entry.y + 1);
        addLegal(entry.x + 1, entry.y + 1);
      }
    }
    const ux = Number((pendingMove.unit as any).x);
    const uy = Number((pendingMove.unit as any).y);
    const sourceTile =
      Number.isFinite(ux) && Number.isFinite(uy) && inside(g, ux, uy)
        ? { x: ux, y: uy }
        : pendingSourceFromPid(g, pendingMove.pending.pid as PlayerId);
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile,
      sourceUnitId: (pendingMove.unit as any).id ?? null,
      pendingMove: {
        pid: pendingMove.pending.pid,
        unitId: pendingMove.pending.unitId,
        forceAbstain: pendingMove.pending.forceAbstain,
      },
    };
  }

  const pendingWhirling = anyG._pendingWhirling as
    | { pid?: PlayerId; unitId?: string }
    | undefined;
  if (pendingWhirling?.pid != null) {
    const unit = pendingWhirling.unitId ? findUnitById(g, pendingWhirling.unitId) : null;
      if (unit) {
        for (const step of neighborsFor(unit, g)) addLegal(step.x, step.y);
        const x = Number((unit as any).x);
        const y = Number((unit as any).y);
        const sourceTile = Number.isFinite(x) && Number.isFinite(y) && inside(g, x, y) ? { x, y } : null;
      return {
        active: true,
        legalTiles,
        softTiles,
        sourceTile,
        sourceUnitId: (unit as any).id ?? null,
      };
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingWhirling.pid as PlayerId),
    };
  }

  const pendingOrb = anyG._pendingOrbCopy as
    | { pid?: PlayerId; code?: string; region?: Region }
    | undefined;
  if (pendingOrb?.pid != null) {
    const ability = pendingOrb.code ? getSpellAbility(pendingOrb.code) : undefined;
    const region = pendingOrb.region ?? g.viewRegion;
    if (ability?.targeting === 'click-unit') {
      for (let yy = 0; yy < g.height; yy += 1) {
        for (let xx = 0; xx < g.width; xx += 1) {
          if (unitArrayAtRegion(g, xx, yy, region).length > 0) addLegal(xx, yy);
        }
      }
    } else if (ability?.targeting === 'click-tile') {
      fillSoftBoard();
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingOrb.pid as PlayerId),
    };
  }

  const pendingFireball = anyG._pendingFireball as
    | { pid?: PlayerId }
    | undefined;
  if (pendingFireball?.pid != null) {
    for (let yy = 0; yy < g.height; yy += 1) for (let xx = 0; xx < g.width; xx += 1) addLegal(xx, yy);
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingFireball.pid as PlayerId),
    };
  }

  const pendingBlink = anyG._pendingBlink as
    | { pid?: PlayerId; unitId?: string }
    | undefined;
  if (pendingBlink?.pid != null) {
    const unit = pendingBlink.unitId ? findUnitById(g, pendingBlink.unitId) : null;
    if (unit) {
      const fromX = Number((unit as any).x);
      const fromY = Number((unit as any).y);
      const region = (((unit as any).region ?? 'surface') as Region);
      if (Number.isFinite(fromX) && Number.isFinite(fromY)) {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            if (!_blinkIsNearby({ x: fromX, y: fromY }, { x: xx, y: yy })) continue;
            const cell = cellOf(g, xx, yy);
            if (region === 'surface' && !cell.site) continue;
            if (region === 'underground' && !(cell.site && !isSiteWater(g, cell.site, xx, yy))) continue;
            if (region === 'underwater' && !(cell.site && isSiteWater(g, cell.site, xx, yy))) continue;
            if (region === 'void' && cell.site) continue;
            addLegal(xx, yy);
          }
        }
        return {
          active: true,
          legalTiles,
          softTiles,
          sourceTile: { x: fromX, y: fromY },
          sourceUnitId: (unit as any).id ?? null,
        };
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingBlink.pid as PlayerId),
    };
  }

  const chain = anyG._chainLightning as
    | { pid?: PlayerId; last?: { x: number; y: number; region: Region }; seenIds?: string[] }
    | undefined;
  if (chain?.pid != null && chain.last) {
    const region = chain.last.region ?? g.viewRegion;
    const seen = new Set(chain.seenIds ?? []);
    for (let yy = 0; yy < g.height; yy += 1) {
      for (let xx = 0; xx < g.width; xx += 1) {
        if (!_clIsNearby(chain.last, { x: xx, y: yy })) continue;
        const list = unitArrayAtRegion(g, xx, yy, region);
        if (list.some((unit) => !seen.has(unit.id))) addLegal(xx, yy);
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: inside(g, chain.last.x, chain.last.y) ? { x: chain.last.x, y: chain.last.y } : null,
    };
  }

  const pendingWaypoint = anyG._pendingWaypointPortal as
    | { pid?: PlayerId; a?: { x: number; y: number } }
    | undefined;
  if (pendingWaypoint?.pid != null && pendingWaypoint.a) {
    for (let yy = 0; yy < g.height; yy += 1) {
      for (let xx = 0; xx < g.width; xx += 1) {
        if (xx === pendingWaypoint.a.x && yy === pendingWaypoint.a.y) continue;
        if (!cellOf(g, xx, yy).site) continue;
        addLegal(xx, yy);
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: inside(g, pendingWaypoint.a.x, pendingWaypoint.a.y)
        ? { x: pendingWaypoint.a.x, y: pendingWaypoint.a.y }
        : null,
    };
  }

  const pendingShoot = anyG._pendingUnitShoot as
    | { pid?: PlayerId; unitId?: string }
    | undefined;
  if (pendingShoot?.pid != null) {
    const unit = pendingShoot.unitId ? findUnitById(g, pendingShoot.unitId) : null;
    if (unit && canTapToPay(g, unit) && effectiveRanged(g, unit) > 0) {
      const ux = Number((unit as any).x);
      const uy = Number((unit as any).y);
      if (Number.isFinite(ux) && Number.isFinite(uy)) {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            const dx = xx - ux;
            const dy = yy - uy;
            if ((dx === 0 && dy === 0) || (dx !== 0 && dy !== 0)) continue;
            addLegal(xx, yy);
          }
        }
        return {
          active: true,
          legalTiles,
          softTiles,
          sourceTile: { x: ux, y: uy },
          sourceUnitId: (unit as any).id ?? null,
        };
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingShoot.pid as PlayerId),
    };
  }

  const pendingPayload = anyG._pendingPayloadTrebuchet as
    | { pid?: PlayerId; unitId?: string }
    | undefined;
  if (pendingPayload?.pid != null) {
    const unit = pendingPayload.unitId ? findUnitById(g, pendingPayload.unitId) : null;
    if (unit) {
      const ux = Number((unit as any).x);
      const uy = Number((unit as any).y);
      if (Number.isFinite(ux) && Number.isFinite(uy)) {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            if (Math.max(Math.abs(xx - ux), Math.abs(yy - uy)) <= 3) addLegal(xx, yy);
          }
        }
        return {
          active: true,
          legalTiles,
          softTiles,
          sourceTile: { x: ux, y: uy },
          sourceUnitId: (unit as any).id ?? null,
        };
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingPayload.pid as PlayerId),
    };
  }

  const pendingSite = anyG._pendingSiteMode as
    | { pid?: PlayerId }
    | undefined;
  if (pendingSite?.pid != null) {
    for (let yy = 0; yy < g.height; yy += 1) {
      for (let xx = 0; xx < g.width; xx += 1) {
        if (legalSitePlacement(g, pendingSite.pid as PlayerId, xx, yy)) addLegal(xx, yy);
      }
    }
    const actingAvatar = g.avatars[pendingSite.pid as PlayerId];
    const sourceUnitId =
      (pendingSite as { tappedAvatarId?: string }).tappedAvatarId ??
      ((actingAvatar as any)?.id ?? null);
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pendingSite.pid as PlayerId),
      sourceUnitId,
    };
  }

  const pendingPlay = anyG._pendingPlay as PendingPlayState | undefined;
  if (pendingPlay?.pid != null) {
    const card = pendingPlayCard(g, pendingPlay);
    const sourceTile = pendingPlaySourceTile(g, pendingPlay);
    const sourceUnitId = pendingPlaySourceUnitId(g, pendingPlay);
    if (!card) return { active: true, legalTiles, softTiles, sourceTile };

    if (card.kind === 'Spell') {
      const spell = card as Extract<Card, { kind: 'Spell' }>;
      const code = spell.spellCode ?? toSpellCode(spell.name);
      const ability = code ? getSpellAbility(code) : undefined;
      let region: Region = g.viewRegion;
      if (pendingPlay.forcedCasterId) {
        const forced = findUnitById(g, pendingPlay.forcedCasterId);
        if (forced) region = ((forced as any).region ?? region) as Region;
      } else if (pendingPlay.source === 'morgana' && pendingPlay.morganaId) {
        const data = findMorganaHandData(g, pendingPlay.morganaId);
        if (data) region = ((data.token as any).region ?? region) as Region;
      } else if (pendingPlay.source === 'algor' && pendingPlay.algorId) {
        const art = findAlgorArtifactById(g, pendingPlay.algorId);
        if (art) region = (art.region ?? region) as Region;
      }
      if (ability?.targeting === 'click-unit') {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            if (unitArrayAtRegion(g, xx, yy, region).length > 0) addLegal(xx, yy);
          }
        }
      } else if (ability?.targeting === 'click-tile') {
        fillSoftBoard();
      }
      return { active: true, legalTiles, softTiles, sourceTile, sourceUnitId };
    }

    if (card.kind === 'AuraCard') {
      const name = card.name ?? '';
      if (/^Sow the Earth$/i.test(name)) {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            const cell = cellOf(g, xx, yy);
            if (auraByNameAtAny(g, 'Salt the Earth', xx, yy)) continue;
            if (!cell.site || cell.site.rubble) addLegal(xx, yy);
          }
        }
      } else if (/^Salt the Earth$/i.test(name)) {
        for (let yy = 0; yy < g.height; yy += 1) {
          for (let xx = 0; xx < g.width; xx += 1) {
            const site = cellOf(g, xx, yy).site;
            if (site && !site.rubble) addLegal(xx, yy);
          }
        }
      } else {
        fillSoftBoard();
      }
      return { active: true, legalTiles, softTiles, sourceTile, sourceUnitId };
    }

    fillSoftBoard();
    return { active: true, legalTiles, softTiles, sourceTile, sourceUnitId };
  }

  const pendingUnit = anyG._pendingUnitMode as
    | { pid?: PlayerId; cardId?: string; region?: Region; source?: 'hand' | 'cemetery' }
    | undefined;
  if (pendingUnit?.pid != null) {
    const pid = pendingUnit.pid as PlayerId;
    const source = pendingUnit.source ?? 'hand';
    const zone = source === 'cemetery' ? (g.cemetery[pid] ?? []) : (g.handSpells[pid] ?? []);
    const card = zone.find((entry) => entry.id === pendingUnit.cardId);
    const targetRegion = (pendingUnit.region ?? 'surface') as Region;
    if (card && card.kind === 'Unit') {
      for (let yy = 0; yy < g.height; yy += 1) {
        for (let xx = 0; xx < g.width; xx += 1) {
          if (canSummonHere(g, pid, xx, yy, targetRegion, card)) addLegal(xx, yy);
        }
      }
    }
    return {
      active: true,
      legalTiles,
      softTiles,
      sourceTile: pendingSourceFromPid(g, pid),
    };
  }

  return { active: false, legalTiles, softTiles, sourceTile: null };
}

type PlacementPreview = { tiles: Array<{ x: number; y: number }> };

function setPlacementPreview(g: Game, tiles: Array<{ x: number; y: number }>): void {
  (g as any)._pendingPlacementPreview = { tiles } as PlacementPreview;
}

function clearPlacementPreview(g: Game): void {
  if ((g as any)._pendingPlacementPreview) delete (g as any)._pendingPlacementPreview;
}
