const loadSharedChatCache = (): Record<string, LandingChatMessage[]> => {
  if (typeof window === 'undefined' || !window.localStorage) return {};
  try {
    const raw = window.localStorage.getItem(SHARED_CHAT_CACHE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') return {};
    const out: Record<string, LandingChatMessage[]> = {};
    for (const [room, list] of Object.entries(parsed as Record<string, unknown>)) {
      if (!Array.isArray(list)) continue;
      out[String(room)] = list
        .filter((entry) => !!entry && typeof entry === 'object')
        .map((entry) => {
          const row = entry as Partial<LandingChatMessage>;
          return {
            id: String(row.id ?? `chat-${Math.random().toString(36).slice(2, 8)}`),
            handle: String(row.handle ?? 'Player'),
            text: String(row.text ?? ''),
            ts: Number.isFinite(Number(row.ts)) ? Number(row.ts) : Date.now(),
            system: !!row.system,
          };
        })
        .slice(-200);
    }
    return out;
  } catch {
    return {};
  }
};

const saveSharedChatCache = (cache: Record<string, LandingChatMessage[]>): void => {
  if (typeof window === 'undefined' || !window.localStorage) return;
  try {
    window.localStorage.setItem(SHARED_CHAT_CACHE_KEY, JSON.stringify(cache));
  } catch {
    // ignore storage failures
  }
};

const buildChatNoticeKey = (room: string, handle: string, text: string, ts: number): string =>
  `${room.trim().toUpperCase()}::${handle.trim().toLowerCase()}::${text.trim()}::${Number.isFinite(ts) ? ts : 0}`;

const rememberChatNoticeKey = (store: Set<string>, key: string): void => {
  store.add(key);
  while (store.size > 48) {
    const first = store.values().next();
    if (first.done) break;
    store.delete(first.value);
  }
};

const consumeChatNoticeKey = (store: Set<string>, key: string): boolean => {
  if (!store.has(key)) return false;
  store.delete(key);
  return true;
};

const SERVER_SAVE_ID_ADJECTIVES = [
  'ARCANE', 'EMBER', 'FROST', 'GOLDEN', 'IVORY', 'JASPER', 'LUNAR', 'MOSSY',
  'NOBLE', 'ONYX', 'RUNE', 'SOLAR', 'TEMPEST', 'UMBER', 'VERDANT', 'WILD',
] as const;
const SERVER_SAVE_ID_NOUNS = [
  'ATLAS', 'BASTION', 'CIPHER', 'DRUID', 'EMBER', 'FALCON', 'GATE', 'HARBOR',
  'KEEP', 'LANTERN', 'MONOLITH', 'NEXUS', 'ORBIT', 'PHOENIX', 'QUARRY', 'SPIRE',
] as const;
const SERVER_SAVE_RECOVERY_ALPHABET = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';

const secureRandomInt = (maxExclusive: number): number => {
  if (!Number.isFinite(maxExclusive) || maxExclusive <= 1) return 0;
  try {
    if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
      const bytes = new Uint32Array(1);
      crypto.getRandomValues(bytes);
      return Number(bytes[0] % maxExclusive);
    }
  } catch {
    // fall through to Math.random
  }
  return Math.floor(Math.random() * maxExclusive);
};

const generateServerSavePlayerId = (): string => {
  const adjective = SERVER_SAVE_ID_ADJECTIVES[secureRandomInt(SERVER_SAVE_ID_ADJECTIVES.length)] ?? 'ARCANE';
  const noun = SERVER_SAVE_ID_NOUNS[secureRandomInt(SERVER_SAVE_ID_NOUNS.length)] ?? 'ATLAS';
  const digits = String(1000 + secureRandomInt(9000));
  return `${adjective}-${noun}-${digits}`;
};

const generateServerSaveRecoveryKey = (): string => {
  const parts: string[] = [];
  for (let group = 0; group < 4; group += 1) {
    let chunk = '';
    for (let idx = 0; idx < 4; idx += 1) {
      chunk += SERVER_SAVE_RECOVERY_ALPHABET[secureRandomInt(SERVER_SAVE_RECOVERY_ALPHABET.length)] ?? 'A';
    }
    parts.push(chunk);
  }
  return parts.join('-');
};

const createServerSaveProfile = (): ServerSaveProfile => ({
  playerId: generateServerSavePlayerId(),
  recoveryKey: generateServerSaveRecoveryKey(),
  createdAt: Date.now(),
  storageMode: 'local',
});

const parseServerSaveProfile = (raw: string | null | undefined): ServerSaveProfile | null => {
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw) as Partial<ServerSaveProfile> | null;
    if (!parsed || typeof parsed !== 'object') return null;
    if (typeof parsed.playerId !== 'string' || !parsed.playerId.trim()) return null;
    if (typeof parsed.recoveryKey !== 'string' || !parsed.recoveryKey.trim()) return null;
    const createdAt = Number(parsed.createdAt);
    const warningAcknowledgedAt =
      parsed.warningAcknowledgedAt == null ? undefined : Number(parsed.warningAcknowledgedAt);
    const storageMode: ServerSaveStorageMode | undefined =
      parsed.storageMode === 'cloudflare' || parsed.storageMode === 'local'
        ? parsed.storageMode
        : undefined;
    return {
      playerId: parsed.playerId.trim().toUpperCase(),
      recoveryKey: parsed.recoveryKey.trim().toUpperCase(),
      createdAt: Number.isFinite(createdAt) ? createdAt : Date.now(),
      warningAcknowledgedAt: Number.isFinite(warningAcknowledgedAt as number) ? warningAcknowledgedAt : undefined,
      storageMode,
    };
  } catch {
    return null;
  }
};

const trimTrailingSlashes = (value: string) => value.replace(/\/+$/, '');

const resolveServerSaveApiBase = (wsUrl: string): string | null => {
  const env = `${(import.meta as any)?.env?.VITE_SERVER_SAVE_API_BASE ?? ''}`.trim();
  if (env) return trimTrailingSlashes(env);
  const raw = wsUrl.trim();
  if (!raw) return null;
  try {
    const parsed = new URL(raw);
    if (parsed.protocol === 'ws:') parsed.protocol = 'http:';
    else if (parsed.protocol === 'wss:') parsed.protocol = 'https:';
    return `${parsed.protocol}//${parsed.host}`;
  } catch {
    return null;
  }
};

const resolveLiveRoomsEndpoint = (wsUrl: string): string | null => {
  const raw = wsUrl.trim();
  if (!raw) return null;
  try {
    const parsed = new URL(raw);
    if (parsed.protocol === 'ws:') parsed.protocol = 'http:';
    else if (parsed.protocol === 'wss:') parsed.protocol = 'https:';
    parsed.pathname = '/rooms';
    parsed.search = '';
    parsed.hash = '';
    return parsed.toString();
  } catch {
    return null;
  }
};

const parseServerSaveApiError = (payload: unknown, fallback: string): string => {
  if (payload && typeof payload === 'object') {
    const p = payload as Record<string, unknown>;
    if (typeof p.error === 'string' && p.error.trim()) return p.error.trim();
    if (typeof p.message === 'string' && p.message.trim()) return p.message.trim();
  }
  return fallback;
};

const postServerSaveApi = async <T,>(baseUrl: string, path: string, body: unknown): Promise<T> => {
  const base = trimTrailingSlashes(baseUrl);
  const endpoint = path.startsWith('/') ? path : `/${path}`;
  const response = await fetch(`${base}${endpoint}`, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(body ?? {}),
  });
  const payload = await response.json().catch(() => null);
  if (!response.ok) {
    const fallback = `Request failed (${response.status}).`;
    throw new Error(parseServerSaveApiError(payload, fallback));
  }
  if (!payload || typeof payload !== 'object') {
    throw new Error('Invalid server response.');
  }
  return payload as T;
};

const normalizeDecklineName = (name: string): string => name.trim().replace(/\s+/g, ' ');

const formatDeckAsImportList = (deck: Decks): string => {
  const rows = new Map<string, { name: string; count: number; order: number }>();
  let order = 0;
  const pushCard = (card: Card | null | undefined) => {
    if (!card || !card.name) return;
    const displayName = normalizeDecklineName(card.name);
    if (!displayName) return;
    const key = displayName.toLowerCase();
    const found = rows.get(key);
    if (found) {
      found.count += 1;
      return;
    }
    rows.set(key, { name: displayName, count: 1, order: order++ });
  };

  for (const card of deck.atlas ?? []) pushCard(card);
  for (const card of deck.spellbook ?? []) pushCard(card);
  pushCard(deck.avatar ?? null);

  return Array.from(rows.values())
    .sort((a, b) => a.order - b.order)
    .map((entry) => `${entry.name} x${entry.count}`)
    .join('\n');
};

const encodeDecklistPayload = (text: string): string => {
  const value = String(text ?? '').trim();
  if (!value) return '';
  const bytes = new TextEncoder().encode(value);
  let binary = '';
  for (let i = 0; i < bytes.length; i += 1) binary += String.fromCharCode(bytes[i]);
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
};

const decodeDecklistPayload = (payload: string): string | null => {
  const raw = String(payload ?? '').trim();
  if (!raw) return null;
  try {
    const b64 = raw.replace(/-/g, '+').replace(/_/g, '/');
    const padded = b64 + '='.repeat((4 - (b64.length % 4)) % 4);
    const binary = atob(padded);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
    return new TextDecoder().decode(bytes);
  } catch {
    return null;
  }
};

const collectionOf = (deck: Decks): Card[] => {
  if (!Array.isArray(deck.collection)) deck.collection = [];
  return deck.collection;
};

function cardManaCost(card: Card | null | undefined): number {
  if (!card) return 0;
  if ('cost' in card && typeof (card as any).cost === 'number') {
    return (card as any).cost ?? 0;
  }
  return 0;
}

const isMagicianAvatar = (av: { name?: string | null; avatarCode?: AvatarCode | null | undefined }) =>
  /^Magician$/i.test(av.name ?? '') || av.avatarCode === 'MAGICIAN';

type StoryEvent =
  | { type: 'MOVE_AND_ATTACK'; pid: PlayerId; unitId: string; path: { x: number; y: number; region: Region }[]; chosenAttackTarget?: { kind: 'unit' | 'site'; id?: string } }
  | { type: 'CAST_SPELL'; pid: PlayerId; cardId: string; target?: any }
  | { type: 'UNIT_DIED'; unitId: string }
  | { type: 'SITE_DESTROYED'; x: number; y: number }
  | { type: 'TURN_START'; pid: PlayerId }
  | { type: 'TURN_END'; pid: PlayerId }

type FxEventKind = 'impact' | 'site_play' | 'undead_summon' | 'unit_destroyed' | 'projectile'
type FxEventSource = 'combat' | 'spell' | 'effect' | 'unknown'
type SiteFxStyle = 'earth' | 'water' | 'air' | 'fire' | 'multi' | 'neutral' | 'default'
type SummonSfxProfile = 'default' | 'airborne' | 'submerge' | 'burrowing' | 'stealth'
type ProjectileFxStyle = 'hook' | 'arrow' | 'fire' | 'lightning'
const SITE_PLACEMENT_FX_MS = 2000
const classifySiteFxStyle = (elements: Elem[]): SiteFxStyle => {
  const uniq = Array.from(new Set(normalizeElementList(elements)))
  if (uniq.length === 0) return 'neutral'
  if (uniq.length > 1) return 'multi'
  const only = uniq[0]
  if (only === 'Earth') return 'earth'
  if (only === 'Water') return 'water'
  if (only === 'Air') return 'air'
  if (only === 'Fire') return 'fire'
  return 'default'
}
const classifySummonSfxProfile = (token: Pick<Token, 'airborne' | 'submerge' | 'burrowing' | 'stealth'>): SummonSfxProfile => {
  if (token.airborne) return 'airborne'
  if (token.submerge) return 'submerge'
  if (token.burrowing) return 'burrowing'
  if (token.stealth) return 'stealth'
  return 'default'
}
type FxEvent = {
  id: number
  kind: FxEventKind
  x?: number
  y?: number
  pid?: PlayerId
  cardName?: string
  siteElements?: Elem[]
  summonSfxProfile?: SummonSfxProfile
  summonUndead?: boolean
  fromX?: number
  fromY?: number
  toX?: number
  toY?: number
  projectileStyle?: ProjectileFxStyle
  projectileReturn?: boolean
  projectileHit?: boolean
  source?: FxEventSource
  turn?: number
}

