type TestModeSnapshotMeta = {
  id: string;
  name: string;
  savedAt: number;
  turn: PlayerId;
  turnNumber: number;
};

type TestModeSnapshotPayload = {
  version: 1;
  meta: TestModeSnapshotMeta;
  game: Game;
};

const testModeSnapshotStorageKey = (id: string): string => `${TEST_MODE_SNAPSHOT_PREFIX}${id}`;

function readTestModeSnapshotIndex(): TestModeSnapshotMeta[] {
  if (typeof window === 'undefined' || !window.localStorage) return [];
  try {
    const raw = window.localStorage.getItem(TEST_MODE_SNAPSHOT_INDEX_KEY);
    const parsed = raw ? JSON.parse(raw) : [];
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((entry): TestModeSnapshotMeta | null => {
        if (!entry || typeof entry !== 'object') return null;
        const id = `${(entry as any).id ?? ''}`.trim();
        const name = `${(entry as any).name ?? ''}`.trim();
        if (!id || !name) return null;
        const savedAt = Number((entry as any).savedAt);
        const turn = Number((entry as any).turn) === 2 ? 2 : 1;
        const turnNumberRaw = Number((entry as any).turnNumber);
        const turnNumber = Number.isFinite(turnNumberRaw) ? Math.max(1, Math.floor(turnNumberRaw)) : 1;
        return {
          id,
          name,
          savedAt: Number.isFinite(savedAt) ? savedAt : 0,
          turn,
          turnNumber,
        };
      })
      .filter((entry): entry is TestModeSnapshotMeta => !!entry)
      .sort((a, b) => b.savedAt - a.savedAt);
  } catch {
    return [];
  }
}

function writeTestModeSnapshotIndex(entries: TestModeSnapshotMeta[]): void {
  if (typeof window === 'undefined' || !window.localStorage) return;
  try {
    window.localStorage.setItem(TEST_MODE_SNAPSHOT_INDEX_KEY, JSON.stringify(entries));
  } catch {
    // ignore storage errors
  }
}

const normalizeTestSnapshotName = (value: string): string =>
  value.trim().replace(/\s+/g, ' ').slice(0, 64);

