const getChatLog = (g: Game): ChatLogEntry[] => {
  const anyGame = g as any;
  if (!Array.isArray(anyGame._chatLog)) anyGame._chatLog = [];
  return anyGame._chatLog as ChatLogEntry[];
};

const getSharedNotepadLog = (g: Game): SharedNotepadEntry[] => {
  const anyGame = g as any;
  if (!Array.isArray(anyGame._sharedNotepadLog)) anyGame._sharedNotepadLog = [];
  return anyGame._sharedNotepadLog as SharedNotepadEntry[];
};

const getFxEvents = (g: Game): FxEvent[] => {
  const anyGame = g as any;
  if (!Array.isArray(anyGame._fxEvents)) anyGame._fxEvents = [];
  return anyGame._fxEvents as FxEvent[];
};

function emitFxEvent(g: Game, event: Omit<FxEvent, 'id' | 'turn'>): void {
  const anyGame = g as any;
  const nextId = (Number(anyGame._fxEventSeq ?? 0) || 0) + 1;
  anyGame._fxEventSeq = nextId;
  const queue = getFxEvents(g);
  queue.push({
    id: nextId,
    turn: g.turnNumber ?? 0,
    ...event,
  });
  if (queue.length > 240) {
    queue.splice(0, queue.length - 240);
  }
}

function emitProjectileFx(
  g: Game,
  opts: {
    fromX: number;
    fromY: number;
    toX: number;
    toY: number;
    style: ProjectileFxStyle;
    returnToSource?: boolean;
    hit?: boolean;
    pid?: PlayerId;
    cardName?: string;
    source?: FxEventSource;
  }
): void {
  if (!Number.isFinite(opts.fromX) || !Number.isFinite(opts.fromY)) return;
  if (!Number.isFinite(opts.toX) || !Number.isFinite(opts.toY)) return;
  emitFxEvent(g, {
    kind: 'projectile',
    x: opts.toX,
    y: opts.toY,
    fromX: opts.fromX,
    fromY: opts.fromY,
    toX: opts.toX,
    toY: opts.toY,
    projectileStyle: opts.style,
    projectileReturn: opts.returnToSource ?? false,
    projectileHit: opts.hit ?? true,
    pid: opts.pid,
    cardName: opts.cardName,
    source: opts.source ?? 'effect',
  });
}

const getActiveAvatarEmotes = (g: Game): Partial<Record<PlayerId, ActiveAvatarEmote>> => {
  const anyGame = g as any;
  if (!anyGame._activeAvatarEmotes || typeof anyGame._activeAvatarEmotes !== 'object') {
    anyGame._activeAvatarEmotes = {};
  }
  return anyGame._activeAvatarEmotes as Partial<Record<PlayerId, ActiveAvatarEmote>>;
};

const pruneExpiredAvatarEmotes = (g: Game, now = Date.now()): boolean => {
  const emotes = getActiveAvatarEmotes(g);
  let changed = false;
  for (const pid of [1, 2] as PlayerId[]) {
    const entry = emotes[pid];
    if (!entry) continue;
    if (!Number.isFinite(entry.expiresAt) || entry.expiresAt <= now) {
      delete emotes[pid];
      changed = true;
    }
  }
  return changed;
};

const pushAvatarEmote = (g: Game, pid: PlayerId, text: string): void => {
  const now = Date.now();
  const chatLog = getChatLog(g);
  chatLog.unshift({ id: `chat_${uid()}`, pid, text, at: now });
  if (chatLog.length > CHAT_LOG_LIMIT) chatLog.length = CHAT_LOG_LIMIT;
  const active = getActiveAvatarEmotes(g);
  active[pid] = { text, expiresAt: now + AVATAR_EMOTE_DURATION_MS };
};

const pushSharedNotepadEntry = (g: Game, pid: PlayerId, text: string): boolean => {
  const trimmed = text.replace(/\r\n/g, '\n').trim();
  if (!trimmed) return false;
  const entries = getSharedNotepadLog(g);
  entries.unshift({ id: `note_${uid()}`, pid, text: trimmed, at: Date.now() });
  if (entries.length > SHARED_NOTEPAD_LIMIT) entries.length = SHARED_NOTEPAD_LIMIT;
  return true;
};

const getAppealState = (g: Game): AppealState => {
  const anyGame = g as any;
  if (!anyGame._appealState || typeof anyGame._appealState !== 'object') {
    anyGame._appealState = {
      requestedBy: {},
      manualMode: false,
    } satisfies AppealState;
  }
  const state = anyGame._appealState as AppealState;
  if (!state.requestedBy || typeof state.requestedBy !== 'object') state.requestedBy = {};
  if (typeof state.manualMode !== 'boolean') state.manualMode = false;
  return state;
};

const setAppealRequested = (g: Game, pid: PlayerId, enabled: boolean): AppealState => {
  const state = getAppealState(g);
  state.requestedBy[pid] = enabled;
  state.lastUpdatedAt = Date.now();
  return state;
};

const clearAppealState = (g: Game): AppealState => {
  const state = getAppealState(g);
  state.requestedBy = {};
  state.manualMode = false;
  delete state.activatedAt;
  state.lastUpdatedAt = Date.now();
  return state;
};

