const auraShapeForCard = (name: string): Aura['shape'] => {
  const normalized = name.trim()
  if (BORDER_AURAS.has(normalized)) return 'border'
  if (SINGLE_TILE_AURAS.has(normalized)) return 'single'
  return '2x2'
}

const hasVermisMysteriis = (g: Game, pid: PlayerId): boolean => {
  for (const art of g.artifacts) {
    if (!/^De Vermis Mysteriis$/i.test(art.name ?? '')) continue;
    const carrierId = art.carriedBy;
    if (!carrierId) continue;
    const located = findTokenOnBoard(g, carrierId);
    if (!located) continue;
    const bearer = located.token;
    if (bearer.player !== pid) continue;
    if (unitIsSilenced(g, bearer)) continue;
    if (!isSpellcasterUnit(g, bearer)) continue;
    return true;
  }
  return false;
};

