registerSpell({
  code: 'SWAP',
  targeting: 'click-unit',
  resolve(ctx, params) {
    if (params.kind !== 'click') return false;
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const region = regionFromView(g);
    const cell = cellOf(g, params.x, params.y);

    void (async () => {
      const state0 = latestStateOr(g);
      const units = unitArrayAtRegion(state0, params.x, params.y, region).filter((u) => u.kind !== 'Avatar') as Token[];
      const artifacts = cellOf(state0, params.x, params.y).artifacts.filter((a) => !a.carriedBy);
      const options: Array<{ label: string; kind: 'unit' | 'artifact'; id: string }> = [];
      units.forEach((u) =>
        options.push({ label: formatTileText(state0, `${u.name} (Unit)`), kind: 'unit', id: String((u as any).id ?? '') }),
      );
      artifacts.forEach((a) =>
        options.push({ label: formatTileText(state0, `${a.name} (Artifact)`), kind: 'artifact', id: String(a.id ?? '') }),
      );
      if (options.length === 0) {
        state0.log.unshift('Swap finds no minion or artifact at the chosen tile.');
        requestGameSync?.();
        return;
      }

      let selection = options[0];
      if (options.length > 1) {
        const idx = await uiSelectOne<number>({
          title: 'Swap',
          message: formatTileText(state0, 'Choose the first target to swap.'),
          options: options.map((opt, i) => ({ label: opt.label, value: i })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= options.length) {
          const state = latestStateOr(state0);
          state.log.unshift('Swap cancelled.');
          requestGameSync?.();
          return;
        }
        selection = options[idx];
      }

      const candidates: Array<{ label: string; id: string }> = [];
      if (selection.kind === 'unit') {
        const others = state0.board
          .flat()
          .flatMap((c) => c.units)
          .filter((u) => u.kind !== 'Avatar' && String((u as any).id ?? '') !== selection.id);
        others.forEach((u) => {
          const ux = (u as any).x as number;
          const uy = (u as any).y as number;
          const ur = ((u as any).region ?? 'surface') as Region;
          candidates.push({
            label: formatTileText(state0, `${u.name} @ (${ux + 1}, ${uy + 1}) [${ur}]`),
            id: String((u as any).id ?? ''),
          });
        });
      } else {
        const others = state0.artifacts.filter((a) => !a.carriedBy && String(a.id ?? '') !== selection.id);
        others.forEach((a) => {
          const pos = getArtifactCurrentPosition(state0, a);
          candidates.push({
            label: formatTileText(state0, `${a.name} @ (${pos.x + 1}, ${pos.y + 1}) [${pos.region}]`),
            id: String(a.id ?? ''),
          });
        });
      }

      if (candidates.length === 0) {
        const state = latestStateOr(state0);
        state.log.unshift('Swap needs a second target — none available.');
        requestGameSync?.();
        return;
      }

      let second = candidates[0];
      if (candidates.length > 1) {
        const idx = await uiSelectOne<number>({
          title: 'Swap',
          message: formatTileText(state0, 'Choose the second target.'),
          options: candidates.map((entry, i) => ({ label: entry.label, value: i })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null) {
          const state = latestStateOr(state0);
          state.log.unshift('Swap cancelled.');
          requestGameSync?.();
          return;
        }
        const parsed = idx;
        if (!Number.isFinite(parsed) || parsed < 0 || parsed >= candidates.length) {
          const state = latestStateOr(state0);
          state.log.unshift('Swap cancelled.');
          requestGameSync?.();
          return;
        }
        second = candidates[parsed];
      }

      const state = latestStateOr(state0);
      if (selection.kind === 'unit') {
        const a = findLiveTokenById(state, selection.id);
        const b = findLiveTokenById(state, second.id);
        if (!a || !b) {
          state.log.unshift('Swap failed — one target is no longer in play.');
          requestGameSync?.();
          return;
        }
        const ax = (a as any).x as number | undefined;
        const ay = (a as any).y as number | undefined;
        const ar = ((a as any).region ?? 'surface') as Region;
        const bx = (b as any).x as number | undefined;
        const by = (b as any).y as number | undefined;
        const br = ((b as any).region ?? 'surface') as Region;
        if (!Number.isFinite(ax) || !Number.isFinite(ay) || !Number.isFinite(bx) || !Number.isFinite(by)) {
          state.log.unshift('Swap failed — one target is not on the board.');
          requestGameSync?.();
          return;
        }
        const destA = cellOf(state, bx!, by!);
        const destB = cellOf(state, ax!, ay!);
        if (!regionAllowedForUnit(state, a, br, destA, bx!, by!) || !regionAllowedForUnit(state, b, ar, destB, ax!, ay!)) {
          state.log.unshift('Swap failed — destination not legal for one of the units.');
          requestGameSync?.();
          return;
        }
        moveUnitTo(state, a, bx!, by!, br, { sourcePlayer: pid });
        moveUnitTo(state, b, ax!, ay!, ar, { sourcePlayer: pid });
        state.log.unshift(`Swap exchanges ${a.name} with ${b.name}.`);
      } else {
        const a = findLiveArtifactById(state, selection.id);
        const b = findLiveArtifactById(state, second.id);
        if (!a || !b) {
          state.log.unshift('Swap failed — one artifact is no longer in play.');
          requestGameSync?.();
          return;
        }
        const posA = getArtifactCurrentPosition(state, a);
        const posB = getArtifactCurrentPosition(state, b);
        if (posA.carrier || posB.carrier) {
          state.log.unshift('Swap cannot move carried artifacts.');
          requestGameSync?.();
          return;
        }
        const cellA = cellOf(state, posA.x, posA.y);
        const cellB = cellOf(state, posB.x, posB.y);
        cellA.artifacts = cellA.artifacts.filter(art => art.id !== a.id);
        cellB.artifacts = cellB.artifacts.filter(art => art.id !== b.id);
        a.x = posB.x; a.y = posB.y; a.region = posB.region;
        b.x = posA.x; b.y = posA.y; b.region = posA.region;
        cellOf(state, posA.x, posA.y).artifacts.push(b);
        cellOf(state, posB.x, posB.y).artifacts.push(a);
        state.log.unshift(`Swap exchanges ${a.name} with ${b.name}.`);
      }
      requestGameSync?.();
    })();
  },
});

registerSpell({
  code: 'APPLY_ALKAHEST',
  targeting: 'click-tile',
  resolve(ctx, params) {
    if (params.kind !== 'click') return false;
    const g = ctx.state as Game;
    const region = regionFromView(g);
    const cell = cellOf(g, params.x, params.y);
    const site = cell.site;
    if (!site || site.rubble) {
      g.log.unshift('Apply Alkahest finds no site to scour.');
      requestGameSync?.();
      return;
    }
    const units = unitArrayAtRegion(g, params.x, params.y, region).filter(u => u.kind !== 'Avatar');
    const artifacts = cell.artifacts.filter(a => a.region === 'surface');
    let destroyed = 0;
    for (const u of units) {
      damageUnit(g, u, unitThresholdHPPlus(g, u), { isDamage: true });
      destroyed += 1;
    }
    for (const art of [...artifacts]) {
      destroyArtifact(g, art);
      destroyed += 1;
    }
    const before = g.auras.length;
    g.auras = g.auras.filter(a => !auraCoversTile(g, a, params.x, params.y));
    const auraDestroyed = before - g.auras.length;
    destroyed += auraDestroyed;
    g.log.unshift(`Apply Alkahest scours ${destroyed} permanents at (${params.x + 1}, ${params.y + 1}).`);
    requestGameSync?.();
  },
});

registerSpell({
  code: 'RETURN_TO_NATURE',
  targeting: 'none',
  resolve(ctx) {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const pending = (g as any)._pendingReturnToNature as { pid: PlayerId; kind: 'pick' | 'fizzle'; reason?: string; targetPid?: PlayerId; cardIds?: string[] } | undefined;
    if (!pending || pending.pid !== pid) {
      g.log.unshift('Return to Nature was not prepared.');
      requestGameSync?.();
      return false;
    }
    delete (g as any)._pendingReturnToNature;

    if (pending.kind === 'fizzle') {
      if (pending.reason === 'no-cemetery') g.log.unshift('Return to Nature finds no cards in any cemetery.');
      else g.log.unshift('Return to Nature finds an empty cemetery.');
      requestGameSync?.();
      return true;
    }

    const targetPid = pending.targetPid as PlayerId | undefined;
    if (!targetPid) {
      g.log.unshift('Return to Nature makes no changes.');
      requestGameSync?.();
      return true;
    }
    const cemetery = g.cemetery[targetPid] ?? [];
    if (cemetery.length === 0) {
      g.log.unshift('Return to Nature finds an empty cemetery.');
      requestGameSync?.();
      return true;
    }
    const picks = Array.isArray(pending.cardIds) ? pending.cardIds.slice(0, 3) : [];
    if (picks.length === 0) {
      g.log.unshift('Return to Nature makes no changes.');
      requestGameSync?.();
      return true;
    }
    const moved: string[] = [];
    for (const id of picks) {
      const idx = cemetery.findIndex(card => card.id === id);
      if (idx < 0) continue;
      const [card] = cemetery.splice(idx, 1);
      if (!card) continue;
      if (card.kind === 'Site') {
        g.decks[targetPid].atlas.push(card);
      } else {
        g.decks[targetPid].spellbook.push(card);
      }
      moved.push(card.name ?? 'Card');
    }
    if (moved.length > 0) {
      g.log.unshift(`Return to Nature tucks ${moved.join(', ')} on the bottom of Player ${targetPid}'s decks.`);
    } else {
      g.log.unshift('Return to Nature makes no changes.');
    }
    draw(g, pid, 'spells', 1);
    requestGameSync?.();
    return true;
  },
});

registerSpell({
  code: 'ACCUSATION',
  targeting: 'none',
  resolve(ctx) {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const opponent = pid === 1 ? 2 : 1;
    const state = latestStateOr(g);
    const hand = state.handSpells[opponent] ?? [];
    if (hand.length === 0) {
      state.log.unshift('Accusation reveals nothing — opponent has no hand.');
      requestGameSync?.();
      return;
    }

    const evilPresent =
      hand.some(card => /evil/i.test(card.name ?? '')) ||
      state.board.flat().some(row =>
        row.units.some(u =>
          u.player === opponent &&
          (/evil/i.test(u.name ?? '') || (Array.isArray((u as any).subTypes) && (u as any).subTypes.some((s: string) => /evil/i.test(s))))
        )
      );

    const handChoices = hand.map((card, i) => ({
      id: String(card.id ?? ''),
      name: card.name ?? `Card ${i + 1}`,
      index: i,
    }));

    void (async () => {
      let idx = 0;
      if (evilPresent || !isCpuPlayer(state, pid)) {
        const choice = await uiSelectOne<number>({
          title: 'Accusation',
          message: formatTileText(state, `Opponent reveals their hand. Choose a card to banish.`),
          options: handChoices.map((card, i) => ({
            label: formatTileText(state, card.name),
            value: i,
          })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (choice == null) {
          const live = latestStateOr(state);
          live.log.unshift('Accusation fizzles — no card selected.');
          requestGameSync?.();
          return;
        }
        idx = choice;
      } else {
        idx = Math.floor(Math.random() * handChoices.length);
      }

      const picked = handChoices[idx] ?? handChoices[0];
      const live = latestStateOr(state);
      const liveHand = live.handSpells[opponent] ?? [];
      let liveIdx = -1;
      if (picked?.id) liveIdx = liveHand.findIndex((card) => String(card.id ?? '') === picked.id);
      if (liveIdx < 0 && picked?.name) {
        const key = normalizedSpellName(picked.name);
        if (key) liveIdx = liveHand.findIndex((card) => normalizedSpellName(card.name ?? '') === key);
      }
      if (liveIdx < 0) liveIdx = Math.max(0, Math.min(liveHand.length - 1, picked?.index ?? 0));

      const [removed] = liveHand.splice(liveIdx, 1);
      if (removed) {
        recordBanishedCards(live, opponent, [removed]);
        live.log.unshift(`Accusation banishes ${removed.name} from Player ${opponent}'s hand.`);
      } else {
        live.log.unshift('Accusation could not find the selected card.');
      }
      requestGameSync?.();
    })();
  },
});

