registerSpell({
  code: 'DREDGE',
  targeting: 'click-tile',
  resolve(ctx, params) {
    if (params.kind !== 'click') return false;
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const cell = cellOf(g, params.x, params.y);
    const site = cell.site;
    if (!site || !isSiteWater(g, site, params.x, params.y)) {
      g.log.unshift('Dredge requires a water site.');
      requestGameSync?.();
      return;
    }
    const underwater = unitArrayAtRegion(g, params.x, params.y, 'underwater');
    for (const u of underwater) moveUnitTo(g, u, params.x, params.y, 'surface', { sourcePlayer: pid });
    for (let i = 0; i < 2; i++) {
      const skel = skeletonTokenFor(pid, params.x, params.y, 'surface');
      const stub: Extract<Card, { kind: 'Unit' }> = {
        id: uid(),
        kind: 'Unit',
        name: skel.name,
        element: skel.element,
        power: skel.power,
        atk: skel.atk,
        def: skel.def,
        subTypes: skel.subTypes,
        threshold: {},
        cost: 0,
        spellcaster: false,
        image: skel.image,
      };
      (skel as any)._srcCard = stub;
      cell.units.push(skel);
      handleUnitSummoned(g, pid, skel, stub);
    }
    g.log.unshift('Dredge surfaces everything here and summons two Skeletons.');
    requestGameSync?.();
  },
});

