registerSpell({
  code: 'LURE',
  targeting: 'none',
  resolve(ctx) {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const region = regionFromView(g);
    const options: Array<{ allyId: string; enemyId: string; dest: { x: number; y: number }; label: string }> = [];
    for (let y = 0; y < g.height; y++) {
      for (let x = 0; x < g.width; x++) {
        const cell = cellOf(g, x, y);
        for (const ally of cell.units) {
          if (ally.kind === 'Avatar') continue;
          if ((ally as any).player !== pid) continue;
          if (((ally as any).region ?? 'surface') !== region) continue;
          for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            const nx = x + dx;
            const ny = y + dy;
            if (!inside(g, nx, ny)) continue;
            const enemies = unitArrayAtRegion(g, nx, ny, region).filter(
              u =>
                u.kind !== 'Avatar' &&
                u.player !== pid &&
                (((u as any).region ?? 'surface') as Region) === region
            ) as Token[];
            for (const enemy of enemies) {
              const dest = { x, y };
              const destCell = cellOf(g, dest.x, dest.y);
              if (!regionAllowedForUnit(g, enemy, region, destCell, dest.x, dest.y)) continue;
              const allyId = String((ally as any).id ?? '');
              const enemyId = String((enemy as any).id ?? '');
              if (!allyId || !enemyId) continue;
              options.push({
                allyId,
                enemyId,
                dest,
                label: formatTileText(
                  g,
                  `${enemy.name} (P${enemy.player}) near ${ally.name} @ (${(dest.x ?? 0) + 1}, ${(dest.y ?? 0) + 1})`,
                ),
              });
            }
          }
        }
      }
    }
    if (options.length === 0) {
      g.log.unshift('Lure finds no enemy minion to tempt closer.');
      requestGameSync?.();
      return;
    }
    void (async () => {
      let pick = options[0];
      if (options.length > 1 && !isCpuPlayer(g, pid)) {
        const idx = await uiSelectOne<number>({
          title: 'Lure',
          message: formatTileText(g, 'Choose which enemy to lure closer to an ally.'),
          options: options.map((opt, i) => ({ label: opt.label, value: i })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= options.length) {
          const state = latestStateOr(g);
          state.log.unshift('Lure is cancelled.');
          requestGameSync?.();
          return;
        }
        pick = options[idx];
      }
      const state = latestStateOr(g);
      const liveEnemy = findLiveTokenById(state, pick.enemyId);
      const liveAlly = findLiveTokenById(state, pick.allyId);
      if (!liveEnemy || !liveAlly) {
        state.log.unshift('Lure fizzles — source or target is gone.');
        requestGameSync?.();
        return;
      }
      const moved = moveUnitTo(state, liveEnemy, pick.dest.x, pick.dest.y, region, {
        bypassAnchor: true,
        sourcePlayer: pid,
      });
      if (moved) {
        liveEnemy.interactedThisTurn = true;
      }
      state.log.unshift(
        moved
          ? `Lure draws ${liveEnemy.name} toward ${liveAlly.name}.`
          : `${liveEnemy.name} resists the lure.`
      );
      requestGameSync?.();
    })();
  },
});

