registerSpell({
  code: 'HOLY_NOVA',
  targeting: 'none',
  resolve(ctx) {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const pending = (g as any)._pendingHolyNova as {
      pid: PlayerId; kind: 'pick' | 'fizzle'; reason?: string; ward?: { kind: 'site' | 'unit'; id: string } | null
    } | undefined;
    if (!pending || pending.pid !== pid) {
      g.log.unshift('Holy Nova was not prepared.');
      requestGameSync?.();
      return false;
    }
    delete (g as any)._pendingHolyNova;
    if (pending.kind === 'fizzle') {
      g.log.unshift('Holy Nova — no caster found.');
      requestGameSync?.();
      return true;
    }
    const casterPos = lastSpellCasterPosition(g, pid);
    if (!casterPos) {
      g.log.unshift('Holy Nova — no caster found.');
      requestGameSync?.();
      return true;
    }
    let center = { x: casterPos.x, y: casterPos.y };
    const ward = pending.ward ?? null;
    if (ward && ward.id) {
      if (ward.kind === 'unit') {
        const unit = findUnitById(g, ward.id);
        const ux = unit ? (unit as any).x : undefined;
        const uy = unit ? (unit as any).y : undefined;
        if (unit && breakWardOn(unit) && Number.isFinite(ux) && Number.isFinite(uy)) {
          center = { x: ux as number, y: uy as number };
          g.log.unshift('Holy Nova breaks a Ward to shift its center.');
        }
      } else {
        let site: Site | null = null;
        let coords: { x: number; y: number } | null = null;
        for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
          const cell = cellOf(g, x, y);
          if (cell.site && cell.site.id === ward.id) {
            site = cell.site;
            coords = { x, y };
            break;
          }
        }
        if (site && coords && breakWardOn(site)) {
          center = { x: coords.x, y: coords.y };
          g.log.unshift('Holy Nova breaks a Ward to shift its center.');
        }
      }
    }
    let hits = 0;
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      const nx = center.x + dx;
      const ny = center.y + dy;
      if (!inside(g, nx, ny)) continue;
      const enemies = unitArrayAtRegion(g, nx, ny, 'surface').filter(u => u.kind !== 'Avatar' && u.player !== pid);
      for (const foe of enemies) {
        damageUnit(g, foe, 2, { sourceElement: 'Earth', isDamage: true });
        hits += 1;
      }
    }
    g.log.unshift(`Holy Nova erupts at (${center.x + 1},${center.y + 1}), smiting ${hits} enemy unit(s).`);
    requestGameSync?.();
    return true;
  },
});

registerSpell({
  code: 'KISS_OF_JUDAS',
  targeting: 'click-unit',
  resolve(ctx, params) {
    if (params.kind !== 'click') return false;
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const avatars: Array<{ pid: PlayerId; avatar: Avatar }> = [];
    for (const ap of [1, 2] as PlayerId[]) {
      const av = g.avatars[ap];
      if (av) avatars.push({ pid: ap, avatar: av });
    }
    const onTile = unitArrayAtRegion(g, params.x, params.y, 'surface').find(u => u.kind === 'Avatar') as Avatar | undefined;
    let target = onTile ? avatars.find(a => a.avatar.id === onTile.id) ?? null : null;
    if (!target) {
      target = avatars.find(a => a.pid !== pid) ?? avatars[0] ?? null;
    }
    if (!target) {
      g.log.unshift('Kiss of Judas — no avatar found.');
      requestGameSync?.();
      return false;
    }
    (g as any)._kissOfJudas = { targetPid: target.pid, turn: g.turnNumber };
    g.log.unshift(`Kiss of Judas brands Player ${target.pid}'s avatar — attacks cannot be defended, and draws occur when attacked this turn.`);
    requestGameSync?.();
    return true;
  },
});

registerSpell({
  code: 'NECRONOMICONCERT',
  targeting: 'none',
  resolve(ctx) {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;
    const casterPos = lastSpellCasterPosition(g, pid);
    if (!casterPos) {
      g.log.unshift('Necronomiconcert — no caster found.');
      requestGameSync?.();
      return;
    }
    const region = casterPos.region;
    let count = 0;
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      const nx = casterPos.x + dx;
      const ny = casterPos.y + dy;
      if (!inside(g, nx, ny)) continue;
      const units = unitArrayAtRegion(g, nx, ny, region);
      for (const u of units) {
        if (u.kind === 'Avatar') continue;
        if ((u as any).player !== pid) continue;
        if (unitHasSubtype(g, u, 'Undead')) count += 1;
        const carriedInstruments = getCarriedArtifacts(g, u).filter(a => artifactHasSubtype(a, 'Instrument')).length;
        count += carriedInstruments;
      }
      const cell = cellOf(g, nx, ny);
      for (const art of cell.artifacts) {
        if (art.carriedBy) continue;
        const artRegion = ((art as any).region ?? 'surface') as Region;
        if (artRegion !== region) continue;
        const owner = artifactOwnerPid(art) ?? art.player;
        if (owner !== pid) continue;
        if (artifactHasSubtype(art, 'Instrument')) count += 1;
      }
    }
    if (count <= 0) {
      g.log.unshift('Necronomiconcert finds no Undead or Instruments nearby.');
      requestGameSync?.();
      return;
    }
    draw(g, pid, 'spells', count);
    g.log.unshift(`Necronomiconcert rocks out — draw ${count} card(s).`);
    requestGameSync?.();
  },
});

registerSpell({
  code: 'BORDER_MILITIA',
  targeting: 'none',
  resolve(ctx) {
    const g = (getLatestGameState?.() ?? ctx.state) as Game;
    const pid = ctx.pid as PlayerId;
    const { allied } = collectBorderSites(g, pid);
    let spawned = 0;
    for (const pos of allied) {
      const cell = cellOf(g, pos.x, pos.y);
      const site = cell.site;
      if (!site || site.rubble || site.controller !== pid) continue;
      const token = footSoldierTokenFor(g, pid, pos.x, pos.y);
      (cell.units ??= []).push(token);
      handleUnitSummoned(g, pid, token, {
        id: token.id,
        kind: 'Unit',
        name: token.name,
        element: token.element,
        power: token.power,
        atk: token.atk ?? token.power,
        def: token.def ?? token.power,
        subTypes: token.subTypes,
        threshold: {},
        cost: 0,
      } as any);
      spawned += 1;
    }
    g.log.unshift(
      spawned > 0
        ? `Border Militia summons ${spawned} Foot Soldier token(s) to allied border sites.`
        : 'Border Militia finds no allied border sites to reinforce.'
    );
    requestGameSync?.();
    return true;
  },
});

