          tapped: false,
          power: cardToSummon.power,
          atk: cardToSummon.atk,
          def: cardToSummon.def,
          airborne: cardToSummon.airborne,
          burrowing: cardToSummon.burrowing,
          submerge: cardToSummon.submerge,
          voidwalk: cardToSummon.voidwalk,
          movementPlus: cardToSummon.movementPlus,
          immobile: cardToSummon.immobile,
          ranged: cardToSummon.ranged,
          stealth: cardToSummon.stealth,
