registerAbility('Deathspeaker', {
  name: 'Deathspeaker',
  tapPrimary: SharedTapPrimary,
  onTurnStart: (ctx) => { (ctx.state as any)._deathspeakerUsed ??= {1:false,2:false}; (ctx.state as any)._deathspeakerUsed[ctx.pid] = false },
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid
    const used = ((g as any)._deathspeakerUsed ?? {})[pid];
    if (used) { g.log.unshift('Deathspeaker: already used this turn.'); return }
    const gyMinion = g.cemetery[pid].find((c): c is Extract<Card, { kind: 'Unit' }> => c.kind === 'Unit');
    if (!gyMinion) { g.log.unshift('Deathspeaker: no dead minion to cast.'); return }
    const cost = (g.avatars[pid].deathsDoor ? 0 : (gyMinion as any).cost ?? 0)
    if (g.mana[pid] < cost) { g.log.unshift('Not enough mana for Deathspeaker.'); return }

    spendMana(g, pid, cost);
    const sourceIdx = g.cemetery[pid].findIndex(c => c.id === gyMinion.id);
    const sourceBanished = (sourceIdx >= 0
      ? g.cemetery[pid].splice(sourceIdx, 1)[0]
      : structuredClone(gyMinion)) as Card;
    recordBanishedCards(g, pid, [sourceBanished]);

    const av = g.avatars[pid];
    const copyCard = structuredClone(gyMinion);
    copyCard.id = uid();
    const summoned = summonUnitCardAt(g, pid, copyCard, av.x, av.y, 'surface', {
      bypassPlacement: true,
      summonSource: 'effect',
    });

    let copyBanished: Card | null = null;
    if (summoned) {
      const live = findTokenOnBoard(g, summoned.id);
      if (live) {
        copyBanished = banishUnitInstance(g, live.token, { source: 'Deathspeaker', skipLog: true });
      }
      const myCemetery = g.cemetery[pid] ?? (g.cemetery[pid] = []);
      const inCemeteryIdx = myCemetery.findIndex(c => c.id === copyCard.id);
      if (inCemeteryIdx >= 0) {
        const [removed] = myCemetery.splice(inCemeteryIdx, 1);
        if (removed) copyBanished = removed;
      }
    }

    recordBanishedCards(g, pid, [copyBanished ?? copyCard]);
    ;(g as any)._deathspeakerUsed[pid] = true
    g.log.unshift(`Deathspeaker banishes ${sourceBanished.name} to cast a copy that enters the realm, uses its Genesis, and is banished${cost === 0 ? ' for (0)' : ''}.`)
  },
})

