registerAbility('Savior', {
  name: 'Savior',
  tapPrimary: SharedTapPrimary,
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    if (g.turn !== pid || g.phase !== 'Main') {
      g.log.unshift('Savior: can only ward during your main phase.');
      return;
    }
    if ((g.mana[pid] ?? 0) < 1) {
      g.log.unshift('Savior: not enough mana to ward a minion.');
      return;
    }
    const candidates = g.board
      .flat()
      .flatMap(cell => cell.units)
      .filter(u => u.kind !== 'Avatar' && u.player === pid && (u as Token).summonedThisTurn) as Token[];
    if (candidates.length === 0) {
      g.log.unshift('Savior: no minion summoned this turn to ward.');
      return;
    }

    void (async () => {
      const gState = getLatestGameState?.() ?? g;
      const refreshed = gState.board
        .flat()
        .flatMap(cell => cell.units)
        .filter(u => u.kind !== 'Avatar' && u.player === pid && (u as Token).summonedThisTurn) as Token[];
      if (refreshed.length === 0) {
        gState.log.unshift('Savior: no summoned minion remains to ward.');
        requestGameSync?.();
        return;
      }
      let choice = refreshed[0];
      if (refreshed.length > 1 && !isCpuPlayer(gState, pid)) {
        const idx = await uiSelectOne<number>({
          title: 'Savior',
          message: formatTileText(gState, 'Ward which minion summoned this turn?'),
          options: refreshed.map((u, i) => ({
            label: formatTileText(gState, `${u.name} @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
            value: i,
          })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= refreshed.length) {
          gState.log.unshift('Savior: warding cancelled.');
          requestGameSync?.();
          return;
        }
        choice = refreshed[idx];
      } else if (refreshed.length > 1 && isCpuPlayer(gState, pid)) {
        choice = refreshed.find(u => wardCount(u) === 0) ?? refreshed[0];
      }
      spendMana(gState, pid, 1);
      grantWard(choice);
      gState.log.unshift(`Savior wards ${choice.name}.`);
      requestGameSync?.();
    })();
  },
});

registerAbility('Dragonlord', {
  name: 'Dragonlord',
  tapPrimary: SharedTapPrimary,
  powerBonus: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];
    if (!av) return 0;
    if ((av as any)._dragonlordCopiedTurn !== g.turnNumber) return 0;
    const copied = (av as any)._dragonlordCopiedCard as Extract<Card, { kind: 'Unit' }> | undefined;
    if (!copied || !/^Moonsong Talagelum$/i.test(copied.name ?? '')) return 0;
    const region = ((av as any).region ?? 'surface') as Region;
    const cells: Array<[number, number]> = nearbyCoords8(g, av.x, av.y);
    let pack = 0;
    for (const [cx, cy] of cells) {
      const neighbors = unitArrayAtRegion(g, cx, cy, region);
      for (const other of neighbors) {
        if (other === av) continue;
        if (other.player !== pid) continue;
        if (isGreyWolvesLike(g, other)) pack += 1;
      }
    }
    return pack;
  },
  onSetup: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];
    if (!av || (av as any)._dragonlordSetAside || (av as any)._chosenDragonName) return;
    void (async () => {
      const gState = getLatestGameState?.() ?? g;
      const avState = gState.avatars[pid];
      if (!avState || (avState as any)._dragonlordSetAside) return;

      const options = collectDragonlordSetAsideOptions(gState, pid);
      if (options.length === 0) {
        gState.log.unshift('Dragonlord finds no Unique Dragon to set aside.');
        requestGameSync?.();
        return;
      }

      const labels = options.map((opt) => {
        const zone =
          opt.source === 'collection' ? 'Collection' : opt.source === 'hand' ? 'Hand' : 'Spellbook';
        return `${opt.card.name} (${zone})`;
      });

      let pickIndex = 0;
      if (!isCpuPlayer(gState, pid)) {
        const idx = await uiSelectOne<number>({
          title: 'Dragonlord',
          message: 'Choose a Unique Dragon to set aside.',
          options: labels.map((label, index) => ({ label, value: index })),
          allowCancel: true,
          cancelLabel: 'Skip',
        });
        if (idx == null || idx < 0 || idx >= options.length) {
          gState.log.unshift('Dragonlord set-aside cancelled.');
          requestGameSync?.();
          return;
        }
        pickIndex = idx;
      } else {
        const raw = pickRandomIndex(gState, options.length, {
          context: 'Dragonlord set aside',
          labels,
          controllerPid: pid,
        });
        pickIndex = Math.max(0, Math.min(options.length - 1, raw));
      }

      const choice = options[pickIndex];
      const chosenCard = structuredClone(choice.card);
      if (choice.source === 'collection') {
        const list = gState.decks[pid].collection ?? (gState.decks[pid].collection = []);
        list.splice(choice.index, 1);
      } else if (choice.source === 'hand') {
        gState.handSpells[pid].splice(choice.index, 1);
      } else {
        gState.decks[pid].spellbook.splice(choice.index, 1);
      }

      (avState as any)._dragonlordSetAside = chosenCard;
      (avState as any)._chosenDragonName = chosenCard.name;
      gState.log.unshift(`Dragonlord sets aside ${chosenCard.name}.`);
      requestGameSync?.();
    })();
  },
  oncePerTurn: (ctx) => {
    const g = ctx.state, pid = ctx.pid, av = g.avatars[pid]
    if (!av) return;
    const adventureActive = Boolean((g as any)?._adventure?.enabled);
    if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
      g.log.unshift('Dragonlord: not your main phase.');
      return;
    }
    if ((av as any)._dragonlordInvokeTurn === g.turnNumber) {
      g.log.unshift('Dragonlord: already invoked this turn.');
      return;
    }
    const setAside = (av as any)._dragonlordSetAside as Extract<Card, { kind: 'Unit' }> | undefined;
    const fallbackName = (av as any)._chosenDragonName as string | undefined;
    const fallbackCard =
      !setAside && fallbackName ? (getCardTemplateByName(fallbackName) as Extract<Card, { kind: 'Unit' }> | null) : null;
    const chosenCard = setAside ?? fallbackCard ?? null;
    if (!chosenCard || chosenCard.kind !== 'Unit') {
      g.log.unshift('Dragonlord: no set-aside Dragon is available.');
      return;
    }
    const meetsThreshold = hasThreshold(threshold(g, pid), chosenCard.threshold ?? {});
    if (!meetsThreshold) {
      g.log.unshift(`Dragonlord: you do not meet ${chosenCard.name}'s threshold.`);
      return;
    }
    if (g.mana[pid] < 3) {
      g.log.unshift('Dragonlord: not enough mana.');
      return;
    }
    spendMana(g, pid, 3);
    (av as any)._dragonlordInvokeTurn = g.turnNumber;
    applyDragonlordCopyTraits(g, av, chosenCard);
    g.log.unshift(`Dragonlord invokes ${chosenCard.name}'s abilities this turn.`);
  },
})

