type HarbingerSquare = { x: number; y: number };

function readHarbingerSquares(g: Game, pid: PlayerId): HarbingerSquare[] {
  const avatar = g.avatars[pid];
  if (!avatar) return [];
  const raw = (avatar as any)._harbingerSquares as Array<{ x?: number; y?: number }> | undefined;
  if (!Array.isArray(raw) || raw.length === 0) return [];
  const out: HarbingerSquare[] = [];
  for (const entry of raw) {
    const x = Number(entry?.x);
    const y = Number(entry?.y);
    if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
    if (!inside(g, x, y)) continue;
    out.push({ x, y });
  }
  return out;
}

function assignHarbingerSquaresIfNeeded(
  g: Game,
  pid: PlayerId,
  opts?: { force?: boolean; log?: boolean },
): boolean {
  const avatar = g.avatars[pid];
  if (!avatar || !/^Harbinger$/i.test(avatar.name ?? '')) return false;
  const existing = readHarbingerSquares(g, pid);
  if (!opts?.force && existing.length > 0) {
    (avatar as any)._harbingerSquares = existing;
    return false;
  }
  const coords: HarbingerSquare[] = [];
  for (let y = 0; y < g.height; y += 1) {
    for (let x = 0; x < g.width; x += 1) coords.push({ x, y });
  }
  shuffleInPlaceMutable(coords);
  const picks = coords.slice(0, 3);
  (avatar as any)._harbingerSquares = picks;
  if (opts?.log && picks.length > 0) {
    const list = picks.map((p) => `(${p.x + 1}, ${p.y + 1})`).join(', ');
    g.log.unshift(`Harbinger marks squares: ${list}.`);
  }
  return true;
}

function initializePostMulliganAvatarEffects(g: Game): void {
  const anyG = g as any;
  if (anyG._postMulliganAvatarInitDone) return;
  for (const pid of [1, 2] as PlayerId[]) {
    assignHarbingerSquaresIfNeeded(g, pid, { log: true });
  }
  anyG._postMulliganAvatarInitDone = true;
}

function harbingerTileOwnersByCell(g: Game): Map<string, PlayerId[]> {
  const marks = new Map<string, PlayerId[]>();
  for (const pid of [1, 2] as PlayerId[]) {
    const avatar = g.avatars[pid];
    if (!avatar || !/^Harbinger$/i.test(avatar.name ?? '')) continue;
    const squares = readHarbingerSquares(g, pid);
    for (const square of squares) {
      const key = `${square.x},${square.y}`;
      const owners = marks.get(key);
      if (owners) owners.push(pid);
      else marks.set(key, [pid]);
    }
  }
  return marks;
}

function canSummonAtHarbingerSquare(
  g: Game,
  pid: PlayerId,
  x: number,
  y: number,
  region: Region,
  card: Extract<Card, { kind: 'Unit' }>,
): boolean {
  if (!inside(g, x, y)) return false;
  if (canSummonHere(g, pid, x, y, region, card)) return true;
  if (region === 'void') return false;
  const site = cellOf(g, x, y).site;
  if (!site) return false;
  const originalController = site.controller;
  site.controller = pid;
  try {
    return canSummonHere(g, pid, x, y, region, card);
  } finally {
    site.controller = originalController;
  }
}

const useImposterMask = (ctx: AbilityCtx) => {
  const g = ctx.state, pid = ctx.pid;
  const av = g.avatars[pid];
  if (!av) return;
  const adventureActive = Boolean((g as any)?._adventure?.enabled);
  if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
    g.log.unshift('Imposter: only during your main phase.');
    requestGameSync?.();
    return;
  }
  const cost = 3;
  if ((g.mana[pid] ?? 0) < cost) {
    g.log.unshift('Imposter: not enough mana.');
    requestGameSync?.();
    return;
  }
  const collection = (g.decks?.[pid]?.collection ?? []) as Card[];
  const avatars = collection
    .map((card, index) => ({ card, index }))
    .filter(({ card }) => card.kind === 'Avatar') as Array<{ card: Extract<Card, { kind: 'Avatar' }>; index: number }>;
  if (avatars.length === 0) {
    g.log.unshift('Imposter finds no Avatar in your collection to banish.');
    requestGameSync?.();
    return;
  }
  if (!payBureauAccessCost(g, pid, 'your collection')) {
    requestGameSync?.();
    return;
  }
  void (async () => {
    let pick = avatars[0];
    if (!isCpuPlayer(g, pid) && avatars.length > 1) {
      const idx = await uiSelectOne<number>({
        title: 'Imposter',
        message: 'Banish which Avatar from your collection to mask yourself?',
        options: avatars.map((entry, i) => ({ label: entry.card.name, value: i })),
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (idx == null || idx < 0 || idx >= avatars.length) {
        g.log.unshift('Imposter declines to wear a new mask.');
        requestGameSync?.();
        return;
      }
      pick = avatars[idx];
    } else if (isCpuPlayer(g, pid) && avatars.length > 1) {
      const idx = pickRandomIndex(g, avatars.length, {
        context: 'Imposter mask',
        labels: avatars.map(entry => entry.card.name ?? 'Avatar'),
        controllerPid: pid,
      });
      pick = avatars[Math.max(0, Math.min(avatars.length - 1, idx))];
    }

    const gState = getLatestGameState?.() ?? g;
    const avState = gState.avatars[pid];
    if (!avState) return;
    const liveCollection = (gState.decks?.[pid]?.collection ?? []) as Card[];
    const liveIdx = liveCollection.findIndex(c => c.id === pick.card.id);
    if (liveIdx < 0) {
      gState.log.unshift('Imposter cannot find that Avatar in the collection.');
      requestGameSync?.();
      return;
    }
    const [banished] = liveCollection.splice(liveIdx, 1);
    if (banished) recordBanishedCards(gState, pid, [banished]);
    spendMana(gState, pid, cost);
    if (!(avState as any)._imposterBaseName) (avState as any)._imposterBaseName = avState.name;
    if (!(avState as any)._imposterBaseImage) (avState as any)._imposterBaseImage = avState.image;
    avState.name = pick.card.name;
    if (pick.card.image) avState.image = pick.card.image;
    (avState as any)._imposterMaskName = pick.card.name;
    (avState as any)._imposterMaskCard = structuredClone(banished ?? pick.card);
    gState.log.unshift(`Imposter masks as ${pick.card.name}.`);
    requestGameSync?.();
  })();
};

registerAbility('Harbinger', {
  name: 'Harbinger',
  tapPrimary: SharedTapPrimary,
  onSetup: (ctx) => {
    const avatar = ctx.state.avatars[ctx.pid];
    if (!avatar) return;
    delete (avatar as any)._harbingerSquares;
    delete (avatar as any)._harbingerCastTurn;
  },
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];
    if (!av) return;
    const adventureActive = Boolean((g as any)?._adventure?.enabled);
    if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
      g.log.unshift('Harbinger: only during your main phase.');
      requestGameSync?.();
      return;
    }
    if ((av as any)._harbingerCastTurn === g.turnNumber) {
      g.log.unshift('Harbinger: already used this turn.');
      requestGameSync?.();
      return;
    }
    const squares = ((av as any)._harbingerSquares ?? []) as Array<{ x: number; y: number }>;
    if (squares.length === 0) {
      g.log.unshift('Harbinger: no marked squares remain.');
      requestGameSync?.();
      return;
    }
    const handUnits = g.handSpells[pid]
      .map((card, index) => ({ card, index }))
      .filter(({ card }) => card.kind === 'Unit') as Array<{ card: Extract<Card, { kind: 'Unit' }>; index: number }>;
    if (handUnits.length === 0) {
      g.log.unshift('Harbinger: no minion in hand to cast.');
      requestGameSync?.();
      return;
    }
    void (async () => {
      let pick = handUnits[0];
      if (!isCpuPlayer(g, pid) && handUnits.length > 1) {
        const idx = await uiSelectOne<number>({
          title: 'Harbinger',
          message: 'Cast which minion to a marked square?',
          options: handUnits.map((entry, i) => ({ label: `${entry.card.name} (Cost ${entry.card.cost ?? 0})`, value: i })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= handUnits.length) {
          g.log.unshift('Harbinger casting cancelled.');
          requestGameSync?.();
          return;
        }
        pick = handUnits[idx];
      } else if (isCpuPlayer(g, pid) && handUnits.length > 1) {
        pick = handUnits.slice().sort((a, b) => (b.card.cost ?? 0) - (a.card.cost ?? 0))[0];
      }

      const gState = getLatestGameState?.() ?? g;
      const liveSquares = ((gState.avatars[pid] as any)?._harbingerSquares ?? []) as Array<{ x: number; y: number }>;
      const card = pick.card;
      const squareOptions: Array<{ x: number; y: number; regions: Region[] }> = [];
      for (const square of liveSquares) {
        const regionOptions: Region[] = [];
        if (canSummonAtHarbingerSquare(gState, pid, square.x, square.y, 'surface', card)) {
          regionOptions.push('surface');
        }
        const hellmouthBurrow = hellmouthAllowsBurrowingForSummon(gState, card, square.x, square.y);
        if ((card.burrowing || hellmouthBurrow) && canSummonAtHarbingerSquare(gState, pid, square.x, square.y, 'underground', card)) {
          regionOptions.push('underground');
        }
        if (card.submerge && canSummonAtHarbingerSquare(gState, pid, square.x, square.y, 'underwater', card)) {
          regionOptions.push('underwater');
        }
        const lucidVoid = lucidDreamersAllowsVoidSummon(gState, pid, square.x, square.y);
        if ((card.voidwalk || lucidVoid) && canSummonAtHarbingerSquare(gState, pid, square.x, square.y, 'void', card)) {
          regionOptions.push('void');
        }
        if (regionOptions.length > 0) squareOptions.push({ x: square.x, y: square.y, regions: regionOptions });
      }
      if (squareOptions.length === 0) {
        gState.log.unshift('Harbinger: no marked squares can receive that minion.');
        requestGameSync?.();
        return;
      }

      let squarePick = squareOptions[0];
      if (squareOptions.length > 1 && !isCpuPlayer(gState, pid)) {
        const idx = await uiSelectOne<number>({
          title: 'Harbinger',
          message: 'Choose a marked square.',
          options: squareOptions.map((opt, i) => ({ label: `(${opt.x + 1}, ${opt.y + 1})`, value: i })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= squareOptions.length) {
          gState.log.unshift('Harbinger casting cancelled.');
          requestGameSync?.();
          return;
        }
        squarePick = squareOptions[idx];
      }

      let targetRegion: Region = squarePick.regions[0];
      if (squarePick.regions.length > 1 && !isCpuPlayer(gState, pid)) {
        const idx = await uiSelectOne<number>({
          title: 'Harbinger',
          message: 'Choose a region to summon.',
          options: squarePick.regions.map((opt, i) => ({
            label: opt ? opt[0].toUpperCase() + opt.slice(1) : 'Region',
            value: i,
          })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= squarePick.regions.length) {
          gState.log.unshift('Harbinger casting cancelled.');
          requestGameSync?.();
          return;
        }
        targetRegion = squarePick.regions[idx];
      }

      if (card.size2x2 && targetRegion === 'surface') {
        if (squarePick.x + 1 >= gState.width || squarePick.y + 1 >= gState.height) {
          gState.log.unshift('Harbinger: not enough space for this 2×2 unit.');
          requestGameSync?.();
          return;
        }
        const required: Array<{ x: number; y: number }> = [
          { x: squarePick.x, y: squarePick.y },
          { x: squarePick.x + 1, y: squarePick.y },
          { x: squarePick.x, y: squarePick.y + 1 },
          { x: squarePick.x + 1, y: squarePick.y + 1 },
        ];
        for (const pos of required) {
          if (!canSummonAtHarbingerSquare(gState, pid, pos.x, pos.y, targetRegion, card)) {
            gState.log.unshift('Harbinger: cannot place a 2×2 unit across those sites.');
            requestGameSync?.();
            return;
          }
          const occupants = unitArrayAtRegion(gState, pos.x, pos.y, targetRegion);
          if (!allowsOccupiedSize2x2Summon(card) && occupants.length > 0) {
            gState.log.unshift('Harbinger: the area is occupied for this 2×2 unit.');
            requestGameSync?.();
            return;
          }
        }
      }

      const t = threshold(gState, pid);
      const vermis = hasVermisMysteriis(gState, pid);
      const tgEligible = unitQualifiesForTournamentGrounds(card);
      const lairThreshold = cardHasSubtype(card, 'Dragon') && playerControlsDragonlordsLair(gState, pid);
      const thresholdOk = hasThreshold(t, card.threshold) || (tgEligible && tournamentGroundsAvailable(gState)) || lairThreshold || vermis;
      if (!thresholdOk) {
        gState.log.unshift('Harbinger: missing threshold to cast that minion.');
        requestGameSync?.();
        return;
      }
      const baseCost = modifiedCostFor(gState, pid, card, card.cost);
      const finalCost = Math.max(0, baseCost - 1);
      if ((gState.mana[pid] ?? 0) < finalCost) {
        gState.log.unshift(`Harbinger: need ${finalCost} mana to cast ${card.name}.`);
        requestGameSync?.();
        return;
      }

      const summoned = summonUnitCardAt(gState, pid, card, squarePick.x, squarePick.y, targetRegion, { bypassPlacement: true });
      if (!summoned) {
        gState.log.unshift('Harbinger: summoning failed.');
        requestGameSync?.();
        return;
      }
      spendMana(gState, pid, finalCost);
      const handIdx = gState.handSpells[pid].findIndex(c => c.id === pick.card.id);
      if (handIdx >= 0) gState.handSpells[pid].splice(handIdx, 1);
      handleCardPlayed(gState, pid, card);
      (gState.avatars[pid] as any)._harbingerCastTurn = gState.turnNumber;
      gState.log.unshift(`Harbinger casts ${card.name} at (${squarePick.x + 1}, ${squarePick.y + 1}) for (1) less.`);
      requestGameSync?.();
    })();
  },
});

registerAbility('Imposter', {
  name: 'Imposter',
  tapPrimary: SharedTapPrimary,
  tapSecondary: (ctx) => {
    useImposterMask(ctx);
  },
});

registerAbility('Pathfinder', {
  name: 'Pathfinder',
  tapPrimary: SharedTapPrimary,
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid, av = g.avatars[pid];
    const adventureActive = Boolean((g as any)?._adventure?.enabled);
    if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
      g.log.unshift('Pathfinder: only during your main phase.');
      requestGameSync?.();
      return;
    }
    if (av.tapped) {
      g.log.unshift('Pathfinder is already tapped.');
      requestGameSync?.();
      return;
    }
    if (!canTapToPay(g, av)) {
      g.log.unshift('Pathfinder cannot tap right now.');
      requestGameSync?.();
      return;
    }
    const top = g.decks[pid].atlas.shift(); if (!top) { g.log.unshift('Pathfinder: atlas empty.'); requestGameSync?.(); return }
    for (const [x,y] of adjacentCoords(g, av.x, av.y)) {
      const cell = cellOf(g, x, y)
      if (!cell.site || cell.site.rubble) {
        av.tapped = true;
        const wasVoid = !cell.site;
        cell.site = { id: uid(), type:'Site', name: top.name, controller: pid, elements:(top as any).elements ?? [], isWater:false, justPlaced:true }
        if (wasVoid) surfaceVoidwalkersAt(g, x, y);
        const from = cellOf(g, av.x, av.y); from.units = from.units.filter(u => u.id !== av.id)
        av.x = x; av.y = y; cell.units.push(av)
        provideMana(g, pid)
        g.log.unshift(`Pathfinder plays ${top.name} adjacent and moves there.`)
        return
      }
    }
    g.decks[pid].atlas.unshift(top); g.log.unshift('Pathfinder: no adjacent void/rubble.'); requestGameSync?.();
  },
})

registerAbility('Persecutor', {
  name: 'Persecutor',
  tapPrimary: SharedTapPrimary,
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];
    if (!av) return;
    const adventureActive = Boolean((g as any)?._adventure?.enabled);
    if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
      g.log.unshift('Persecutor: only during your main phase.');
      requestGameSync?.();
      return;
    }
    if ((av as any)._persecutorTurn === g.turnNumber) {
      g.log.unshift('Persecutor: already used this turn.');
      requestGameSync?.();
      return;
    }

      const resolveChoice = (action: 'step' | 'brand') => {
        if (action === 'brand') {
        const enemies = g.board.flat().flatMap(c => c.units)
          .filter(u => u.player !== pid && !enemyTargetingBlocked(g, u, pid));
        if (enemies.length === 0) {
          g.log.unshift('Persecutor finds no enemy to brand.');
          requestGameSync?.();
          return;
        }
        let target = enemies[0];
        if (enemies.length > 1 && !isCpuPlayer(g, pid)) {
          void (async () => {
            const idx = await uiSelectOne<number>({
              title: 'Persecutor',
              message: formatTileText(g, 'Brand which enemy as Evil this turn?'),
              options: enemies.map((u, i) => ({
                label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
                value: i,
              })),
              allowCancel: true,
              cancelLabel: 'Cancel',
            });
            if (idx == null || idx < 0 || idx >= enemies.length) {
              g.log.unshift('Persecutor declines to brand an enemy.');
              requestGameSync?.();
              return;
            }
            target = enemies[idx];
            (target as any)._brandedEvilTurn = g.turnNumber;
            (target as any)._brandedEvilByPid = pid;
            (av as any)._persecutorTurn = g.turnNumber;
            g.log.unshift(`Persecutor brands ${target.name} as Evil this turn.`);
            requestGameSync?.();
          })();
        } else {
          target = isCpuPlayer(g, pid)
            ? enemies[Math.max(0, Math.min(enemies.length - 1, pickRandomIndex(g, enemies.length, {
              context: 'Persecutor brand',
              controllerPid: pid,
              labels: enemies.map(u => u.name ?? 'Enemy'),
            })))]
            : enemies[0];
          (target as any)._brandedEvilTurn = g.turnNumber;
          (target as any)._brandedEvilByPid = pid;
          (av as any)._persecutorTurn = g.turnNumber;
          g.log.unshift(`Persecutor brands ${target.name} as Evil this turn.`);
          requestGameSync?.();
        }
        return;
      }

      const evilUnits = g.board.flat().flatMap(c => c.units)
        .filter(u => unitHasSubtype(g, u, 'Evil'));
      if (evilUnits.length === 0) {
        g.log.unshift('Persecutor senses no Evil to pursue.');
        requestGameSync?.();
        return;
      }
      const ax = av.x, ay = av.y;
      const distances = evilUnits.map(u => ({
        unit: u,
        dist: Math.max(Math.abs(((u as any).x ?? ax) - ax), Math.abs(((u as any).y ?? ay) - ay)),
      }));
      const minDist = Math.min(...distances.map(d => d.dist));
      const nearest = distances.filter(d => d.dist === minDist).map(d => d.unit);
      const target = isCpuPlayer(g, pid) && nearest.length > 1
        ? nearest[Math.max(0, Math.min(nearest.length - 1, pickRandomIndex(g, nearest.length, {
          context: 'Persecutor step',
          controllerPid: pid,
          labels: nearest.map(u => u.name ?? 'Evil'),
        })))]
        : nearest[0];

      const options = neighborsFor(av, g);
      const targetX = (target as any).x as number;
      const targetY = (target as any).y as number;
      const closer = options
        .map(opt => ({
          opt,
          dist: Math.max(Math.abs(opt.x - targetX), Math.abs(opt.y - targetY)),
        }))
        .filter(entry => entry.dist < minDist);
      if (closer.length === 0) {
        g.log.unshift('Persecutor cannot step closer to Evil.');
        requestGameSync?.();
        return;
      }
      const stepChoice = closer.sort((a, b) => a.dist - b.dist)[0].opt;
      const moved = moveUnitTo(g, av, stepChoice.x, stepChoice.y, stepChoice.region, { sourcePlayer: pid });
      if (moved) {
        (av as any)._persecutorTurn = g.turnNumber;
        g.log.unshift(`Persecutor steps toward ${target.name}.`);
      } else {
        g.log.unshift('Persecutor cannot step closer.');
      }
      requestGameSync?.();
    };

    if (isCpuPlayer(g, pid)) {
      resolveChoice('step');
      return;
    }

    void (async () => {
      const choice = await uiSelectOne<'step' | 'brand'>({
        title: 'Persecutor',
        message: formatTileText(g, 'Choose one: step toward the closest Evil, or brand an enemy as Evil this turn.'),
        options: [
          { label: 'Step toward closest Evil', value: 'step' },
          { label: 'Brand an enemy as Evil', value: 'brand' },
        ],
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (!choice) {
        g.log.unshift('Persecutor holds position.');
        requestGameSync?.();
        return;
      }
      resolveChoice(choice);
    })();
  },
});

registerAbility('Seer', {
  name: 'Seer',
  tapPrimary: SharedTapPrimary,
  onTurnStart: (ctx) => {
    const g = ctx.state as Game;
    const pid = ctx.pid as PlayerId;

    const promptForDeck = (which: 'spells' | 'atlas') => {
      const deck =
        which === 'spells'
          ? g.decks[pid].spellbook
          : g.decks[pid].atlas;
      if (!Array.isArray(deck) || deck.length === 0) return;
      const top = deck[0];
      if (!top) return;

      void (async () => {
        const choice = await uiSelectOne<'top' | 'bottom'>({
          title: 'Seer',
          message: formatTileText(
            g,
            which === 'spells'
              ? `Top spell: ${top.name}. Keep it or send it to the bottom?`
              : `Top site: ${top.name}. Keep it or send it to the bottom?`
          ),
          options: [
            { label: 'Keep on top', value: 'top' },
            { label: 'Put on bottom', value: 'bottom' },
          ],
          allowCancel: true,
          cancelLabel: 'Keep on top',
        });

        const latest = getLatestGameState?.() ?? g;
        const liveDeck =
          which === 'spells'
            ? latest.decks[pid].spellbook
            : latest.decks[pid].atlas;
        if (!Array.isArray(liveDeck) || liveDeck.length === 0) {
          requestGameSync?.();
          return;
        }

        const idx = liveDeck.findIndex((card) => card.id === top.id);
        if (idx < 0) {
          requestGameSync?.();
          return;
        }

        const [card] = liveDeck.splice(idx, 1);
        if (choice === 'bottom') {
          liveDeck.push(card);
          latest.log.unshift(
            `Seer vision: ${card.name} moves to the bottom of your ${which === 'spells' ? 'spellbook' : 'atlas'}.`
          );
        } else {
          liveDeck.unshift(card);
          latest.log.unshift(
            `Seer vision: ${card.name} remains on top of your ${which === 'spells' ? 'spellbook' : 'atlas'}.`
          );
        }
        requestGameSync?.();
      })();
    };

    if (g.decks[pid].spellbook.length > 0) {
      promptForDeck('spells');
    } else if (g.decks[pid].atlas.length > 0) {
      promptForDeck('atlas');
    }
  },
})

registerAbility('Sorcerer', {
  name: 'Sorcerer',
  tapPrimary: SharedTapPrimary,
  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];
    const adventureActive = Boolean((g as any)?._adventure?.enabled);
    if (!av) return;
    if (g.turn !== pid || (!adventureActive && g.phase !== 'Main')) {
      g.log.unshift('Sorcerer: only during your main phase.');
      requestGameSync?.();
      return;
    }
    if (!canTapToPay(g, av)) {
      g.log.unshift('Sorcerer cannot tap right now.');
      requestGameSync?.();
      return;
    }
    const c = g.decks[pid].spellbook.shift();
    if (c) {
      av.tapped = true;
      g.handSpells[pid].push(c);
      g.log.unshift('Sorcerer draws a spell.');
    } else {
      g.log.unshift('Sorcerer: spellbook is empty.');
    }
  },
})

registerAbility('Sparkmage', {
  name: 'Sparkmage',
  tapPrimary: SharedTapPrimary,

  onTurnStart: (ctx) => {
    (ctx.state as any)._sparkmageAirSum ??= { 1: 0, 2: 0 };
    (ctx.state as any)._sparkmageAirSum[ctx.pid] = 0;
  },

  onCardCast: (ctx, card) => {
    if (card.kind !== 'Spell') return;
    const g = ctx.state, pid = ctx.pid;
    (g as any)._sparkmageAirSum ??= { 1: 0, 2: 0 };
    const air = ((card as any).threshold?.Air ?? 0);
    (g as any)._sparkmageAirSum[pid] = ((g as any)._sparkmageAirSum[pid] ?? 0) + Math.max(0, air);
  },

  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];

    if (g.turn !== pid || g.phase !== 'Main') { g.log.unshift('Sparkmage: not your main phase.'); return; }
    if (av.tapped) { g.log.unshift('Sparkmage: avatar already tapped.'); return; }

    av.tapped = true;

    const total = Math.max(0, (((g as any)._sparkmageAirSum ?? {})[pid] ?? 0));
    if (total <= 0) { g.log.unshift('Sparkmage: no Air threshold accumulated on spells cast this turn.'); return; }

    const adj: Array<{ x:number; y:number }> = [
      {x: av.x+1, y: av.y  }, {x: av.x-1, y: av.y  }, {x: av.x,   y: av.y+1}, {x: av.x,   y: av.y-1},
      {x: av.x+1, y: av.y+1}, {x: av.x+1, y: av.y-1}, {x: av.x-1, y: av.y+1}, {x: av.x-1, y: av.y-1},
    ].filter(p => inside(g, p.x, p.y));

    if (adj.length === 0) { g.log.unshift('Sparkmage: no nearby locations in bounds.'); return; }

    void (async () => {
      const idx = await uiSelectOne<number>({
        title: 'Sparkmage',
        message: 'Choose a nearby location.',
        options: adj.map((p, i) => ({
          label: `(${p.x + 1}, ${p.y + 1})`,
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (idx == null || idx < 0 || idx >= adj.length) { g.log.unshift('Sparkmage: cancelled.'); return; }

      const targetTile = adj[idx];

      const list = unitArrayAtRegion(g, targetTile.x, targetTile.y, 'surface')
        .filter(u => u.id !== av.id);

      if (list.length === 0) { g.log.unshift('Sparkmage: no eligible unit at that location.'); return; }

      const rawIdx = pickRandomIndex(g, list.length, {
        context: 'Sparkmage discharge',
        labels: list.map(unit => `${unit.name} (P${unit.player})`),
        controllerPid: pid,
      });
      const victimIdx = Math.max(0, Math.min(list.length - 1, rawIdx));
      const victim = list[victimIdx];
      damageUnit(g, victim, total, { sourceUnit: av });
      g.log.unshift(`Sparkmage zaps ${victim.name} for ${total} at (${targetTile.x + 1}, ${targetTile.y + 1}).`);
      requestGameSync?.();
    })();
  },
});

