registerAbility('Waveshaper', {
  name: 'Waveshaper',
  tapPrimary: SharedTapPrimary,

  tapSecondary: (ctx) => {
    const g = ctx.state, pid = ctx.pid;
    const av = g.avatars[pid];

    if (g.turn !== pid || g.phase !== 'Main') { g.log.unshift('Waveshaper: not your main phase.'); return; }
    if (av.tapped) { g.log.unshift('Waveshaper: already tapped.'); return; }

    av.tapped = true;

    const waterSeeds: Array<{x:number;y:number}> = [];
    for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
      const s = cellOf(g, x, y).site;
      if (s && isSiteWater(g, s, x, y) && s.controller === pid) waterSeeds.push({ x, y });
    }
    if (waterSeeds.length === 0) { g.log.unshift('Waveshaper: you control no Water sites.'); return; }

    const seen = new Set<string>();
    const key  = (x:number,y:number) => `${x},${y}`;
    const q: Array<{x:number;y:number}> = [];

    for (const p of waterSeeds) { const k = key(p.x, p.y); if (!seen.has(k)) { seen.add(k); q.push(p); } }

    const dirs4: Array<[number,number]> = [[1,0],[-1,0],[0,1],[0,-1]];
    while (q.length) {
      const p = q.shift()!;
      for (const [dx,dy] of dirs4) {
        const nx = p.x + dx, ny = p.y + dy;
        if (!inside(g, nx, ny)) continue;
        const s = cellOf(g, nx, ny).site;
        if (!s || !isSiteWater(g, s, nx, ny) || s.controller !== pid) continue;
        const kk = key(nx, ny);
        if (!seen.has(kk)) { seen.add(kk); q.push({ x: nx, y: ny }); }
      }
    }

    const candidates: Array<{ x:number; y:number; site: Site }> = [];
    for (const kk of seen) {
      const [sx, sy] = kk.split(',').map(n => parseInt(n, 10));
      for (const [dx,dy] of dirs4) {
        const nx = sx + dx, ny = sy + dy;
        if (!inside(g, nx, ny)) continue;
        const s = cellOf(g, nx, ny).site;
        if (s && !isSiteWater(g, s, nx, ny) && !s.rubble) {
          if (!candidates.some(c => c.x === nx && c.y === ny)) candidates.push({ x: nx, y: ny, site: s });
        }
      }
    }

    if (candidates.length === 0) { g.log.unshift('Waveshaper: no adjacent site to flood near your body of water.'); return; }

    const prevFlood = g.waveshaperFlood[pid];
    if (prevFlood) {
      const s = cellOf(g, prevFlood.x, prevFlood.y).site;
      if (s && s.floodedByPid === pid) {
        s.isWater = false;
        s.floodedByPid = null as any;
        g.log.unshift(`Waveshaper: previous flooded site at (${prevFlood.x + 1}, ${prevFlood.y + 1}) recedes.`);
      }
      g.waveshaperFlood[pid] = null;
    }

    void (async () => {
      let idx = 0;
      if (candidates.length > 1) {
        const selection = await uiSelectOne<number>({
          title: 'Waveshaper',
          message: 'Choose a site to flood (adjacent to your body of water).',
          options: candidates.map((c, i) => ({
            label: formatTileText(g, `${c.site.name} @ (${c.x + 1}, ${c.y + 1})`),
            value: i,
          })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (selection == null) {
          g.log.unshift('Waveshaper: cancelled.');
          requestGameSync?.();
          return;
        }
        idx = selection;
      }

      const dest = candidates[idx];

      dest.site.isWater = true;
      dest.site.floodedByPid = pid;
      dest.site.justPlaced = true;
      g.waveshaperFlood[pid] = { x: dest.x, y: dest.y };

      g.log.unshift(`Waveshaper floods ${dest.site.name} at (${dest.x + 1}, ${dest.y + 1}).`);

      const unitsHere = unitArrayAtRegion(g, dest.x, dest.y, 'surface');
      let tappedCount = 0;
      for (const u of unitsHere) {
        if (u.kind === 'Token' && !(u as Token).submerge) {
          u.tapped = true;
          (u as Token).skipUntapOnce = true;
          tappedCount++;
        }
      }
      if (tappedCount > 0) g.log.unshift(`Waveshaper taps ${tappedCount} minion(s) (they won’t untap next time).`);
      requestGameSync?.();
    })();
  },
});

