        game!.artifacts = game!.artifacts.filter(a => a.id !== fourWaters.id);
        handleArtifactRegionChange(game!, fourWaters);
        refreshUnitArtifactPassives(game!, u);
        const store = (game as any)._fourWaters ?? ((game as any)._fourWaters = {});
