function AdventureMiniMap({ game, mode, onToggleMode }: {
  game: Game;
  mode: 'near' | 'far';
  onToggleMode: () => void;
}) {
  const adventureRuntime = (game as any)._adventure as AdventureRuntime | undefined;
  const adventureActive = Boolean(adventureRuntime?.enabled);
  if (!adventureActive) return null;
  const mapWidthPx = 180;
  const mapHeightPx = game.width > 0 ? Math.max(110, (mapWidthPx * game.height) / Math.max(1, game.width)) : 120;
  const dots = [1, 2].map((pid) => {
    const av = game.avatars?.[pid as PlayerId];
    const ax = (av as any)?.x;
    const ay = (av as any)?.y;
    if (!Number.isFinite(ax) || !Number.isFinite(ay)) return null;
    return {
      pid: pid as PlayerId,
      left: ((ax as number) + 0.5) / Math.max(1, game.width) * mapWidthPx,
      top: ((ay as number) + 0.5) / Math.max(1, game.height) * mapHeightPx,
      color: pid === 1 ? '#7dd3fc' : '#fca5a5',
    };
  }).filter(Boolean) as Array<{ pid: PlayerId; left: number; top: number; color: string }>;

  return (
    <div
      style={{
        flex: 1,
        minWidth: 220,
        background: 'rgba(10,14,20,0.9)',
        border: '1px solid rgba(113,180,255,0.45)',
        borderRadius: 12,
        padding: '12px 14px',
        boxShadow: '0 12px 22px rgba(0,0,0,0.4)',
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
      }}
    >
      <div className="badge" style={{ alignSelf: 'center' }}>Map</div>
      <div style={{ position: 'relative', width: mapWidthPx, height: mapHeightPx, background: '#0b1116', border: '1px solid #1c2735', borderRadius: 6 }}>
        <div style={{ position: 'absolute', inset: 4, border: '1px dashed #1f2c3c', borderRadius: 4 }} />
        {dots.map(dot => (
          <div
            key={dot.pid}
            title={`Player ${dot.pid}`}
            style={{
              position: 'absolute',
              width: 8,
              height: 8,
              borderRadius: '50%',
              background: dot.color,
              left: dot.left - 4,
              top: dot.top - 4,
              boxShadow: `0 0 6px ${dot.color}`,
            }}
          />
        ))}
      </div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 8 }}>
        <span style={{ fontSize: 11, color: '#9fb0c2' }}>Viewport</span>
        <button
          className="btn"
          style={{ padding: '4px 8px', fontSize: 11 }}
          onClick={onToggleMode}
        >
          {mode === 'near' ? 'Show 5×5' : 'Show 3×3'}
        </button>
      </div>
    </div>
  );
}

