function DeckPile({
  src,
  label,
  count,
  width,
  aspectRatio,
  onActivate,
  disabled,
  highlight,
}: {
  src: string
  label: string
  count: number
  width: number
  aspectRatio: string
  onActivate?: () => void
  disabled?: boolean
  highlight?: boolean
}) {
  const imageSrcs = useMemo(() => buildAssetFallbacks(src), [src]);
  const isInteractive = typeof onActivate === 'function'
  const handleActivate = (e: React.MouseEvent | React.KeyboardEvent) => {
    if (!isInteractive || disabled) return
    onActivate?.()
    e.stopPropagation()
  }
  return (
    <div
      style={{
        position: 'relative',
        width,
        aspectRatio,
        border: highlight ? '2px solid rgba(246,197,111,0.85)' : '1px solid rgba(246,197,111,0.35)',
        borderRadius: 8,
        background: '#0c1117',
        overflow: 'hidden',
        cursor: isInteractive && !disabled ? 'pointer' : 'default',
        opacity: disabled ? 0.7 : 1,
        pointerEvents: disabled ? 'none' : 'auto',
      }}
      role={isInteractive ? 'button' : undefined}
      aria-disabled={isInteractive ? disabled : undefined}
      tabIndex={isInteractive ? 0 : undefined}
      onClick={handleActivate}
      onKeyDown={(e) => {
        if (!isInteractive || disabled) return
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault()
          handleActivate(e)
        }
      }}
      aria-label={label}
    >
      <img
        src={imageSrcs[0] ?? src}
        data-fallbacks={imageSrcs.slice(1).join('|')}
        alt={label}
        onError={advanceImageFallback}
        style={{ width: '100%', height: '100%', objectFit: 'contain', display: 'block' }}
      />
      <div
        style={{
          position: 'absolute',
          bottom: 6,
          right: 6,
          fontSize: 13,
          fontWeight: 600,
          color: '#cde2ff',
          background: 'rgba(12,17,23,0.9)',
          padding: '2px 6px',
          borderRadius: 6,
        }}
      >
        {count}
      </div>
    </div>
  )
}

