function SiteInCell({
  site,
  onClick,
  highlight,
  hasWard = false,
  rotateCard90 = true,
  interactive = true,
  compactHighlights = false,
}: {
  site: Site;
  onClick?: (e: React.MouseEvent<HTMLDivElement>) => void;
  highlight?: boolean;
  hasWard?: boolean;
  rotateCard90?: boolean;
  interactive?: boolean;
  compactHighlights?: boolean;
}) {
  const hb = useHoverBindingsForCard({ src: site.image, name: site.name, rotate90: rotateCard90, baseWidth: 240, zoom: 1.05 })
  const isFlooded = !site.rubble && site.floodedByPid != null;
  const hideRubbleLabel = Boolean(site.rubble && (site as any)._adventureRubble);
  const siteFxStyle = classifySiteFxStyle(normalizeElementList(site.elements));
  const firePlacementFxActive = site.justPlaced && siteFxStyle === 'fire';
  const siteImageOptions = React.useMemo(
    () => buildAssetFallbacks(site.image, SITE_CARD_BACKS),
    [site.image, site.id],
  );
  const [siteImgSrc, setSiteImgSrc] = React.useState<string>(siteImageOptions[0] ?? '');
  React.useEffect(() => {
    setSiteImgSrc(siteImageOptions[0] ?? '');
  }, [site.id, site.image, siteImageOptions]);
  const advanceSiteImage = React.useCallback(() => {
    const idx = siteImageOptions.indexOf(siteImgSrc);
    const next = idx >= 0 ? siteImageOptions[idx + 1] : undefined;
    if (next) {
      setSiteImgSrc(next);
    } else {
      setSiteImgSrc('');
    }
  }, [siteImgSrc, siteImageOptions]);
  const [siteImageOpacity, setSiteImageOpacity] = React.useState<number>(() => (site.justPlaced ? 0 : 1));
  const [siteImageFadeActive, setSiteImageFadeActive] = React.useState<boolean>(() => Boolean(site.justPlaced));
  const siteFadeFrameRef = React.useRef<number | null>(null);
  const siteFadeTimerRef = React.useRef<number | null>(null);
  const clearSiteFadeTimers = React.useCallback(() => {
    if (siteFadeFrameRef.current != null) {
      window.cancelAnimationFrame(siteFadeFrameRef.current);
      siteFadeFrameRef.current = null;
    }
    if (siteFadeTimerRef.current != null) {
      window.clearTimeout(siteFadeTimerRef.current);
      siteFadeTimerRef.current = null;
    }
  }, []);
  React.useEffect(() => {
    return () => {
      clearSiteFadeTimers();
    };
  }, [clearSiteFadeTimers]);
  React.useEffect(() => {
    clearSiteFadeTimers();
    if (!site.justPlaced) {
      setSiteImageFadeActive(false);
      setSiteImageOpacity(1);
      return;
    }
    setSiteImageFadeActive(true);
    setSiteImageOpacity(0);
    siteFadeFrameRef.current = window.requestAnimationFrame(() => {
      siteFadeFrameRef.current = window.requestAnimationFrame(() => {
        setSiteImageOpacity(1);
        siteFadeFrameRef.current = null;
      });
    });
    siteFadeTimerRef.current = window.setTimeout(() => {
      setSiteImageFadeActive(false);
      siteFadeTimerRef.current = null;
    }, SITE_PLACEMENT_FX_MS + 50);
  }, [site.id, site.justPlaced, clearSiteFadeTimers]);
  const siteBaseTransform = rotateCard90
    ? (compactHighlights ? 'translateY(37px) scale(0.924) rotate(90deg)' : 'rotate(90deg) scale(1.32)')
    : undefined;
  return (
    <div
      className="site"
      data-board-interactive={interactive ? 'true' : undefined}
      style={{
        position: 'absolute',
        inset: 0,
        overflow: 'hidden',
        zIndex: highlight ? 1 : 0,
        cursor: onClick && interactive ? 'pointer' : 'default',
        pointerEvents: interactive ? 'auto' : 'none',
        borderRadius: 0,
        border: hasWard ? `${compactHighlights ? 1 : 2}px solid rgba(255, 216, 94, 0.95)` : 'none',
        outline: 'none',
        boxShadow: hasWard
          ? `${compactHighlights ? '0 0 10px rgba(255, 209, 78, 0.8), inset 0 0 10px rgba(255, 219, 117, 0.3)' : '0 0 16px rgba(255, 209, 78, 0.85), inset 0 0 16px rgba(255, 219, 117, 0.35)'}`
          : undefined,
        transition: 'box-shadow 0.2s ease, border-color 0.2s ease',
        boxSizing: 'content-box',
        background: siteImgSrc ? 'transparent' : undefined,
      }}
      onClick={onClick}
      tabIndex={onClick && interactive ? 0 : undefined}
      onPointerEnter={hb.onPointerEnter}
      onPointerMove={hb.onPointerMove}
      onPointerLeave={hb.onPointerLeave}
      onPointerCancel={hb.onPointerCancel}
      onPointerUp={hb.onPointerUp}
      onFocus={hb.onFocus}
      onBlur={hb.onBlur}
    >
      {siteImgSrc ? (
        <div
          style={{
            position: 'absolute',
            inset: 0,
            width: '100%',
            height: '100%',
            transformOrigin: 'center',
            pointerEvents: 'none',
          }}
        >
          <img
            src={siteImgSrc}
            alt={`${site.name} art`}
            className={`so-site-art${firePlacementFxActive ? ' is-fire-placement' : ''}`}
            onError={advanceSiteImage}
            style={{
              ['--so-site-base-transform' as any]: siteBaseTransform ?? 'none',
              width: '100%',
              height: '100%',
              objectFit: 'contain',
              objectPosition: 'center',
              transform: 'var(--so-site-base-transform)',
              transformOrigin: 'center center',
              opacity: siteImageOpacity,
              transition: siteImageFadeActive ? `opacity ${SITE_PLACEMENT_FX_MS}ms linear` : 'opacity 140ms ease-out',
              animation: firePlacementFxActive ? `so-site-fire-card-warp ${SITE_PLACEMENT_FX_MS}ms ease-in-out both` : undefined,
              filter: firePlacementFxActive ? 'saturate(1.14) contrast(1.08)' : undefined,
              pointerEvents: 'none',
            }}
          />
        </div>
      ) : (
        <div style={{ position: 'absolute', inset: 0, display: 'grid', placeItems: 'center', color: '#cde2ff', background: site.rubble ? 'rgba(0,0,0,.25)' : 'transparent' }}>
          {site.rubble ? (hideRubbleLabel ? '' : 'Rubble') : site.name}
        </div>
      )}
      {firePlacementFxActive && (
        <div
          className="so-site-fire-heat-overlay"
          style={{ animationDuration: `${SITE_PLACEMENT_FX_MS}ms` }}
        />
      )}
      {isFlooded && (
        <>
          <div
            style={{
              position: 'absolute',
              inset: 0,
              background: 'rgba(32,132,255,0.3)',
              pointerEvents: 'none',
              zIndex: 2,
            }}
          />
          <div
            style={{
              position: 'absolute',
              top: 8,
              right: 10,
              padding: '2px 8px',
              borderRadius: 6,
              background: 'rgba(22,64,128,0.85)',
              color: '#d6e8ff',
              fontSize: 10,
              fontWeight: 600,
              letterSpacing: 0.5,
              textTransform: 'uppercase',
              pointerEvents: 'none',
              zIndex: 3,
              boxShadow: '0 2px 6px rgba(0,0,0,0.35)',
            }}
          >
            Flooded
          </div>
        </>
      )}
      {hasWard && (
        <div
          style={{
            position: 'absolute',
            top: 8,
            left: 10,
            padding: '2px 8px',
            borderRadius: 6,
            background: 'rgba(122, 90, 0, 0.85)',
            color: '#ffe9a5',
            fontSize: 10,
            fontWeight: 700,
            letterSpacing: 0.5,
            textTransform: 'uppercase',
            pointerEvents: 'none',
            zIndex: 4,
            boxShadow: '0 2px 6px rgba(0,0,0,0.35)',
          }}
        >
          🛡 WARD
        </div>
      )}
    </div>
  )
}

function UnitOnBoard({ u, showPower }: { u: Unit; showPower: number }) {
  const imageSrcs = useMemo(() => buildAssetFallbacks((u as any).image), [((u as any).image as string | undefined)]);
  if (imageSrcs.length > 0) {
    return (
      <img
        src={imageSrcs[0]}
        data-fallbacks={imageSrcs.slice(1).join('|')}
        alt={`${u.name} art`}
        onError={advanceImageFallback}
        style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover', pointerEvents: 'none' }}
      />
    )
  }
  return (
    <>
      <div className="av-row"><span className="tag">{elemIcon(u.element)} {u.name} {u.kind === 'Avatar' && (u as Avatar).deathsDoor ? ICON.dd : ''}</span></div>
      <div className="av-row" style={{ justifyContent: 'space-between' }}>
        <span className="tag">{ICON.power} {showPower}</span>
        <span className="tag">{ICON.life} {u.kind === 'Avatar' ? (u as Avatar).life : Math.max(0, (unitThresholdHP(u) - ((u as Token).damage ?? 0)))}</span>
      </div>
      {'summonedThisTurn' in u && (u as Token).summonedThisTurn && (<div style={{ position: 'absolute', bottom: 4, right: 6, fontSize: 10, opacity: 0.8 }}>⏳</div>)}
      {(u as any).ranged && (
        <div style={{ position: 'absolute', bottom: 4, left: 6, fontSize: 10, opacity: 0.8 }}>
          {ICON.bow} R∞
        </div>
      )}
    </>
  )
}

function baseStatsForUnit(u: Unit): { power?: number; def?: number } | null {
  if (u.kind === 'Avatar') return { power: (u as Avatar).power, def: undefined };
  const src = (u as any)._srcCard ?? getCardTemplateByName(u.name ?? '');
  if (!src || src.kind !== 'Unit') return null;
  const basePower =
    typeof (src as any).atk === 'number'
      ? (src as any).atk
      : (typeof (src as any).power === 'number' ? (src as any).power : undefined);
  const baseDef =
    typeof (src as any).def === 'number'
      ? (src as any).def
      : (typeof (src as any).defence === 'number' ? (src as any).defence : undefined);
  return { power: basePower, def: baseDef };
}

function LookXOverlay({ game, onChange, mp, onIntent }: { game: Game; onChange: () => void; mp?: MpSession | null; onIntent?: (intent: MpIntent) => void }) {
  const s = (game as any)._lookX as
    | { pid: PlayerId; which: 'atlas' | 'spells'; cards: Card[]; toTake: number; putRest: 'top' | 'bottom'; pickedIds: string[] }
    | undefined
  if (!s) return null
  const titleDeck = s.which === 'spells' ? 'Spellbook' : 'Atlas'

  const isMpJoin = !!(mp && mp.role === 'join' && onIntent)
  const canControl = !mp || mp.localPid === s.pid
  const hiddenCardBack = s.which === 'atlas' ? '/assets/Sorcery_Atlas.png' : '/assets/Sorcery_Spellbook.png';
  const displayCards: Card[] = canControl
    ? s.cards
    : s.cards.map((card, idx) => ({
        id: `hidden_lookx_${s.pid}_${idx}`,
        kind: s.which === 'atlas' ? 'Site' : 'Spell',
        name: 'Card Back',
        elements: [],
        element: 'Air',
        cost: 0,
        threshold: {},
        image: hiddenCardBack,
        text: '',
      } as any));

  const togglePick = (id: string) => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'lookX:toggle', cardId: id })
    }
    const i = s.pickedIds.indexOf(id)
    if (i >= 0) s.pickedIds.splice(i, 1)
    else if (s.pickedIds.length < s.toTake) s.pickedIds.push(id)
    onChange()
  }
  const move = (idx: number, dir: -1 | 1) => {
    if (!canControl) return
    const j = idx + dir
    if (j < 0 || j >= s.cards.length) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'lookX:move', from: idx, to: j })
    }
    const tmp = s.cards[idx]
    s.cards[idx] = s.cards[j]
    s.cards[j] = tmp
    onChange()
  }
  const canConfirm = s.toTake === 0 || s.pickedIds.length === Math.min(s.toTake, s.cards.length)
  const onConfirm = () => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'lookX:confirm', placement: s.putRest })
      return
    }
    commitLookX(game, s.pid)
    onChange()
  }
  const reviewSingleCard = s.toTake === 0 && s.cards.length === 1
  const finalizePlacement = (placement: 'top' | 'bottom') => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'lookX:confirm', placement })
      return
    }
    s.putRest = placement
    onConfirm()
  }

  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,.6)', display: 'grid', placeItems: 'center', zIndex: 1000 }}>
      <div className="panel stack" style={{ maxWidth: 980, width: '92%', background: '#0b1116', border: '1px solid #2a3543', padding: 16, borderRadius: 12 }}>
        <div className="title">Look at top {s.cards.length} of {titleDeck}</div>
        <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap', alignItems: 'flex-start', justifyContent: 'center' }}>
          {displayCards.map((c, idx) => (
            <LookXCardOption
              key={c.id}
              card={c}
              index={idx}
              selected={canControl && s.pickedIds.includes((s.cards[idx] as any)?.id)}
              canMoveLeft={idx > 0}
              canMoveRight={idx < s.cards.length - 1}
              onMoveLeft={() => move(idx, -1)}
              onMoveRight={() => move(idx, +1)}
              onToggle={() => togglePick((s.cards[idx] as any)?.id)}
              allowToggle={canControl && s.toTake > 0}
            />
          ))}
        </div>
        <div className="rowwrap" style={{ gap: 8, justifyContent: 'space-between', alignItems: 'center', marginTop: 8 }}>
          <span className="badge">
            {!canControl
              ? 'Opponent is resolving this look/scry decision.'
              : s.toTake > 0
              ? `Select ${s.toTake} card${s.toTake > 1 ? 's' : ''} to add to your hand`
              : reviewSingleCard
                ? 'Choose Top or Bottom'
                : 'Review and Confirm'}
          </span>
          <div className="rowwrap" style={{ gap: 8 }}>
            {reviewSingleCard ? (
              <>
                <button className="btn" disabled={!canControl || !canConfirm} onClick={() => finalizePlacement('bottom')}>Bottom</button>
                <button className="btn primary" disabled={!canControl || !canConfirm} onClick={() => finalizePlacement('top')}>Top</button>
              </>
            ) : (
              <>
                <span className="badge">Rest to: {s.putRest === 'bottom' ? 'bottom' : 'top'} of {titleDeck}</span>
                <button className="btn" disabled={!canControl || !canConfirm} onClick={onConfirm}>Confirm</button>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

function MulliganOverlay({ game, onChange, mp, onIntent }: { game: Game; onChange: () => void; mp?: MpSession | null; onIntent?: (intent: MpIntent) => void }) {
  const pending = (game as any)._pendingMulligan as PendingMulliganState | undefined;
  if (!pending) return null;
  const pid = pending.pid as PlayerId;
  const isMpJoin = !!(mp && mp.role === 'join' && onIntent)
  const isRemoteOpponentView = !!(mp && mp.localPid !== pid)
  const canControl = !mp || mp.localPid === pid
  const atlasHand = game.handAtlas[pid] ?? [];
  const spellsHand = game.handSpells[pid] ?? [];
  const hiddenAtlasCard = (idx: number): Card => ({
    id: `hidden_mulligan_${pid}_atlas_${idx}`,
    kind: 'Site',
    name: 'Atlas Card Back',
    elements: [],
    image: '/assets/Sorcery_Atlas.png',
    text: '',
  } as any);
  const hiddenSpellCard = (idx: number): Card => ({
    id: `hidden_mulligan_${pid}_spell_${idx}`,
    kind: 'Spell',
    name: 'Spell Card Back',
    element: 'Air',
    cost: 0,
    threshold: {},
    image: '/assets/Sorcery_Spellbook.png',
    text: '',
  } as any);

  const atlasEntries = pending.atlas
    .map((entry, idx) => {
      if (isRemoteOpponentView) return { entry, card: hiddenAtlasCard(idx) };
      const card = atlasHand.find(c => c.id === entry.id);
      return { entry, card: card ?? hiddenAtlasCard(idx) };
    });

  const spellEntries = pending.spells
    .map((entry, idx) => {
      if (isRemoteOpponentView) return { entry, card: hiddenSpellCard(idx) };
      const card = spellsHand.find(c => c.id === entry.id);
      return { entry, card: card ?? hiddenSpellCard(idx) };
    });

  const toggleEntry = (entry: PendingMulliganEntry) => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'mulligan:toggle', entryId: entry.id })
    }
    entry.mulligan = !entry.mulligan;
    onChange();
  };

  const selectedCount = canControl
    ? pending.atlas.filter(e => e.mulligan).length + pending.spells.filter(e => e.mulligan).length
    : 0;

  const handleKeepAll = () => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'mulligan:complete', mode: 'keep' })
      return
    }
    completeMulligan(game, 'keep');
    onChange();
  };

  const handleMulligan = () => {
    if (!canControl) return
    if (isMpJoin && onIntent) {
      onIntent({ type: 'mulligan:complete', mode: 'mulligan' })
      return
    }
    completeMulligan(game, 'mulligan');
    onChange();
  };

  return (
    <div
      style={{
        position: 'fixed',
        inset: 0,
        background: 'rgba(5,8,12,0.85)',
        display: 'grid',
        placeItems: 'center',
        zIndex: 1200,
      }}
    >
      <div
        className="panel stack"
        style={{
          background: '#091018',
          border: '1px solid #243041',
          padding: 14,
          borderRadius: 14,
          maxHeight: '80vh',
          overflowY: 'auto',
          width: 'fit-content',
          maxWidth: 'min(94vw, 900px)',
        }}
      >
        <div className="title">Player {pid} — Opening Mulligan</div>
        <div style={{ fontSize: 13, color: '#9fb0c2', marginBottom: 16 }}>
          {canControl
            ? 'Select any cards you wish to reshuffle back, then draw replacements. You may do this once.'
            : `Player ${pid} is choosing their mulligan. Card identities are hidden.`}
        </div>
        <div className="stack" style={{ gap: 12 }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: 10, justifyItems: 'center' }}>
            <div className="subtitle" style={{ marginBottom: 4, justifySelf: 'start' }}>Atlas Cards</div>
            {atlasEntries.length === 0 ? (
              <div style={{ fontSize: 12, color: '#708090' }}>No atlas cards in hand.</div>
            ) : (
              <div
                className="rowwrap"
                style={{
                  gap: 10,
                  flexWrap: 'wrap',
                  alignItems: 'flex-start',
                  justifyContent: 'center',
                  width: 'fit-content',
                  maxWidth: 'min(92vw, 880px)',
                  margin: '0 auto',
                }}
              >
                {atlasEntries.map(({ entry, card }) => (
                  <MulliganCardOption
                    key={card.id}
                    card={card}
                    selected={canControl ? entry.mulligan : false}
                    onToggle={() => toggleEntry(entry)}
                    canToggle={canControl}
                  />
                ))}
              </div>
            )}
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: 10, justifyItems: 'center' }}>
            <div className="subtitle" style={{ marginBottom: 4, justifySelf: 'start' }}>Spellbook Cards</div>
            {spellEntries.length === 0 ? (
              <div style={{ fontSize: 12, color: '#708090' }}>No spell cards in hand.</div>
            ) : (
              <div
                className="rowwrap"
                style={{
                  gap: 10,
                  flexWrap: 'wrap',
                  alignItems: 'flex-start',
                  justifyContent: 'center',
                  width: 'fit-content',
                  maxWidth: 'min(92vw, 880px)',
                  margin: '0 auto',
                }}
              >
                {spellEntries.map(({ entry, card }) => (
                  <MulliganCardOption
                    key={card.id}
                    card={card}
                    selected={canControl ? entry.mulligan : false}
                    onToggle={() => toggleEntry(entry)}
                    canToggle={canControl}
                  />
                ))}
              </div>
            )}
          </div>
        </div>
        {canControl ? (
          <div
            className="rowwrap"
            style={{ justifyContent: 'space-between', marginTop: 20, alignItems: 'center', gap: 12 }}
          >
            <span className="badge">
              Mulliganing {selectedCount} card{selectedCount === 1 ? '' : 's'}
            </span>
            <div className="rowwrap" style={{ gap: 8 }}>
              <button className="btn" onClick={handleKeepAll}>Keep All</button>
              <button
                className="btn primary"
                onClick={handleMulligan}
                disabled={selectedCount === 0}
              >
                Mulligan Selected
              </button>
            </div>
          </div>
        ) : (
          <div className="rowwrap" style={{ justifyContent: 'center', marginTop: 20 }}>
            <span className="badge">Waiting for opponent mulligan.</span>
          </div>
        )}
      </div>
    </div>
  );
}

function MulliganCardOption({
  card,
  selected,
  onToggle,
  canToggle = true,
}: {
  card: Card;
  selected: boolean;
  onToggle: () => void;
  canToggle?: boolean;
}) {
  const hb = useHoverBindingsForCard({
    src: (card as any).image,
    name: card.name,
    cardKind: card.kind,
    baseWidth: 200,
    zoom: 1.4,
  });

  return (
    <div
      tabIndex={0}
      onPointerEnter={hb?.onPointerEnter}
      onPointerMove={hb?.onPointerMove}
      onPointerLeave={hb?.onPointerLeave}
      onPointerUp={hb?.onPointerUp}
      onFocus={hb?.onFocus}
      onBlur={hb?.onBlur}
      style={{ position: 'relative' }}
    >
      <MiniCard c={card} scale={1.75} />
      <button
        className="btn"
        onClick={onToggle}
        disabled={!canToggle}
        style={{
          position: 'absolute',
          bottom: 4,
          left: '50%',
          transform: 'translateX(-50%)',
          minWidth: 84,
          opacity: 0.95,
          borderColor: selected ? '#7dd3fc' : undefined,
        }}
      >
        {selected ? 'Keep' : 'Mulligan'}
      </button>
    </div>
  );
}

function LookXCardOption({
  card,
  index,
  selected,
  canMoveLeft,
  canMoveRight,
  onMoveLeft,
  onMoveRight,
  onToggle,
  allowToggle,
}: {
  card: Card
  index: number
  selected: boolean
  canMoveLeft: boolean
  canMoveRight: boolean
  onMoveLeft: () => void
  onMoveRight: () => void
  onToggle: () => void
  allowToggle: boolean
}) {
  const hb = useHoverBindingsForCard({
    src: (card as any).image,
    name: card.name,
    cardKind: card.kind,
    baseWidth: 220,
    zoom: 1.5,
  })

  return (
    <div
      style={{ position: 'relative' }}
      tabIndex={0}
      onPointerEnter={hb.onPointerEnter}
      onPointerMove={hb.onPointerMove}
      onPointerLeave={hb.onPointerLeave}
      onPointerUp={hb.onPointerUp}
      onFocus={hb.onFocus}
      onBlur={hb.onBlur}
    >
      <MiniCard c={card} scale={1.85} />
      <div style={{ position: 'absolute', top: 4, left: 4, display: 'flex', gap: 4 }}>
        <button className="btn" onClick={onMoveLeft} disabled={!canMoveLeft}>←</button>
        <button className="btn" onClick={onMoveRight} disabled={!canMoveRight}>→</button>
      </div>
      {allowToggle && (
        <button
          className="btn"
          onClick={onToggle}
          style={{ position: 'absolute', bottom: 4, left: 4, opacity: 0.95, borderColor: selected ? '#7dd3fc' : undefined }}
        >
          {selected ? '✓ Take' : 'Take'}
        </button>
      )}
    </div>
  )
}

function ZoneCardPreview({ card, onClick }: { card: Card; onClick?: () => void }) {
  const hb = useHoverBindingsForCard({
    src: (card as any).image,
    name: card.name,
    cardKind: card.kind,
    baseWidth: 216,
    zoom: 1.5,
  })

  const handleKey = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (!onClick) return
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      onClick()
    }
  }

  return (
    <div
      tabIndex={0}
      onPointerEnter={hb.onPointerEnter}
      onPointerMove={hb.onPointerMove}
      onPointerLeave={hb.onPointerLeave}
      onPointerUp={hb.onPointerUp}
      onFocus={hb.onFocus}
      onBlur={hb.onBlur}
      onClick={onClick}
      onKeyDown={handleKey}
      role={onClick ? 'button' : undefined}
      style={{ position: 'relative', cursor: onClick ? 'pointer' : 'default' }}
    >
      <MiniCard c={card} scale={1} />
    </div>
  )
}


async function maybeOfferDodgeRoll(g: Game, defenderPid: PlayerId, target: Unit): Promise<boolean> {
  const hand = g.handSpells[defenderPid];
  const idx = hand.findIndex(c =>
    c.kind === 'Spell' &&
    ((c.spellCode ?? toSpellCode(c.name)) === 'DODGE_ROLL')
  );
  if (idx < 0) return false;

  const card = hand[idx] as Extract<Card, { kind: 'Spell' }>;

  const actualCost = modifiedCostFor(g, defenderPid, card, card.cost);
  if (g.mana[defenderPid] < actualCost) return false;
  if (!hasThreshold(threshold(g, defenderPid), card.threshold)) return false;

  const ok = await uiConfirmForPid(defenderPid, {
    title: 'Dodge Roll',
    message: formatTileText(g, `Play Dodge Roll on ${target.name}? (Cost ${actualCost})`),
    confirmLabel: 'Play',
    cancelLabel: 'Decline',
  });
  if (!ok) return false;

  const reg = (target as any).region as Region;
  const tx = (target as any).x as number, ty = (target as any).y as number;
  const adj: Array<{x:number;y:number}> = [
    {x:tx+1,y:ty},{x:tx-1,y:ty},{x:tx,y:ty+1},{x:tx,y:ty-1},
    {x:tx+1,y:ty+1},{x:tx+1,y:ty-1},{x:tx-1,y:ty+1},{x:tx-1,y:ty-1},
  ].filter(p => inside(g, p.x, p.y) && regionAllowedForUnit(g, target, reg, cellOf(g, p.x, p.y), p.x, p.y));

  if (adj.length === 0) { g.log.unshift('Dodge Roll: no legal tile to dodge to.'); return false; }

  let dest = adj[0];
  if (adj.length > 1) {
    const sel = await uiSelectOneForPid<number>(defenderPid, {
      title: 'Dodge Roll — Choose Destination',
      message: formatTileText(g, 'Select a tile to roll into.'),
      options: adj.map((p, i) => ({
        label: formatTileText(g, `(${p.x + 1},${p.y + 1})`),
        value: i,
      })),
      allowCancel: true,
      cancelLabel: 'Cancel',
    });
    if (sel == null) {
      g.log.unshift('Dodge Roll: cancelled.');
      return false;
    }
    dest = adj[sel];
  }

  spendMana(g, defenderPid, actualCost);

  moveUnitTo(g, target, dest.x, dest.y, reg);

  sendToCemetery(g, defenderPid, structuredClone(card));
  hand.splice(idx, 1);

  g.log.unshift(`${target.name} dodges the attack and rolls to (${dest.x+1},${dest.y+1}).`);
  requestGameSync?.();
  return true;
}
const cheb = (ax:number, ay:number, bx:number, by:number) => Math.max(Math.abs(ax - bx), Math.abs(ay - by))

type OrbCopyPending = {
  pid: PlayerId,
  code: string,
  cardSnap: Extract<Card,{kind:'Spell'}>,
  region: Region
}

function _runOrbImmediateCopy(g: Game, pid: PlayerId, card: Extract<Card,{kind:'Spell'}>) {
  const code = card.spellCode ?? toSpellCode(card.name);
  if (code === 'BONE_SPEAR') {
    void (async () => {
      delete (g as any)._pendingBoneSpear;
      const pending = await prepareBoneSpearCast(g, pid);
      if (!pending) {
        g.log.unshift(`${card.name} fizzles — Orb copy has no effect.`);
        requestGameSync?.();
        return;
      }
      (g as any)._pendingBoneSpear = { pid, ...pending };
      const resolved = runSpell(g, pid, card, { kind: 'immediate' });
      if (!resolved) {
        delete (g as any)._pendingBoneSpear;
        g.log.unshift(`${card.name} fizzles — Orb copy has no effect.`);
        requestGameSync?.();
        return;
      }
      applyHoundsAuraForAll(g);
      g.log.unshift(`Orb of Ba’al Berith copies ${card.name}.`);
      requestGameSync?.();
    })();
    return;
  }
  if (code === 'HEAT_RAY') {
    void (async () => {
      delete (g as any)._pendingHeatRayDir;
      const dir = await selectCardDirection(g, pid, card.name, 'Choose a direction for the copied Heat Ray (N, S, E, W).');
      if (!dir) {
        g.log.unshift(`${card.name} fizzles — Orb copy cancelled.`);
        requestGameSync?.();
        return;
      }
      (g as any)._pendingHeatRayDir = dir;
      const resolved = runSpell(g, pid, card, { kind: 'immediate' });
      if (!resolved) {
        delete (g as any)._pendingHeatRayDir;
        g.log.unshift(`${card.name} fizzles — Orb copy has no effect.`);
        requestGameSync?.();
        return;
      }
      applyHoundsAuraForAll(g);
      g.log.unshift(`Orb of Ba’al Berith copies ${card.name}.`);
      requestGameSync?.();
    })();
    return;
  }
  const resolved = runSpell(g, pid, card, { kind: 'immediate' })
  if (!resolved) {
    g.log.unshift(`${card.name} fizzles — Orb copy has no effect.`);
    return;
  }
  applyHoundsAuraForAll(g);
  g.log.unshift(`Orb of Ba’al Berith copies ${card.name}.`)
}

function _armOrbPendingCopy(g: Game, pid: PlayerId, code: string, card: Extract<Card,{kind:'Spell'}>, region: Region) {
  (g as any)._pendingOrbCopy = { pid, code, cardSnap: structuredClone(card), region } as OrbCopyPending
  g.log.unshift(`Orb of Ba’al Berith: choose targets for the copy of ${card.name}.`)
}

function _maybeTriggerOrbOnSpellCast(
  g: Game,
  spellController: PlayerId,
  caster: { x: number; y: number; region: Region },
  card: Extract<Card,{kind:'Spell'}>,
  code: string,
  targeted: boolean
) {
  const orbs = g.artifacts.filter(a =>
    a.name === "Orb of Ba'al Berith" &&
    a.region === caster.region &&
    cheb(a.x, a.y, caster.x, caster.y) <= 1
  )

  if (orbs.length === 0) return

  for (const orb of orbs) {
    ;(orb as any)._usedTurn ??= -1
    if ((orb as any)._usedTurn === g.turn) continue

    ;(orb as any)._usedTurn = g.turn

    if (!targeted) {
      _runOrbImmediateCopy(g, spellController, card)
    } else {
      _armOrbPendingCopy(g, spellController, code, card, caster.region)
    }
  }
}

function unitCarriesArtifact(g: Game, u: Unit, name: string): Artifact | null {
  const id = (u as any).id as string | undefined
  if (!id) return null
  return g.artifacts.find(a => a.carriedBy === id && a.name === name) ?? null
}

function artifactHasSubtype(art: Artifact, subtype: string): boolean {
  const subs = (art.subTypes ?? []).map(s => s.toLowerCase())
  return subs.includes(subtype.toLowerCase())
}

function cardHasSubtype(card: Card, subtype: string): boolean {
  const list = Array.isArray((card as any).subTypes)
    ? (card as any).subTypes as string[]
    : typeof (card as any).subTypes === 'string'
      ? ((card as any).subTypes as string).split(/[,/]/).map(s => s.trim())
      : [];
  return list.some(s => s.toLowerCase() === subtype.toLowerCase());
}

function cardIsEvilForDenOfEvil(card: Card): boolean {
  return (
    cardHasSubtype(card, 'Evil') ||
    cardHasSubtype(card, 'Undead') ||
    cardHasSubtype(card, 'Vampire') ||
    cardHasSubtype(card, 'Monster') ||
    cardHasSubtype(card, 'Demon')
  );
}

function cardIsFireCard(card: Card): boolean {
  const threshold = (card as any).threshold as Threshold | undefined;
  if (threshold && ((threshold.Fire ?? (threshold as any).fire ?? 0) > 0)) return true;
  const element = (card as any).element as Elem | undefined;
  if (element === 'Fire') return true;
  const elements = (card as any).elements as Elem[] | undefined;
  if (Array.isArray(elements) && elements.includes('Fire')) return true;
  const provides = (card as any).provides as Elem[] | undefined;
  if (Array.isArray(provides) && provides.includes('Fire')) return true;
  return false;
}

function artifactImmovable(art: Artifact): boolean {
  if (!art) return false;
  if ((art as any)._immovable) return true;
  return /^Iron Man Talus$/i.test(art.name ?? '');
}

function artifactIsWeaponOrArmor(art: Artifact): boolean {
  if (artifactHasSubtype(art, 'Weapon') || artifactHasSubtype(art, 'Armor')) return true
  return /weapon|armor|shield|sword|lance|bow|dagger|axe|blade|spear|helm|mace|hammer/i.test(art.name)
}

function cardIsWeaponOrArmor(card: Extract<Card, { kind: 'ArtifactCard' }>): boolean {
  const subs = (card.subTypes ?? []).map(s => s.toLowerCase());
  if (subs.includes('weapon') || subs.includes('armor')) return true;
  return /weapon|armor|shield|sword|lance|bow|dagger|axe|blade|spear|helm|mace|hammer/i.test(card.name);
}

function unitRawSubTypes(u: Unit): string[] {
  const direct = ((u as any).subTypes as string[] | undefined) ?? []
  if (direct.length > 0) return direct
  const src = (u as any)._srcCard as (Card | undefined)
  const fromSrc = (src as any)?.subTypes as string[] | undefined
  return fromSrc ?? []
}

function unitHasRawSubtype(u: Unit, subtype: string): boolean {
  const list = unitRawSubTypes(u)
  if (list.length === 0) return false
  const needle = subtype.toLowerCase()
  return list.some(s => s.toLowerCase() === needle)
}

function unitHasBaseSubtype(u: Unit, subtype: string): boolean {
  if (unitHasRawSubtype(u, subtype)) return true;
  const extra = (u as any)._extraSubTypes as string[] | undefined;
  if (!extra || extra.length === 0) return false;
  const needle = subtype.toLowerCase();
  return extra.some(s => s.toLowerCase() === needle);
}

function unitControlledByCorruptor(g: Game, u: Unit): boolean {
  const pid = (u as any).player as PlayerId | undefined;
  if (pid == null) return false;
  const av = g.avatars[pid];
  return !!av && /^Corruptor$/i.test(av.name ?? '');
}

function unitHasSubtype(g: Game, u: Unit, subtype: string): boolean {
  const needle = subtype.toLowerCase()
  if (needle === 'evil' && u.kind === 'Token' && saintOfRedemptionActive(g)) return false;
  if (needle === 'evil' && (u as any)._brandedEvilTurn === g.turnNumber) return true;
  if (u.kind !== 'Avatar' && (u as any)._allMinionTypes) return true
  if (/^Moonsong Talagelum$/i.test(u.name ?? '') && needle === 'grey wolves') return true;
  if (unitHasRawSubtype(u, subtype)) return true
  const extra = (u as any)._extraSubTypes as string[] | undefined;
  if (extra && extra.some(s => s.toLowerCase() === needle)) return true;
  if (unitControlledByCorruptor(g, u)) {
    if (needle === 'monster' && (unitHasBaseSubtype(u, 'Beast') || (isBowerOfBlissActive(g) && unitHasRawSubtype(u, 'Mortal')))) return true;
    if (needle === 'undead' && unitHasBaseSubtype(u, 'Mortal')) return true;
    if (needle === 'demon' && unitHasBaseSubtype(u, 'Angel')) return true;
  }
  if (needle === 'beast' && isBowerOfBlissActive(g) && unitHasRawSubtype(u, 'Mortal')) return true
  return false
}

function isDoomOfDilmun(u: Unit): boolean {
  return u.kind !== 'Avatar' && /^The Doom of Dilmun$/i.test(u.name ?? '');
}

function applyKingArthurControlLock(g: Game): void {
  const hasArthur = g.board.flat().some(cell =>
    cell.units.some(u => u.kind !== 'Avatar' && /^King Arthur$/i.test(u.name ?? ''))
  );
  if (!hasArthur) return;

  const revertUnit = (u: Unit, ownerPid: PlayerId) => {
    if (u.player !== ownerPid) {
      u.player = ownerPid;
      if (u.kind !== 'Avatar') refreshUnitArtifactPassives(g, u);
    }
  };

  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        const owner = (unit as any)._ownerPid as PlayerId | undefined;
        if (owner != null) revertUnit(unit, owner);
      }
    }
  }

  for (const row of g.board) {
    for (const cell of row) {
      const site = cell.site;
      if (site && (site as any)._ownerPid != null && site.controller !== (site as any)._ownerPid) {
        site.controller = (site as any)._ownerPid as PlayerId;
      }
    }
  }

  for (const art of g.artifacts) {
    const owner = art.owner ?? null;
    if (owner != null && art.player !== owner) {
      art.player = owner;
      if (art.carriedBy) {
        const carrier = findTokenOnBoard(g, art.carriedBy);
        if (carrier && carrier.token.player !== owner) {
          carrier.token.carrying = carrier.token.carrying.filter(id => id !== art.id);
          art.carriedBy = null;
          const { x, y, region } = getArtifactCurrentPosition(g, art);
          const dropCell = cellOf(g, x, y);
          if (!dropCell.artifacts.some(a => a.id === art.id)) dropCell.artifacts.push(art);
        }
      }
      syncCarryableArtifactController(g, art);
    }
  }
}

function applyLumberingGiantRule(g: Game): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if (unit.kind === 'Avatar') continue;
        if (/^Lumbering Giant$/i.test(unit.name ?? '')) {
          (unit as any)._cannotDefend = true;
        }
      }
    }
  }
}

function applyRibbleBoggartAuras(g: Game): void {
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if ((unit as any)._boggartTempPower) {
        const base = (unit as any)._tempPowerBonus ?? 0;
        (unit as any)._tempPowerBonus = base;
      }
    }
  }
}

function applyVarmintWarrensEffect(g: Game): void {
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      delete (unit as any)._varmintProtected;
    }
  }
  for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
    const cell = cellOf(g, x, y);
    const site = cell.site;
    if (!site || site.rubble || !/^Varmint Warrens$/i.test(site.name ?? '')) continue;
    const beasts = unitArrayAtRegion(g, x, y, 'surface').filter(u => u.kind !== 'Avatar' && unitHasSubtype(g, u, 'Beast'));
    for (const beast of beasts) {
      (beast as any)._varmintProtected = true;
    }
  }
}

function applySirBorsAura(g: Game): void {
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if ((unit as any)._borsSuppressed) {
        const base = ensureUnitArtifactBase(unit as Token);
        (unit as any).stealth = base.stealth;
        delete (unit as any)._borsSuppressed;
      }
    }
  }
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if (!/^Sir Bors the Younger$/i.test(unit.name ?? '')) continue;
      const token = unit as Token;
      const region = ((token as any).region ?? 'surface') as Region;
      for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
        const nx = token.x + dx;
        const ny = token.y + dy;
        if (!inside(g, nx, ny)) continue;
        const units = unitArrayAtRegion(g, nx, ny, region);
        for (const other of units) {
          if (other.player === token.player) continue;
          if (other.kind === 'Avatar') continue;
          (other as any).stealth = false;
          maybeEndInfiltrate(g, other);
          (other as any)._borsSuppressed = true;
        }
      }
    }
  }
}

function applyRebecksAura(g: Game): void {
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if ((unit as any)._rebecksCharge) {
        const base = ensureUnitArtifactBase(unit as Token);
        (unit as any).charge = base.charge;
        delete (unit as any)._rebecksCharge;
      }
    }
  }
  for (const row of g.board) for (const cell of row) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if (!/^Rebecks$/i.test(unit.name ?? '')) continue;
      const token = unit as Token;
      const region = ((token as any).region ?? 'surface') as Region;
      for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
        const nx = token.x + dx;
        const ny = token.y + dy;
        if (!inside(g, nx, ny)) continue;
        const units = unitArrayAtRegion(g, nx, ny, region);
        for (const other of units) {
          if (other.kind === 'Avatar') continue;
          if (other.player !== token.player) continue;
          if (!unitHasSubtype(g, other, 'Giant')) continue;
          (other as any).charge = true;
          (other as any)._rebecksCharge = true;
        }
      }
    }
  }
}

function applyOverbearingBailiffEffect(g: Game): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if ((unit as any)._bailiffBonus) delete (unit as any)._bailiffBonus;
      }
    }
  }
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if (unit.kind === 'Avatar') continue;
        if (!/^Overbearing Bailiff$/i.test(unit.name ?? '')) continue;
        const token = unit as Token;
        const backRow = token.player === 1 ? g.height - 1 : 0;
        if (token.y !== backRow) continue;
        let royaltyNearby = false;
        for (let dy = -1; dy <= 1 && !royaltyNearby; dy++) for (let dx = -1; dx <= 1 && !royaltyNearby; dx++) {
          const nx = token.x + dx;
          const ny = token.y + dy;
          if (!inside(g, nx, ny)) continue;
          const units = unitArrayAtRegion(g, nx, ny, (token as any).region ?? 'surface');
          for (const other of units) {
            if (other.player !== token.player) continue;
            if (unitHasSubtype(g, other, 'Royalty') || /king|queen|prince|princess/i.test(other.name ?? '')) {
              royaltyNearby = true;
              break;
            }
          }
        }
        if (!royaltyNearby) (token as any)._bailiffBonus = 7;
      }
    }
  }
}

function applyPendragonBannerAura(g: Game): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if ((unit as any)._pendragonBonus) delete (unit as any)._pendragonBonus;
      }
    }
  }
  for (const art of g.artifacts) {
    if (!/^Pendragon Banner$/i.test(art.name ?? '')) continue;
    const owner = artifactOwnerPid(art);
    if (owner == null) continue;
    const { x, y, region } = getArtifactCurrentPosition(g, art);
    const hereUnits = unitArrayAtRegion(g, x, y, region);
    const enemiesHere = hereUnits.some(u => u.player !== owner);
    if (enemiesHere) continue;
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      const nx = x + dx;
      const ny = y + dy;
      if (!inside(g, nx, ny)) continue;
      const units = unitArrayAtRegion(g, nx, ny, region);
      for (const u of units) {
        if (u.player !== owner) continue;
        (u as any)._pendragonBonus = ((u as any)._pendragonBonus ?? 0) + 1;
      }
    }
  }
}

function applyPebbledPathsEffect(g: Game): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if ((unit as any)._pebbledChargeRemoved) {
          const base = unit.kind !== 'Avatar' ? ensureUnitArtifactBase(unit as Token) : null;
          if (base) (unit as any).charge = base.charge;
          delete (unit as any)._pebbledChargeRemoved;
        }
      }
    }
  }
  for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
    const site = g.board[y][x].site;
    if (!site || site.rubble || !/^Pebbled Paths$/i.test(site.name ?? '')) continue;
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      if (dx === 0 && dy === 0) continue;
      const nx = x + dx;
      const ny = y + dy;
      if (!inside(g, nx, ny)) continue;
      const neighborSite = g.board[ny][nx].site;
      if (!neighborSite || neighborSite.rubble) continue;
      const units = unitArrayAtRegion(g, nx, ny, 'surface');
      for (const u of units) {
        if (u.kind === 'Avatar') continue;
        (u as any).charge = false;
        (u as any)._pebbledChargeRemoved = true;
      }
    }
  }
}

async function activateLovePotion(g: Game, bearer: Token): Promise<void> {
  const art = unitCarriesArtifact(g, bearer, 'Love Potion');
  if (!art) return;
  const region = ((bearer as any).region ?? 'surface') as Region;
  const cell = cellOf(g, bearer.x, bearer.y);
  const enemies = cell.units.filter(u => u.player !== bearer.player && u.kind !== 'Avatar' && ((u as any).region ?? 'surface') === region);
  if (enemies.length === 0) {
    g.log.unshift('Love Potion — no enemy minion here to charm.');
    requestGameSync?.();
    return;
  }

  let target = enemies[0] as Token;
  if (enemies.length > 1) {
    const idx = await uiSelectOne<number>({
      title: 'Love Potion',
      message: 'Choose an enemy minion here to charm.',
      options: enemies.map((u, i) => ({
        label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
        value: i,
      })),
      allowCancel: true,
      cancelLabel: 'Cancel',
    });
    if (idx == null || idx < 0 || idx >= enemies.length) {
      g.log.unshift('Love Potion activation cancelled.');
      requestGameSync?.();
      return;
    }
    target = enemies[idx] as Token;
  }

  const prevPid = target.player as PlayerId;
  bearer.tapped = true;
  bearer.interactedThisTurn = true;
  destroyArtifact(g, art, { log: 'Love Potion is sacrificed.' });
  target.player = bearer.player;
  (target as any)._lovePotionCharm = { bearerId: (bearer as any).id, prevPid };
  refreshUnitArtifactPassives(g, target);
  applyHoundsAuraForAll(g);
  g.log.unshift(`Love Potion charms ${target.name}; it now fights for Player ${bearer.player}.`);
  requestGameSync?.();
}

async function activateNellyLongarms(g: Game, nelly: Token): Promise<void> {
  const pid = nelly.player as PlayerId;
  const dir = await selectCardDirection(g, pid, 'Nelly Longarms', 'Choose a direction to snag a target.');
  if (!dir) {
    g.log.unshift('Nelly Longarms waits patiently.');
    requestGameSync?.();
    return;
  }
  if (!canTapToPay(g, nelly)) {
    g.log.unshift('Nelly Longarms cannot act right now.');
    requestGameSync?.();
    return;
  }
  nelly.tapped = true;
  nelly.interactedThisTurn = true;
  const region = ((nelly as any).region ?? 'surface') as Region;
  let x = nelly.x;
  let y = nelly.y;
  const delta = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];
  while (inside(g, x + delta[0], y + delta[1])) {
    const nx = x + delta[0];
    const ny = y + delta[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid, nelly)) return;
    x = nx; y = ny;
    const units = unitArrayAtRegion(g, x, y, region).filter(u => !(u as any).stealth);
    if (units.length === 0) continue;
    let target = units[0];
    if (units.length > 1) {
      const idx = await uiSelectOne<number>({
        title: 'Nelly Longarms',
        message: formatTileText(g, 'Choose a unit to drag.'),
        options: units.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (idx == null || idx < 0 || idx >= units.length) {
        g.log.unshift('Nelly Longarms cancels the pull.');
        requestGameSync?.();
        return;
      }
      target = units[idx];
    }
    const anchorCell = cellOf(g, nelly.x, nelly.y);
    if (!regionAllowedForUnit(g, target, region, anchorCell, nelly.x, nelly.y)) {
      g.log.unshift(`${target.name} cannot be dragged to Nelly's location.`);
      requestGameSync?.();
      return;
    }
    moveUnitTo(g, target, nelly.x, nelly.y, region);
    g.log.unshift(`Nelly Longarms drags ${target.name} to (${nelly.x + 1}, ${nelly.y + 1}).`);
    const site = anchorCell.site;
    if (site && isSiteWater(g, site, nelly.x, nelly.y) && (target as any).submerge) {
      const wants = await uiConfirm({
        title: 'Nelly Longarms',
        message: 'Submerge the dragged unit?',
        confirmLabel: 'Submerge',
        cancelLabel: 'Keep at surface',
      });
      if (wants && regionAllowedForUnit(g, target, 'underwater', anchorCell, nelly.x, nelly.y)) {
        moveUnitTo(g, target, nelly.x, nelly.y, 'underwater');
        g.log.unshift(`${target.name} is submerged beneath the site.`);
      }
    }
    requestGameSync?.();
    return;
  }
  g.log.unshift(`Nelly Longarms lashes ${dir} but finds no target.`);
  requestGameSync?.();
}

async function throwHolyWater(g: Game, bearer: Token): Promise<void> {
  const pid = bearer.player as PlayerId;
  const art = unitCarriesArtifact(g, bearer, 'Holy Water');
  if (!art) return;
  const dir = await selectCardDirection(g, pid, 'Holy Water', 'Choose a direction to throw Holy Water.');
  if (!dir) {
    g.log.unshift('Holy Water throw cancelled.');
    requestGameSync?.();
    return;
  }
  if (!canTapToPay(g, bearer)) {
    g.log.unshift('Holy Water bearer cannot act right now.');
    requestGameSync?.();
    return;
  }
  bearer.tapped = true;
  bearer.interactedThisTurn = true;
  destroyArtifact(g, art, { log: 'Holy Water is sacrificed.' });

  const region = ((bearer as any).region ?? 'surface') as Region;
  let x = bearer.x;
  let y = bearer.y;
  const delta = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];
  while (inside(g, x + delta[0], y + delta[1])) {
    const nx = x + delta[0];
    const ny = y + delta[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid, bearer)) return;
    x = nx; y = ny;
    const targets = unitArrayAtRegion(g, x, y, region)
      .filter(u => !(u as any).stealth)
      .filter(u => !projectileSkipsUnit(g, u));
    if (targets.length === 0) continue;

    let target: Unit = targets[0];
    if (targets.length > 1) {
      const idx = await uiSelectOne<number>({
        title: 'Holy Water',
        message: formatTileText(g, `Choose a unit to hit (${dir}).`),
        options: targets.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Default target',
      });
      if (idx != null && idx >= 0 && idx < targets.length) {
        target = targets[idx];
      }
    }

    if (target.kind === 'Avatar') {
      g.log.unshift(`Holy Water splashes ${target.name} but has no effect.`);
      requestGameSync?.();
      return;
    }

    if (unitHasSubtype(g, target, 'Evil')) {
      const removed = banishUnitInstance(g, target, { source: 'Holy Water' });
      if (removed) recordBanishedCards(g, target.player as PlayerId, [removed]);
      g.log.unshift(`Holy Water banishes the Evil ${target.name}.`);
    } else {
      grantWard(target);
      g.log.unshift(`Holy Water wards ${target.name}.`);
    }
    requestGameSync?.();
    return;
  }

  g.log.unshift('Holy Water flies off the edge and hits nothing.');
  requestGameSync?.();
}

async function throwRhongomyniad(g: Game, bearer: Token): Promise<void> {
  const pid = bearer.player as PlayerId;
  const art = unitCarriesArtifact(g, bearer, 'Rhongomyniad');
  if (!art) return;
  const dir = await selectCardDirection(g, pid, 'Rhongomyniad', 'Choose a direction to hurl Rhongomyniad.');
  if (!dir) {
    g.log.unshift('Rhongomyniad throw cancelled.');
    requestGameSync?.();
    return;
  }
  if (!canTapToPay(g, bearer)) {
    g.log.unshift('Rhongomyniad bearer cannot act right now.');
    requestGameSync?.();
    return;
  }
  bearer.tapped = true;
  bearer.interactedThisTurn = true;
  const region = ((bearer as any).region ?? 'surface') as Region;
  let x = bearer.x;
  let y = bearer.y;
  const delta = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];
  let hits = 0;
  while (inside(g, x + delta[0], y + delta[1])) {
    const nx = x + delta[0];
    const ny = y + delta[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid, bearer)) break;
    x = nx; y = ny;
    const units = unitArrayAtRegion(g, x, y, region).filter(u => u !== bearer && !(u as any).stealth);
    if (units.length === 0) continue;
    let target: Unit = units[0];
    const enemy = units.find(u => u.player !== pid);
    if (enemy) target = enemy;
    const dmgOpts: DamageOpts = { isDamage: true, sourceUnit: bearer, isRangedStrike: true };
    damageUnit(g, target, 3, dmgOpts);
    hits += 1;
    g.log.unshift(`Rhongomyniad pierces ${target.name} for 3 at (${x + 1}, ${y + 1}).`);
  }
  if (hits === 0) {
    g.log.unshift(`Rhongomyniad flies ${dir} but hits nothing.`);
  }
  requestGameSync?.();
}

async function activateMesterStoorWorm(g: Game, worm: Token): Promise<void> {
  const dir = await selectCardDirection(g, worm.player as PlayerId, 'Mester Stoor Worm', 'Choose a direction to unleash its tidal sweep.');
  if (!dir) {
    g.log.unshift('Mester Stoor Worm holds its wrath.');
    requestGameSync?.();
    return;
  }
  worm.tapped = true;
  worm.interactedThisTurn = true;
  const region = ((worm as any).region ?? 'surface') as Region;
  const delta = dir === 'N' ? [0,-1] : dir === 'S' ? [0,1] : dir === 'E' ? [1,0] : [-1,0];
  let x = worm.x;
  let y = worm.y;
  let slain = 0;
  for (let step = 0; step < 3; step++) {
    const nx = x + delta[0];
    const ny = y + delta[1];
    if (!inside(g, nx, ny)) break;
    x = nx; y = ny;
    const units = unitArrayAtRegion(g, x, y, region);
    for (const target of units) {
      const lethal = unitThresholdHPPlus(g, target);
      damageUnit(g, target, lethal, { sourceUnit: worm, sourceElement: 'Water', isDamage: true, redirected: true });
      slain += 1;
    }
  }
  g.log.unshift(`Mester Stoor Worm sweeps ${dir}, unleashing lethal waves${slain > 0 ? ` on ${slain} unit(s)` : ' but strikes no one'}.`);
  requestGameSync?.();
}

function playerHasUnitNamed(g: Game, pid: PlayerId, name: string): boolean {
  for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
    for (const u of g.board[y][x].units) {
      if (u.player === pid && u.kind !== 'Avatar' && new RegExp(`^${name}$`, 'i').test(u.name ?? '')) {
        return true;
      }
    }
  }
  return false;
}

function playerControlsSiteNamed(g: Game, pid: PlayerId, name: string): boolean {
  for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
    const site = g.board[y][x].site;
    if (!site || site.rubble) continue;
    if (site.controller !== pid) continue;
    if (new RegExp(`^${name}$`, 'i').test(site.name ?? '')) return true;
  }
  return false;
}

function applyBluecapLocks(g: Game): void {
  for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
    const cell = g.board[y][x];
    const site = cell.site;
    if (!site) continue;
    const hasKnocker = cell.units.some(
      u => u.kind !== 'Avatar' && /^Bluecap Knockers$/i.test(u.name ?? '') && ((u as any).region ?? 'surface') === 'surface'
    );
    if (hasKnocker) {
      (site as any)._bluecapLock = true;
      if (!site.bedrock) {
        site.bedrock = true;
        (site as any)._bluecapBedrockApplied = true;
      }
    } else if ((site as any)._bluecapLock) {
      delete (site as any)._bluecapLock;
      if ((site as any)._bluecapBedrockApplied) {
        delete (site as any)._bluecapBedrockApplied;
        site.bedrock = false;
      }
    }
  }
}

function unitHasElement(u: Unit, elem: Elem): boolean {
  if (u.kind === 'Avatar') return u.element === elem
  const token = u as Token
  if ((token as any)._allElements) return true
  const extras = (token as any)._extraElements as Elem[] | undefined
  if (Array.isArray(extras) && extras.includes(elem)) return true
  if (token.element === elem) return true
  return false
}

function isGnomeHollows(site: Site | null | undefined): boolean {
  if (!site || site.rubble) return false;
  return /^Gnome Hollows$/i.test(site.name ?? '');
}

function basePowerOfCard(card: Extract<Card, { kind: 'Unit' }>): number {
  if (typeof card.power === 'number') return card.power ?? 0;
  if (typeof card.atk === 'number') return card.atk ?? 0;
  if (typeof card.def === 'number') return card.def ?? 0;
  return 0;
}

function basePowerOfUnit(u: Unit): number {
  if (u.kind === 'Avatar') return u.power ?? 0;
  const token = u as Token;
  if (typeof token.atk === 'number') return token.atk ?? 0;
  if (typeof token.power === 'number') return token.power ?? 0;
  if (typeof token.def === 'number') return token.def ?? 0;
  return 0;
}

function gnomeHollowsBlocksCard(site: Site | null | undefined, card: Extract<Card, { kind: 'Unit' }>): boolean {
  if (!isGnomeHollows(site)) return false;
  return basePowerOfCard(card) >= 3;
}

function gnomeHollowsBlocksUnit(g: Game, unit: Unit, x: number, y: number, region: Region): boolean {
  if (region !== 'surface') return false;
  if (unitIgnoresSiteAbilities(g, unit)) return false;
  const cell = cellOf(g, x, y);
  const site = cell.site;
  if (!isGnomeHollows(site)) return false;
  return basePowerOfUnit(unit) >= 3;
}

function unitHasVoidwalkAt(g: Game, u: Unit, loc: { x: number; y: number; region: Region }): boolean {
  if (u.kind === 'Avatar') return false;
  const token = u as Token;
  if (token.voidwalk) return true;
  if (loc.region !== 'surface') return false;
  if (unitIgnoresSiteAbilities(g, u)) return false;
  if (!Number.isFinite(loc.x) || !Number.isFinite(loc.y)) return false;
  const cell = cellOf(g, loc.x, loc.y);
  const site = cell.site;
  if (!site || site.rubble) return false;
  return /^Planar Gate$/i.test(site.name ?? '');
}

function unitHasVoidwalkNow(g: Game, u: Unit): boolean {
  const x = (u as any).x as number | undefined;
  const y = (u as any).y as number | undefined;
  const region = ((u as any).region ?? 'surface') as Region;
  if (!Number.isFinite(x) || !Number.isFinite(y)) return false;
  return unitHasVoidwalkAt(g, u, { x: x!, y: y!, region });
}

function arcadeOfBonesProtectsUnit(g: Game, u: Unit): boolean {
  if (!unitHasSubtype(g, u, 'Undead')) return false;
  const region = ((u as any).region ?? 'surface') as Region;
  if (region !== 'surface') return false;
  const y = (u as any).y as number | undefined;
  if (!Number.isFinite(y)) return false;
  return g.artifacts.some(
    (a) =>
      /^Arcade of Bones$/i.test(a.name ?? '') &&
      (a.region ?? 'surface') === region &&
      a.y === y
  );
}

function destroyArtifact(g: Game, art: Artifact, opts?: { log?: string; draw?: { pid: PlayerId; n: number } }) {
  const ref = g.artifacts.find(a => a.id === art.id)
  if (!ref) return
  const koscheiOwner = (ref as any)._koscheiOwner as PlayerId | undefined;
  if (!g.winner && koscheiOwner != null && /^Koschei's Egg$/i.test(ref.name ?? '')) {
    g.winner = koscheiOwner === 1 ? 2 : 1;
    g.log.unshift(`Koschei's Egg leaves the realm — Player ${g.winner} wins!`);
  }
  const deathritePos = getArtifactCurrentPosition(g, ref);
  const deathriteOwner = artifactOwnerPid(ref);

  const binding = (ref as any)._grosseBinding as GrosseBinding | undefined;
  if (binding) {
    releaseGrosseBinding(g, binding, 'the artifact is destroyed', { skipArtifactRemoval: true });
  }
  const infusionBinding = (ref as any)._infusionBinding as InfusionBinding | undefined;
  if (infusionBinding) {
    releaseInfusionBinding(g, infusionBinding, 'the artifact is destroyed');
  }
  const hemoBinding = (ref as any)._hemogolemBinding as HemogolemBinding | undefined;
  if (hemoBinding) {
    releaseHemogolemBinding(g, hemoBinding, 'the artifact is destroyed');
  }
  if ((ref as any)._tabulaLock && ref.carriedBy) {
    const carrier = findUnitById(g, ref.carriedBy);
    if (carrier && carrier.kind !== 'Avatar') {
      delete (carrier as any)._tabulaRasa;
    }
  }

  const sidrakLockedIds = (ref as any)._sidrakLockedIds as string[] | undefined;
  if (sidrakLockedIds && sidrakLockedIds.length > 0) {
    const states =
      ((ref as any)._sidrakLockedStates ?? {}) as Record<
        string,
        { hadImmobile: boolean; immobileValue: boolean; hadCannotDefend: boolean; cannotDefendValue: boolean }
      >;
    for (const id of sidrakLockedIds) {
      const found = findTokenOnBoard(g, id);
      const unit = found?.token;
      if (!unit || unit.kind === 'Avatar') continue;
      const state = states[id];
      if (state?.hadImmobile) {
        if (state.immobileValue) (unit as any)._immobileUnit = true;
        else delete (unit as any)._immobileUnit;
      } else {
        delete (unit as any)._immobileUnit;
      }
      if (state?.hadCannotDefend) {
        if (state.cannotDefendValue) (unit as any)._cannotDefend = true;
        else delete (unit as any)._cannotDefend;
      } else {
        delete (unit as any)._cannotDefend;
      }
    }
    delete (ref as any)._sidrakLockedIds;
    delete (ref as any)._sidrakLockedStates;
  }

  if (ref.carriedBy) {
    const carrier = g.board.flat().flatMap(c => c.units).find(u => (u as any).id === ref.carriedBy)
    if (carrier) {
      const t = carrier as Token
      t.carrying = t.carrying.filter(id => id !== ref.id)
      refreshUnitArtifactPassives(g, carrier)
    }
  }

  ref.carriedBy = null
  syncCarryableArtifactController(g, ref);

  if (inside(g, ref.x, ref.y)) {
    const cell = cellOf(g, ref.x, ref.y)
    cell.artifacts = cell.artifacts.filter(a => a.id !== ref.id)
  }
  releaseAlgorHand(g, ref);

  if ((ref as any)._gargoyleToken) {
    handleMonasteryGargoyleArtifactDestroyed(g, ref);
  }

  if (/^Kairos the Archivist$/i.test(ref.name ?? '')) {
    const snap = (ref as any)._kairosArchive as any | undefined;
    if (snap) {
      try {
        g.board = structuredClone(snap.board);
        g.artifacts = structuredClone(snap.artifacts);
        g.auras = structuredClone(snap.auras);
        g.handSpells = structuredClone(snap.handSpells);
        g.handAtlas = structuredClone(snap.handAtlas);
        g.cemetery = structuredClone(snap.cemetery);
        g.banished = structuredClone(snap.banished);
        g.mana = structuredClone(snap.mana);
        g.decks = structuredClone(snap.decks);
        g.log.unshift('Kairos restores the archived state of the realm.');
        requestGameSync?.();
      } catch {
        g.log.unshift('Kairos fails to restore the realm.');
      }
    }
    const owner = artifactOwnerPid(ref);
    if (owner != null) {
      (g.banished[owner] ?? (g.banished[owner] = [])).push(
        { id: uid(), kind: 'ArtifactCard', name: ref.name, cost: ref.cost ?? 0, text: (ref as any).text, image: ref.image } as Extract<Card, { kind: 'ArtifactCard' }>
      );
    }
  }

  g.artifacts = g.artifacts.filter(a => a.id !== ref.id)

  if (/^Clay Golem$/i.test(ref.name ?? '') && deathriteOwner != null) {
    void (async () => {
      const { x, y, region } = deathritePos;
      if (!Number.isFinite(x) || !Number.isFinite(y) || region !== 'surface' || !inside(g, x, y)) {
        g.log.unshift('Clay Golem crumbles without a place to shape the land.');
        requestGameSync?.();
        return;
      }
      const adj = adjacentCoords(g, x, y)
        .map(([ax, ay]) => ({ x: ax, y: ay, cell: cellOf(g, ax, ay) }))
        .filter(({ cell }) => !cell.site || cell.site.rubble);
      if (adj.length === 0) {
        g.log.unshift('Clay Golem — no adjacent void or rubble to reshape.');
        requestGameSync?.();
        return;
      }
      const deck = g.decks?.[deathriteOwner]?.atlas;
      if (!deck || deck.length === 0) {
        g.log.unshift('Clay Golem — atlas deck is empty.');
        requestGameSync?.();
        return;
      }
      const top = deck.shift();
      if (!top) {
        g.log.unshift('Clay Golem — atlas deck is empty.');
        requestGameSync?.();
        return;
      }
      if (top.kind !== 'Site') {
        deck.unshift(top);
        g.log.unshift('Clay Golem reveals a non-site and cannot shape the land.');
        requestGameSync?.();
        return;
      }
      let choice = adj[0];
      if (adj.length > 1 && !isCpuPlayer(g, deathriteOwner)) {
        const idx = await uiSelectOne<number>({
          title: 'Clay Golem',
          message: formatTileText(g, `Clay Golem reveals ${top.name}. Choose an adjacent void or rubble.`),
          options: adj.map(({ x: ax, y: ay }, i) => ({
            label: formatTileText(g, `(${ax + 1}, ${ay + 1})`),
            value: i,
          })),
          allowCancel: true,
          cancelLabel: 'Cancel',
        });
        if (idx == null || idx < 0 || idx >= adj.length) {
          deck.unshift(top);
          g.log.unshift('Clay Golem leaves the land unchanged.');
          requestGameSync?.();
          return;
        }
        choice = adj[idx];
      }
      g.log.unshift(`Clay Golem reveals ${top.name}.`);
      forcePlaceSite(g, deathriteOwner, choice.x, choice.y, top as Extract<Card, { kind: 'Site' }>, 'Clay Golem');
      requestGameSync?.();
    })();
  }

  if (opts?.draw) {
    draw(g, opts.draw.pid, 'spells', opts.draw.n)
  }
  if (opts?.log) g.log.unshift(opts.log)
}

type ReleaseGrosseOptions = {
  skipTokenRemoval?: boolean;
  skipArtifactRemoval?: boolean;
};

function artifactOwnerPid(art: Artifact): PlayerId | null {
  return art.owner ?? null;
}

function getArtifactCurrentPosition(g: Game, art: Artifact): { x: number; y: number; region: Region; carrier?: Unit } {
  let x = art.x;
  let y = art.y;
  let region = art.region;
  let carrier: Unit | undefined;
  if (art.carriedBy) {
    const located = findTokenOnBoard(g, art.carriedBy);
    if (located) {
      carrier = located.token;
      x = (carrier as any).x ?? x;
      y = (carrier as any).y ?? y;
      region = ((carrier as any).region ?? region) as Region;
    }
  }
  if (!carrier) {
    const infusionBinding = (art as any)._infusionBinding as InfusionBinding | undefined;
    if (infusionBinding) {
      const carriedInfusion = findCarriedMinionById(g, infusionBinding.tokenId);
      const infusionToken = findTokenOnBoard(g, infusionBinding.tokenId)?.token ?? carriedInfusion?.token;
      const anchor = carriedInfusion?.carrier ?? infusionToken;
      if (infusionToken) {
        x = (anchor as any).x ?? x;
        y = (anchor as any).y ?? y;
        region = (((anchor as any).region ?? region) as Region);
      }
    }
  }
  return { x, y, region, carrier };
}

function artifactIsSilenced(g: Game, art: Artifact): boolean {
  const { x, y, region } = getArtifactCurrentPosition(g, art);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return false;
  if (region !== 'surface') return false;
  return acidRainSilencesHere(g, x, y);
}

function artifactIsCarryable(art: Artifact): boolean {
  if ((art as any)._infusionFactoryCarry) return true;
  const isAutomaton =
    art.isAutomaton ||
    (Array.isArray(art.subTypes) && art.subTypes.some(s => typeof s === 'string' && /automaton/i.test(s)));
  const isMonument = art.isMonument || artifactHasSubtype(art, 'Monument');
  return !isMonument && !isAutomaton;
}

function setArtifactCarrier(g: Game, art: Artifact, carrierId: string | null | undefined): void {
  if (!carrierId || !artifactIsCarryable(art)) {
    art.carriedBy = null;
    syncCarryableArtifactController(g, art);
    return;
  }
  art.carriedBy = carrierId;
  const carrier = findTokenOnBoard(g, carrierId)?.token ?? null;
  activateKoscheiEgg(g, art, carrier);
  syncCarryableArtifactController(g, art);
}

function syncCarryableArtifactController(g: Game, art: Artifact): void {
  if (!artifactIsCarryable(art)) {
    const pos = getArtifactCurrentPosition(g, art);
    if (art.carriedBy) {
      art.carriedBy = null;
      if (Number.isFinite(pos.x) && Number.isFinite(pos.y)) {
        const cell = cellOf(g, pos.x, pos.y);
        if (!cell.artifacts.some(a => a.id === art.id)) cell.artifacts.push(art);
        handleArtifactRegionChange(g, art);
      }
    }
  }
  const prev = art.player;
  if (!artifactIsCarryable(art)) {
    art.player = artifactOwnerPid(art);
    if (prev !== art.player) refreshManaForAll(g);
    return;
  }
  if (art.carriedBy) {
    const located = findTokenOnBoard(g, art.carriedBy);
    art.player = located?.token.player ?? null;
  } else {
    art.player = null;
  }
  if (prev !== art.player) refreshManaForAll(g);
}

function triggerNearbyDeathArtifacts(g: Game, dead: Token, x: number, y: number, region: Region): void {
  for (const art of g.artifacts) {
    const { x: ax, y: ay, region: ar } = getArtifactCurrentPosition(g, art);
    if (ar !== region) continue;
    if (cheb(ax, ay, x, y) > 1) continue;
    if (artifactIsSilenced(g, art)) continue;
    const owner = artifactOwnerPid(art);
    if (/^Alabaster Box$/i.test(art.name ?? '') && owner != null) {
      const healed = healAvatarLife(g, owner, 1);
      g.log.unshift(`Alabaster Box mends Player ${owner} for ${healed} as ${dead.name} dies nearby.`);
    }
    if (/^Bleeding Skull$/i.test(art.name ?? '') && owner != null) {
      const opp = owner === 1 ? 2 : 1;
      const avatar = g.avatars[opp];
      if (avatar) {
        applyAvatarDamage(g, avatar, 1, { isDamage: true });
        g.log.unshift(`Bleeding Skull punishes Player ${opp} for a nearby death.`);
      }
    }
  }
}

function triggerNearbyDeathSites(g: Game, dead: Token, x: number, y: number, region: Region): void {
  if (region !== 'surface') return;
  if (!unitHasSubtype(g, dead, 'Evil')) return;
  const owner = (dead as Token).player as PlayerId | undefined;
  if (owner == null) return;

  let triggers = 0;
  for (let oy = -1; oy <= 1; oy++) {
    for (let ox = -1; ox <= 1; ox++) {
      const sx = x + ox;
      const sy = y + oy;
      if (!inside(g, sx, sy)) continue;
      const site = cellOf(g, sx, sy).site;
      if (!site || site.rubble) continue;
      if (!/^Purgatory$/i.test(site.name ?? '')) continue;
      if (siteAbilitiesSuppressedAt(g, sx, sy, site)) continue;
      triggers += 1;
    }
  }

  if (triggers > 0) {
    const avatar = g.avatars[owner];
    if (avatar) {
      applyAvatarDamage(g, avatar, triggers, { isDamage: true, sourceElement: 'Fire' });
      g.log.unshift(
        triggers === 1
          ? `Purgatory sears Player ${owner} for 1 as their Evil minion dies nearby.`
          : `Purgatory sears Player ${owner} for ${triggers} as their Evil minion dies near overlapping flames.`
      );
    }
  }
}

function awakenHollowOnesNearDeath(g: Game, dead: Token, x: number, y: number, region: Region): void {
  if (!unitHasSubtype(g, dead, 'Mortal') && !unitHasSubtype(g, dead, 'Beast')) return;
  const awakened: Token[] = [];
  for (const cell of g.board.flat()) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      if (!/^Hollow One$/i.test(unit.name ?? '')) continue;
      const token = unit as Token;
      const ux = (token as any).x as number;
      const uy = (token as any).y as number;
      const ur = ((token as any).region ?? 'surface') as Region;
      if (ur !== region) continue;
      if (cheb(ux, uy, x, y) > 1) continue;
      if ((token as any)._hollowOneAwake) continue;
      (token as any)._hollowOneAwake = true;
      awakened.push(token);
    }
  }
  if (awakened.length > 0) {
    g.log.unshift(
      awakened.length === 1
        ? 'Hollow One stirs as a Mortal or Beast dies nearby.'
        : `Hollow Ones stir (${awakened.length}) as a Mortal or Beast dies nearby.`
    );
  }
}

function animateArtifactWithPoltergeist(g: Game, poltergeist: Token, art: Artifact): void {
  if (artifactImmovable(art)) {
    g.log.unshift(`${art.name ?? 'The artifact'} cannot be animated or moved by force.`);
    return;
  }
  if (!artifactIsCarryable(art)) {
    g.log.unshift(`${art.name ?? 'This artifact'} is fixed in place and cannot be carried or animated.`);
    return;
  }
  const bindingList: GrosseBinding[] = (poltergeist as any)._grosseBindings ?? ((poltergeist as any)._grosseBindings = []);
  if (bindingList.some(entry => entry.artifactId === art.id)) return;

  const prevOwner = artifactOwnerPid(art);
  const prevCarriedBy = art.carriedBy ?? null;
  const { x, y, region, carrier } = getArtifactCurrentPosition(g, art);

  if (carrier) {
    carrier.carrying = carrier.carrying.filter(id => id !== art.id);
    refreshUnitArtifactPassives(g, carrier);
  }

  if (inside(g, x, y)) {
    const cell = cellOf(g, x, y);
    cell.artifacts = cell.artifacts.filter(a => a.id !== art.id);
  }

  const basePower = Math.max(1, art.cost ?? 0);
  const automaton: Token = {
    id: uid(),
    kind: 'Token',
    name: `${art.name} Automaton`,
    element: poltergeist.element,
    player: poltergeist.player,
    x,
    y,
    region,
    tapped: false,
    power: basePower,
    atk: basePower,
    def: basePower,
    carrying: [art.id],
    summonedThisTurn: true,
    damage: 0,
    subTypes: ['Automaton'],
    image: art.image,
  };

  art.player = poltergeist.player;
  setArtifactCarrier(g, art, automaton.id);
  art.x = x;
  art.y = y;
  art.region = region;

  handleArtifactRegionChange(g, art);

  const cell = cellOf(g, x, y);
  cell.units.push(automaton);
  if (art.carriedBy === automaton.id && !automaton.carrying.includes(art.id)) {
    automaton.carrying.push(art.id);
  }

  refreshUnitArtifactPassives(g, automaton);

  const binding: GrosseBinding = {
    poltergeistId: poltergeist.id,
    artifactId: art.id,
    tokenId: automaton.id,
    prevOwner,
    prevCarriedBy,
    prevX: x,
    prevY: y,
    prevRegion: region,
  };

  bindingList.push(binding);
  (art as any)._grosseBinding = binding;
  (automaton as any)._grosseBinding = binding;

  g.log.unshift(`${poltergeist.name} animates ${art.name}, creating an Automaton with power ${basePower}.`);
  applyHoundsAuraForAll(g);
}

function releaseGrosseBinding(g: Game, binding: GrosseBinding, reason: string, opts: ReleaseGrosseOptions = {}): void {
  const { skipTokenRemoval, skipArtifactRemoval } = opts;

  const artifact = g.artifacts.find(a => a.id === binding.artifactId);
  const tokenEntry = findTokenOnBoard(g, binding.tokenId);

  if (tokenEntry && !skipTokenRemoval) {
    delete (tokenEntry.token as any)._grosseBinding;
    removeUnitById(g, binding.tokenId);
  } else if (tokenEntry) {
    delete (tokenEntry.token as any)._grosseBinding;
  }

  if (artifact) {
    if (!skipArtifactRemoval) {
      if (artifact.carriedBy) {
        const carrierEntry = findTokenOnBoard(g, artifact.carriedBy);
        if (carrierEntry) {
          carrierEntry.token.carrying = carrierEntry.token.carrying.filter(id => id !== artifact.id);
          refreshUnitArtifactPassives(g, carrierEntry.token);
        }
        setArtifactCarrier(g, artifact, null);
      }
      artifact.player = binding.prevOwner;
      artifact.x = binding.prevX;
      artifact.y = binding.prevY;
      artifact.region = binding.prevRegion;
      const cell = inside(g, binding.prevX, binding.prevY) ? cellOf(g, binding.prevX, binding.prevY) : null;
      if (binding.prevCarriedBy) {
        const located = findTokenOnBoard(g, binding.prevCarriedBy);
        if (located) {
          setArtifactCarrier(g, artifact, located.token.id);
          if (artifact.carriedBy === located.token.id) {
            located.token.carrying.push(artifact.id);
            if (cell) cell.artifacts = cell.artifacts.filter(a => a.id !== artifact.id);
            refreshUnitArtifactPassives(g, located.token);
          } else if (cell && !cell.artifacts.some(a => a.id === artifact.id)) {
            cell.artifacts.push(artifact);
          }
        } else if (cell) {
          if (!cell.artifacts.some(a => a.id === artifact.id)) cell.artifacts.push(artifact);
        }
      } else if (cell) {
        if (!cell.artifacts.some(a => a.id === artifact.id)) cell.artifacts.push(artifact);
      }
      handleArtifactRegionChange(g, artifact);
      if (!binding.prevCarriedBy) syncCarryableArtifactController(g, artifact);
    }
    delete (artifact as any)._grosseBinding;
  }

  const poltergeistEntry = findTokenOnBoard(g, binding.poltergeistId);
  if (poltergeistEntry) {
    const list: GrosseBinding[] = (poltergeistEntry.token as any)._grosseBindings ?? [];
    (poltergeistEntry.token as any)._grosseBindings = list.filter(entry => entry.artifactId !== binding.artifactId);
  }

  const summary = artifact ? artifact.name : 'an artifact';
  g.log.unshift(`Grösse Poltergeist releases control of ${summary} as ${reason}.`);
}

function findCarriedMinionById(g: Game, unitId: string): { token: Token; carrier: Token } | null {
  for (const cell of g.board.flat()) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      const carrier = unit as Token;
      const carried = (carrier as any)._carriedMinions as Token[] | undefined;
      if (!Array.isArray(carried) || carried.length === 0) continue;
      const found = carried.find((entry) => entry.id === unitId);
      if (found) return { token: found, carrier };
    }
  }
  return null;
}

function unitCanCarryMinions(unit: Unit | null | undefined): unit is Token {
  if (!unit || unit.kind === 'Avatar') return false;
  const name = unit.name ?? '';
  return (
    /^Haast Eagle$/i.test(name) ||
    /^Fine Courser$/i.test(name) ||
    /^Bodach Bogeyman$/i.test(name) ||
    /^Hyperparasite$/i.test(name) ||
    /^Phantom Steed$/i.test(name) ||
    /^Zephyranne Airship$/i.test(name) ||
    /^Beast of Burden$/i.test(name) ||
    /^Stagecoach$/i.test(name) ||
    /^War Horse$/i.test(name) ||
    (unit as any)._stagecoachCarrier === true
  );
}

function carryMinionWithoutLog(g: Game, carrier: Token, passenger: Token): void {
  const cell = inside(g, passenger.x, passenger.y) ? cellOf(g, passenger.x, passenger.y) : null;
  if (cell) cell.units = cell.units.filter((unit) => unit.id !== passenger.id);
  if (multiTileLocations(passenger)) clearMultiTileOccupancy(g, passenger);
  passenger.carriedBy = carrier.id;
  passenger.x = carrier.x;
  passenger.y = carrier.y;
  (passenger as any).region = ((carrier as any).region ?? 'surface') as Region;
  passenger.tapped = true;
  passenger.summonedThisTurn = true;
  const carried = haastCarriedMinions(carrier);
  if (!carried.some((entry) => entry.id === passenger.id)) carried.push(passenger);
}

type ReleaseInfusionOptions = { skipTokenRemoval?: boolean };

function releaseInfusionBinding(
  g: Game,
  binding: InfusionBinding,
  reason: string,
  opts: ReleaseInfusionOptions = {},
): void {
  const { skipTokenRemoval } = opts;
  const artifact = g.artifacts.find(a => a.id === binding.artifactId);
  const tokenEntry = findTokenOnBoard(g, binding.tokenId);
  const carriedTokenEntry = tokenEntry ? null : findCarriedMinionById(g, binding.tokenId);
  const infusionToken = (tokenEntry?.token as Token | undefined) ?? carriedTokenEntry?.token ?? null;
  const tokenAnchor = carriedTokenEntry?.carrier ?? infusionToken;
  const tokenWasTapped = !!(infusionToken as any)?.tapped;
  const tokenLoc = tokenAnchor
    ? {
        x: (tokenAnchor as any).x as number | undefined,
        y: (tokenAnchor as any).y as number | undefined,
        region: (((tokenAnchor as any).region ?? 'surface') as Region),
      }
    : null;

  if (artifact) {
    const fallbackPos = getArtifactCurrentPosition(g, artifact);
    let x = fallbackPos.x;
    let y = fallbackPos.y;
    let region = fallbackPos.region;
    if (tokenLoc && Number.isFinite(tokenLoc.x) && Number.isFinite(tokenLoc.y)) {
      x = tokenLoc.x as number;
      y = tokenLoc.y as number;
      region = tokenLoc.region;
    }
    artifact.carriedBy = null;
    artifact.x = x;
    artifact.y = y;
    artifact.region = region;
    if (Number.isFinite(x) && Number.isFinite(y)) {
      const cell = cellOf(g, x, y);
      if (!cell.artifacts.some(a => a.id === artifact.id)) cell.artifacts.push(artifact);
    }
    handleArtifactRegionChange(g, artifact);
    syncCarryableArtifactController(g, artifact);
    if (tokenWasTapped) (artifact as any).tapped = true;
    delete (artifact as any)._infusionBinding;
    delete (artifact as any)._infusionFactoryCarry;
  }

  if (tokenEntry) {
    delete (tokenEntry.token as any)._infusionBinding;
    if (!skipTokenRemoval) removeUnitById(g, binding.tokenId);
  } else if (carriedTokenEntry) {
    delete (carriedTokenEntry.token as any)._infusionBinding;
    delete carriedTokenEntry.token.carriedBy;
    const carried = haastCarriedMinions(carriedTokenEntry.carrier);
    (carriedTokenEntry.carrier as any)._carriedMinions = carried.filter((entry) => entry.id !== binding.tokenId);
  }

  const summary = artifact ? artifact.name : 'an artifact';
  g.log.unshift(`Infusion Factory releases ${summary} as ${reason}.`);
}

type ReleaseHemogolemOptions = { skipTokenRemoval?: boolean };

function releaseHemogolemBinding(
  g: Game,
  binding: HemogolemBinding,
  reason: string,
  opts: ReleaseHemogolemOptions = {},
): void {
  const { skipTokenRemoval } = opts;
  const artifact = g.artifacts.find(a => a.id === binding.artifactId);
  const tokenEntry = findTokenOnBoard(g, binding.tokenId);

  if (artifact) {
    delete (artifact as any)._hemogolemBinding;
  }
  if (tokenEntry) {
    delete (tokenEntry.token as any)._hemogolemBinding;
    if (!skipTokenRemoval) removeUnitById(g, binding.tokenId);
  }

  const summary = artifact ? artifact.name : 'Hemogolem';
  g.log.unshift(`Hemogolem collapses as ${reason}.`);
}

function createInfusionAutomaton(
  g: Game,
  art: Artifact,
  owner: PlayerId,
  x: number,
  y: number,
  region: Region,
): Token | null {
  const currentTurnRaw = Number(g.turnNumber ?? 0);
  const currentTurn = Number.isFinite(currentTurnRaw) ? Math.max(0, Math.floor(currentTurnRaw)) : 0;
  const enteredTurnRaw = Number((art as any)._enteredTurn);
  const enteredTurn = Number.isFinite(enteredTurnRaw) ? Math.max(0, Math.floor(enteredTurnRaw)) : null;
  const applySummoningSickness = enteredTurn != null && currentTurn > 0 && enteredTurn >= currentTurn;

  const stub: Extract<Card, { kind: 'Unit' }> = {
    id: uid(),
    kind: 'Unit',
    name: `${art.name ?? 'Artifact'} Automaton`,
    element: 'Earth',
    cost: 0,
    threshold: {},
    power: 2,
    atk: 2,
    def: 2,
    subTypes: ['Automaton'],
    text: 'Animated by Infusion Factory.',
    image: art.image,
  } as any;
  if (/^Poisonous Dagger$/i.test(art.name ?? '')) {
    (stub as any).lethal = true;
  }
  if (/^Peacemaker Arbalest$/i.test(art.name ?? '')) {
    (stub as any).ranged = 1;
  }
  const token = summonUnitCardAt(g, owner, stub, x, y, region, { bypassPlacement: true });
  if (!token) return null;
  const binding: InfusionBinding = { artifactId: art.id, tokenId: token.id };
  (token as any)._infusionBinding = binding;
  (art as any)._infusionBinding = binding;
  // Codex: units without carry capability must immediately drop carried objects.
  // Infusion automatons therefore do not self-carry their source artifact.
  (art as any)._infusionFactoryCarry = false;
  if (Array.isArray(token.carrying) && token.carrying.includes(art.id)) {
    token.carrying = token.carrying.filter(id => id !== art.id);
  }
  setArtifactCarrier(g, art, null);
  art.x = x;
  art.y = y;
  art.region = region;
  const cell = cellOf(g, x, y);
  cell.artifacts = cell.artifacts.filter(a => a.id !== art.id);
  handleArtifactRegionChange(g, art);
  refreshUnitArtifactPassives(g, token);
  token.tapped = !!(art as any).tapped;
  token.summonedThisTurn = applySummoningSickness && !token.charge;
  if (!token.tapped) (art as any).tapped = false;
  g.log.unshift(`${art.name ?? 'An artifact'} animates into an Automaton (Infusion Factory).`);
  return token;
}

function syncInfusionFactoryAutomata(g: Game): boolean {
  const factories: Array<{ x: number; y: number }> = [];
  forEachSite(g, (site, x, y) => {
    if (!/^Infusion Factory$/i.test(site.name ?? '')) return;
    if (siteAbilitiesSuppressedAt(g, x, y, site)) return;
    factories.push({ x, y });
  });
  if (factories.length === 0) {
    let released = false;
    for (const art of g.artifacts) {
      const binding = (art as any)._infusionBinding as InfusionBinding | undefined;
      if (binding) {
        releaseInfusionBinding(g, binding, 'the factory falls silent');
        released = true;
      }
    }
    return released;
  }
  const factoryReach = new Set<string>();
  for (const factory of factories) {
    for (const [nx, ny] of adjacentCoords(g, factory.x, factory.y)) {
      factoryReach.add(`${nx},${ny}`);
    }
  }
  const isAdjacentFactory = (x: number, y: number): boolean => factoryReach.has(`${x},${y}`);

  let changed = false;
  for (const art of g.artifacts) {
    const binding = (art as any)._infusionBinding as InfusionBinding | undefined;
    if ((art as any)._grosseBinding) {
      if (binding) {
        releaseInfusionBinding(g, binding, 'the artifact is already animated');
        changed = true;
      }
      continue;
    }
    if ((art as any)._hemogolemBinding) continue;
    const { x, y, region } = getArtifactCurrentPosition(g, art);
    const adjacent = region === 'surface' && Number.isFinite(x) && Number.isFinite(y) && isAdjacentFactory(x, y);
    if (art.carriedBy) {
      const carriedByOwnInfusionToken = !!binding && art.carriedBy === binding.tokenId;
      if (carriedByOwnInfusionToken) {
        // Codex compliance: automatons that cannot carry must immediately drop.
        const carrier = findTokenOnBoard(g, binding!.tokenId)?.token;
        if (carrier && Array.isArray(carrier.carrying)) {
          carrier.carrying = carrier.carrying.filter(id => id !== art.id);
        }
        setArtifactCarrier(g, art, null);
        changed = true;
      } else if (binding) {
        releaseInfusionBinding(g, binding, 'it is being carried');
        changed = true;
        continue;
      } else if (adjacent) {
        const owner = artifactOwnerPid(art) ?? art.player;
        if (owner == null) continue;
        const carrier = findUnitById(g, art.carriedBy);
        if (carrier && Array.isArray((carrier as any).carrying)) {
          (carrier as any).carrying = (carrier as any).carrying.filter((id: string) => id !== art.id);
        }
        setArtifactCarrier(g, art, null);
        art.x = x;
        art.y = y;
        art.region = region;
        if (carrier) refreshUnitArtifactPassives(g, carrier);
        const token = createInfusionAutomaton(g, art, owner, x, y, region);
        if (token && carrier && unitCanCarryMinions(carrier)) {
          carryMinionWithoutLog(g, carrier, token);
        }
        changed = true;
        continue;
      }
      if (!carriedByOwnInfusionToken) {
        continue;
      }
    }
    if (!adjacent) {
      if (binding) {
        releaseInfusionBinding(g, binding, 'it is no longer adjacent');
        changed = true;
      }
      continue;
    }
    if (binding) {
      const tokenEntry = findTokenOnBoard(g, binding.tokenId) ?? findCarriedMinionById(g, binding.tokenId);
      if (!tokenEntry) {
        releaseInfusionBinding(g, binding, 'its automaton has vanished');
        const owner = artifactOwnerPid(art) ?? art.player;
        if (owner != null) {
          createInfusionAutomaton(g, art, owner, x, y, region);
          changed = true;
        }
      }
      continue;
    }
    const owner = artifactOwnerPid(art) ?? art.player;
    if (owner == null) continue;
    if (createInfusionAutomaton(g, art, owner, x, y, region)) changed = true;
  }
  return changed;
}

function createHemogolemAutomaton(
  g: Game,
  art: Artifact,
  owner: PlayerId,
  x: number,
  y: number,
  region: Region,
): Token | null {
  const power = Math.max(1, Math.floor(art.cost ?? 4));
  const stub: Extract<Card, { kind: 'Unit' }> = {
    id: uid(),
    kind: 'Unit',
    name: 'Hemogolem',
    element: 'Earth',
    cost: 0,
    threshold: {},
    power,
    atk: power,
    def: power,
    subTypes: ['Automaton'],
    text: 'Animated by Hemogolem.',
    image: art.image,
  } as any;
  const token = summonUnitCardAt(g, owner, stub, x, y, region, { bypassPlacement: true });
  if (!token) return null;
  const binding: HemogolemBinding = { artifactId: art.id, tokenId: token.id };
  (token as any)._hemogolemBinding = binding;
  (art as any)._hemogolemBinding = binding;
  g.log.unshift('Hemogolem lurches into motion.');
  return token;
}

function syncHemogolemAutomata(g: Game): boolean {
  let changed = false;
  const liveArtifacts = new Set<string>();
  for (const art of g.artifacts) {
    if (!/^Hemogolem$/i.test(art.name ?? '')) continue;
    liveArtifacts.add(art.id);
    const binding = (art as any)._hemogolemBinding as HemogolemBinding | undefined;
    if (art.carriedBy) {
      if (binding) {
        releaseHemogolemBinding(g, binding, 'it is being carried');
        changed = true;
      }
      continue;
    }
    const { x, y, region } = getArtifactCurrentPosition(g, art);
    if (!inside(g, x, y)) {
      if (binding) {
        releaseHemogolemBinding(g, binding, 'it slips beyond the realm');
        changed = true;
      }
      continue;
    }
    const owner = artifactOwnerPid(art) ?? art.player;
    if (owner == null) continue;
    if (binding) {
      const tokenEntry = findTokenOnBoard(g, binding.tokenId);
      const token = tokenEntry?.token as Token | undefined;
      if (!token || token.x !== x || token.y !== y || ((token as any).region ?? 'surface') !== region) {
        releaseHemogolemBinding(g, binding, 'it must reform');
        if (createHemogolemAutomaton(g, art, owner, x, y, region)) changed = true;
      }
      continue;
    }
    if (createHemogolemAutomaton(g, art, owner, x, y, region)) changed = true;
  }
  for (const cell of g.board.flat()) {
    for (const unit of cell.units) {
      if (unit.kind === 'Avatar') continue;
      const binding = (unit as any)._hemogolemBinding as HemogolemBinding | undefined;
      if (!binding) continue;
      if (!liveArtifacts.has(binding.artifactId)) {
        releaseHemogolemBinding(g, binding, 'its core is gone', { skipTokenRemoval: true });
        removeUnitById(g, binding.tokenId);
        changed = true;
      }
    }
  }
  return changed;
}

function mismanagedMortuaryActive(g: Game): boolean {
  let active = false;
  forEachSite(g, (site, x, y) => {
    if (active) return;
    if (!/^Mismanaged Mortuary$/i.test(site.name ?? '')) return;
    if (site.rubble) return;
    if (siteAbilitiesSuppressedAt(g, x, y, site)) return;
    active = true;
  });
  return active;
}

function syncMismanagedMortuaryCemetery(g: Game): boolean {
  const active = mismanagedMortuaryActive(g);
  const swap = (g as any)._mismanagedMortuarySwap as { p1: Card[]; p2: Card[] } | undefined;
  g.cemetery[1] ??= [];
  g.cemetery[2] ??= [];
  if (active) {
    if (swap) return false;
    (g as any)._mismanagedMortuarySwap = { p1: g.cemetery[1], p2: g.cemetery[2] };
    g.cemetery = { 1: (g as any)._mismanagedMortuarySwap.p2, 2: (g as any)._mismanagedMortuarySwap.p1 };
    g.log.unshift('Mismanaged Mortuary swaps the cemeteries.');
    return true;
  }
  if (!active && swap) {
    g.cemetery = { 1: swap.p1, 2: swap.p2 };
    delete (g as any)._mismanagedMortuarySwap;
    g.log.unshift('Mismanaged Mortuary releases the cemeteries.');
    return true;
  }
  return false;
}

const ROYAL_NAME_REGEX = /(King|Queen|Prince|Princess)/i;

function isRoyalUnit(u: Unit): boolean {
  if (u.kind === 'Avatar') return true;
  return ROYAL_NAME_REGEX.test(u.name);
}

function findRoyalBodyguard(g: Game, pid: PlayerId, x: number, y: number, region: Region): Unit | null {
  const guards = g.board.flat().flatMap(c => c.units)
    .filter(u => u.name === 'Royal Bodyguard' && u.player === pid && u.kind !== 'Avatar' && ((u as any).region ?? 'surface') === region);
  for (const guard of guards) {
    const gx = (guard as any).x ?? 0;
    const gy = (guard as any).y ?? 0;
    if (Math.max(Math.abs(gx - x), Math.abs(gy - y)) <= 1) {
      return guard;
    }
  }
  return null;
}

function playerHasArtifact(g: Game, pid: PlayerId, name: string): boolean {
  return g.artifacts.some(a => {
    if (a.name !== name) return false;
    if (artifactIsCarryable(a)) {
      if (!a.carriedBy) return false;
      const located = findTokenOnBoard(g, a.carriedBy);
      return located?.token.player === pid;
    }
    return artifactOwnerPid(a) === pid;
  });
}

function countArtifactsByName(g: Game, pid: PlayerId, name: string): number {
  let total = 0;
  for (const art of g.artifacts) {
    if (art.name !== name) continue;
    if (artifactIsSilenced(g, art)) continue;
    if (artifactIsCarryable(art)) {
      if (!art.carriedBy) continue;
      const located = findTokenOnBoard(g, art.carriedBy);
      if (located && located.token.player === pid) total += 1;
      continue;
    }
    if (artifactOwnerPid(art) === pid) total += 1;
  }
  return total;
}

function unitHasLethal(g: Game, u: Unit): boolean {
  if ((u as any)._tempLethal) return true;
  return !!((u as any).lethal) || unitCarriesArtifact(g, u, 'Poisonous Dagger') !== null
}

function priamusProtectsFromLethal(g: Game, target: Unit): boolean {
  if (target.kind === 'Avatar') return false;
  const pid = (target as any).player as PlayerId | undefined;
  if (pid == null) return false;
  const tx = (target as any).x as number | undefined;
  const ty = (target as any).y as number | undefined;
  const region = ((target as any).region ?? 'surface') as Region;
  if (typeof tx !== 'number' || typeof ty !== 'number') return false;
  for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
    const nx = tx + dx;
    const ny = ty + dy;
    if (!inside(g, nx, ny)) continue;
    const units = unitArrayAtRegion(g, nx, ny, region);
    for (const u of units) {
      if (u.kind === 'Avatar') continue;
      if (u.player !== pid) continue;
      if (!/^Sir Priamus$/i.test(u.name ?? '')) continue;
      if (unitIsSilenced(g, u)) continue;
      return true;
    }
  }
  return false;
}

function unitHasLethalAgainst(g: Game, source: Unit, target: Unit): boolean {
  const heroLethal =
    /^Intrepid Hero$/i.test(source.name ?? '') &&
    !unitIsSilenced(g, source) &&
    unitHasSubtype(g, target, 'Evil');
  if (!heroLethal && !unitHasLethal(g, source)) return false;
  if (priamusProtectsFromLethal(g, target)) return false;
  return true;
}

function faerieQueenePreventsDamage(g: Game, target: Unit, opts?: DamageOpts): boolean {
  if (!opts?.sourceUnit) return false;
  if (target.kind === 'Avatar') return false;
  if (!unitHasSubtype(g, target, 'Faerie')) return false;
  const pid = (target as any).player as PlayerId | undefined;
  if (pid == null) return false;
  const tx = (target as any).x as number | undefined;
  const ty = (target as any).y as number | undefined;
  const region = ((target as any).region ?? 'surface') as Region;
  if (typeof tx !== 'number' || typeof ty !== 'number') return false;
  const power = strikeDamagePlus(g, opts.sourceUnit);
  if (power < 4) return false;
  for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
    const nx = tx + dx;
    const ny = ty + dy;
    if (!inside(g, nx, ny)) continue;
    const units = unitArrayAtRegion(g, nx, ny, region);
    for (const u of units) {
      if (u.kind === 'Avatar') continue;
      if (u.player !== pid) continue;
      if (!/^The Faerie Queene$/i.test(u.name ?? '')) continue;
      if (unitIsSilenced(g, u)) continue;
      g.log.unshift(`The Faerie Queene shields ${target.name} — no damage from high-power units.`);
      return true;
    }
  }
  return false;
}

function sirYvainAdjacentBonus(g: Game, u: Unit): number {
  const id = (u as any).id as string | undefined;
  const pid = (u as any).player as PlayerId | undefined;
  if (!id || pid == null) return 0;
  const ux = (u as any).x as number | undefined;
  const uy = (u as any).y as number | undefined;
  const region = ((u as any).region ?? 'surface') as Region;
  if (!Number.isFinite(ux) || !Number.isFinite(uy)) return 0;

  const partnerId =
    /^Sir Yvain$/i.test(u.name ?? '')
      ? (u as any)._yvainCompanionId as string | undefined
      : (u as any)._yvainPartnerId as string | undefined;
  if (!partnerId) return 0;
  const partnerEntry = findTokenOnBoard(g, partnerId);
  if (!partnerEntry) return 0;
  const partner = partnerEntry.token;
  if (partner.player !== pid) return 0;
  const px = (partner as any).x as number | undefined;
  const py = (partner as any).y as number | undefined;
  const pregion = ((partner as any).region ?? 'surface') as Region;
  if (pregion !== region) return 0;
  if (!Number.isFinite(px) || !Number.isFinite(py)) return 0;
  if (cheb(ux!, uy!, px!, py!) > 1) return 0;
  return 2;
}

function fallenAngelAdjacentBonus(g: Game, u: Unit): number {
  if (!unitHasSubtype(g, u, 'Demon')) return 0;
  const pid = (u as any).player as PlayerId | undefined;
  const ux = (u as any).x as number | undefined;
  const uy = (u as any).y as number | undefined;
  const region = ((u as any).region ?? 'surface') as Region;
  if (pid == null || !Number.isFinite(ux) || !Number.isFinite(uy)) return 0;
  const coords: Array<[number, number]> = nearbyCoords8(g, ux!, uy!);
  const seen = new Set<string>();
  let bonus = 0;
  for (const [nx, ny] of coords) {
    const units = unitArrayAtRegion(g, nx, ny, region);
    for (const unit of units) {
      if (unit.kind === 'Avatar') continue;
      if (unit.player !== pid) continue;
      if (!/^Fallen Angel$/i.test(unit.name ?? '')) continue;
      if (unitIsSilenced(g, unit)) continue;
      const id = (unit as any).id as string | undefined;
      if (!id || seen.has(id)) continue;
      seen.add(id);
      bonus += 1;
    }
  }
  return bonus;
}

function reveredRevenantHasAdjacentWard(g: Game, token: Token): boolean {
  const pid = token.player as PlayerId | undefined;
  const ux = token.x as number | undefined;
  const uy = token.y as number | undefined;
  const region = ((token as any).region ?? 'surface') as Region;
  if (pid == null || !Number.isFinite(ux) || !Number.isFinite(uy)) return false;
  const coords: Array<[number, number]> = nearbyCoords8(g, ux!, uy!);
  for (const [nx, ny] of coords) {
    if (region === 'surface') {
      const site = cellOf(g, nx, ny).site;
      if (site && !site.rubble && site.controller === pid && isWardedEffective(g, site)) return true;
    }
    const units = unitArrayAtRegion(g, nx, ny, region);
    for (const unit of units) {
      if (unit.player !== pid) continue;
      if ((unit as any).id === token.id) continue;
      if (isWardedEffective(g, unit)) return true;
    }
  }
  return false;
}

function shooterIgnoresStealth(g: Game, u: Unit): boolean {
  return unitCarriesArtifact(g, u, 'Truesight Crossbow') !== null
}

function drumsMakeDamageLethal(g: Game, u: Unit): boolean {
  if (u.kind === 'Avatar') return false
  const ux = (u as any).x ?? 0
  const uy = (u as any).y ?? 0
  const ur = (u as any).region ?? 'surface'
  return g.artifacts.some(art =>
    art.name === 'Drums of Doom' &&
    Math.max(Math.abs((art.x ?? 0) - ux), Math.abs((art.y ?? 0) - uy)) <= 1 &&
    art.region === ur
  )
}

function isWithinMazeZone(mino: Unit, x: number, y: number, region: Region): boolean {
  const mx = (mino as any).x ?? 0;
  const my = (mino as any).y ?? 0;
  const mr = (mino as any).region ?? 'surface';
  if (mr !== region) return false;
  return Math.abs(mx - x) <= 1 && Math.abs(my - y) <= 1;
}

function mazeBlocksMove(mino: Unit, fromX: number, fromY: number, fromRegion: Region, toX: number, toY: number, toRegion: Region): boolean {
  if (!isWithinMazeZone(mino, fromX, fromY, fromRegion)) return false;
  return !isWithinMazeZone(mino, toX, toY, toRegion);
}

function usePnakoticManuscript(g: Game, pid: PlayerId, unitId: string) {
  const u = g.board.flat().flatMap(c => c.units).find(v => v.id === unitId)
  if (!u) return

  if (!(g.turn === pid && g.phase === 'Main')) { g.log.unshift('Pnakotic Manuscript: not your main phase.'); return }
  if (!canTapToPay(g, u)) { g.log.unshift('Pnakotic Manuscript: bearer cannot tap now.'); return }

  const orb = unitCarriesArtifact(g, u, 'Pnakotic Manuscript')
  if (!orb) { g.log.unshift('Pnakotic Manuscript: this unit is not the bearer.'); return }

  const top = g.decks[pid].spellbook[0]
  if (!top) { g.log.unshift('Pnakotic Manuscript: no spell on top to reveal.'); return }

  u.tapped = true
  if (u.kind !== 'Avatar') (u as Token).interactedThisTurn = true

  const cost = Math.max(0, (top as any).cost ?? 0)
  g.log.unshift(`Pnakotic Manuscript reveals ${top.name} (cost ${cost}) and draws it.`)

  g.handSpells[pid].push(g.decks[pid].spellbook.shift()!)

  damageUnit(g, u, cost, { isDamage: true, sourceUnit: u })
}

async function pudgeButcherHook(g: Game, pudge: Token, dir: 'N' | 'S' | 'E' | 'W'): Promise<void> {
  const region = (pudge as any).region ?? 'surface';
  let x = pudge.x;
  let y = pudge.y;
  const delta = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];
  const anchorX = pudge.x;
  const anchorY = pudge.y;
  const anchorCell = cellOf(g, anchorX, anchorY);

  while (inside(g, x + delta[0], y + delta[1])) {
    x += delta[0];
    y += delta[1];

    const occupants = unitArrayAtRegion(g, x, y, region)
      .filter(u => !(u as any).stealth);
    if (occupants.length === 0) continue;

    let target = occupants[0];
    if (occupants.length > 1) {
      const sel = await uiSelectOne<number>({
        title: 'Pudge Butcher — Hook Target',
        message: formatTileText(g, `Choose a unit to snag (${dir}).`),
        options: occupants.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1},${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (sel == null) {
        g.log.unshift('Pudge Butcher lowers his hook.');
        requestGameSync?.();
        return;
      }
      target = occupants[sel];
    }

    if ((target as any).size2x2) {
      g.log.unshift(`Pudge Butcher's hook can't haul the massive ${target.name}.`);
      requestGameSync?.();
      return;
    }

    if (!regionAllowedForUnit(g, target, region, anchorCell, anchorX, anchorY)) {
      g.log.unshift(`Pudge Butcher snags ${target.name}, but it cannot occupy (${anchorX + 1}, ${anchorY + 1}).`);
      emitProjectileFx(g, {
        fromX: anchorX,
        fromY: anchorY,
        toX: x,
        toY: y,
        style: 'hook',
        returnToSource: true,
        hit: true,
        pid: pudge.player as PlayerId,
        cardName: 'Pudge Butcher',
        source: 'effect',
      });
      requestGameSync?.();
      return;
    }

    emitProjectileFx(g, {
      fromX: anchorX,
      fromY: anchorY,
      toX: x,
      toY: y,
      style: 'hook',
      returnToSource: true,
      hit: true,
      pid: pudge.player as PlayerId,
      cardName: 'Pudge Butcher',
      source: 'effect',
    });
    moveUnitTo(g, target, anchorX, anchorY, region);
    g.log.unshift(`Pudge Butcher hooks ${target.name} to (${anchorX + 1}, ${anchorY + 1}).`);
    requestGameSync?.();

    const wantFight = await uiConfirm({
      title: 'Pudge Butcher',
      message: formatTileText(g, `Fight ${target.name}?`),
      confirmLabel: 'Fight',
      cancelLabel: 'Spare',
    });
    if (wantFight) {
      const post = await maybeHandleWitherwingRescues(g, pudge, [target], cellOf(g, anchorX, anchorY));
      if (post.length > 0) fight(g, pudge, post, true);
      else g.log.unshift('Witherwing Heroes rescue the hooked target.');
      requestGameSync?.();
    } else {
      g.log.unshift(`Pudge Butcher drags ${target.name} close but does not attack.`);
    }
    return;
  }

  emitProjectileFx(g, {
    fromX: anchorX,
    fromY: anchorY,
    toX: x,
    toY: y,
    style: 'hook',
    returnToSource: true,
    hit: false,
    pid: pudge.player as PlayerId,
    cardName: 'Pudge Butcher',
    source: 'effect',
  });
  g.log.unshift(`Pudge Butcher hurls his hook ${dir} but catches nothing.`);
  requestGameSync?.();
}

async function meatHookPull(g: Game, bearer: Token, dir: 'N' | 'S' | 'E' | 'W'): Promise<void> {
  const pid = bearer.player as PlayerId;
  const region = (bearer as any).region ?? 'surface';
  let x = bearer.x;
  let y = bearer.y;
  const delta = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];
  const anchorX = bearer.x;
  const anchorY = bearer.y;
  const anchorCell = cellOf(g, anchorX, anchorY);

  while (inside(g, x + delta[0], y + delta[1])) {
    const nx = x + delta[0];
    const ny = y + delta[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid, bearer)) {
      emitProjectileFx(g, {
        fromX: anchorX,
        fromY: anchorY,
        toX: nx,
        toY: ny,
        style: 'hook',
        returnToSource: true,
        hit: false,
        pid,
        cardName: 'Meat Hook',
        source: 'effect',
      });
      return;
    }
    x = nx;
    y = ny;

    const occupants = unitArrayAtRegion(g, x, y, region)
      .filter(u => !(u as any).stealth)
      .filter(u => !projectileSkipsUnit(g, u));
    if (occupants.length === 0) continue;

    let target = occupants[0];
    if (occupants.length > 1) {
      const sel = await uiSelectOne<number>({
        title: 'Meat Hook — Target',
        message: formatTileText(g, `Choose a unit to hook (${dir}).`),
        options: occupants.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1},${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Cancel',
      });
      if (sel == null) {
        g.log.unshift('Meat Hook is reeled back without a catch.');
        requestGameSync?.();
        return;
      }
      target = occupants[sel];
    }

    if ((target as any).size2x2) {
      g.log.unshift(`Meat Hook cannot haul the massive ${target.name}.`);
      requestGameSync?.();
      return;
    }

    if (!regionAllowedForUnit(g, target, region, anchorCell, anchorX, anchorY)) {
      g.log.unshift(`Meat Hook snags ${target.name}, but it cannot occupy (${anchorX + 1}, ${anchorY + 1}).`);
      emitProjectileFx(g, {
        fromX: anchorX,
        fromY: anchorY,
        toX: x,
        toY: y,
        style: 'hook',
        returnToSource: true,
        hit: true,
        pid,
        cardName: 'Meat Hook',
        source: 'effect',
      });
      requestGameSync?.();
      return;
    }

    emitProjectileFx(g, {
      fromX: anchorX,
      fromY: anchorY,
      toX: x,
      toY: y,
      style: 'hook',
      returnToSource: true,
      hit: true,
      pid,
      cardName: 'Meat Hook',
      source: 'effect',
    });
    moveUnitTo(g, target, anchorX, anchorY, region, { sourcePlayer: pid, bypassAnchor: true, ignoreGnome: true });
    g.log.unshift(`Meat Hook drags ${target.name} to (${anchorX + 1}, ${anchorY + 1}).`);
    requestGameSync?.();

    if (target.player !== pid) {
      const wantFight = isCpuPlayer(g, pid)
        ? true
        : await uiConfirm({
            title: 'Meat Hook',
            message: formatTileText(g, `Fight ${target.name}?`),
            confirmLabel: 'Fight',
            cancelLabel: 'Spare',
          });
      if (wantFight) {
        const post = await maybeHandleWitherwingRescues(g, bearer, [target], cellOf(g, anchorX, anchorY));
        if (post.length > 0) fight(g, bearer, post, true);
        else g.log.unshift('Witherwing Heroes rescue the hooked target.');
      } else {
        g.log.unshift(`Meat Hook reels in ${target.name} but no fight follows.`);
      }
      requestGameSync?.();
    }
    return;
  }

  emitProjectileFx(g, {
    fromX: anchorX,
    fromY: anchorY,
    toX: x,
    toY: y,
    style: 'hook',
    returnToSource: true,
    hit: false,
    pid,
    cardName: 'Meat Hook',
    source: 'effect',
  });
  g.log.unshift(`Meat Hook flies ${dir} but catches nothing.`);
  requestGameSync?.();
}

type ProjectileLoc = { x: number; y: number; region: Region };

function projectileBlockedBySite(
  g: Game,
  from: ProjectileLoc,
  to: ProjectileLoc,
  sourcePid?: PlayerId,
  sourceUnit?: Unit
): boolean {
  if (!inside(g, to.x, to.y)) return false;
  const unitsAtTarget = unitArrayAtRegion(g, to.x, to.y, to.region);
  if (unitsAtTarget.length > 0) {
    const blocker = unitsAtTarget.find(u => /^Sir Morien$/i.test(u.name ?? '') && !unitIsSilenced(g, u));
    if (blocker) {
      const owner = (blocker as any).player as PlayerId | undefined;
      const shooterPid = sourcePid ?? ((sourceUnit as any)?.player as PlayerId | undefined);
      if (owner != null && shooterPid != null && owner !== shooterPid) {
        g.log.unshift(`Sir Morien wards this tile — enemy projectile cannot enter (${to.x + 1}, ${to.y + 1}).`);
        return true;
      }
    }
  }
  if (to.region !== 'surface') return false;
  const nextSite = cellOf(g, to.x, to.y).site;
  if (!nextSite || nextSite.rubble || !/^Impenetrable Copse$/i.test(nextSite.name ?? '')) return false;
  let fromSite: Site | null = null;
  if (inside(g, from.x, from.y)) fromSite = cellOf(g, from.x, from.y).site;
  if (fromSite && fromSite === nextSite) return false;
  g.log.unshift(`Impenetrable Copse deflects the projectile at (${to.x + 1}, ${to.y + 1}).`);
  return true;
}

const projectileSkipsUnit = (g: Game, u: Unit): boolean => {
  if (/^Crawler$/i.test(u.name ?? '')) return true;
  if (u.kind === 'Avatar') {
    const pid = (u as any).player as PlayerId | undefined;
    const ux = (u as any).x as number | undefined;
    const uy = (u as any).y as number | undefined;
    const region = ((u as any).region ?? 'surface') as Region;
    if (pid == null || !Number.isFinite(ux) || !Number.isFinite(uy)) return false;
    const coords: Array<[number, number]> = nearbyCoords8(g, ux!, uy!);
    for (const [nx, ny] of coords) {
      const units = unitArrayAtRegion(g, nx, ny, region);
      for (const unit of units) {
        if (unit.kind === 'Avatar') continue;
        if (unit.player !== pid) continue;
        if (!/^Crawling Congregation$/i.test(unit.name ?? '')) continue;
        if (unitIsSilenced(g, unit)) continue;
        return true;
      }
    }
    return false;
  }
  const token = u as Token;
  if (/^Crawling Congregation$/i.test(token.name ?? '')) {
    return !unitIsSilenced(g, token);
  }
  const pid = token.player as PlayerId | undefined;
  const ux = token.x as number | undefined;
  const uy = token.y as number | undefined;
  const region = ((token as any).region ?? 'surface') as Region;
  if (pid == null || !Number.isFinite(ux) || !Number.isFinite(uy)) return false;
  const coords: Array<[number, number]> = nearbyCoords8(g, ux!, uy!);
  for (const [nx, ny] of coords) {
    const units = unitArrayAtRegion(g, nx, ny, region);
    for (const unit of units) {
      if (unit.kind === 'Avatar') continue;
      if (unit.player !== pid) continue;
      if (!/^Crawling Congregation$/i.test(unit.name ?? '')) continue;
      if (unitIsSilenced(g, unit)) continue;
      return true;
    }
  }
  return false;
};

async function shootCustomProjectile(
  g: Game,
  from: { x: number; y: number; region: Region },
  dir: 'N'|'S'|'E'|'W',
  amount: number,
  label = 'Projectile',
  opts?: DamageOpts & { projectileStyle?: ProjectileFxStyle }
) {
  const fromX = from.x;
  const fromY = from.y;
  let { x, y } = from;
  const region = from.region;
  const sourcePid = opts?.sourceUnit ? ((opts.sourceUnit as any).player as PlayerId | undefined) : undefined;
  const projectileStyle: ProjectileFxStyle = opts?.projectileStyle ?? 'arrow';
  const d = dir === 'N' ? [0,-1] : dir === 'S' ? [0,1] : dir === 'E' ? [1,0] : [-1,0];

  while (inside(g, x + d[0], y + d[1])) {
    const nx = x + d[0];
    const ny = y + d[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, opts?.sourceUnit ? (opts.sourceUnit as any).player : undefined, opts?.sourceUnit)) {
      emitProjectileFx(g, {
        fromX,
        fromY,
        toX: nx,
        toY: ny,
        style: projectileStyle,
        hit: false,
        pid: sourcePid,
        cardName: label,
        source: 'effect',
      });
      return;
    }
    x = nx; y = ny;

    const list = unitArrayAtRegion(g, x, y, region);
    const targetables = list
      .filter(u => !(u as any).stealth && !enemyTargetingBlocked(g, u, sourcePid))
      .filter(u => !projectileSkipsUnit(g, u));
    if (targetables.length === 0) continue;

    let target: Unit = targetables[0];
    if (targetables.length > 1) {
      const choice = await uiSelectOne<number>({
        title: label,
        message: formatTileText(g, `Choose a unit to hit (${dir}).`),
        options: targetables.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Default target',
      });
      if (choice != null && choice >= 0 && choice < targetables.length) {
        target = targetables[choice];
      }
    }

    g.log.unshift(`${label} hits ${target.name} for ${amount} at (${x + 1}, ${y + 1}).`);
    emitProjectileFx(g, {
      fromX,
      fromY,
      toX: x,
      toY: y,
      style: projectileStyle,
      hit: true,
      pid: sourcePid,
      cardName: label,
      source: 'effect',
    });
    const dmgOpts: DamageOpts = { ...(opts ?? {}), isRangedStrike: true };
    damageUnit(g, target, amount, dmgOpts);
    return;
  }

  g.log.unshift(`${label} flies off the edge and hits nothing.`);
  emitProjectileFx(g, {
    fromX,
    fromY,
    toX: Number.isFinite(x) ? x : fromX,
    toY: Number.isFinite(y) ? y : fromY,
    style: projectileStyle,
    hit: false,
    pid: sourcePid,
    cardName: label,
    source: 'effect',
  });
}
async function fireballProjectile(
  g: Game,
  pid: PlayerId,
  from: { x: number; y: number; region: Region },
  dir: 'N' | 'S' | 'E' | 'W'
) {
  const fromX = from.x;
  const fromY = from.y;
  let { x, y } = from;
  const region = from.region;
  const d = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];

  while (inside(g, x + d[0], y + d[1])) {
    const nx = x + d[0];
    const ny = y + d[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid)) {
      emitProjectileFx(g, {
        fromX,
        fromY,
        toX: nx,
        toY: ny,
        style: 'fire',
        hit: false,
        pid,
        cardName: 'Fireball',
        source: 'spell',
      });
      return;
    }
    x = nx; y = ny;

    const list = unitArrayAtRegion(g, x, y, region);

    const targetables = list.filter(u => !(u as any).stealth).filter(u => !projectileSkipsUnit(g, u));
    if (targetables.length === 0) continue;

    let target: Unit = targetables[0];
    if (targetables.length > 1) {
      const choice = await uiSelectOne<number>({
        title: 'Fireball',
        message: formatTileText(g, `Choose a unit to hit (${dir}).`),
        options: targetables.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Default target',
      });
      if (choice != null && choice >= 0 && choice < targetables.length) {
        target = targetables[choice];
      }
    }

    g.log.unshift(`Fireball explodes at (${x + 1}, ${y + 1}) and hits ${target.name} for 4.`);
    emitProjectileFx(g, {
      fromX,
      fromY,
      toX: x,
      toY: y,
      style: 'fire',
      hit: true,
      pid,
      cardName: 'Fireball',
      source: 'spell',
    });
    damageUnit(g, target, 4, { sourceElement: 'Fire' });

    const others = list.filter(u => u.id !== (target as any).id);
    for (const u of others) {
      damageUnit(g, u, 2, { sourceElement: 'Fire' });
    }
    if (others.length > 0) g.log.unshift(`Fireball splash deals 2 to ${others.length} other unit(s).`);
    return;
  }

  g.log.unshift('Fireball flies off the edge and hits nothing.');
  emitProjectileFx(g, {
    fromX,
    fromY,
    toX: Number.isFinite(x) ? x : fromX,
    toY: Number.isFinite(y) ? y : fromY,
    style: 'fire',
    hit: false,
    pid,
    cardName: 'Fireball',
    source: 'spell',
  });
}
function canReachCellThisAction(g: Game, u: Unit, x: number, y: number, region: Region): boolean {
  const reach = neighborsFor(u, g);
  return reach.some(s => s.x === x && s.y === y && s.region === region);
}

function canDefendAtBattleLocation(
  u: Unit,
  x: number,
  y: number,
  region: Region,
  opts?: { siteAttack?: boolean },
): boolean {
  if (!(u as any)._cannotDefend) return true;
  if (!opts?.siteAttack) return false;
  if (!/^Skeleton$/i.test(u.name ?? '')) return false;
  const ux = (u as any).x as number | undefined;
  const uy = (u as any).y as number | undefined;
  const ur = ((u as any).region ?? 'surface') as Region;
  return ux === x && uy === y && ur === region;
}

function listEligibleDefendersByMovement(g: Game, defenderPid: PlayerId, x: number, y: number, region: Region): Unit[] {
  const out: Unit[] = [];
  for (let yy = 0; yy < g.height; yy++) {
    for (let xx = 0; xx < g.width; xx++) {
      for (const u of g.board[yy][xx].units) {
        if (u.player !== defenderPid) continue;
        if ((u as any)._cannotDefend) continue;
        if (!canTapToPay(g, u)) continue;
        if (!canReachCellThisAction(g, u, x, y, region)) continue;
        out.push(u);
      }
    }
  }
  return out;
}

function resolveWaypointPortalSecondClick(g: Game, x: number, y: number) {
  const st = (g as any)._pendingWaypointPortal as { pid: PlayerId; a: { x:number; y:number } } | undefined;
  if (!st) return;
  const cell = cellOf(g, x, y);
  if (!cell.site) { g.log.unshift('Waypoint Portal: site B must be a site.'); return; }
  if (st.a.x === x && st.a.y === y) { g.log.unshift('Waypoint Portal: pick a different site for site B.'); return; }

  (g as any)._waypointPortals ??= [];
  (g as any)._waypointPortals.push({ a: st.a, b: { x, y }, expiresTurn: g.turn });
  delete (g as any)._pendingWaypointPortal;

  g.log.unshift(`Waypoint Portal links (${st.a.x + 1},${st.a.y + 1}) ↔ (${x + 1},${y + 1}) for this turn.`);
}
function _isAtopTower(g: Game, u: Unit): boolean {
  if (u.kind === 'Avatar') return false;
  const cell = cellOf(g, (u as any).x, (u as any).y);
  return !!(u as any).region && (u as any).region === 'surface' && !!cell.site && /tower/i.test(cell.site.name);
}
function isSpellcasterNow(g: Game, u: Unit): boolean {
  if (u.kind === 'Avatar') return true;
  const t = u as Token;
  const src = (t as any)._srcCard as (Extract<Card,{kind:'Unit'}>|undefined);
  const hasKeyword = !!(src?.text && /\bspellcaster\b/i.test(src.text));
  const lichOnTower = (t.name === 'Spire Lich') && _isAtopTower(g, u);
  if (hasKeyword || lichOnTower) return true;
  if ((t as any)._wiccanSpellcasterTurn === g.turnNumber) return true;
  if ((t as any)._oneShotSpellcasterTurn === g.turnNumber) return true;
  return false;
}
function _blinkIsNearby(a: { x: number; y: number }, b: { x: number; y: number }) {
  return Math.max(Math.abs(a.x - b.x), Math.abs(a.y - b.y)) <= 1 && !(a.x === b.x && a.y === b.y);
}

function _clIsNearby(from: {x:number;y:number}, to:{x:number;y:number}) {
  return Math.max(Math.abs(from.x - to.x), Math.abs(from.y - to.y)) <= 1;
}
async function resolveChainLightningClick(g: Game, x: number, y: number) {
  const st = (g as any)._chainLightning as
    | { pid: PlayerId; last: { x:number; y:number; region: Region }; seenIds: string[]; element?: string }
    | undefined;
  if (!st) return;
  const pid = st.pid;
  const region = st.last.region ?? g.viewRegion;

  if (!_clIsNearby(st.last, { x, y })) {
    delete (g as any)._chainLightning;
    g.log.unshift('Chain Lightning ends.');
    return;
  }
  const list = unitArrayAtRegion(g, x, y, region);
  const target = list.find(u => !st.seenIds.includes(u.id));
  if (!target) {
    delete (g as any)._chainLightning;
    g.log.unshift('Chain Lightning ends (no new unit here).');
    return;
  }

  const wants = await uiConfirm({
    title: 'Chain Lightning',
    message: formatTileText(g, `Spend (2) to chain to ${target.name}?`),
    confirmLabel: 'Chain',
    cancelLabel: 'End',
  });
  if (!wants) {
    delete (g as any)._chainLightning;
    g.log.unshift('Chain Lightning ends.');
    requestGameSync?.();
    return;
  }
  const hopCost = 2;
  if (g.mana[pid] < hopCost) {
    delete (g as any)._chainLightning;
    g.log.unshift('Chain Lightning ends (not enough mana).');
    return;
  }

  spendMana(g, pid, hopCost);
  damageUnit(g, target, 2, { isDamage: true, sourceElement: st.element ?? 'Air' });
  g.log.unshift(`Chain Lightning chains to ${target.name} for 2 (−${hopCost}).`);
  st.last = { x, y, region };
  st.seenIds.push(target.id);
  requestGameSync?.();
}

function finalizeChainLightning(g: Game, _pid: PlayerId) {
  delete (g as any)._chainLightning;
}

function resolveBlinkClick(g: Game, x: number, y: number) {
  const st = (g as any)._pendingBlink as { pid: PlayerId; unitId: string } | undefined;
  if (!st) return;
  const pid = st.pid;

  const unit = g.board.flat().flatMap(c => c.units).find(u => u.id === st.unitId);
  if (!unit) {
    delete (g as any)._pendingBlink;
    g.log.unshift('Blink ended: unit no longer present.');
    return;
  }

  const from = { x: (unit as any).x, y: (unit as any).y };
  if (!_blinkIsNearby(from, { x, y })) {
    g.log.unshift('Blink: choose a nearby destination (same tile or surrounding).');
    return;
  }
  if (!inside(g, x, y)) {
    g.log.unshift('Blink: destination outside the realm.');
    return;
  }

  const cell = cellOf(g, x, y);
  const r = (unit as any).region as Region;

  if (r === 'surface'     && !cell.site)                         { g.log.unshift('Blink: surface destination requires a site.'); return; }
  if (r === 'underground' && !(cell.site && !isSiteWater(g, cell.site, x, y))) { g.log.unshift('Blink: choose a land site underground.'); return; }
  if (r === 'underwater'  && !(cell.site &&  isSiteWater(g, cell.site, x, y))) { g.log.unshift('Blink: choose a water site underwater.'); return; }
  if (r === 'void'        &&  cell.site)                         { g.log.unshift('Blink: void destination must be in the void.'); return; }

  const prev = cellOf(g, from.x, from.y);
  prev.units = prev.units.filter(u => u.id !== unit.id);
  (unit as any).x = x; (unit as any).y = y;
  cell.units.push(unit);

  g.log.unshift(`Blink teleports ${unit.name} to (${x + 1}, ${y + 1}) ${r}.`);

  draw(g, pid, 'spells', 1);
  g.log.unshift('Blink — draw 1 spell.');

  delete (g as any)._pendingBlink;
}

function resolveWhirlingBladesClick(g: Game, x: number, y: number) {
  const st = (g as any)._pendingWhirling as
    | { pid: PlayerId; unitId: string; stepsLeft: number }
    | undefined;
  if (!st) return;

  const u = g.board.flat().flatMap(c => c.units).find(v => v.id === st.unitId);
  if (!u) {
    delete (g as any)._pendingWhirling;
    g.log.unshift('Whirling Blades ends: unit no longer present.');
    return;
  }

  const legal = neighborsFor(u, g);
  const next = legal.find(s => s.x === x && s.y === y);
  if (!next) {
    delete (g as any)._pendingWhirling;
    g.log.unshift('Whirling Blades ends.');
    return;
  }

  moveUnitTo(g, u, next.x, next.y, next.region);
  g.log.unshift(`${u.name} spins to (${next.x + 1}, ${next.y + 1}) ${next.region}.`);

  const hereEnemies = unitArrayAtRegion(g, next.x, next.y, next.region).filter(v => v.player !== (u as any).player);
  if (hereEnemies.length > 0) {
    const dmg = strikeDamagePlus(g, u);
    let hits = 0;
    for (const v of hereEnemies) {
      if (dmg > 0) {
        const amount = unitHasLethalAgainst(g, u, v) ? Math.max(dmg, unitThresholdHPPlus(g, v)) : dmg;
        damageUnit(g, v, amount, { isDamage: true, sourceUnit: u });
        hits++;
      }
    }
    g.log.unshift(hits > 0
      ? `Whirling Blades: ${u.name} strikes ${hits} foe(s) for ${dmg}.`
      : `Whirling Blades: ${u.name} finds no valid target to strike.`);
  } else {
    g.log.unshift(`Whirling Blades: no enemies to strike at the destination.`);
  }

  st.stepsLeft -= 1;
  if (st.stepsLeft <= 0) {
    delete (g as any)._pendingWhirling;
    g.log.unshift('Whirling Blades ends.');
  } else {
    g.log.unshift(`Whirling Blades: choose one more legal step for ${u.name} (or click elsewhere to end).`);
  }
}

async function maybeHandleWitherwingRescues(
  g: Game,
  attacker: Unit,
  defenders: Unit[],
  cell: Cell,
): Promise<Unit[]> {
  if (defenders.length === 0) return defenders;
  const defenderPid = defenders[0]?.player as PlayerId | undefined;
  if (defenderPid == null) return defenders;

  const attackerRegion = ((attacker as any).region ?? 'surface') as Region;
  const withers = cell.units.filter(
    u =>
      u.player === defenderPid &&
      u.kind !== 'Avatar' &&
      /^Witherwing Hero$/i.test(u.name ?? '') &&
      (((u as any).region ?? 'surface') as Region) === attackerRegion,
  ) as Token[];

  if (withers.length === 0) return defenders;

  const survivors: Unit[] = [];

  for (const candidate of defenders) {
    let rescued = false;
    if (candidate.player === defenderPid && candidate.kind !== 'Avatar') {
      const targetToken = candidate as Token;
      const targetRegion = ((targetToken as any).region ?? 'surface') as Region;
      for (const hero of withers) {
        if (hero.id === targetToken.id) continue;
        const heroRegion = ((hero as any).region ?? 'surface') as Region;
        if (heroRegion !== targetRegion) continue;
        const heroPower = strikeDamagePlus(g, hero);
        const targetPower = strikeDamagePlus(g, targetToken);
        if (targetPower < heroPower) {
          const confirmRescue = await uiConfirmForPid(defenderPid, {
            title: 'Witherwing Hero',
            message: formatTileText(g, `Rescue ${targetToken.name}?`),
            confirmLabel: 'Rescue',
            cancelLabel: 'Leave',
          });
          if (confirmRescue) {
            if (returnUnitToOwnerHand(g, targetToken, `Witherwing Hero rescues ${targetToken.name}, returning it to hand.`)) {
              rescued = true;
              requestGameSync?.();
            }
          }
          break;
        }
      }
    }
    if (!rescued) survivors.push(candidate);
  }

  return survivors;
}

async function resolveMoveAndAttack(
  g: Game,
  pid: PlayerId,
  unitId: string,
  to: { x: number; y: number; region: Region },
  opts?: {
    skipAttack?: boolean;
    quickAttack?: boolean;
    preferredTargetUnitId?: string;
    battleFocus?: { x: number; y: number; region: Region };
  },
) {
  let unit = g.board.flat().flatMap(c => c.units).find(u => u.id === unitId)
  if (!unit) return
  if (!canTapToPay(g, unit)) { g.log.unshift(`Cannot activate: ${unit.name} cannot tap this turn.`); return }

  const forceState = (g as any)._tvinnaxForce as { unitId?: string } | undefined;
  const forcingTvinnax = forceState?.unitId === unit.id;
  const unitOwner = (unit as any).player as PlayerId | undefined;
  const cpuForcing =
    forcingTvinnax &&
    (g as any)._opponentType === 'cpu' &&
    unitOwner === 2;
  const cpuAttacker = (g as any)._opponentType === 'cpu' && pid === 2;

  const isKarkemishChimera = /^Karkemish Chimera$/i.test(unit.name ?? '');

  const neigh = neighborsFor(unit, g)
  const prev = { x: (unit as any).x as number, y: (unit as any).y as number, region: (unit as any).region as Region }
  const originSite =
    prev.region === 'surface' && inside(g, prev.x, prev.y)
      ? cellOf(g, prev.x, prev.y).site
      : null;
  const dreadThicketSite =
    originSite &&
    !originSite.rubble &&
    /^Dread Thicket$/i.test(originSite.name ?? '') &&
    !siteAbilitiesSuppressedAt(g, prev.x, prev.y, originSite)
      ? originSite
      : null;
  const dreadThicketReady =
    !!dreadThicketSite && (dreadThicketSite as any)._dreadThicketTurn !== g.turnNumber;
  const staying = prev.x === to.x && prev.y === to.y && prev.region === to.region
  const ok = staying || neigh.some(s => s.x === to.x && s.y === to.y && s.region === to.region)
  if (!ok) return

  if (
    unit.kind !== 'Avatar' &&
    /^Cerberus in Chains$/i.test(unit.name ?? '') &&
    (unit as any)._cerberusInChains === true
  ) {
    if (!staying) {
      const av = g.avatars[pid];
      if (!av) return;
      if (!(to.x === av.x && to.y === av.y && to.region === av.region)) {
        g.log.unshift('Cerberus in Chains cannot stray from its master.');
        return;
      }
    }
  }
  if (unit.kind !== 'Avatar' && /^Dalcean Phalanx$/i.test(unit.name ?? '')) {
    if (!staying) {
      if (prev.region !== 'surface' || to.region !== 'surface') {
        g.log.unshift('Dalcean Phalanx can only advance forward on the surface.');
        return;
      }
      const dir = ((unit as any).player as PlayerId ?? 1) === 1 ? -1 : 1;
      if (!(to.x === prev.x && to.y === prev.y + dir)) {
        g.log.unshift('Dalcean Phalanx can only advance straight forward.');
        return;
      }
    }
  }

  const adventureActive = Boolean((g as any)?._adventure?.enabled);
  const targetCell = g.board[to.y][to.x]
  const adventureTileTarget = adventureTileFrom(g, to.x, to.y);
  const hiddenRubble = adventureTileHasHiddenAtlas(adventureTileTarget);
  const isVoidSquare = !targetCell.site && !hiddenRubble
  const unitSilenced = unitIsSilenced(g, unit)
  const hasVoidwalk = !unitSilenced && unitHasVoidwalkAt(g, unit, prev)
  let battleLocation = { x: to.x, y: to.y, region: to.region as Region };
  if (!staying) {
    if (isVoidSquare && !hasVoidwalk && !adventureActive) { g.log.unshift(`${unit.name} cannot move into the void without Voidwalk.`); return }
    if (!regionAllowedForUnit(g, unit, to.region, targetCell, to.x, to.y)) return
  }

  const wasTapped = !!unit.tapped
  const wasInteracted = unit.kind !== 'Avatar' ? !!(unit as Token).interactedThisTurn : false

  let didMove = false
  if (!staying) {
    const moved = moveUnitTo(g, unit, to.x, to.y, to.region, { sourcePlayer: pid })
    if (moved) {
      didMove = true
      g.log.unshift(`${unit.name} moves to (${to.x + 1}, ${to.y + 1}) ${to.region}.`)
    } else {
      g.log.unshift(`${unit.name} cannot be moved.`)
    }
  } else {
    g.log.unshift(`${unit.name} holds position at (${to.x + 1}, ${to.y + 1}) ${to.region}.`)
  }
  unit.tapped = true
  if (unit.kind !== 'Avatar') (unit as Token).interactedThisTurn = true

  const movingInfusion = unit.kind !== 'Avatar'
    ? ((unit as any)._infusionBinding as InfusionBinding | undefined)
    : undefined;
  if (movingInfusion) {
    syncInfusionFactoryAutomata(g);
    const liveMover = findUnitOnBoardById(g, unit.id);
    if (!liveMover) {
      g.log.unshift(`${unit.name} loses Infusion Factory animation after moving and cannot complete an attack.`);
      requestGameSync?.();
      return;
    }
    unit = liveMover;
  }

  if ((unit as any)._awakenedIntercept) {
    delete (unit as any)._awakenedIntercept;
    return;
  }

  if ((unit as any).size2x2 && to.region === 'surface') {
    const focusCandidate = opts?.battleFocus;
    if (
      focusCandidate &&
      focusCandidate.region === to.region &&
      size2x2AnchorCoversTile(to.x, to.y, focusCandidate.x, focusCandidate.y)
    ) {
      to = { x: focusCandidate.x, y: focusCandidate.y, region: focusCandidate.region };
      battleLocation = { x: to.x, y: to.y, region: to.region };
    }
    if (opts?.preferredTargetUnitId) {
      const preferredTarget = findUnitOnBoardById(g, opts.preferredTargetUnitId);
      if (
        preferredTarget &&
        ((preferredTarget as any).region ?? to.region) === to.region &&
        size2x2AnchorCoversTile((unit as any).x, (unit as any).y, (preferredTarget as any).x, (preferredTarget as any).y)
      ) {
        to = { x: (preferredTarget as any).x, y: (preferredTarget as any).y, region: to.region };
        battleLocation = { x: to.x, y: to.y, region: to.region };
      }
    }
  }

  const hereUnits = unitArrayAtRegion(g, to.x, to.y, to.region).filter(u => u.id !== unit.id)
  const hostileArtifactsHere = targetCell.artifacts.filter(a => (a as any)._adventureHostile);
  const site = g.board[to.y][to.x].site
  const siteIsDome = !!site && /^Dome of Osiros$/i.test(site.name)
  const putridPresenceNearby = putridPresenceAllowsSubsurfaceAttack(g, to.x, to.y);
  let hereEnemies = hereUnits.filter(u => u.player !== pid)
  if (siteIsDome && site && site.controller !== pid) {
    hereEnemies = []
  }
  let enemySite = !!site && site.controller != null && site.controller !== pid && !siteIsDome
  if (enemySite && to.region !== 'surface' && !putridPresenceNearby) {
    enemySite = false;
  }
  const subsurfaceSiteAttack = enemySite && to.region !== 'surface' && putridPresenceNearby;
  const sandstormHere = to.region === 'surface' && sandstormActiveAt(g, to.x, to.y);
  if (sandstormHere) {
    if (hereEnemies.length > 0 || enemySite || hostileArtifactsHere.length > 0) {
      g.log.unshift(`Sandstorm shrouds (${to.x + 1}, ${to.y + 1}) — attacks and intercepts are impossible.`);
    }
    hereEnemies = [];
    enemySite = false;
    hostileArtifactsHere.length = 0;
  }
  const blizzardHere = to.region === 'surface' && blizzardActiveAt(g, to.x, to.y);
  if (blizzardHere) {
    if (hereEnemies.length > 0 || enemySite || hostileArtifactsHere.length > 0) {
      g.log.unshift(`Blizzard lashes (${to.x + 1}, ${to.y + 1}) — attacks and intercepts are impossible.`);
    }
    hereEnemies = [];
    enemySite = false;
    hostileArtifactsHere.length = 0;
  }
  const siegeBlockers = hereEnemies.filter(enemy => {
    if (((enemy as any).region ?? to.region) !== to.region) return false;
    if (enemy.kind === 'Avatar') return false;
    if (!canDefendAtBattleLocation(enemy, to.x, to.y, to.region, { siteAttack: true })) return false;
    return canTapToPay(g, enemy);
  });
  const canSiege = enemySite && siegeBlockers.length === 0
  let defenseResolved = false
  const cannotAttack = unit.kind !== 'Avatar' && (unit as any)._cannotAttack;
  const moverIsAirborne = !!(unit as any).airborne && (unit as any).region === 'surface'
  const moverHasStealth = !!(unit as any).stealth
  const moverMadDash = (unit as any)._madDashTurn === g.turn
  const describeUnits = (list: Unit[]) =>
    list
      .map((u) => {
        const ux = (u as any).x as number | undefined;
        const uy = (u as any).y as number | undefined;
        const ur = ((u as any).region ?? 'surface') as Region;
        const pos =
          Number.isFinite(ux) && Number.isFinite(uy)
            ? ` @ (${(ux as number) + 1}, ${(uy as number) + 1})`
            : '';
        return `${u.name ?? 'Unit'}${pos} ${ur}`;
      })
      .join(', ');
  const canAttackEnemyUnit = (u: Unit) => {
    const enemyRegion = ((u as any).region ?? to.region) as Region;
    const enemyAirborne = enemyRegion === 'surface' && !!(u as any).airborne;
    if (enemyAirborne && !moverIsAirborne) return false;
    return true;
  };
  const tapDefenders = (list: Unit[]) => {
    for (const d of list) {
      if (!canTapToPay(g, d)) continue;
      d.tapped = true;
      if (d.kind !== 'Avatar') (d as Token).interactedThisTurn = true;
    }
  };
  let attackableEnemies = hereEnemies.filter(canAttackEnemyUnit);
  const canThisIntercept = (u: Unit) => {
    if (moverHasStealth) return false
    const enemyAirborne = !!(u as any).airborne && (u as any).region === 'surface'
    const enemyRanged = effectiveRanged(g, u) > 0
    if (moverIsAirborne) return enemyAirborne || enemyRanged
    return true
  }
  const maybePromptIntercept = async (messageOverride?: string): Promise<boolean> => {
    if (staying || hereEnemies.length === 0) return false;
    const defenderPid = pid === 1 ? 2 : 1;
    const hereAll = g.board[to.y][to.x].units.filter(u => u.region === to.region);
    const interceptables = moverMadDash ? [] : hereAll.filter(u =>
      u.player === defenderPid &&
      !(u as any)._cannotDefend &&
      canTapToPay(g, u) &&
      canThisIntercept(u)
    );
    if (interceptables.length === 0) return false;
    const tutorialStep = getTutorialRuntime(g)?.step;
    const autoTutorialIntercept =
      tutorialStep === 'player_move_huntress_8' &&
      pid === 1 &&
      defenderPid === 2 &&
      /^Sherwood Huntress$/i.test(unit.name ?? '');
    const tutorialRuntime = getTutorialRuntime(g);
    let pickedInt: Unit | null = null;
    if (autoTutorialIntercept) {
      pickedInt = interceptables.find((u) => /^Pit Vipers$/i.test(u.name ?? '')) ?? interceptables[0] ?? null;
      if (tutorialRuntime) {
        tutorialRuntime.flags ??= {};
        tutorialRuntime.flags.autoInterceptDuringMove = true;
      }
    } else {
      const idx = await uiSelectOneForPid<number>(defenderPid, {
        title: 'Intercept',
        message: formatTileText(g, messageOverride ?? 'Choose an interceptor or decline.'),
        options: interceptables.map((u, i) => ({
          label: formatTileText(g, `${u.name}`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Decline',
      });
      if (idx != null) pickedInt = interceptables[idx];
    }
    if (pickedInt) {
      pickedInt.tapped = true;
      g.log.unshift(`Intercept: ${pickedInt.name} intercepts.`);
      const post = await maybeHandleWitherwingRescues(g, unit, [pickedInt], g.board[to.y][to.x]);
      if (post.length > 0) {
        const remaining = await maybeHandleWispEvade(g, unit, post, battleLocation);
        if (remaining.length > 0) {
          await prepareStrikeAllocationsForFight(g, unit, remaining);
          fight(g, unit, remaining, true);
          if (autoTutorialIntercept) {
            const defender = remaining.find((u) => /^Pit Vipers$/i.test(u.name ?? '')) ?? remaining[0];
            if (defender && unitIsAlive(g, defender)) {
              damageUnit(g, defender, 99, { isDamage: true, sourceUnit: unit });
            }
            if (unitIsAlive(g, unit)) {
              damageUnit(g, unit, 99, { isDamage: true, sourceUnit: defender ?? unit });
            }
            tutorialRuntime?.flags && (tutorialRuntime.flags.enemyInterceptResolved = true);
            g.log.unshift('Intercept exchange: Sherwood Huntress and Pit Vipers are both destroyed.');
          }
          defenseResolved = true;
          await attemptSiegeIfPossible();
          requestGameSync?.();
        } else {
          g.log.unshift("Wills-o'-the-Wisp eludes the interception — combat fizzles.");
          await attemptSiegeIfPossible();
          requestGameSync?.();
        }
      } else {
        g.log.unshift('Witherwing Heroes rescue the interceptor — combat fizzles.');
        await attemptSiegeIfPossible();
        requestGameSync?.();
      }
      return true;
    }
    g.log.unshift('Intercept declined.');
    return false;
  };
  const attemptSiegeIfPossible = async () => {
    if (cannotAttack) return;
    if (!unitIsAlive(g, unit)) return;
    const tileCell = cellOf(g, to.x, to.y);
    const currentSite = tileCell.site;
    if (!currentSite || currentSite.controller == null || currentSite.controller === pid) return;
    await siegeSiteIfUnopposed(g, pid, unit, to.x, to.y);
  };
  const attackPossible = attackableEnemies.length > 0 || enemySite || hostileArtifactsHere.length > 0;
  const skipAttack = opts?.skipAttack === true || cannotAttack;
  if (attackPossible && whiteHartBlocksAttacksAt(g, to.x, to.y, to.region, unit)) {
    hereEnemies = [];
    attackableEnemies = [];
    enemySite = false;
    g.log.unshift('White Hart’s presence forbids attacks at this location.');
  }
  if (peaceOfferingBlocksAttacks(g, pid)) {
    if (attackPossible) {
      g.log.unshift('Peace Offering forbids attacks against your foe this turn.');
    }
    requestGameSync?.();
    return;
  }
  if (!attackPossible || skipAttack) {
    if (!attackPossible && hereEnemies.length > 0 && attackableEnemies.length === 0) {
      g.log.unshift('Airborne units cannot be attacked without Airborne.');
    }
    if (cannotAttack && attackPossible) {
      g.log.unshift(`${unit.name} cannot attack or siege.`);
    }
    if (skipAttack && !staying && attackableEnemies.length > 0) {
      const intercepted = await maybePromptIntercept(`${unit.name} abstains — intercept?`);
      if (intercepted) return;
    }
    await attemptSiegeIfPossible();
    requestGameSync?.();
    return;
  }

  const avatarHere = attackableEnemies.find(u => u.kind === 'Avatar');
  if (avatarHere) {
    const ax = (avatarHere as any).x as number | undefined;
    const ay = (avatarHere as any).y as number | undefined;
    const aRegion = ((avatarHere as any).region ?? to.region) as Region;
    if (aRegion === 'surface' && Number.isFinite(ax) && Number.isFinite(ay) && sphereOfAnimosityActive(g, ax!, ay!)) {
      attackableEnemies = attackableEnemies.filter(u => u.kind === 'Avatar');
      enemySite = false;
    }
  }

  const isMonstrousLion = /^Monstrous Lion$/i.test(unit.name ?? '');
  type AttackChoice = { kind: 'none' } | { kind: 'unit'; u: Unit } | { kind: 'site' } | { kind: 'artifact'; art: Artifact }
  let choices: AttackChoice[] = []
  for (const u of attackableEnemies) choices.push({ kind: 'unit', u })
  if (enemySite && !isMonstrousLion) choices.push({ kind: 'site' })
  for (const art of hostileArtifactsHere) choices.push({ kind: 'artifact', art })
  choices.push({ kind: 'none' })

  if (forcingTvinnax) {
    choices = choices.filter(choice => choice.kind !== 'none');
    const unitOnly = choices.filter(choice => choice.kind === 'unit');
    if (unitOnly.length > 0) choices = unitOnly;
  }

  const greenKnight = attackableEnemies.find(
    enemy =>
      enemy.kind !== 'Avatar' &&
      /^The Green Knight$/i.test(enemy.name ?? '') &&
      !unitIsSilenced(g, enemy)
  );
  if (greenKnight && unit.kind !== 'Avatar') {
    const alreadyForced =
      choices.length === 1 && choices[0].kind === 'unit' && (choices[0] as any).u === greenKnight;
    choices = [{ kind: 'unit', u: greenKnight }];
    if (!alreadyForced) {
      g.log.unshift(`${unit.name} is compelled to attack The Green Knight.`);
    }
  }

  const toLabel = (c: AttackChoice, i: number) =>
    c.kind === 'unit'
      ? `${i + 1}) Unit: ${c.u.name} @ (${(c.u as any).x + 1},${(c.u as any).y + 1})`
      : c.kind === 'site'
        ? `${i + 1}) Attack Site`
        : c.kind === 'artifact'
          ? `${i + 1}) Destroy ${c.art.name}`
        : `${i + 1}) Do NOT attack`

  const selectChimeraDefenders = async (current: Unit[], ensureId: string | null): Promise<Unit[]> => {
    if (!isKarkemishChimera) return current;
    if (current.length <= 3) {
      if (ensureId && !current.some(def => def.id === ensureId)) {
        const forced = g.board[to.y][to.x].units.find(u => u.id === ensureId && ((u as any).region ?? to.region) === to.region);
        if (forced) return [...current, forced].slice(0, 3);
      }
      return current;
    }

    const defenderPid = current[0]?.player as PlayerId | undefined;
    const defenderIsCpu = defenderPid != null && isCpuPlayer(g, defenderPid);
    if (defenderIsCpu) {
      const ensureIdx = ensureId ? current.findIndex(def => def.id === ensureId) : -1;
      const chosen = [
        ...(ensureIdx >= 0 ? [current[ensureIdx]] : []),
        ...current.filter((_, idx) => idx !== ensureIdx),
      ].slice(0, 3);
      return chosen;
    }

    const options = current.map((def, idx) => {
      const dx = (def as any).x ?? to.x;
      const dy = (def as any).y ?? to.y;
      return {
        label: formatTileText(g, `${def.name} (P${def.player}) @ (${dx + 1}, ${dy + 1})`),
        value: idx,
      };
    });

    let selection: number[] | null = null;
    while (true) {
      const chosen = await uiSelectManyForPid<number>(defenderPid, {
        title: 'Karkemish Chimera',
        message: formatTileText(g, 'Select up to three defenders for Karkemish Chimera to engage.'),
        options,
        allowEmpty: false,
        confirmLabel: 'Engage',
        cancelLabel: 'Auto-select',
      });
      if (!chosen) {
        if (ensureId) {
          const idx = current.findIndex(def => def.id === ensureId);
          selection = idx >= 0 ? [idx] : [0];
        } else {
          selection = current.slice(0, 3).map((_, i) => i);
        }
        break;
      }
      const uniq = Array.from(new Set(chosen));
      if (uniq.length === 0) {
        g.log.unshift('Karkemish Chimera must engage at least one defender.');
        continue;
      }
      if (uniq.length > 3) {
        g.log.unshift('Karkemish Chimera can engage at most three defenders.');
        continue;
      }
      if (ensureId && !uniq.some(idx => current[idx] && current[idx].id === ensureId)) {
        g.log.unshift('Include the originally targeted unit among the defenders.');
        continue;
      }
      selection = uniq;
      break;
    }

    return selection!.map(i => current[i]).filter((def): def is Unit => !!def);
  };
  const estimateRemainingHp = (u: Unit): number => {
    if (u.kind === 'Avatar') return Math.max(1, (u as Avatar).life ?? 1);
    const lethal = unitThresholdHPPlus(g, u);
    const damage = Math.max(0, (u as Token).damage ?? 0);
    return Math.max(1, lethal - damage);
  };
  const estimateIncomingFromDefenders = (defenderPid: PlayerId, siteAttack: boolean): number => {
    const defenders = g.board[to.y][to.x].units.filter((d) => {
      if (d.player !== defenderPid) return false;
      if (((d as any).region ?? to.region) !== to.region) return false;
      if (!canDefendAtBattleLocation(d, to.x, to.y, to.region, { siteAttack })) return false;
      return canTapToPay(g, d);
    });
    if (defenders.length === 0) return 0;
    return defenders.reduce((sum, d) => sum + Math.max(0, strikeDamagePlus(g, d)), 0);
  };
  const estimateCpuChoiceScore = (candidate: AttackChoice): number => {
    const attackerHp = estimateRemainingHp(unit);
    if (candidate.kind === 'none') return forcingTvinnax ? -9999 : 0;

    if (candidate.kind === 'site') {
      const defenderPid = (site?.controller as PlayerId | null) ?? (pid === 1 ? 2 : 1);
      const incoming = estimateIncomingFromDefenders(defenderPid, true);
      const likelyDie = incoming >= attackerHp && incoming > 0;
      let score = canSiege ? 9 : 2;
      if (likelyDie) score -= 7;
      return score;
    }

    if (candidate.kind === 'artifact') {
      const defenderPid = ((candidate.art as any).player as PlayerId | undefined) ?? (pid === 1 ? 2 : 1);
      const incoming = estimateIncomingFromDefenders(defenderPid, false);
      const likelyDie = incoming >= attackerHp && incoming > 0;
      let score = 4;
      if (likelyDie) score -= 6;
      return score;
    }

    const target = candidate.u;
    const attackerPower = Math.max(0, strikeDamagePlus(g, unit));
    const targetHp = estimateRemainingHp(target);
    const lethal = unitHasLethalAgainst(g, unit, target);
    const canKill = lethal || attackerPower >= targetHp;
    const defenderPid = target.player as PlayerId;
    let incoming = estimateIncomingFromDefenders(defenderPid, false);
    if (
      canDefendAtBattleLocation(target, to.x, to.y, to.region, { siteAttack: false }) &&
      !canTapToPay(g, target)
    ) {
      incoming += Math.max(0, strikeDamagePlus(g, target));
    }
    const likelyDie = incoming >= attackerHp && incoming > 0;

    let score = target.kind === 'Avatar' ? 16 : 6;
    if (canKill) score += target.kind === 'Avatar' ? 4 : 5;
    else score -= 2;
    if ((target as any).tapped) score += 1;
    if (likelyDie) score -= canKill ? 4 : 11;
    if (/^Petrosan Cavalry$/i.test(unit.name ?? '') && likelyDie && !canKill) score -= 6;
    if (/^Shield Maidens$/i.test(target.name ?? '') && likelyDie) score -= 4;
    return score;
  };

  let choice: AttackChoice | null = null;
  let attackSelectionCancelled = false;
  if (choices.length === 0) {
    choice = null;
  } else if (opts?.preferredTargetUnitId) {
    const preferred = choices.find(
      (candidate): candidate is { kind: 'unit'; u: Unit } =>
        candidate.kind === 'unit' && ((candidate.u as any).id as string | undefined) === opts.preferredTargetUnitId
    );
    if (preferred) choice = preferred;
  }
  if (!choice && opts?.quickAttack) {
    const siteChoice = choices.find((candidate) => candidate.kind === 'site') ?? null;
    const unitChoices = choices.filter((candidate): candidate is { kind: 'unit'; u: Unit } => candidate.kind === 'unit');
    const artifactChoices = choices.filter((candidate): candidate is { kind: 'artifact'; art: Artifact } => candidate.kind === 'artifact');
    if (siteChoice) {
      choice = siteChoice;
    } else if (unitChoices.length === 1) {
      choice = unitChoices[0];
    } else if (artifactChoices.length === 1) {
      choice = artifactChoices[0];
    }
  } else if (cpuAttacker) {
    let best: AttackChoice | null = null;
    let bestScore = Number.NEGATIVE_INFINITY;
    for (const candidate of choices) {
      const score = estimateCpuChoiceScore(candidate);
      if (score > bestScore) {
        bestScore = score;
        best = candidate;
      }
    }
    choice = best;
  } else if (choices.length === 1) {
    choice = choices[0];
  } else if (cpuForcing) {
    choice = choices[0];
  }
  if (!choice && choices.length > 0 && !cpuAttacker && !cpuForcing) {
    const selectedIndex = await uiSelectOne<number>({
      title: formatTileText(g, `${unit.name} — Choose Attack`),
      message: formatTileText(
        g,
        choices.length === 0
          ? 'No attack options available.'
          : forcingTvinnax
            ? 'Tvinnax Berserker must attack — select the unit to strike.'
            : 'Select your attack target (or choose to skip).'
      ),
      options: choices.map((c, idx) => ({
        label: toLabel(c, idx),
        value: idx,
      })),
      allowCancel: !forcingTvinnax,
      cancelLabel: forcingTvinnax ? undefined : 'Cancel attack',
    });
    if (selectedIndex == null) {
      if (forcingTvinnax) {
        choice = choices[0];
      } else {
        attackSelectionCancelled = true;
        choice = null;
      }
    } else {
      choice = choices[selectedIndex];
    }
  }

  if (!choice) {
    if (attackSelectionCancelled) {
      g.log.unshift(`${unit.name} cancels the attack.`);
    } else {
      await attemptSiegeIfPossible();
    }
    requestGameSync?.();
    return;
  }

  if (choice.kind === 'unit') {
    const ux = (choice.u as any).x as number | undefined;
    const uy = (choice.u as any).y as number | undefined;
    const targetPos =
      Number.isFinite(ux) && Number.isFinite(uy)
        ? ` @ (${(ux as number) + 1}, ${(uy as number) + 1})`
        : '';
    g.log.unshift(`${unit.name} attacks ${choice.u.name}${targetPos}.`);
  } else if (choice.kind === 'site') {
    const siteName = site?.name ?? 'the site';
    g.log.unshift(`${unit.name} attacks ${siteName} at (${to.x + 1}, ${to.y + 1}).`);
  } else if (choice.kind === 'artifact') {
    const artName = choice.art.name ?? 'the artifact';
    g.log.unshift(`${unit.name} attacks ${artName} at (${to.x + 1}, ${to.y + 1}).`);
  }

  if (unit.name === 'Skirmishers of Mu' && effectiveRanged(g, unit) > 0) {
    const dir = cpuAttacker
      ? null
      : await selectCardDirection(g, pid, 'Skirmishers of Mu', 'Shoot once (N, S, E, W) or cancel to skip.');
    if (dir) {
      await shootProjectile(g, pid, unit.id, dir)
      if (unit.kind !== 'Avatar') (unit as Token).interactedThisTurn = true
    } else if (!cpuAttacker) {
      g.log.unshift('Skirmishers of Mu hold their fire.');
    }
  }

  if (choice.kind === 'unit' || choice.kind === 'site' || choice.kind === 'artifact') {
    // Target the controlling player of the chosen enemy if present; otherwise default to the opposing seat.
    const defenderPid =
      choice.kind === 'unit'
        ? (choice.u.player as PlayerId)
        : choice.kind === 'artifact'
          ? ((choice.art as any).player as PlayerId ?? (pid === 1 ? 2 : 1))
          : (pid === 1 ? 2 : 1);
    const originalSiteDefendersIds = new Set<string>();
    if (choice.kind === 'site') {
      for (const enemy of hereEnemies) {
        if (
          enemy.player === defenderPid &&
          ((enemy as any).region ?? to.region) === to.region &&
          canDefendAtBattleLocation(enemy, to.x, to.y, to.region, { siteAttack: true })
        ) {
          originalSiteDefendersIds.add(enemy.id);
        }
      }
    }
    if (choice.kind === 'unit') {
      if (await freeCityRetaliate(g, unit, site ?? null, choice.u.player as PlayerId, { x: to.x, y: to.y })) {
        requestGameSync?.();
        return;
      }
      triggerCaptainBaldassare(g, unit, choice.u.player as PlayerId);
      const dodged = await maybeOfferDodgeRoll(g, defenderPid, choice.u);
      if (dodged) {
        const stillEnemies = g.board[to.y][to.x].units.filter(u => u.player === defenderPid && u.region === to.region);
        if (stillEnemies.length === 0) {
          g.log.unshift('The attack misses as the target rolls away.');
          requestGameSync?.();
          return;
        }
      }
    }
    const allEligible = listEligibleDefendersByMovement(g, defenderPid, to.x, to.y, to.region);
    const tileDefenders = g.board[to.y][to.x].units.filter(u =>
      u.player === defenderPid &&
      u.region === to.region &&
      canDefendAtBattleLocation(u, to.x, to.y, to.region, { siteAttack: choice.kind === 'site' }) &&
      canTapToPay(g, u)
    );
    const defenseTargetId = choice.kind === 'unit' ? ((choice.u as any).id as string | undefined) : undefined;
    const hasOptionalTileDefenders = defenseTargetId
      ? tileDefenders.some(u => (u as any).id !== defenseTargetId)
      : tileDefenders.length > 0;
    const canPromptDefend = allEligible.length > 0 || hasOptionalTileDefenders;
    let allowDefend = true;
    if (dreadThicketReady && dreadThicketSite) {
      (dreadThicketSite as any)._dreadThicketTurn = g.turnNumber;
      allowDefend = false;
      g.log.unshift('Dread Thicket shrouds the assault — defenders cannot be declared.');
    } else if (canPromptDefend) {
      const label =
        choice.kind === 'unit'
          ? choice.u.name ?? 'the unit'
          : choice.kind === 'site'
            ? site?.name ?? 'the site'
            : choice.kind === 'artifact'
              ? choice.art.name ?? 'the artifact'
              : 'the attack';
      allowDefend = await uiConfirmForPid(defenderPid, {
        title: 'Defend',
        message: formatTileText(g, `Defend ${label} against ${unit.name} at (${to.x + 1}, ${to.y + 1})?`),
        confirmLabel: 'Defend',
        cancelLabel: 'Decline',
      });
      if (!allowDefend) {
        g.log.unshift('Defend: declined.');
      }
    }

    let chosenDefs: Unit[] = [];
    if (allowDefend && allEligible.length > 0) {
      const selections = await uiSelectManyForPid<number>(defenderPid, {
        title: 'Defend',
        message: formatTileText(g,
          `Choose any number of units to move in against ${unit.name} at (${to.x + 1}, ${to.y + 1}) (leave empty to decline).`),
        options: allEligible.map((u, i) => ({
          label: formatTileText(g, `${u.name} @ (${(u as any).x + 1},${(u as any).y + 1}) [${(u as any).region}]`),
          value: i,
        })),
        allowEmpty: true,
        confirmLabel: 'Move In',
        cancelLabel: 'Back',
      });
      if (selections) chosenDefs = selections.map(idx => allEligible[idx]);

      if (chosenDefs.length > 0) {
        const selectedDefs = [...chosenDefs];
        const infusionMovedIds = new Set<string>();
        const selectedDefNames = new Map<string, string>();
        for (const d of selectedDefs) {
          if (d.id) selectedDefNames.set(d.id, d.name ?? 'Defender');
          const hasInfusion = !!((d as any)._infusionBinding as InfusionBinding | undefined);
          const relocating = !((d as any).x === to.x && (d as any).y === to.y && (d as any).region === to.region);
          if (hasInfusion && relocating && d.id) infusionMovedIds.add(d.id);
          if (relocating) {
            moveUnitTo(g, d, to.x, to.y, to.region);
          }
          const liveDef = findUnitOnBoardById(g, d.id);
          if (!liveDef) continue;
          liveDef.tapped = true;
          if (liveDef.kind !== 'Avatar') (liveDef as Token).interactedThisTurn = true;
        }
        if (infusionMovedIds.size > 0) {
          syncInfusionFactoryAutomata(g);
        }
        const failedInfusion: string[] = [];
        const stabilizedDefs: Unit[] = [];
        for (const d of selectedDefs) {
          const liveDef = findUnitOnBoardById(g, d.id);
          if (liveDef) {
            stabilizedDefs.push(liveDef);
            continue;
          }
          if (infusionMovedIds.has(d.id)) {
            failedInfusion.push(selectedDefNames.get(d.id) ?? d.name ?? 'Defender');
          }
        }
        chosenDefs = stabilizedDefs;
        if (failedInfusion.length > 0) {
          g.log.unshift(`Infusion Factory release: ${failedInfusion.join(', ')} cannot complete the defense.`);
        }
        if (chosenDefs.length > 0) {
          g.log.unshift(`Defend: ${chosenDefs.length} unit(s) move in to defend: ${describeUnits(chosenDefs)}.`);
        } else {
          g.log.unshift('Defend: no reinforcements remain after movement.');
        }
      } else if (selections) {
        g.log.unshift('Defend: no reinforcements chosen.');
      }
    }

    const defendingIds = new Set<string>();
    for (const d of chosenDefs) {
      if (d.id) defendingIds.add(d.id);
    }

    let defenders = allowDefend ? g.board[to.y][to.x].units.filter(u => {
      const unitId = (u as any).id as string | undefined;
      return (
        u.player === defenderPid &&
        u.region === to.region &&
        canDefendAtBattleLocation(u, to.x, to.y, to.region, { siteAttack: choice.kind === 'site' }) &&
        ((unitId != null && defendingIds.has(unitId)) || canTapToPay(g, u))
      );
    }) : [];

    if (choice.kind === 'site') {
      if (await freeCityRetaliate(g, unit, site ?? null, site?.controller ?? null, { x: to.x, y: to.y })) {
        requestGameSync?.();
        return;
      }
      const controller = site?.controller as PlayerId | null;
      if (controller != null) {
        triggerCaptainBaldassare(g, unit, controller);
      }
      const currentRegion = ((unit as any).region ?? 'surface') as Region;
      const isSubsurfaceRegion = currentRegion === 'underground' || currentRegion === 'underwater';
      const subsurfaceAttackEnabled = isSubsurfaceRegion && subsurfaceSiteAttack;
      if (isSubsurfaceRegion && !subsurfaceAttackEnabled) {
        if (didMove) moveUnitTo(g, unit, prev.x, prev.y, prev.region);
        unit.tapped = wasTapped;
        if (unit.kind !== 'Avatar') (unit as Token).interactedThisTurn = wasInteracted;
        g.log.unshift(`${unit.name} must surface before attacking the site.`);
        requestGameSync?.();
        return;
      }
      if (subsurfaceAttackEnabled && isSubsurfaceRegion) {
        g.log.unshift('Putrid Presence taints the land — the subsurface can be attacked from below.');
      }
    }

    defenders = await selectChimeraDefenders(defenders, choice.kind === 'unit' ? ((choice.u as any).id as string) : null);

    if (choice.kind === 'unit') {
      const targetId = (choice.u as any).id as string;
      if (/^Harassing Ruffians$/i.test(unit.name ?? '')) {
        defenders = [choice.u];
        g.log.unshift('Harassing Ruffians attack — defenders cannot assist the target.');
      }
      let fearScatters = false;
      if (/^Lord of Fear$/i.test(unit.name ?? '')) {
        if (defenders.length <= 1) {
          defenders = [];
          fearScatters = true;
          g.log.unshift('Lord of Fear strikes — enemies dare not defend alone.');
        }
      }
      if (!fearScatters) {
        const liveTarget = targetId ? findUnitOnBoardById(g, targetId) : null;
        const targetRegion = ((liveTarget as any)?.region ?? to.region) as Region;
        const targetStillHere =
          !!liveTarget &&
          (liveTarget as any).x === to.x &&
          (liveTarget as any).y === to.y &&
          targetRegion === to.region;
        const defenderIsCpu = isCpuPlayer(g, defenderPid);
        let targetWithdrew = false;
        const otherDefenders = defenders.filter(u => u.id !== targetId);
        if (targetStillHere && otherDefenders.length > 0) {
          let keepTargetInFight = true;
          if (defenderIsCpu && liveTarget?.kind === 'Avatar') {
            const avatarDefender = liveTarget as Avatar;
            const attackerHp = estimateRemainingHp(unit);
            const otherStrike = otherDefenders.reduce(
              (sum, d) => sum + Math.max(0, strikeDamagePlus(g, d)),
              0
            );
            const avatarStrike = Math.max(0, strikeDamagePlus(g, avatarDefender));
            const otherHasLethal = otherDefenders.some(
              (d) => Math.max(0, strikeDamagePlus(g, d)) > 0 && unitHasLethalAgainst(g, d, unit)
            );
            const avatarHasLethal =
              avatarStrike > 0 && unitHasLethalAgainst(g, avatarDefender, unit);
            const killsWithoutAvatar = otherHasLethal || otherStrike >= attackerHp;
            const killsWithAvatar =
              killsWithoutAvatar || avatarHasLethal || (otherStrike + avatarStrike) >= attackerHp;
            const enemyAvatarLife = g.avatars[pid]?.life ?? 0;
            keepTargetInFight =
              !killsWithoutAvatar && killsWithAvatar && enemyAvatarLife > 10;
          } else if (!defenderIsCpu) {
            const withdraw = await uiConfirmForPid(defenderPid, {
              title: 'Defender Option',
              message: formatTileText(g, `Withdraw ${liveTarget!.name ?? 'the defended unit'} from combat against ${unit.name}?`),
              confirmLabel: 'Withdraw',
              cancelLabel: 'Keep Fighting',
            });
            keepTargetInFight = !withdraw;
          }
          if (keepTargetInFight) {
            defenders = [liveTarget!, ...otherDefenders];
          } else {
            defenders = otherDefenders;
            targetWithdrew = true;
            g.log.unshift(
              liveTarget!.kind === 'Avatar'
                ? `${liveTarget!.name} stays out of the defense.`
                : `${liveTarget!.name} withdraws from the fight.`
            );
          }
        } else if (!targetWithdrew && targetStillHere && !defenders.some(u => u.id === targetId)) {
          defenders = [liveTarget!, ...defenders];
        }
        if (defenders.some(u => u.id === targetId)) {
          const hasAlternateDefender = defenders.some(u => u.id !== targetId);
          if (!hasAlternateDefender) {
            g.log.unshift(`${choice.u.name} has no other defenders — they must face the attack.`);
          }
        }
      }

        if (defenders.length > 0) {
          defenders = await maybeHandleWitherwingRescues(g, unit, defenders, g.board[to.y][to.x]);
          if (defenders.length > 0) {
            defenders = await selectChimeraDefenders(defenders, (choice.u as any).id as string);
            const remaining = await maybeHandleWispEvade(g, unit, defenders, battleLocation);
            if (remaining.length > 0) {
              g.log.unshift(`Defenders: ${describeUnits(remaining)}.`);
              tapDefenders(remaining);
              await prepareStrikeAllocationsForFight(g, unit, remaining);
              fight(g, unit, remaining, true);
              requestGameSync?.();
            } else {
            g.log.unshift("Wills-o'-the-Wisp vanishes before the blow lands.");
            requestGameSync?.();
          }
        } else {
          g.log.unshift('Witherwing Heroes spirit the defenders away — no combat occurs.');
          requestGameSync?.();
        }
      } else {
        const post = await maybeHandleWitherwingRescues(g, unit, [choice.u], g.board[to.y][to.x]);
        if (post.length > 0) {
          const remaining = await maybeHandleWispEvade(g, unit, post, battleLocation);
          if (remaining.length > 0) {
            g.log.unshift(`Defenders: ${describeUnits(remaining)}.`);
            tapDefenders(remaining);
            await prepareStrikeAllocationsForFight(g, unit, remaining);
            fight(g, unit, remaining, true);
            requestGameSync?.();
          } else {
            g.log.unshift("Wills-o'-the-Wisp slips away — no combat occurs.");
            requestGameSync?.();
          }
        } else {
          g.log.unshift('Witherwing Heroes spirit the defenders away — no combat occurs.');
          requestGameSync?.();
        }
      }
      return;
    }

    // Site attack
    const prevSiteCtx = (g as any)._siteAttackContext;
    (g as any)._siteAttackContext = { attackerId: (unit as any).id ?? null };
    const finishRealmEaterSiteAttack = async (allowSiegeDamage: boolean) => {
      if (allowSiegeDamage) {
        await attemptSiegeIfPossible();
      } else {
        g.log.unshift(`${site?.name ?? 'The site'} is defended — no siege damage is dealt.`);
      }
      if (/^Realm-Eater$/i.test(unit.name ?? '')) {
        realmEaterDevourSite(g, unit, to.x, to.y);
      }
      requestGameSync?.();
    };
    try {
      const chosenDefIds = new Set(chosenDefs.map(d => d.id));
      let committed: Unit[] = [];
      if (defenders.length > 0) {
        for (const d of defenders) {
          let keep = true;
          if (originalSiteDefendersIds.has(d.id) && !chosenDefIds.has(d.id)) {
            keep = await uiConfirmForPid(defenderPid, {
              title: 'Defender Option',
              message: formatTileText(g, `Keep ${d.name} defending ${site?.name ?? 'the site'}?`),
              confirmLabel: 'Defend',
              cancelLabel: 'Stay Out',
            });
          }
          if (keep) committed.push(d);
        }
      }

      if (committed.length > 0) {
        committed = await selectChimeraDefenders(committed, null);
        const postRescue = await maybeHandleWitherwingRescues(g, unit, committed, g.board[to.y][to.x]);
        if (postRescue.length > 0) {
          const remaining = await maybeHandleWispEvade(g, unit, postRescue, battleLocation);
          if (remaining.length > 0) {
            g.log.unshift(`Defenders: ${describeUnits(remaining)}.`);
            tapDefenders(remaining);
            await prepareStrikeAllocationsForFight(g, unit, remaining);
            fight(g, unit, remaining, true);
            defenseResolved = true;
            await finishRealmEaterSiteAttack(false);
          } else {
            g.log.unshift("Wills-o'-the-Wisp fades away — no combat occurs.");
            await finishRealmEaterSiteAttack(true);
          }
        } else {
          g.log.unshift('Witherwing Heroes rescue the defenders — the site stands unguarded.');
          await finishRealmEaterSiteAttack(true);
        }
        return;
      }

      if (/^Dame Britomart$/i.test(unit.name ?? '')) {
        const mortals = (g.cemetery[pid] ?? []).filter(
          (c): c is Extract<Card, { kind: 'Unit' }> =>
            c.kind === 'Unit' && (c.subTypes ?? []).some(s => s.toLowerCase() === 'mortal')
        );
        if (mortals.length > 0) {
          const wants = await uiConfirm({
            title: 'Dame Britomart',
            message: formatTileText(g, 'Summon a Mortal from your cemetery here instead of sieging?'),
            confirmLabel: 'Summon',
            cancelLabel: 'Siege',
          });
          if (wants) {
            let pick = mortals[0];
            if (mortals.length > 1) {
              const idx = await uiSelectOne<number>({
                title: 'Dame Britomart',
                message: 'Choose a Mortal to summon.',
                options: mortals.map((c, i) => ({ label: c.name, value: i })),
                allowCancel: true,
                cancelLabel: 'Cancel',
              });
              if (idx != null && idx >= 0 && idx < mortals.length) pick = mortals[idx];
            }
            const cemetery = g.cemetery[pid];
            const idx = cemetery.findIndex(c => c.id === pick.id);
            if (idx >= 0) {
              const [card] = cemetery.splice(idx, 1) as Extract<Card, { kind: 'Unit' }>[];
              const token: Token = {
                id: uid(),
                kind: 'Token',
                name: card.name,
                element: card.element,
                player: pid,
                x: to.x,
                y: to.y,
                region: to.region,
                tapped: false,
                power: card.power,
                atk: card.atk,
                def: card.def,
                airborne: card.airborne,
                burrowing: card.burrowing,
                submerge: card.submerge,
                voidwalk: card.voidwalk,
                movementPlus: card.movementPlus,
                immobile: card.immobile,
                ranged: card.ranged,
                stealth: card.stealth,
                lethal: card.lethal,
                deathriteText: card.deathriteText,
                carrying: [],
                summonedThisTurn: true,
                damage: 0,
                ...(card.size2x2 ? { size2x2: true } : {}),
                image: card.image,
                subTypes: card.subTypes ? [...card.subTypes] : undefined,
                provides: card.provides ? [...card.provides] : undefined,
                providesGeneric: card.providesGeneric,
              };
              (token as any)._srcCard = card;
              cellOf(g, to.x, to.y).units.push(token);
              handleUnitSummoned(g, pid, token, card);
              g.log.unshift(`Dame Britomart calls ${card.name} from the grave instead of sieging.`);
              requestGameSync?.();
              return;
            }
          }
        }
      }

      await finishRealmEaterSiteAttack(true);
    } finally {
      if (prevSiteCtx) (g as any)._siteAttackContext = prevSiteCtx;
      else delete (g as any)._siteAttackContext;
    }
    return;
  }

  if (!staying && hereEnemies.length > 0) {
    const intercepted = await maybePromptIntercept();
    if (intercepted) return;
  }

  if (canSiege && !defenseResolved) {
    const success = await siegeSiteIfUnopposed(g, pid, unit, to.x, to.y)
    if (success) dispelSylvanSplendorAt(g, to.x, to.y);
  }
  // Final pass: if a site was the intended target and we're still here, apply siege damage once.
  if ((choice as any).kind === 'site') {
    await attemptSiegeIfPossible();
    if (/^Realm-Eater$/i.test(unit.name ?? '')) {
      realmEaterDevourSite(g, unit, to.x, to.y);
    }
  }
  requestGameSync?.()
}

async function shootProjectile(
  g: Game,
  pid: PlayerId,
  shooterId: string,
  dir: 'N'|'S'|'E'|'W',
  opts?: {
    bypassTap?: boolean;
    damageOverride?: number;
    skipAfterStrike?: boolean;
    sourceElement?: string;
    projectileStyle?: ProjectileFxStyle;
  }
) {
  const shooter = g.board.flat().flatMap(c => c.units).find(u => u.id === shooterId);
  if (!shooter) return;
  const bypass = !!opts?.bypassTap;
  if (!bypass && !canTapToPay(g, shooter)) return;

  const region = (shooter as any).region as Region;
  const ignoreStealth = shooterIgnoresStealth(g, shooter);
  const sourcePid = shooter.player as PlayerId | undefined;
  const shooterX = Number((shooter as any).x);
  const shooterY = Number((shooter as any).y);
  const projectileStyle: ProjectileFxStyle = opts?.projectileStyle ?? 'arrow';
  const lance = unitCarriesArtifact(g, shooter, 'Lance');
  const lanceActive = lance && !artifactIsSilenced(g, lance) ? lance : null;
  const lethal = !opts?.damageOverride
    ? (target: Unit) => unitHasLethalAgainst(g, shooter, target)
    : () => false;

  if (!bypass) {
    shooter.tapped = true;
    if (shooter.kind !== 'Avatar') (shooter as Token).interactedThisTurn = true;
  }

  let x = (shooter as any).x;
  let y = (shooter as any).y;
  const d = dir === 'N' ? [0, -1] : dir === 'S' ? [0, 1] : dir === 'E' ? [1, 0] : [-1, 0];

  while (inside(g, x + d[0], y + d[1])) {
    const nx = x + d[0];
    const ny = y + d[1];
    if (projectileBlockedBySite(g, { x, y, region }, { x: nx, y: ny, region }, pid, shooter)) {
      emitProjectileFx(g, {
        fromX: shooterX,
        fromY: shooterY,
        toX: nx,
        toY: ny,
        style: projectileStyle,
        hit: false,
        pid: sourcePid,
        cardName: (shooter as any).name,
        source: 'combat',
      });
      return;
    }
    x = nx;
    y = ny;

    const list = unitArrayAtRegion(g, x, y, region);

    const targetables = list.filter(
      u => (ignoreStealth || !(u as any).stealth) && !enemyTargetingBlocked(g, u, sourcePid)
    );
    if (targetables.length === 0) continue;

    let target: Unit = targetables[0];
    if (targetables.length > 1) {
      const choice = await uiSelectOne<number>({
        title: `${(shooter as any).name} — Projectile`,
        message: formatTileText(g, `Choose a unit to hit (${dir}).`),
        options: targetables.map((u, i) => ({
          label: formatTileText(g, `${u.name} (P${u.player}) @ (${(u as any).x + 1}, ${(u as any).y + 1})`),
          value: i,
        })),
        allowCancel: true,
        cancelLabel: 'Default target',
      });
      if (choice != null && choice >= 0 && choice < targetables.length) {
        target = targetables[choice];
      }
    }

    g.log.unshift(`${(shooter as any).name} shoots ${dir} and hits ${target.name}.`);
    emitProjectileFx(g, {
      fromX: shooterX,
      fromY: shooterY,
      toX: x,
      toY: y,
      style: projectileStyle,
      hit: true,
      pid: sourcePid,
      cardName: (shooter as any).name,
      source: 'combat',
    });
    const amountBase = (opts?.damageOverride ?? strikeDamagePlus(g, shooter)) + (lanceActive ? 1 : 0);
    const amount = lethal(target) ? Math.max(amountBase, unitThresholdHPPlus(g, target)) : amountBase;

    if (!(target.name === 'Sling Pixies' && amount >= 4)) {
      const damageOpts: DamageOpts = { isDamage: true, sourceUnit: shooter, isRangedStrike: true };
      if (opts?.sourceElement) damageOpts.sourceElement = opts.sourceElement;
      damageUnit(g, target, amount, damageOpts);
      if (amount > 0) handleUnitStruck(g, shooter, target);
    } else {
      g.log.unshift('Sling Pixies take no damage from powerful shots (≥4 power).');
    }
    if (lanceActive) destroyArtifact(g, lanceActive, { log: 'Lance breaks.' });

    if (!opts?.skipAfterStrike) afterRangedStrike(g, shooter);
    return;
  }

  g.log.unshift(`${(shooter as any).name} shoots ${dir} but hits nothing.`);
  emitProjectileFx(g, {
    fromX: shooterX,
    fromY: shooterY,
    toX: Number.isFinite(x) ? x : shooterX,
    toY: Number.isFinite(y) ? y : shooterY,
    style: projectileStyle,
    hit: false,
    pid: sourcePid,
    cardName: (shooter as any).name,
    source: 'combat',
  });
}
function tilesOfAura2x2(g: Game, anchor: { x: number; y: number }) {
  const { x, y } = anchor;
  const pts: Array<{ x: number; y: number }> = [];
  if (x >= 0 && y >= 0 && x + 1 < g.width && y + 1 < g.height) {
    pts.push({ x, y }, { x: x + 1, y }, { x, y: y + 1 }, { x: x + 1, y: y + 1 });
  }
  return pts;
}

function auraCoversTile(g: Game, aura: Aura, x: number, y: number): boolean {
  if (aura.shape === 'single' || aura.shape === 'border') {
    return aura.anchor.x === x && aura.anchor.y === y;
  }
  return tilesOfAura2x2(g, aura.anchor).some(t => t.x === x && t.y === y);
}

function auraByNameAt(g: Game, player: PlayerId, name: string, x: number, y: number): Aura | undefined {
  return g.auras.find(a => a.player === player && a.name === name && auraCoversTile(g, a, x, y));
}

function auraByNameAtAny(g: Game, name: string, x: number, y: number): Aura | undefined {
  return g.auras.find(a => a.name === name && auraCoversTile(g, a, x, y));
}

function singleAuraAt(g: Game, x: number, y: number): Aura | undefined {
  return g.auras.find(a => (a.shape === 'single' || a.shape === 'border') && a.anchor.x === x && a.anchor.y === y);
}

function oppositeBorderDir(dir: BorderDir): BorderDir {
  switch (dir) {
    case 'N': return 'S';
    case 'S': return 'N';
    case 'E': return 'W';
    case 'W': return 'E';
  }
}

function borderDirFromDelta(dx: number, dy: number): BorderDir | null {
  if (dx === 0 && dy === -1) return 'N';
  if (dx === 0 && dy === 1) return 'S';
  if (dx === 1 && dy === 0) return 'E';
  if (dx === -1 && dy === 0) return 'W';
  return null;
}

function borderAuraAt(g: Game, x: number, y: number, dir: BorderDir): Aura | undefined {
  return g.auras.find(
    a =>
      a.shape === 'border' &&
      a.anchor.x === x &&
      a.anchor.y === y &&
      (a.borderDir == null || a.borderDir === dir)
  );
}

function anyBorderAuraAt(g: Game, x: number, y: number): Aura | undefined {
  return g.auras.find(a => a.shape === 'border' && a.anchor.x === x && a.anchor.y === y);
}

function borderAuraBetween(g: Game, fromX: number, fromY: number, toX: number, toY: number): Aura | undefined {
  const dir = borderDirFromDelta(toX - fromX, toY - fromY);
  if (!dir) return undefined;
  const atOrigin = borderAuraAt(g, fromX, fromY, dir);
  if (atOrigin) return atOrigin;
  const atDest = borderAuraAt(g, toX, toY, oppositeBorderDir(dir));
  return atDest;
}

function siteUnderDrought(g: Game, x: number, y: number): boolean {
  return g.auras.some(a => a.effect?.drought && tilesOfAura2x2(g, a.anchor).some(t => t.x === x && t.y === y));
}

function siteUnderFlood(g: Game, x: number, y: number): boolean {
  return g.auras.some(a => a.effect?.flood && tilesOfAura2x2(g, a.anchor).some(t => t.x === x && t.y === y));
}

function silentHillsSilencesHere(g: Game, x: number, y: number): boolean {
  const list: Array<{ x: number; y: number; controller: PlayerId }> | undefined = (g as any)._silentHills;
  if (!list || list.length === 0) return false;
  for (const entry of list) {
    if (cheb(entry.x, entry.y, x, y) <= 1) {
      const cell = cellOf(g, entry.x, entry.y);
      if (cell.site && !cell.site.rubble) return true;
    }
  }
  return false;
}

function sandstormActiveAt(g: Game, x: number, y: number): boolean {
  return g.auras.some(a => a.name === 'Sandstorm' && auraCoversTile(g, a, x, y));
}

function blizzardActiveAt(g: Game, x: number, y: number): boolean {
  return g.auras.some(a => a.name === 'Blizzard' && auraCoversTile(g, a, x, y));
}

function putridPresenceAllowsSubsurfaceAttack(g: Game, siteX: number, siteY: number): boolean {
  for (let dy = -1; dy <= 1; dy++) {
    for (let dx = -1; dx <= 1; dx++) {
      const cx = siteX + dx;
      const cy = siteY + dy;
      if (!inside(g, cx, cy)) continue;
      const units = cellOf(g, cx, cy).units;
      for (const u of units) {
        if (u.kind === 'Avatar') continue;
        if (!/^Putrid Presence$/i.test(u.name ?? '')) continue;
        if (unitIsSilenced(g, u)) continue;
        return true;
      }
    }
  }
  return false;
}

function isSiteWater(g: Game, site: Site | null | undefined, x: number, y: number): boolean {
  const worldFlooded = Boolean((g as any)._worldFlooded);
  if (!site) return worldFlooded;
  if (!worldFlooded && siteUnderDrought(g, x, y)) return false;
  if (worldFlooded) return true;
  if (site.isWater) return true;
  if (siteUnderFlood(g, x, y)) return true;
  return false;
}

function unitIsImmobile(u: Unit): boolean {
  if (u.kind === 'Avatar') {
    if ((u as any)._realmEaterImmobile) return true;
    return false;
  }
  const token = u as Token;
  if ((token as any)._ignoreImmobilize) return false;
  return token.immobile === true || (token as any)._immobileUnit === true;
}

function unitIsSilenced(g: Game, u: Unit): boolean {
  if (u.kind === 'Avatar') return false;
  if ((u as any)._tabulaRasa === true) return true;
  if ((u as any)._onslaughtTurn === g.turnNumber) return false;
  const tempSilence = (g as any)._tempSilencedUnits as Record<string, number> | undefined;
  if (tempSilence && (u as any).id) {
    const currentTurn = typeof g.turnNumber === 'number' ? g.turnNumber : 0;
    const expires = tempSilence[(u as any).id];
    if (typeof expires === 'number') {
      if (currentTurn <= expires) return true;
      delete tempSilence[(u as any).id];
    }
  }
  if (isBowerOfBlissActive(g) && unitHasRawSubtype(u, 'Mortal')) return true;
  const region = (u as any).region ?? 'surface';
  const ux = (u as any).x as number | undefined;
  const uy = (u as any).y as number | undefined;
  if (
    Number.isFinite(ux) &&
    Number.isFinite(uy) &&
    sistersOfSilenceAffects(g, u, region as Region, ux!, uy!)
  ) {
    return true;
  }
  if (Number.isFinite(ux) && Number.isFinite(uy)) {
    for (let dy = -1; dy <= 1; dy++) for (let dx = -1; dx <= 1; dx++) {
      if (dx === 0 && dy === 0) continue;
      const nx = ux! + dx;
      const ny = uy! + dy;
      if (!inside(g, nx, ny)) continue;
      const neighbors = unitArrayAtRegion(g, nx, ny, region as Region);
      for (const other of neighbors) {
        if (other.kind === 'Avatar') continue;
        if ((other as any).id === (u as any).id) continue;
        if (!/^Sister Stef[áa]nia$/i.test(other.name ?? '')) continue;
        return true;
      }
    }
  }
  if (region === 'surface' && Number.isFinite(ux) && Number.isFinite(uy)) {
    if (silentHillsSilencesHere(g, ux!, uy!)) {
      const cell = cellOf(g, ux!, uy!);
      if (cell.site && !cell.site.rubble) return true;
    }
  }
  if (region !== 'surface') return false;
  for (const aura of g.auras) {
    if (!aura.effect?.silence) continue;
    const tiles = tilesOfAura2x2(g, aura.anchor);
    if (tiles.some(t => t.x === ux && t.y === uy)) return true;
  }
  return false;
}
function processDevilsEggAtEndOfTurn(g: Game) {
  for (let y = 0; y < g.height; y++) {
    for (let x = 0; x < g.width; x++) {
      const s = cellOf(g, x, y).site;
      if (!s) continue;
      if (s.name === "Devil's Egg" && s.controller != null) {
        lifeLossAvatarFromSiege(g, s, 1, s.controller ?? undefined);
        g.log.unshift(`Devil's Egg at (${x + 1}, ${y + 1}) siphons 1 life from Player ${s.controller}.`);
      }
    }
  }
}

function processGriefLarvaeAtEndOfTurn(g: Game, pid: PlayerId) {
  for (const row of g.board) {
    for (const cell of row) {
      for (const u of cell.units) {
        if (u.kind === 'Avatar') continue;
        if ((u as any).player !== pid) continue;
        if (!/^Grief Larvae$/i.test(u.name ?? '')) continue;
        const site = cell.site;
        if (site && site.controller != null) {
          lifeLossAvatarFromSiege(g, site, 1, pid);
          g.log.unshift(`Grief Larvae gnaw at ${site.name}, dealing 1 siege damage to Player ${site.controller}.`);
        }
      }
    }
  }
}

function processDesecratorKiteAtEndOfTurn(g: Game, pid: PlayerId) {
  for (const row of g.board) {
    for (const cell of row) {
      for (const u of cell.units) {
        if (u.kind === 'Avatar') continue;
        if ((u as any).player !== pid) continue;
        if (!/^Desecrator Kite$/i.test(u.name ?? '')) continue;
        const site = cell.site;
        if (site && site.controller != null) {
          lifeLossAvatarFromSiege(g, site, 1, pid);
          g.log.unshift(`Desecrator Kite harrows ${site.name}, dealing 1 siege damage to Player ${site.controller}.`);
        }
      }
    }
  }
}

function processLocustsOfIllyriaAtEndOfTurn(g: Game, pid: PlayerId): void {
  const lastSummoned = (g as any)._locustsSummonedTurn?.[pid];
  if (lastSummoned === g.turnNumber) return;
  const locusts = g.board.flat().flatMap(c => c.units)
    .filter(u => u.kind !== 'Avatar' && u.player === pid && /^Locusts of Illyria$/i.test(u.name ?? '')) as Token[];
  if (locusts.length === 0) return;

  let sequence = Promise.resolve();
  for (const locust of locusts) {
    const id = (locust as any).id as string | undefined;
    if (!id) continue;
    sequence = sequence.then(async () => {
      const located = findTokenOnBoard(g, id);
      if (!located || located.token.kind === 'Avatar') return;
      const token = located.token as Token;
      const region = ((token as any).region ?? 'surface') as Region;
      const ux = (token as any).x as number | undefined;
      const uy = (token as any).y as number | undefined;
      if (!Number.isFinite(ux) || !Number.isFinite(uy)) return;
      const source = (token as any)._srcCard as Extract<Card, { kind: 'Unit' }> | undefined;
      const copy: Extract<Card, { kind: 'Unit' }> = source ?? {
        id: uid(),
        kind: 'Unit',
        name: token.name ?? 'Locusts of Illyria',
        element: token.element,
        power: token.power,
        atk: token.atk,
        def: token.def,
        threshold: {},
        cost: 0,
        subTypes: token.subTypes ? [...token.subTypes] : undefined,
      } as any;
      const candidates = nearbyCoords8(g, ux!, uy!)
        .filter(([x, y]) => canSummonHere(g, pid, x, y, region, copy));
      if (candidates.length === 0) {
        g.log.unshift('Locusts of Illyria find no nearby site to infest.');
        requestGameSync?.();
        return;
      }
      let choice = candidates[0];
      if (candidates.length > 1) {
        if (isCpuPlayer(g, pid)) {
          const idx = pickRandomIndex(g, candidates.length, { context: 'Locusts of Illyria', controllerPid: pid });
          choice = candidates[Math.max(0, Math.min(candidates.length - 1, idx))];
        } else {
          const idx = await uiSelectOne<number>({
            title: 'Locusts of Illyria',
            message: formatTileText(g, 'Choose where a tapped copy swarms.'),
            options: candidates.map(([x, y], i) => ({
              label: formatTileText(g, `(${x + 1}, ${y + 1})`),
              value: i,
            })),
            allowCancel: true,
            cancelLabel: 'Skip',
          });
          if (idx == null || idx < 0 || idx >= candidates.length) {
            g.log.unshift('Locusts of Illyria remain still.');
            requestGameSync?.();
            return;
          }
          choice = candidates[idx];
        }
      }
      const spawned = summonUnitCardAt(g, pid, copy, choice[0], choice[1], region);
      if (spawned) {
        spawned.tapped = true;
        spawned.interactedThisTurn = true;
        spawned.summonedThisTurn = true;
        g.log.unshift(`Locusts of Illyria swarm at (${choice[0] + 1}, ${choice[1] + 1}).`);
      }
      requestGameSync?.();
    });
  }
  sequence.catch(() => {});
}

function processOrmInfestorAtEndOfTurn(g: Game, pid: PlayerId): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const u of cell.units) {
        if (u.kind === 'Avatar') continue;
        if ((u as any).player !== pid) continue;
        if (!/^Orm Infestor$/i.test(u.name ?? '')) continue;
        const ux = (u as any).x as number | undefined;
        const uy = (u as any).y as number | undefined;
        if (!Number.isFinite(ux) || !Number.isFinite(uy)) continue;
        const site = cellOf(g, ux!, uy!).site;
        if (!site || site.rubble || site.controller == null) continue;
        lifeLossAvatarFromSiege(g, site, 1, pid);
        const healed = healAvatarLife(g, pid, 1);
        g.log.unshift(`Orm Infestor gnaws ${site.name}, dealing 1 siege damage and healing ${healed}.`);
      }
    }
  }
}

function processNadirSeedAtEndOfTurn(g: Game, pid: PlayerId) {
  for (const art of g.artifacts) {
    if (!/^Nadir Seed$/i.test(art.name ?? '')) continue;
    if (art.carriedBy) continue;
    if (artifactIsSilenced(g, art)) continue;
    const { x, y, region } = getArtifactCurrentPosition(g, art);
    if (region !== 'surface' || !Number.isFinite(x) || !Number.isFinite(y) || !inside(g, x, y)) continue;
    const site = cellOf(g, x, y).site;
    if (!site || site.rubble || site.controller !== pid) continue;
    const unspent = g.mana[pid] ?? 0;
    if (unspent <= 0) continue;
    const av = g.avatars[pid];
    if (!av) continue;
    applyAvatarDamage(g, av, unspent, { isDamage: true, sourceElement: 'Curse' });
    g.log.unshift(`Nadir Seed drains ${unspent} life from ${av.name}'s unspent mana.`);
  }
}

function processDefilerSpireAtEndOfTurn(g: Game, pid: PlayerId) {
  for (let y = 0; y < g.height; y++) {
    for (let x = 0; x < g.width; x++) {
      const cell = g.board[y][x];
      const site = cell.site;
      if (!site || site.rubble || !/^Defiler Spire$/i.test(site.name ?? '')) continue;
      const units = unitArrayAtRegion(g, x, y, 'surface');
      for (const u of units) {
        if (u.kind === 'Avatar') continue;
        if (!unitHasSubtype(g, u, 'Evil')) continue;
        const owner = (u as any).player as PlayerId | undefined;
        if (owner !== pid) continue;
        const av = g.avatars[owner];
        if (av) {
          applyAvatarDamage(g, av, 1, { sourceElement: 'Curse' });
          g.log.unshift(`Defiler Spire bleeds Player ${owner} for 1 life.`);
        }
      }
    }
  }
}

function processWildfiresAtEndOfTurn(g: Game) {
  const fires = (g as any)._wildfires as Array<{
    id: string;
    pid: PlayerId;
    x: number;
    y: number;
    visited?: string[];
  }> | undefined;

  if (!fires || fires.length === 0) return;

  const key = (x: number, y: number) => `${x},${y}`;

  for (let i = fires.length - 1; i >= 0; i--) {
    const wf = fires[i];
    const victims = unitArrayAtRegion(g, wf.x, wf.y, 'surface');
    let hits = 0;
    for (const v of victims) {
      damageUnit(g, v, 3, { sourceElement: 'Fire' });
      hits += 1;
    }
    if (hits > 0) {
      g.log.unshift(`Wildfire sears ${hits} unit(s) at (${wf.x + 1}, ${wf.y + 1}).`);
    } else {
      g.log.unshift(`Wildfire crackles at (${wf.x + 1}, ${wf.y + 1}) but finds no victims.`);
    }

    wf.visited ??= [];
    if (!wf.visited.includes(key(wf.x, wf.y))) {
      wf.visited.push(key(wf.x, wf.y));
    }

    let moved = false;
    for (const [dx, dy] of DIRS4) {
      const nx = wf.x + dx;
      const ny = wf.y + dy;
      if (!inside(g, nx, ny)) continue;
      const destCell = cellOf(g, nx, ny);
      if (!destCell.site || destCell.site.rubble) continue;
      const posKey = key(nx, ny);
      if (wf.visited.includes(posKey)) continue;
      wf.x = nx;
      wf.y = ny;
      wf.visited.push(posKey);
      g.log.unshift(`Wildfire spreads to (${nx + 1}, ${ny + 1}).`);
      moved = true;
      break;
    }

    if (!moved) {
      fires.splice(i, 1);
      g.log.unshift('Wildfire exhausts its fuel and burns out.');
    }
  }

  if (fires.length === 0) {
    delete (g as any)._wildfires;
  }
}
function processInvasionAtEndOfTurn(g: Game, pid: PlayerId): void {
  for (let i = g.auras.length - 1; i >= 0; i--) {
    const aura = g.auras[i];
    if (!/^Invasion$/i.test(aura.name ?? '')) continue;
    if (aura.player !== pid) continue;
    const turnsLeft = typeof (aura as any)._invasionTurns === 'number' ? (aura as any)._invasionTurns : 3;

    let spawned = 0;
    forEachSite(g, (site, sx, sy) => {
      if (!auraCoversTile(g, aura, sx, sy)) return;
      if (site.controller == null || site.controller === pid) return;
      const occupants = unitArrayAtRegion(g, sx, sy, 'surface');
      if (occupants.length > 0) return;
      summonFootSoldier(g, pid, sx, sy);
      spawned += 1;
    });

    if (spawned > 0) {
      g.log.unshift(`Invasion summons Foot Soldiers onto ${spawned} enemy site(s).`);
    } else {
      g.log.unshift('Invasion finds no empty enemy sites in its area.');
    }

    const remaining = turnsLeft - 1;
    (aura as any)._invasionTurns = remaining;
    if (remaining <= 0) {
      g.auras.splice(i, 1);
      releaseAuraSourceCard(g, aura);
      g.log.unshift('Invasion dissipates after three turns.');
    }
  }
}
function processWarpSpasmAtEndOfTurn(g: Game, pid: PlayerId): void {
  const doomed: Token[] = [];
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if (unit.kind === 'Avatar') continue;
        const token = unit as Token;
        const mark = (token as any)._warpSpasm as { owner?: PlayerId; bonus?: number } | undefined;
        if (mark && mark.owner === pid) doomed.push(token);
      }
    }
  }

  for (const token of doomed) {
    const data = (token as any)._warpSpasm as { bonus?: number } | undefined;
    if (data && typeof data.bonus === 'number') {
      const cur = (token as any)._tempPowerBonus ?? 0;
      const next = cur - data.bonus;
      (token as any)._tempPowerBonus = next > 0 ? next : 0;
    }
    delete (token as any)._warpSpasm;
    const lethal = unitThresholdHPPlus(g, token);
    damageUnit(g, token, lethal, { sourceElement: 'Void' });
    g.log.unshift(`${token.name} is torn apart by the Warp Spasm.`);
  }
}

function processThunderstormsAtEndOfTurn(g: Game, pid: PlayerId) {
  const storms = g.auras.filter(a => a.name === 'Thunderstorm' && a.player === pid);
  if (storms.length === 0) return;

  for (let i = storms.length - 1; i >= 0; i--) {
    const a = storms[i] as Aura & { _stormRemaining?: number };

    if (a._stormRemaining == null) a._stormRemaining = 3;

    const tiles = tilesOfAura2x2(g, a.anchor);
    const victims: Unit[] = [];
    for (const t of tiles) {
      const here = unitArrayAtRegion(g, t.x, t.y, 'surface');
      for (const u of here) victims.push(u);
    }

      if (victims.length > 0) {
        const rawIdx = pickRandomIndex(g, victims.length, {
          context: 'Thunderstorm strike',
          labels: victims.map(unit => `${unit.name} (P${unit.player})`),
          controllerPid: pid,
        });
      const idx = Math.max(0, Math.min(victims.length - 1, rawIdx));
      const v = victims[idx];
      damageUnit(g, v, 3);
      g.log.unshift(`Thunderstorm strikes ${v.name} for 3 within the storm area.`);
    } else {
      g.log.unshift('Thunderstorm rumbles — no unit to strike in its area.');
    }

    void (async () => {
      const dir = await uiSelectOne<string>({
        title: 'Thunderstorm',
        message: 'Move the Thunderstorm 1 step?',
        options: [
          { label: 'Stay put', value: 'STAY' },
          { label: 'North', value: 'N' },
          { label: 'North-East', value: 'NE' },
          { label: 'East', value: 'E' },
          { label: 'South-East', value: 'SE' },
          { label: 'South', value: 'S' },
          { label: 'South-West', value: 'SW' },
          { label: 'West', value: 'W' },
          { label: 'North-West', value: 'NW' },
        ],
        allowCancel: true,
        cancelLabel: 'Cancel',
      });

      if (dir == null || dir === 'STAY') {
        g.log.unshift('Thunderstorm crackles in place.');
        requestGameSync?.();
        return;
      }

      const dirMap: Record<string, [number, number]> = {
        'N':  [ 0,-1], 'NE': [ 1,-1], 'E':  [ 1, 0], 'SE': [ 1, 1],
        'S':  [ 0, 1], 'SW': [-1, 1], 'W':  [-1, 0], 'NW': [-1,-1],
      };
      const delta = dirMap[dir];
      if (!delta) {
        g.log.unshift('Thunderstorm move ignored (invalid direction).');
        requestGameSync?.();
        return;
      }

      const [dx, dy] = delta;
      const to = { x: a.anchor.x + dx, y: a.anchor.y + dy };
      const inBounds = (to.x >= 0 && to.y >= 0 && to.x + 1 < g.width && to.y + 1 < g.height);
      if (inBounds) {
        a.anchor = to;
        g.log.unshift(`Thunderstorm drifts ${dir} to anchor (${to.x + 1}, ${to.y + 1}).`);
      } else {
        g.log.unshift('Thunderstorm cannot move outside the realm and remains in place.');
      }
      requestGameSync?.();
    })();

    a._stormRemaining -= 1;
    if (a._stormRemaining <= 0) {
      const idx = g.auras.indexOf(a);
      if (idx >= 0) {
        g.auras.splice(idx, 1);
        releaseAuraSourceCard(g, a);
      }
      g.log.unshift('Thunderstorm dissipates.');
    }
  }
  applyHoundsAuraForAll(g);
}

function processFallingStarAtEndOfTurn(g: Game, pid: PlayerId): void {
  for (let i = g.auras.length - 1; i >= 0; i--) {
    const aura = g.auras[i];
    if (!/^Falling Star$/i.test(aura.name ?? '')) continue;
    if (aura.player !== pid) continue;
    const turnsLeft = typeof (aura as any)._fallingStarTurns === 'number' ? (aura as any)._fallingStarTurns : 3;
    const next = turnsLeft - 1;
    if (next > 0) {
      (aura as any)._fallingStarTurns = next;
      continue;
    }

    g.auras.splice(i, 1);
    releaseAuraSourceCard(g, aura);
    g.log.unshift('Falling Star begins its descent.');

    const anchor = { x: aura.anchor.x, y: aura.anchor.y };
    void (async () => {
      const tiles = tilesOfAura2x2(g, anchor);
      const siteTiles = tiles.filter(t => {
        const site = cellOf(g, t.x, t.y).site;
        return site && !site.rubble;
      });
      if (siteTiles.length === 0) {
        g.log.unshift('Falling Star finds no affected sites to land upon.');
        requestGameSync?.();
        return;
      }

      const hand = g.handSpells[pid].filter(c => c.kind === 'Unit') as Extract<Card, { kind: 'Unit' }>[];
      if (hand.length === 0) {
        g.log.unshift('Falling Star falls, but you have no minions to summon.');
        requestGameSync?.();
        return;
      }

      let wants = true;
      if (!isCpuPlayer(g, pid)) {
        wants = await uiConfirmForPid(pid, {
          title: 'Falling Star',
          message: 'Summon a minion from your hand onto an affected site?',
          confirmLabel: 'Summon',
          cancelLabel: 'Skip',
        });
      }
      if (!wants) {
        g.log.unshift('Falling Star fades without a landing.');
        requestGameSync?.();
        return;
      }

      let chosen = hand[0];
      if (hand.length > 1) {
        if (isCpuPlayer(g, pid)) {
          chosen = hand.reduce((best, cur) => {
            const bestPower = best.power ?? best.atk ?? 0;
            const curPower = cur.power ?? cur.atk ?? 0;
            return curPower > bestPower ? cur : best;
          }, hand[0]);
        } else {
          const idx = await uiSelectOne<number>({
            title: 'Falling Star',
            message: 'Choose a minion to summon.',
            options: hand.map((card, index) => ({
              label: `${card.name} (cost ${card.cost ?? 0})`,
              value: index,
            })),
            allowCancel: true,
            cancelLabel: 'Cancel',
          });
          if (idx == null || idx < 0 || idx >= hand.length) {
            g.log.unshift('Falling Star summoning cancelled.');
            requestGameSync?.();
            return;
          }
          chosen = hand[idx];
        }
      }

      let landingOptions: Array<{ x: number; y: number }> = [];
      if (chosen.size2x2) {
        const required = [
          { x: anchor.x, y: anchor.y },
          { x: anchor.x + 1, y: anchor.y },
          { x: anchor.x, y: anchor.y + 1 },
          { x: anchor.x + 1, y: anchor.y + 1 },
        ];
        const allSites = required.every(pos => {
          const site = cellOf(g, pos.x, pos.y).site;
          return site && !site.rubble;
        });
        const empty =
          allowsOccupiedSize2x2Summon(chosen) ||
          required.every(pos => unitArrayAtRegion(g, pos.x, pos.y, 'surface').length === 0);
        if (allSites && empty) landingOptions = [{ x: anchor.x, y: anchor.y }];
      } else {
        landingOptions = siteTiles.map(t => ({ x: t.x, y: t.y }));
      }

      if (landingOptions.length === 0) {
        g.log.unshift('Falling Star cannot find a safe landing spot for that minion.');
        requestGameSync?.();
        return;
      }

      let landing = landingOptions[0];
      if (landingOptions.length > 1) {
        if (isCpuPlayer(g, pid)) {
          const idx = pickRandomIndex(g, landingOptions.length, {
            context: 'Falling Star landing',
            controllerPid: pid,
            labels: landingOptions.map(t => `(${t.x + 1}, ${t.y + 1})`),
          });
          landing = landingOptions[Math.max(0, Math.min(landingOptions.length - 1, idx))];
        } else {
          const idx = await uiSelectOne<number>({
            title: 'Falling Star',
            message: 'Choose an affected site to land on.',
            options: landingOptions.map((t, index) => ({
              label: `(${t.x + 1}, ${t.y + 1})`,
              value: index,
            })),
            allowCancel: true,
            cancelLabel: 'Cancel',
          });
          if (idx == null || idx < 0 || idx >= landingOptions.length) {
            g.log.unshift('Falling Star landing cancelled.');
            requestGameSync?.();
            return;
          }
          landing = landingOptions[idx];
        }
      }

      const handIdx = g.handSpells[pid].findIndex(c => c.id === chosen.id);
      if (handIdx < 0) {
        g.log.unshift('Falling Star summon failed - card missing from hand.');
        requestGameSync?.();
        return;
      }
      const [removed] = g.handSpells[pid].splice(handIdx, 1) as Extract<Card, { kind: 'Unit' }>[];
      const summoned = summonUnitCardAt(g, pid, removed, landing.x, landing.y, 'surface', {
        bypassPlacement: true,
        summonSource: 'hand',
      });
      if (!summoned) {
        g.handSpells[pid].push(removed);
        g.log.unshift('Falling Star failed to summon the chosen minion.');
        requestGameSync?.();
        return;
      }
      g.log.unshift(`${summoned.name} crashes down as the Falling Star strikes.`);

      const others = unitArrayAtRegion(g, landing.x, landing.y, 'surface')
        .filter(u => (u as any).id !== summoned.id);
      if (others.length > 0) {
        const dmg = strikeDamagePlus(g, summoned);
        let hits = 0;
        for (const target of others) {
          if (dmg <= 0) continue;
          const amount = unitHasLethalAgainst(g, summoned, target)
            ? Math.max(dmg, unitThresholdHPPlus(g, target))
            : dmg;
          damageUnit(g, target, amount, { isDamage: true, sourceUnit: summoned });
          hits += 1;
        }
        if (hits > 0) {
          g.log.unshift(`Falling Star impact: ${summoned.name} strikes ${hits} unit(s).`);
        }
      }
      applyHoundsAuraForAll(g);
      requestGameSync?.();
    })();
  }
}

function processBetrayalReturns(g: Game, pid: PlayerId): void {
  for (const row of g.board) {
    for (const cell of row) {
      for (const unit of cell.units) {
        if (unit.kind === 'Avatar') continue;
        const prev = (unit as any)._betrayalPrevPid as PlayerId | undefined;
        const expires = (unit as any)._betrayalExpiresTurn as number | undefined;
        const caster = (unit as any)._betrayalCaster as PlayerId | undefined;
        if (prev != null && expires === g.turnNumber && caster === pid) {
          unit.player = prev;
          delete (unit as any)._betrayalPrevPid;
          delete (unit as any)._betrayalExpiresTurn;
          delete (unit as any)._betrayalCaster;
          refreshUnitArtifactPassives(g, unit);
          g.log.unshift(`${unit.name} returns to Player ${prev} as Betrayal ends.`);
        }
      }
    }
  }
}

function processAinoAtEndOfTurn(g: Game, pid: PlayerId): void {
  const units = g.board
    .flat()
    .flatMap(row => row.units)
    .filter(u => u.kind !== 'Avatar' && (u as any).player === pid && /^Aino$/i.test(u.name ?? '')) as Token[];
  for (const unit of units) {
    const ux = (unit as any).x as number | undefined;
    const uy = (unit as any).y as number | undefined;
    const region = ((unit as any).region ?? 'surface') as Region;
    if (region !== 'surface') continue;
    if (!Number.isFinite(ux) || !Number.isFinite(uy)) continue;
    if (uy !== 0 && uy !== g.height - 1) continue;
    const destY = uy === 0 ? g.height - 1 : 0;
    void (async () => {
      const want = await uiConfirm({
        title: 'Aino',
        message: formatTileText(g, 'Move between the top and bottom edges to gain Stealth?'),
        confirmLabel: 'Step across',
        cancelLabel: 'Stay',
      });
      if (!want) {
        requestGameSync?.();
        return;
      }
      moveUnitTo(g, unit, ux!, destY, region, { sourcePlayer: pid, bypassAnchor: true, ignoreGnome: true });
      if (canGainStealth(unit)) {
        (unit as Token).stealth = true;
        g.log.unshift('Aino slips between realms and gains Stealth.');
      } else {
        g.log.unshift('Aino crosses the realm but cannot gain Stealth.');
      }
      requestGameSync?.();
    })();
  }
}

function pickUpArtifacts(g: Game, pid: PlayerId, unitId: string) {
  const u = g.board.flat().flatMap(c => c.units).find(v => v.id === unitId)
  if (!u || u.player !== pid) return

  const ux = (u as any).x, uy = (u as any).y, ur = (u as any).region as Region
  const cell = cellOf(g, ux, uy)
  if (ur === 'surface' && redRockOfRavannisAt(g, ux, uy)) {
    g.log.unshift('Red Rock of Ravannis forbids carrying artifacts here.');
    return;
  }
  if (!Array.isArray((u as any).carrying)) (u as any).carrying = [];

  const isMagpie = /^Thieving Magpie$/i.test((u as any).name ?? '');
  let stolen = 0;
  if (isMagpie) {
    const carriers = unitArrayAtRegion(g, ux, uy, ur).filter(v => v.kind !== 'Avatar' && (v as any).id !== (u as any).id) as Token[];
    for (const carrier of carriers) {
      const arts = getCarriedArtifacts(g, carrier);
      for (const art of arts) {
        if (!artifactIsCarryable(art)) continue;
        const cost = art.cost ?? 0;
        if (cost > 1) continue;
        carrier.carrying = carrier.carrying?.filter(id => id !== art.id) ?? [];
        setArtifactCarrier(g, art, (u as any).id);
        art.x = ux; art.y = uy; art.region = ur;
        if (art.carriedBy === (u as any).id) {
          if (!Array.isArray((u as Token).carrying)) (u as Token).carrying = [];
          (u as Token).carrying.push(art.id);
        }
        handleArtifactRegionChange(g, art);
        refreshUnitArtifactPassives(g, carrier);
        stolen += 1;
      }
    }
  }

  const hereSurface = cell.artifacts.filter(a => a.carriedBy == null && artifactIsCarryable(a) && a.region === ur)

  let count = 0
  for (const a of hereSurface) {
    // Special pickup hooks
    if (a.name === '13 Treasures of Britain') {
      draw(g, pid, 'spells', 1);
      // Teleport the treasures to a random site (or any tile if none)
      const candidates: Array<{ x: number; y: number; region: Region }> = [];
      for (let y = 0; y < g.height; y++) {
        for (let x = 0; x < g.width; x++) {
          const c = cellOf(g, x, y);
          if (c.site && !c.site.rubble) candidates.push({ x, y, region: 'surface' });
        }
      }
      if (candidates.length === 0) {
        for (let y = 0; y < g.height; y++) for (let x = 0; x < g.width; x++) {
          candidates.push({ x, y, region: 'surface' });
        }
      }
      const idx = pickRandomIndex(g, candidates.length, { context: '13 Treasures of Britain' });
      const dest = candidates[Math.max(0, idx)];
      if (dest) {
        a.carriedBy = null;
        a.x = dest.x; a.y = dest.y; a.region = dest.region;
        const destCell = cellOf(g, dest.x, dest.y);
        if (!destCell.artifacts.some(s => s.id === a.id)) destCell.artifacts.push(a);
        syncCarryableArtifactController(g, a);
        handleArtifactRegionChange(g, a);
        g.log.unshift('The 13 Treasures of Britain vanish and reappear elsewhere!');
      }
      cell.artifacts = cell.artifacts.filter(s => s.id !== a.id);
      continue;
    }
    if (a.name === "Erik's Curiosa") {
      draw(g, pid, 'spells', 1);
      // Quick removal: manually delete from artifacts + cell, then fire region sync/log
      g.artifacts = g.artifacts.filter((art) => art.id !== a.id);
      cell.artifacts = cell.artifacts.filter(s => s.id !== a.id);
      handleArtifactRegionChange(g, a);
      syncCarryableArtifactController(g, a);
      g.log.unshift("Erik's Curiosa is ripped apart — draw a card.");
      cell.artifacts = cell.artifacts.filter(s => s.id !== a.id);
      continue;
    }

    a.carriedBy = (u as any).id
    setArtifactCarrier(g, a, (u as any).id);
    if (a.carriedBy === (u as any).id) {
      if (!Array.isArray((u as Token).carrying)) (u as Token).carrying = [];
      (u as Token).carrying.push(a.id)
      if ((a as any)._tabulaLock) {
        (u as any)._tabulaRasa = true;
      }
    }

    a.x = ux; a.y = uy; a.region = ur
    handleArtifactRegionChange(g, a)

    count++
  }

  cell.artifacts = cell.artifacts.filter(a => a.carriedBy == null)

  if (count > 0) g.log.unshift(`${u.name} picks up ${count} artifact(s).`)
  if (stolen > 0) g.log.unshift(`${u.name} snatches ${stolen} carried artifact(s) worth (1) or less.`)
  if (count > 0 || stolen > 0) {
    refreshManaForAll(g);
  }

  // Adventure mode: allow picking up face-up friendly cards as "equippable" (adds to hand).
  const adv: AdventureRuntime | undefined = (g as any)._adventure;
  let cardsAdded = 0;
  if (adv?.enabled && adv.scenario) {
    const key = advKey(ux, uy);
    const tile = adv.scenario.tiles[key];
    if (tile && Array.isArray(tile.cards) && tile.cards.length > 0) {
      const hostilePresent = tile.cards.some(c => (c.alignment ?? 'neutral') === 'hostile');
      if (!hostilePresent) {
        const takeable = tile.cards.filter(
          c =>
            !c.faceDown &&
            (c.alignment ?? 'neutral') !== 'hostile' &&
            !adventureStubIsSite(c)
        );
        if (takeable.length > 0) {
          let added = 0;
          for (const stub of takeable) {
            // Skip anything already claimed or marked as cast into play.
            if ((stub as any)._claimed || (stub as any)._casted) continue;
            const base = stub.card ?? getCardTemplateByName(stub.name);
            if (!base) continue;
            const inst = newCardInstance(base);
            if (inst.kind === 'Site') {
              // Sites cannot be picked up into hand; they must be played normally.
              continue;
            } else {
              g.handSpells[pid].push(inst);
            }
            added += 1;
            (stub as any)._claimed = true;
          }
          if (added > 0) {
            tile.cards = tile.cards.filter(c => !(c as any)._claimed);
            g.log.unshift(`${u.name} collects ${added} card(s) from the realm into hand.`);
            cardsAdded += added;
          } else {
            g.log.unshift(`${u.name} finds no eligible cards to collect here.`);
          }
        } else {
          g.log.unshift(`${u.name} finds no eligible cards to collect here.`);
        }
      } else {
        g.log.unshift(`${u.name} cannot pick up cards while hostile foes are present here.`);
      }
    }
  }
  if (count === 0 && stolen === 0 && cardsAdded === 0) {
    g.log.unshift(`${u.name} finds nothing to pick up.`);
  }
  refreshUnitArtifactPassives(g, u)
}
async function dropArtifacts(g: Game, pid: PlayerId, unitId: string) {
  const u = g.board.flat().flatMap(c => c.units).find(v => v.id === unitId)
  if (!u || u.player !== pid) return
  if (/^Lord of Greed$/i.test(u.name ?? '')) {
    g.log.unshift('Lord of Greed refuses to drop artifacts.');
    return;
  }
  if (g.turn !== pid || g.phase !== 'Main') {
    g.log.unshift('Drop can only be used during your main phase.');
    return;
  }
  if (g.resolving) {
    g.log.unshift('Cannot drop while the storyline is resolving.');
    return;
  }
  const t = u as Token
  const dropTurn = (u as any)._dropUsedTurn as number | undefined;
  if (dropTurn === g.turnNumber) {
    g.log.unshift('Drop can only be used once per turn.');
    return;
  }
  if ((u as any).interactedThisTurn) { g.log.unshift('Cannot drop: unit has already interacted this turn.'); return }
  if (!Array.isArray(t.carrying)) t.carrying = [];

  const ux = (u as any).x, uy = (u as any).y, ur = (u as any).region as Region
  const cell = cellOf(g, ux, uy)
  if (ur === 'surface' && Number.isFinite(ux) && Number.isFinite(uy) && auraByNameAtAny(g, 'Cursed Iron', ux, uy)) {
    g.log.unshift('Cursed Iron forbids dropping artifacts here.');
    return;
  }

  const carried = getCarriedArtifacts(g, t);
  const droppable = carried.filter(
    a => a.name !== 'Magnetic Muzzle' && a.name !== 'Blade of Thorns' && !(a as any)._tabulaLock
  );
  const muzzleOnly = carried.length > 0 && droppable.length === 0;
  if (muzzleOnly) {
    g.log.unshift('Magnetic Muzzle cannot be dropped and clings tightly.');
    return;
  }
  if (droppable.length === 0) {
    g.log.unshift(`${u.name} has no artifacts to drop.`);
    return;
  }

  let chosenList: Artifact[] = [];
  if (!isCpuPlayer(g, pid)) {
    const selection = await uiSelectMany<number>({
      title: 'Drop Artifacts',
      message: formatTileText(g, 'Select any artifacts to drop (or none to cancel).'),
      options: droppable.map((a, i) => ({ label: formatTileText(g, `${a.name}`), value: i })),
      initialSelected: droppable.map((_, i) => i),
      allowEmpty: true,
      confirmLabel: 'Drop Selected',
      cancelLabel: 'Cancel',
    });
    if (selection == null) {
      g.log.unshift('Drop cancelled.');
      return;
    }
    if (selection.length === 0) {
      g.log.unshift('No artifacts dropped.');
      return;
    }
    const uniq = Array.from(new Set(selection)).filter(i => i >= 0 && i < droppable.length);
    chosenList = uniq.map(i => droppable[i]).filter(Boolean);
  } else {
    chosenList = droppable.slice(); // CPU drops all droppable artifacts
  }

  if (chosenList.length === 0) {
    g.log.unshift('No artifact selected to drop.');
    return;
  }

  let droppedCount = 0;
  for (const chosen of chosenList) {
    chosen.carriedBy = null;
    chosen.x = ux; chosen.y = uy; chosen.region = ur;
    if (!cell.artifacts.some(s => s.id === chosen.id)) cell.artifacts.push(chosen);
    handleArtifactRegionChange(g, chosen);
    syncCarryableArtifactController(g, chosen);
    t.carrying = t.carrying.filter(id => {
      if (id === chosen.id) return false;
      const art = g.artifacts.find(a => a.id === id);
      return art && art.carriedBy === (u as any).id;
    });
    droppedCount += 1;
  }
  if (droppedCount > 0) {
    const label = droppedCount === 1 ? chosenList[0].name : `${droppedCount} artifacts`;
    g.log.unshift(`${u.name} drops ${label}.`);
    ;(u as any)._dropUsedTurn = g.turnNumber;
    ;(u as any).interactedThisTurn = true;
    refreshUnitArtifactPassives(g, u)
    refreshManaForAll(g);
  } else {
    g.log.unshift('No artifacts dropped.');
  }
}

function haastCarriedMinions(carrier: Token): Token[] {
  const list = (carrier as any)._carriedMinions
  if (Array.isArray(list)) return list
  const fresh: Token[] = []
  ;(carrier as any)._carriedMinions = fresh
  return fresh
}

function haastCarryMinion(g: Game, carrier: Token, target: Token) {
  const cell = cellOf(g, target.x, target.y)
  cell.units = cell.units.filter((u) => u.id !== target.id)
  if (multiTileLocations(target)) clearMultiTileOccupancy(g, target)
  target.carriedBy = carrier.id
  target.x = carrier.x
  target.y = carrier.y
  ;(target as any).region = carrier.region
  target.tapped = true
  target.summonedThisTurn = true
  const carried = haastCarriedMinions(carrier)
  carried.push(target)
  g.log.unshift(`${carrier.name} swoops up ${target.name}.`)
}

function haastDropCarriedMinions(g: Game, carrier: Token, opts?: { forced?: boolean }): boolean {
  const forced = !!opts?.forced;
  if (!forced) {
    const pid = carrier.player as PlayerId;
    if (g.turn !== pid || g.phase !== 'Main') {
      g.log.unshift(`${carrier.name} can only drop passengers during its controller's main phase.`);
      return false;
    }
    const dropTurn = (carrier as any)._dropUsedTurn as number | undefined;
    if (dropTurn === g.turnNumber) {
      g.log.unshift(`${carrier.name} has already used Drop this turn.`);
      return false;
    }
    if ((carrier as any).interactedThisTurn) {
      g.log.unshift(`${carrier.name} has already interacted this turn and cannot drop passengers.`);
      return false;
    }
  }

  const carried = haastCarriedMinions(carrier)
  if (carried.length === 0) return false
  const cell = cellOf(g, carrier.x, carrier.y)
  let dropped = 0;
  const remaining: Token[] = [];
  const droppedNames: string[] = [];
  for (const minion of carried) {
    if (!/^Undesirables$/i.test(minion.name ?? '')) {
      const blocked = cell.units.some(
        u =>
          u.kind !== 'Avatar' &&
          (u as any).player === minion.player &&
          /^Undesirables$/i.test(u.name ?? '')
      );
      if (blocked) {
        g.log.unshift(`${minion.name} cannot disembark — blocked by allied Undesirables here.`);
        remaining.push(minion);
        continue;
      }
    }
    delete minion.carriedBy
    minion.x = carrier.x
    minion.y = carrier.y
    ;(minion as any).region = carrier.region
    minion.tapped = true
    minion.summonedThisTurn = true
    if (!cell.units.some((u) => u.id === minion.id)) cell.units.push(minion)
    if (multiTileLocations(minion)) syncMultiTileOccupancy(g, minion)
    dropped += 1;
    if (minion.name) droppedNames.push(minion.name);
  }
  if (dropped > 0) {
    const label = droppedNames.length === 1 ? droppedNames[0] : `${droppedNames.length} minions`;
    g.log.unshift(`${carrier.name} releases ${label}.`);
  } else {
    g.log.unshift(`${carrier.name} cannot release passengers here.`);
  }
  (carrier as any)._carriedMinions = remaining
  if (!forced) {
    (carrier as Token).interactedThisTurn = true;
    (carrier as any)._dropUsedTurn = g.turnNumber;
  }
  return true
}

function releaseHaastCarriedMinions(g: Game, carrier: Token, x: number, y: number, region: Region) {
  const carried = (carrier as any)._carriedMinions as Token[] | undefined
  if (!carried || carried.length === 0) return
  const cell = cellOf(g, x, y)
  for (const minion of carried) {
    delete minion.carriedBy
    minion.x = x
    minion.y = y
    ;(minion as any).region = region
    minion.tapped = true
    minion.summonedThisTurn = true
    cell.units.push(minion)
    if (multiTileLocations(minion)) syncMultiTileOccupancy(g, minion)
    g.log.unshift(`${carrier.name} drops ${minion.name} as it falls.`)
  }
  (carrier as any)._carriedMinions = []
}

function renderThresholdBadges(th: Threshold): React.ReactNode {
  const parts: React.ReactNode[] = []
  ;(['Air', 'Earth', 'Fire', 'Water'] as Elem[]).forEach((elem) => {
    const value = th[elem] ?? 0
    if (value > 0) {
      parts.push(
        <span key={elem} style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
          <ElemIconImg e={elem} size={14} /> {value}
        </span>
      )
    }
  })
  return parts.length ? (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 10 }}>{parts}</span>
  ) : (
    <span>—</span>
  )
}

type CardBrowserAddAction = { label: string; onAdd: (card: Card) => void };

function CardBrowser({
  readOnly = false,
  onAdd,
  extraCards = [],
  thumbScale = 1,
  addLabel,
  addActions,
  enableRarityFilter = false,
  disableHover = false,
}: {
  readOnly?: boolean;
  onAdd?: (card: Card) => void;
  extraCards?: Card[];
  thumbScale?: number;
  addLabel?: string;
  addActions?: CardBrowserAddAction[];
  enableRarityFilter?: boolean;
  disableHover?: boolean;
}) {
  const [q, setQ] = useState('')
  const [kinds, setKinds] = useState<{ [k in Card['kind']]: boolean }>({ Site: true, Spell: true, Unit: true, ArtifactCard: true, AuraCard: true, Avatar: true } as any)
  const [elems, setElems] = useState<{ [e in Elem]: boolean }>({ Air: true, Earth: true, Fire: true, Water: true })
  const [rarities, setRarities] = useState<Record<AdvRarity, boolean>>({
    Ordinary: true,
    Exceptional: true,
    Elite: true,
    Unique: true,
  })

  const pool = useMemo(() => [...extraCards], [extraCards])

  const results = useMemo(() => {
    const qq = q.trim().toLowerCase()
    return pool
      .filter(c => kinds[c.kind] && (c.kind === 'Site' ? true : (c as any).element ? elems[(c as any).element as Elem] : true))
      .filter(c => !enableRarityFilter || rarities[cardRarityForAdventure(c)])
      .filter(c => { if (!qq) return true; const text = (c as any).text ?? ''; const bucket = `${c.name} ${text} ${(c as any).element ?? ''} ${c.kind}`; return bucket.toLowerCase().includes(qq) })
      .sort((a, b) => a.name.localeCompare(b.name))
  }, [q, kinds, elems, pool, enableRarityFilter, rarities])

  return (
    <div className="stack">
      <div className="rowwrap" style={{ gap: 6, flexWrap: 'wrap' }}>
        <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search cards by name, text, element…" style={{ padding: '8px 10px', background: '#0c1117', border: '1px solid #283241', borderRadius: 6, color: '#e5eefc', minWidth: 260 }} />
        <div className="rowwrap" style={{ gap: 6 }}>
          {(['Site', 'Spell', 'Unit', 'ArtifactCard', 'AuraCard', 'Avatar'] as Card['kind'][]).map((k) => (
            <label key={k} style={{ fontSize: 11, color: '#9fb0c2' }}>
              <input type="checkbox" checked={kinds[k]} onChange={() => setKinds({ ...kinds, [k]: !kinds[k] })} /> {k}
            </label>
          ))}
        </div>
        <div className="rowwrap" style={{ gap: 6 }}>
          {(['Air', 'Earth', 'Fire', 'Water'] as Elem[]).map((e) => (
            <label key={e} style={{ fontSize: 11, color: '#9fb0c2' }}>
              <input type="checkbox" checked={elems[e]} onChange={() => setElems({ ...elems, [e]: !elems[e] })} /> {elemIcon(e)} {e}
            </label>
          ))}
        </div>
        {enableRarityFilter && (
          <div className="rowwrap" style={{ gap: 6 }}>
            {(['Ordinary', 'Exceptional', 'Elite', 'Unique'] as AdvRarity[]).map((r) => (
              <label key={r} style={{ fontSize: 11, color: '#9fb0c2' }}>
                <input
                  type="checkbox"
                  checked={rarities[r]}
                  onChange={() => setRarities(prev => ({ ...prev, [r]: !prev[r] }))}
                /> {r}
              </label>
            ))}
          </div>
        )}
      </div>

      <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap' }}>
        {results.map((c) => (
          <CardBrowserItem
            key={(c as any).id}
            card={c}
            readOnly={readOnly}
            onAdd={onAdd}
            thumbScale={thumbScale}
            addLabel={addLabel}
            addActions={addActions}
            disableHover={disableHover}
          />
        ))}
        {results.length === 0 && <div style={{ color: '#9fb0c2', fontSize: 12 }}>No cards match.</div>}
      </div>
    </div>
  )
}

function CardBrowserItem({
  card,
  readOnly,
  onAdd,
  thumbScale,
  addLabel,
  addActions,
  disableHover,
}: {
  card: Card
  readOnly?: boolean
  onAdd?: (card: Card) => void
  thumbScale: number
  addLabel?: string
  addActions?: CardBrowserAddAction[]
  disableHover?: boolean
}) {
  const hb = disableHover ? null : useHoverBindingsForCard({ src: (card as any).image, name: card.name, cardKind: card.kind, baseWidth: 216, zoom: 1.5 })
  const canAdd = !readOnly && (!!onAdd || (addActions && addActions.length > 0));
  const defaultAddLabel = card.kind === 'Avatar'
    ? 'Add to Collection'
    : `Add to ${card.kind === 'Site' ? 'Atlas' : 'Spellbook'}`;

  return (
    <div
      style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6 }}
      tabIndex={0}
      onPointerEnter={hb?.onPointerEnter}
      onPointerMove={hb?.onPointerMove}
      onPointerLeave={hb?.onPointerLeave}
      onPointerUp={hb?.onPointerUp}
      onFocus={hb?.onFocus}
      onBlur={hb?.onBlur}
    >
      <MiniCard c={card} scale={thumbScale} showNameOverlay />
      {canAdd && (
        addActions && addActions.length > 0 ? (
          <div className="rowwrap" style={{ gap: 4, justifyContent: 'center' }}>
            {addActions.map((action) => (
              <button
                key={action.label}
                className="btn"
                onClick={() => action.onAdd(card)}
                style={{ fontSize: 11 }}
              >
                {action.label}
              </button>
            ))}
          </div>
        ) : (
          <button className="btn" onClick={() => onAdd && onAdd(card)}>
            {addLabel ?? defaultAddLabel}
          </button>
        )
      )}
    </div>
  )
}

function BinderPocket({
  card,
  onAdd,
  disableHover = false,
  dragData,
}: {
  card?: Card;
  onAdd?: (mode: 'click' | 'swipe') => void;
  disableHover?: boolean;
  dragData?: { id: string; zone?: string; pid?: string | number };
}) {
  const hb = disableHover ? null : useHoverBindingsForCard({
    src: (card as any)?.image,
    name: card?.name,
    cardKind: card?.kind,
    baseWidth: 216,
    zoom: 2.2,
    context: 'default',
  });
  const cardImageSrcs = useMemo(() => buildAssetFallbacks((card as any)?.image), [((card as any)?.image as string | undefined)]);
  const canAdd = Boolean(card && onAdd);
  const swipeRef = useRef<{ x: number; y: number; active: boolean; swiped: boolean }>({ x: 0, y: 0, active: false, swiped: false });
  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!canAdd) return;
    swipeRef.current = { x: e.clientX, y: e.clientY, active: true, swiped: false };
  };
  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (swipeRef.current.active && canAdd) {
      const dx = e.clientX - swipeRef.current.x;
      const dy = e.clientY - swipeRef.current.y;
      if (dy < -70 && Math.abs(dx) < 120) {
        swipeRef.current.swiped = true;
        onAdd?.('swipe');
        window.setTimeout(() => {
          swipeRef.current.swiped = false;
        }, 120);
      }
    }
    swipeRef.current.active = false;
    hb?.onPointerUp?.(e);
  };
  const handleClick = () => {
    if (!canAdd) return;
    if (swipeRef.current.swiped) {
      swipeRef.current.swiped = false;
      return;
    }
    onAdd?.('click');
  };
  return (
    <div
      role={canAdd ? 'button' : undefined}
      tabIndex={0}
      onClick={handleClick}
      onPointerDown={handlePointerDown}
      onPointerEnter={hb?.onPointerEnter}
      onPointerMove={hb?.onPointerMove}
      onPointerLeave={hb?.onPointerLeave}
      onPointerUp={handlePointerUp}
      onFocus={hb?.onFocus}
      onBlur={hb?.onBlur}
      draggable={canAdd}
      onDragStart={(e) => {
        if (!card) return;
        e.dataTransfer.setData('text/plain', card.id);
        e.dataTransfer.setData('text/card-name', card.name ?? '');
        e.dataTransfer.effectAllowed = 'copy';
        if (dragData) {
          e.dataTransfer.setData('application/x-gm-card', JSON.stringify(dragData));
        }
      }}
      style={{
        width: '100%',
        aspectRatio: '63 / 88',
        minHeight: 195,
        borderRadius: 12,
        border: '1px solid #1f2937',
        background: 'linear-gradient(180deg, #151c29, #0d131f)',
        boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.06), 0 12px 24px rgba(0,0,0,0.35)',
        padding: 6,
        position: 'relative',
        overflow: 'hidden',
        cursor: canAdd ? 'pointer' : 'default',
      }}
    >
      <div
        style={{
          position: 'absolute',
          inset: 6,
          borderRadius: 10,
          border: '1px dashed rgba(255,255,255,0.08)',
          pointerEvents: 'none',
        }}
      />
      <div
        style={{
          position: 'absolute',
          top: 8,
          left: 8,
          right: 8,
          bottom: 8,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        {card ? (
          cardImageSrcs.length > 0 ? (
            <img
              src={cardImageSrcs[0]}
              data-fallbacks={cardImageSrcs.slice(1).join('|')}
              alt={card.name}
              onError={advanceImageFallback}
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'contain',
                borderRadius: 10,
                boxShadow: '0 6px 16px rgba(0,0,0,0.35)',
              }}
              draggable={false}
            />
          ) : (
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: '100%', height: '100%' }}>
              <MiniCard c={card} scale={2.6} />
            </div>
          )
        ) : (
          <div style={{ fontSize: 12, color: '#6b7280' }}>Empty pocket</div>
        )}
      </div>
    </div>
  );
}

function DeckBuilder({
  initial,
  initialName,
  initialShowcase,
  prefillListText,
  onPrefillListConsumed,
  onSave,
  cardPool,
}: {
  initial?: Decks;
  initialName?: string;
  initialShowcase?: DeckShowcase | null;
  prefillListText?: string | null;
  onPrefillListConsumed?: () => void;
  onSave: (d: Decks, meta?: { name?: string; showcase?: DeckShowcase | null }) => void;
  cardPool: Card[];
}) {
  const [atlas, setAtlas] = useState<Card[]>(() => initial?.atlas ?? [])
  const [spells, setSpells] = useState<Card[]>(() => initial?.spellbook ?? [])
  const [collection, setCollection] = useState<Card[]>(() => initial?.collection ?? [])
  const [avatarCard, setAvatarCard] = useState<Extract<Card, { kind: 'Avatar' }> | null>(
    () => (initial?.avatar ? newCardInstance(initial.avatar) : null)
  )
  const [tab, setTab] = useState<'shelves' | 'build'>('shelves')
  const [listText, setListText] = useState('')
  const [binderQuery, setBinderQuery] = useState('')
  const [currentName, setCurrentName] = useState<string | null>(initialName ?? null)
  const [binderKinds, setBinderKinds] = useState<{ [k in Card['kind']]: boolean }>({
    Site: true,
    Spell: true,
    Unit: true,
    ArtifactCard: true,
    AuraCard: true,
    Avatar: true,
  } as any)
  const [binderElems, setBinderElems] = useState<{ [e in Elem]: boolean }>({ Air: true, Earth: true, Fire: true, Water: true })
  const [importUrl, setImportUrl] = useState('')
  const [importingUrl, setImportingUrl] = useState(false)
  const [simGames, setSimGames] = useState(1000)
  const [showcaseSearch, setShowcaseSearch] = useState('')
  const [showcasePickerOpen, setShowcasePickerOpen] = useState(false)
  const [showcaseOptions, setShowcaseOptions] = useState<Card[]>([])
  const [currentShowcase, setCurrentShowcase] = useState<DeckShowcase | null>(
    () => initialShowcase ?? (initial?.avatar ? { name: initial.avatar.name, image: initial.avatar.image } : null)
  )
  const [showcaseSource, setShowcaseSource] = useState<'avatar' | 'custom' | null>(
    () => (initialShowcase ? 'custom' : (initial?.avatar ? 'avatar' : null))
  )
  const showcaseResolver = useRef<((value: DeckShowcase | null) => void) | null>(null)
  const [playerShelf, setPlayerShelf] = useState<PlayerShelfEntry[]>(() => {
    if (typeof window === 'undefined' || !window.localStorage) return [];
    try {
      const raw = window.localStorage.getItem(PLAYER_SHELF_KEY);
      const parsed = raw ? JSON.parse(raw) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  })

  useEffect(() => {
    if (typeof window === 'undefined' || !window.localStorage) return;
    try {
      window.localStorage.setItem(PLAYER_SHELF_KEY, JSON.stringify(playerShelf));
    } catch {}
  }, [playerShelf]);

  useEffect(() => {
    if (showcaseSource === 'custom') return;
    if (avatarCard) {
      setCurrentShowcase({ name: avatarCard.name, image: avatarCard.image });
      setShowcaseSource('avatar');
    } else {
      setCurrentShowcase(null);
      setShowcaseSource(null);
    }
  }, [avatarCard, showcaseSource]);

  const addCardTo = (p: Card, count = 1, target?: 'spellbook' | 'collection' | 'atlas' | 'avatar') => {
    const copies = Array.from({ length: count }, () => newCardInstance(p))
    if (p.kind === 'Avatar') {
      if (target === 'collection') {
        setCollection((c) => [...c, ...copies]);
      } else {
        const next = newCardInstance(p) as Extract<Card, { kind: 'Avatar' }>;
        setAvatarCard(next);
      }
      return;
    }
    if (target === 'collection') setCollection((c) => [...c, ...copies]);
    else if (target === 'atlas') setAtlas((a) => [...a, ...copies]);
    else if (p.kind === 'Site') setAtlas((a) => [...a, ...copies]);
    else setSpells((s) => [...s, ...copies]);
  }
  const removeCard = (id: string) => {
    setAtlas((a) => a.filter(c => c.id !== id));
    setSpells((s) => s.filter(c => c.id !== id));
    setCollection((c) => c.filter(card => card.id !== id));
  }
  const clear = () => {
    setAtlas([]);
    setSpells([]);
    setCollection([]);
    setAvatarCard(null);
    setCurrentName(null);
    setCurrentShowcase(null);
    setShowcaseSource(null);
  }
  const findByName = (name: string) => cardPool.find(c => c.name.toLowerCase() === name.toLowerCase())
  const cloneDeck = (deck: Decks): Decks => ({
    atlas: (deck.atlas ?? []).map(cloneCard),
    spellbook: (deck.spellbook ?? []).map(cloneCard),
    collection: (deck.collection ?? []).map(cloneCard),
    avatar: deck.avatar ? cloneCard(deck.avatar) : null,
  })
  useEffect(() => {
    setCurrentName(initialName ?? null);
  }, [initialName]);

  useEffect(() => {
    if (initialShowcase) {
      setCurrentShowcase(initialShowcase);
      setShowcaseSource('custom');
    } else {
      setShowcaseSource(avatarCard ? 'avatar' : null);
    }
  }, [initialShowcase, avatarCard]);

  useEffect(() => {
    if (!prefillListText) return;
    setTab('build');
    setListText(prefillListText);
    onPrefillListConsumed?.();
  }, [onPrefillListConsumed, prefillListText]);

  const loadDeckIntoBuilder = (
    deck: Decks,
    name?: string,
    showcase?: DeckShowcase | null
  ) => {
    const cloned = cloneDeck(deck);
    let resolvedAvatar = cloned.avatar ?? null;
    if (!resolvedAvatar && Array.isArray(cloned.collection)) {
      const idx = cloned.collection.findIndex(c => c.kind === 'Avatar');
      if (idx >= 0) {
        resolvedAvatar = cloned.collection.splice(idx, 1)[0] as Extract<Card, { kind: 'Avatar' }>;
      }
    }
    setAtlas(cloned.atlas);
    setSpells(cloned.spellbook);
    setCollection(cloned.collection ?? []);
    setAvatarCard(resolvedAvatar);
    setTab('build');
    if (name) setCurrentName(name);
    if (showcase) {
      setCurrentShowcase(showcase);
      setShowcaseSource('custom');
    } else {
      setShowcaseSource('avatar');
    }
  };

  const importList = () => {
    const lines = listText.split('\n').map(s => s.trim()).filter(Boolean)
    const additions: { p: Card, n: number }[] = []
    for (const line of lines) {
      let n = 1, name = line
      const m1 = line.match(/x\s*(\d+)$/i); if (m1) { n = Math.max(1, parseInt(m1[1], 10)); name = line.replace(m1[0], '').trim() }
      const m2 = line.match(/^(\d+)\s+(.+)$/); if (m2) { n = Math.max(1, parseInt(m2[1], 10)); name = m2[2].trim() }
      const found = findByName(name); if (found) additions.push({ p: found, n })
    }
    for (const { p, n } of additions) {
      addCardTo(p, n);
    }
    setListText('')
  }
  const addCopiesToTarget = async (
    card: Card,
    count: number,
    target?: 'atlas' | 'spellbook' | 'collection' | 'avatar'
  ) => {
    if (!Number.isFinite(count) || count <= 0) return;
    if (card.kind === 'Avatar') {
      if (target === 'collection') {
        addCardTo(card, count, 'collection');
      } else {
        addCardTo(card, 1, 'avatar');
      }
      return;
    }
    if (target === 'avatar') {
      await uiAlert({ title: 'Invalid drop', message: 'Only avatar cards can be added to the Avatar slot.' });
      return;
    }
    if (target === 'atlas' && card.kind !== 'Site') {
      await uiAlert({ title: 'Invalid drop', message: 'Only site cards can be added to the Atlas.' });
      return;
    }
    if (target === 'spellbook' && card.kind === 'Site') {
      await uiAlert({ title: 'Invalid drop', message: 'Site cards must be added to the Atlas.' });
      return;
    }
    const resolvedTarget = target ?? (card.kind === 'Site' ? 'atlas' : 'spellbook');
    addCardTo(card, count, resolvedTarget);
  };

  const handleCarouselAdd = async (card: Card, mode: 'click' | 'swipe' | 'drag' = 'click') => {
    if (mode === 'click') {
      const countInput = await uiPrompt({
        title: card.name ?? 'Add Card',
        message: 'How many copies would you like to add?',
        defaultValue: '1',
        placeholder: '1',
        confirmLabel: 'Add',
        cancelLabel: 'Cancel',
        allowEmpty: false,
      });
      if (countInput == null) return;
      const parsedCount = parseInt(countInput, 10);
      if (!Number.isFinite(parsedCount) || parsedCount <= 0) {
        await uiAlert({ title: 'Invalid count', message: 'Please enter a whole number of 1 or more.' });
        return;
      }
      await addCopiesToTarget(card, parsedCount);
      return;
    }
    await addCopiesToTarget(card, 1);
  };

  const stackCardsForTray = (cards: Card[]) => {
    const map = new Map<string, { card: Card; count: number }>();
    for (const card of cards) {
      const key = `${card.name}|${card.kind}|${(card as any).element ?? ''}|${(card as any).setCode ?? ''}`;
      const entry = map.get(key);
      if (entry) entry.count += 1;
      else map.set(key, { card, count: 1 });
    }
    return Array.from(map.values()).sort((a, b) => a.card.name.localeCompare(b.card.name));
  };

  const atlasStacks = useMemo(() => stackCardsForTray(atlas), [atlas]);
  const spellStacks = useMemo(() => stackCardsForTray(spells), [spells]);
  const collectionStacks = useMemo(() => stackCardsForTray(collection), [collection]);

  const normalizeDeckName = (name: string) => name.trim().replace(/\s+/g, ' ').toLowerCase();
  const deckCardIndex = useMemo(() => {
    const map = new Map<string, Card>();
    for (const card of cardPool) map.set(normalizeDeckName(card.name), card);
    return map;
  }, [cardPool]);

  const buildDeckFromCuriosa = (entries: CuriosaDeckEntry[], avatarName?: string) => {
    const nextAtlas: Card[] = [];
    const nextSpells: Card[] = [];
    const nextCollection: Card[] = [];
    const missing: string[] = [];

    const pushCopies = (card: Card, count: number, zone?: 'atlas' | 'spellbook' | 'collection') => {
      let resolvedZone = zone;
      if (!resolvedZone) {
        resolvedZone = card.kind === 'Site' ? 'atlas' : card.kind === 'Avatar' ? 'collection' : 'spellbook';
      }
      if (resolvedZone === 'atlas' && card.kind !== 'Site') resolvedZone = card.kind === 'Avatar' ? 'collection' : 'spellbook';
      if (resolvedZone === 'spellbook' && card.kind === 'Site') resolvedZone = 'atlas';
      if (resolvedZone === 'collection' && card.kind !== 'Avatar' && card.kind === 'Site') {
        resolvedZone = 'atlas';
      }
      const list = resolvedZone === 'atlas' ? nextAtlas : resolvedZone === 'collection' ? nextCollection : nextSpells;
      for (let i = 0; i < count; i++) list.push(newCardInstance(card));
    };

    const addByName = (name: string, count: number, zone?: 'atlas' | 'spellbook' | 'collection') => {
      const card = deckCardIndex.get(normalizeDeckName(name));
      if (!card) {
        missing.push(name);
        return;
      }
      pushCopies(card, count, zone);
    };

    for (const entry of entries) {
      addByName(entry.name, entry.count, entry.zone);
    }

    if (avatarName) {
      const alreadyIncluded = entries.some((entry) => normalizeDeckName(entry.name) === normalizeDeckName(avatarName));
      if (!alreadyIncluded) addByName(avatarName, 1, 'collection');
    }

    return { deck: { atlas: nextAtlas, spellbook: nextSpells, collection: nextCollection }, missing };
  };

  const formatCuriosaListLines = (entries: CuriosaDeckEntry[]) =>
    entries
      .filter((entry) => entry.name && entry.count > 0)
      .map((entry) => `${entry.count} ${entry.name.trim()}`);

  const importDeckFromUrl = async () => {
    const url = importUrl.trim();
    if (!url) return;
    setImportingUrl(true);
    const proxyBase =
      (import.meta as any).env?.VITE_CURIOSA_PROXY?.trim?.() ||
      (import.meta.env.DEV ? '/curiosa-trpc' : '');
    try {
      const deckId = parseCuriosaDeckId(url);
      if (!deckId) {
        throw new CuriosaImportError('bad_id', 'Only Curiosa deck URLs are supported right now.');
      }

      const raw = await fetchCuriosaDeckJson(deckId, {
        debug: import.meta.env.DEV,
        proxyBase,
      });
      let parsed: ReturnType<typeof parseCuriosaDeckResponse>;
      try {
        parsed = parseCuriosaDeckResponse(raw, deckId);
      } catch (err: any) {
        if (err instanceof CuriosaImportError && err.code === 'parse_failed') {
          const categories = extractCuriosaCategoryLists(raw);
          const deckLines = [
            ...formatCuriosaListLines(categories.Aura),
            ...formatCuriosaListLines(categories.Artifact),
            ...formatCuriosaListLines(categories.Minion),
            ...formatCuriosaListLines(categories.Magic),
            ...formatCuriosaListLines(categories.Site),
          ];
          const collectionLines = formatCuriosaListLines(categories.Collection);

          if (deckLines.length > 0) {
            setListText(deckLines.join('\n'));
          }

          if (collectionLines.length > 0) {
            // eslint-disable-next-line no-console
            console.log('[Curiosa Collection]\n' + collectionLines.join('\n'));
          }

          await uiAlert({
            title: 'Curiosa import fallback',
            message: deckLines.length
              ? 'We could not auto-parse the deck, so the card names were placed into Import by List (with counts). Scroll down and click “Add from List”. Collection cards (if any) were logged to the console separately.'
              : 'We could not auto-parse the deck and no list entries were detected. Try another deck URL.',
          });
          return;
        }
        throw err;
      }
      const { deck, missing } = buildDeckFromCuriosa(parsed.entries, parsed.avatarName ?? undefined);

      if (deck.atlas.length + deck.spellbook.length + (deck.collection?.length ?? 0) === 0) {
        throw new CuriosaImportError('parse_failed', 'Curiosa returned a deck with no recognizable cards.');
      }

      setAtlas(deck.atlas);
      setSpells(deck.spellbook);
      setCollection(deck.collection ?? []);
      setTab('build');
      setImportUrl('');

      const total = deck.atlas.length + deck.spellbook.length + (deck.collection?.length ?? 0);
      if (missing.length > 0) {
        await uiAlert({
          title: 'Import completed with missing cards',
          message: `Imported ${total} card(s). Missing: ${missing.slice(0, 12).join(', ')}${missing.length > 12 ? '…' : ''}`,
        });
      } else {
        await uiAlert({
          title: 'Import complete',
          message: `Imported ${total} card(s).`,
        });
      }
    } catch (err: any) {
      if (err instanceof CuriosaImportError) {
        const message =
          err.code === 'bad_id'
            ? 'Please paste a Curiosa deck URL like https://curiosa.io/decks/<id>.'
            : err.code === 'not_found'
              ? 'Deck not found or is private on Curiosa.'
              : err.code === 'fetch_failed'
                ? 'Unable to reach Curiosa. This can be a network or CORS issue.'
                + (proxyBase ? ' If you are using a proxy, ensure it is running and reachable.' : ' If this persists, configure VITE_CURIOSA_PROXY or run the dev proxy.')
                : err.code === 'parse_failed'
                  ? err.message
                  : 'Unable to import this deck URL.';
        await uiAlert({ title: 'Import failed', message });
        return;
      }
      await uiAlert({ title: 'Import failed', message: err?.message ?? 'Unknown error.' });
    } finally {
      setImportingUrl(false);
    }
  };

  const handleTrayDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    if (e.dataTransfer) e.dataTransfer.dropEffect = 'copy';
  };

  const handleTrayDrop = async (
    e: React.DragEvent<HTMLDivElement>,
    target: 'atlas' | 'spellbook' | 'collection' | 'avatar'
  ) => {
    e.preventDefault();
    const cardId = e.dataTransfer.getData('text/plain');
    const cardName = e.dataTransfer.getData('text/card-name');
    const card =
      cardPool.find((c) => c.id === cardId) ||
      (cardName ? findByName(cardName) : undefined);
    if (!card) {
      await uiAlert({ title: 'Card not found', message: 'That card could not be found in the card pool.' });
      return;
    }
    await addCopiesToTarget(card, 1, target);
  };

  const openShowcasePicker = (options: Card[]) =>
    new Promise<DeckShowcase | null>((resolve) => {
      showcaseResolver.current = resolve;
      setShowcaseOptions(options);
      setShowcaseSearch('');
      setShowcasePickerOpen(true);
    });

  const closeShowcasePicker = (value: DeckShowcase | null) => {
    setShowcasePickerOpen(false);
    const resolve = showcaseResolver.current;
    showcaseResolver.current = null;
    resolve?.(value);
  };

  const pickShowcaseCard = async (): Promise<DeckShowcase | null> => {
    const combined = [...atlas, ...spells, ...collection];
    if (avatarCard) combined.unshift(avatarCard);
    if (combined.length === 0) return null;
    const unique = new Map<string, Card>();
    for (const c of combined) {
      if (!unique.has(c.name)) unique.set(c.name, c);
    }
    const options = Array.from(unique.values()).sort((a, b) => a.name.localeCompare(b.name));
    return openShowcasePicker(options);
  };

  const deleteFromPlayerShelf = async (entry: { id: string; name: string }) => {
    const ok = await uiConfirm({
      title: 'Delete deck?',
      message: `Delete "${entry.name}" from your Player Shelf?`,
      confirmLabel: 'Delete',
      cancelLabel: 'Cancel',
    });
    if (!ok) return;
    setPlayerShelf((prev) => prev.filter((d) => d.id !== entry.id));
  };

  const saveToPlayerShelf = async () => {
    const total = atlas.length + spells.length + collection.length;
    if (total === 0) {
      await uiAlert({ title: 'Nothing to save', message: 'Add cards before saving a deck.' });
      return;
    }
    const nameInput = await uiPrompt({
      title: 'Save to Player Shelf',
      message: 'Name this deck.',
      defaultValue: 'Custom Deck',
      placeholder: 'Deck name',
      confirmLabel: 'Save',
      cancelLabel: 'Cancel',
      allowEmpty: false,
    });
    if (!nameInput) return;
    const name = nameInput.trim();
    if (!name) return;
    const showcase =
      currentShowcase ??
      (avatarCard ? { name: avatarCard.name, image: avatarCard.image } : undefined);

    const existing = playerShelf.find((d) => d.name.toLowerCase() === name.toLowerCase());
    if (existing) {
      const overwrite = await uiConfirm({
        title: 'Overwrite deck?',
        message: `A deck named "${name}" already exists on your Player Shelf. Replace it?`,
        confirmLabel: 'Replace',
        cancelLabel: 'Cancel',
      });
      if (!overwrite) return;
      setPlayerShelf((prev) =>
        prev.map((entry) =>
          entry.id === existing.id
            ? {
                ...entry,
                name,
                decks: structuredClone({ atlas, spellbook: spells, collection, avatar: avatarCard ?? null }),
                savedAt: Date.now(),
                showcase,
              }
            : entry
        )
      );
      setCurrentName(name);
      if (showcase) {
        setCurrentShowcase(showcase);
        setShowcaseSource(currentShowcase ? showcaseSource : 'avatar');
      }
      return;
    }
    setPlayerShelf((prev) => [
      {
        id: uid(),
        name,
        decks: structuredClone({ atlas, spellbook: spells, collection, avatar: avatarCard ?? null }),
        savedAt: Date.now(),
        showcase,
      },
      ...prev,
    ]);
    setCurrentName(name);
    if (showcase) {
      setCurrentShowcase(showcase);
      setShowcaseSource(currentShowcase ? showcaseSource : 'avatar');
    }
  };
  const binderFiltered: Card[] = useMemo(() => {
    const q = binderQuery.trim().toLowerCase();
    return cardPool
      .filter(c => binderKinds[c.kind])
      .filter(c => (c.kind === 'Site' || c.kind === 'Avatar') ? true : binderElems[(c as any).element as Elem] ?? true)
      .filter(c => {
        if (!q) return true;
        const text = (c as any).text ?? '';
        const setName = (c as any).setName ?? '';
        const setCode = (c as any).setCode ?? '';
        const bucket = `${c.name} ${text} ${(c as any).element ?? ''} ${c.kind} ${setName} ${setCode}`;
        return bucket.toLowerCase().includes(q);
      })
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [cardPool, binderQuery, binderKinds, binderElems]);

  const binderCards = binderFiltered;
  const showcaseFiltered = useMemo(() => {
    const q = showcaseSearch.trim().toLowerCase();
    if (!q) return showcaseOptions;
    return showcaseOptions.filter((c) => {
      const text = (c as any).text ?? '';
      const bucket = `${c.name} ${text} ${(c as any).element ?? ''} ${c.kind}`;
      return bucket.toLowerCase().includes(q);
    });
  }, [showcaseOptions, showcaseSearch]);

function loadPreconByName(label: PreconName) {
  const list = PRECONS[label];
  setAtlas([]); setSpells([]); setCollection([]);
  setAvatarCard(null);
  setCurrentName(null);
  setCurrentShowcase(null);
  setShowcaseSource(null);
  let added = 0, missed: string[] = [];

  for (const raw of list) {
    const { name, n } = parseLine(raw);
    const found = findByName(name);
    if (found) { addCardTo(found, n); added += n; } else { missed.push(name); }
  }

  setTab('build');
  const avatar = cardPool.find(
    (card): card is Extract<Card, { kind: 'Avatar' }> =>
      card.kind === 'Avatar' && card.name.toLowerCase() === label.toLowerCase()
  );
  if (avatar) {
    const inst = newCardInstance(avatar);
    setAvatarCard(inst);
    setCurrentShowcase({ name: inst.name, image: inst.image });
    setShowcaseSource('avatar');
  }
  // eslint-disable-next-line no-console
  console.log(`[Precon ${label}] added ${added}. Missing: ${missed.join(", ") || "none"}`);
}

  const decks: Decks = { atlas, spellbook: spells, collection, avatar: avatarCard ?? null }
  const exportDecklistText = useMemo(
    () => formatDeckAsImportList(decks),
    [atlas, spells, collection, avatarCard]
  );
  const copyDecklist = useCallback(async () => {
    const text = exportDecklistText.trim();
    if (!text) {
      await uiAlert({ title: 'Nothing to export', message: 'Add cards before copying a decklist.' });
      return;
    }
    try {
      if (typeof navigator !== 'undefined' && navigator.clipboard?.writeText) {
        await navigator.clipboard.writeText(text);
        await uiAlert({ title: 'Decklist copied', message: 'Decklist copied to clipboard.' });
        return;
      }
    } catch {
      // fall through to prompt fallback
    }
    await uiPrompt({
      title: 'Decklist',
      message: 'Clipboard is unavailable. Copy this decklist manually.',
      defaultValue: text,
      allowEmpty: true,
      confirmLabel: 'Close',
      cancelLabel: 'Close',
    });
  }, [exportDecklistText]);
  const totalCards = atlas.length + spells.length + collection.length
  const constructedIssues = constructedDeckWarnings(decks);

  const { decklist, cardIndex } = useMemo(() => {
    const cards = [...atlas, ...spells];
    const index: CardIndex = {};
    const list: DeckEntry[] = [];
    for (const c of cards) {
      index[c.id] = c;
      list.push({ cardId: c.id, qty: 1 });
    }
    return { decklist: list, cardIndex: index };
  }, [atlas, spells]);

  const deckStats: DeckStats | null = useMemo(() => {
    if (decklist.length === 0) return null;
    return computeDeckStats(decklist, cardIndex);
  }, [decklist, cardIndex]);

  const simResult: SimulationResult | null = useMemo(() => {
    if (decklist.length === 0) return null;
    return simulateDraws(decklist, cardIndex, { games: simGames, turns: 5, seed: 4242 });
  }, [decklist, cardIndex, simGames]);

  const suggestions = useMemo(() => deckStats ? suggestFromStats(deckStats) : [], [deckStats]);

  const confirmSave = () => {
    const warnings = constructedDeckWarnings(decks);
    if (warnings.length > 0) {
      const proceed = window.confirm(
        `Deck is not Constructed legal:\n- ${warnings.join('\n- ')}\n\nSave anyway?`
      );
      if (!proceed) return;
    }
    onSave(decks, { name: currentName ?? undefined, showcase: currentShowcase ?? null });
    setTab('build');
  };

  const toolbarButtonStyle: React.CSSProperties = {
    minWidth: 150,
    padding: '12px 20px',
    fontSize: 15,
    fontWeight: 600,
  }

  const preconCardStyle: React.CSSProperties = {
    width: 150,
    padding: 8,
    borderRadius: 14,
    border: '1px solid #283241',
    background: 'linear-gradient(180deg, #111823 0%, #090d13 100%)',
    display: 'flex',
    flexDirection: 'column',
    gap: 8,
    alignItems: 'center',
    color: '#e5eefc',
    fontWeight: 600,
    fontSize: 14,
    boxShadow: '0 6px 18px rgba(0,0,0,0.35)',
    transition: 'transform 120ms ease, box-shadow 120ms ease, border-color 120ms ease',
  };

  const TabBtn = ({ id, label }: { id: 'shelves' | 'build'; label: string }) => (
    <button
      className="btn"
      onClick={() => setTab(id)}
      style={{
        ...toolbarButtonStyle,
        borderColor: tab === id ? '#7dd3fc' : '#283241',
        boxShadow: tab === id ? '0 0 0 3px rgba(125,211,252,.25)' : undefined,
      }}
    >
      {label}
    </button>
  )
  const deckTilts = [-3, 2.5, -2.5, 3];

  return (
    <div className="stack" style={{ gap: 24 }}>
      <div className="stack" style={{ gap: 16, alignItems: 'center' }}>
        <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap', justifyContent: 'center' }}>
          <TabBtn id="shelves" label="Shelves" />
          <TabBtn id="build" label="Build" />
        </div>
        {constructedIssues.length > 0 && (
          <div style={{ color: '#fbbf24', fontSize: 12, textAlign: 'center' }}>
            {constructedIssues.map((msg, i) => (
              <div key={i}>⚠ {msg}</div>
            ))}
          </div>
        )}
        {tab === 'shelves' && (
          <>
            <div className="stack" style={{ gap: 10, width: '100%' }}>
              <span style={{ fontSize: 12, color: '#7dd3fc', textTransform: 'uppercase', letterSpacing: 1 }}>
                Player Shelf
              </span>
              <div
                className="shelf"
                style={{
                  padding: '12px 10px 18px',
                  borderRadius: 12,
                  position: 'relative',
                }}
              >
                <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap', justifyContent: 'center', alignItems: 'flex-end' }}>
                  {playerShelf.length === 0 && (
                    <div style={{ color: '#9fb0c2', fontSize: 12 }}>No saved decks yet.</div>
                  )}
                  {playerShelf.map((entry, idx) => {
                    const tilt = deckTilts[idx % deckTilts.length];
                    const atlasCount = entry.decks?.atlas?.length ?? 0;
                    const spellCount = entry.decks?.spellbook?.length ?? 0;
                    const collectionCount = entry.decks?.collection?.length ?? 0;
                    const showcase = entry.showcase;
                    const showcaseSrcs = showcase?.image ? buildAssetFallbacks(showcase.image) : [];
                    return (
                      <div
                        key={entry.id}
                        className="deck-stack-wrap"
                        style={{ ['--deck-tilt' as any]: `${tilt}deg`, ['--deck-tilt-inv' as any]: `${-tilt}deg` } as React.CSSProperties}
                      >
                        <button
                          type="button"
                          className="deck-stack"
                          onClick={() => loadDeckIntoBuilder(entry.decks, entry.name, entry.showcase ?? null)}
                          title={`Load ${entry.name}`}
                        >
                          <div className="deck-stack__cards">
                            <span className="deck-stack__card layer-1" />
                            <span className="deck-stack__card layer-2" />
                            <span className="deck-stack__card layer-3" />
                            {showcase?.image ? (
                              <img
                                className="deck-stack__showcase"
                                src={showcaseSrcs[0] ?? showcase.image}
                                data-fallbacks={showcaseSrcs.slice(1).join('|')}
                                alt={showcase.name}
                                onError={advanceImageFallback}
                              />
                            ) : showcase?.name ? (
                              <div className="deck-stack__showcase-fallback">{showcase.name}</div>
                            ) : null}
                          </div>
                          <div className="deck-stack__label">{entry.name}</div>
                          <div className="deck-stack__meta">
                            Atlas {atlasCount} • Spellbook {spellCount} • Collection {collectionCount}
                          </div>
                        </button>
                        <button
                          type="button"
                          className="deck-stack__delete"
                          onClick={(e) => {
                            e.stopPropagation();
                            deleteFromPlayerShelf(entry);
                          }}
                          title="Delete deck"
                        >
                          ✕
                        </button>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
            <div className="stack" style={{ gap: 10, width: '100%' }}>
              <span style={{ fontSize: 12, color: '#7dd3fc', textTransform: 'uppercase', letterSpacing: 1 }}>
                Preconstructed Shelf
              </span>
              <div
                className="shelf"
                style={{
                  padding: '12px 10px 18px',
                  borderRadius: 12,
                  position: 'relative',
                }}
              >
                <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap', justifyContent: 'center', alignItems: 'flex-end' }}>
                  {(Object.keys(PRECONS) as PreconName[]).map((name, idx) => {
                    const tilt = deckTilts[idx % deckTilts.length];
                    const showcase = { name, image: preconAvatarImage(name) };
                    const showcaseSrcs = showcase.image ? buildAssetFallbacks(showcase.image) : [];
                    return (
                      <button
                        key={name}
                        type="button"
                        className="deck-stack"
                        style={{ ['--deck-tilt' as any]: `${tilt}deg`, ['--deck-tilt-inv' as any]: `${-tilt}deg` } as React.CSSProperties}
                        onClick={() => loadPreconByName(name)}
                        title={`Load ${name} precon`}
                      >
                        <div className="deck-stack__cards">
                          <span className="deck-stack__card layer-1" />
                          <span className="deck-stack__card layer-2" />
                          <span className="deck-stack__card layer-3" />
                          {showcase.image ? (
                            <img
                              className="deck-stack__showcase"
                              src={showcaseSrcs[0] ?? showcase.image}
                              data-fallbacks={showcaseSrcs.slice(1).join('|')}
                              alt={showcase.name}
                              onError={advanceImageFallback}
                            />
                          ) : (
                            <div className="deck-stack__showcase-fallback">{showcase.name}</div>
                          )}
                        </div>
                        <div className="deck-stack__label">{name}</div>
                        <div className="deck-stack__meta">Preconstructed Deck</div>
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          </>
        )}
      </div>
      {tab === 'build' ? (
        <div className="stack" style={{ gap: 16 }}>
          <div className="rowwrap" style={{ gap: 12, flexWrap: 'wrap', justifyContent: 'center' }}>
            <button
              className="btn"
              onClick={confirmSave}
              style={toolbarButtonStyle}
            >
              Confirm Deck
            </button>
            <button
              className="btn"
              onClick={saveToPlayerShelf}
              style={toolbarButtonStyle}
            >
              Save to Player Shelf
            </button>
            <button
              className="btn"
              onClick={() => { void copyDecklist(); }}
              style={toolbarButtonStyle}
            >
              Copy Decklist
            </button>
            <button
              className="btn"
              onClick={async () => {
                const picked = await pickShowcaseCard();
                if (!picked) return;
                setCurrentShowcase(picked);
                if (avatarCard && picked.name === avatarCard.name) {
                  setShowcaseSource('avatar');
                } else {
                  setShowcaseSource('custom');
                }
              }}
              style={toolbarButtonStyle}
            >
              Set Showcase
            </button>
            <button
              className="btn"
              onClick={clear}
              style={toolbarButtonStyle}
            >
              Clear
            </button>
          </div>
          <div style={{ textAlign: 'center', fontSize: 12, color: '#9fb0c2' }}>
            Showcase: {currentShowcase?.name ?? (avatarCard ? `${avatarCard.name} (default)` : 'None')}
          </div>
          <div
            className="panel"
            style={{
              padding: 16,
              border: '1px dashed #334155',
              borderRadius: 14,
              background: 'linear-gradient(135deg, rgba(12,18,26,0.9), rgba(9,12,18,0.95))',
              boxShadow: 'inset 0 1px 0 rgba(255,255,255,0.06)',
              minHeight: 120,
            }}
          >
            <div className="title" style={{ marginBottom: 6 }}>Build Tray</div>
            <div style={{ color: '#9fb0c2', fontSize: 12 }}>
              Drag cards from the carousel into Avatar, Atlas, Spellbook, or Collection to add 1 copy.
            </div>
            <div className="rowwrap" style={{ gap: 16, alignItems: 'stretch', flexWrap: 'wrap', marginTop: 12 }}>
              <div
                className="card-tray"
                onDragOver={handleTrayDragOver}
                onDrop={(e) => handleTrayDrop(e, 'avatar')}
                style={{
                  minWidth: 220,
                  flex: '1 1 220px',
                  padding: 10,
                  borderRadius: 10,
                  border: '1px dashed #2b3647',
                  display: 'flex',
                  flexDirection: 'column',
                  alignSelf: 'stretch',
                }}
              >
                <div className="title">Avatar</div>
                <div style={{ fontSize: 11, color: '#9fb0c2', marginBottom: 6 }}>Drop a single avatar here.</div>
                <div className="rowwrap" style={{ gap: 6, flexWrap: 'wrap', flex: 1, alignContent: 'flex-start' }}>
                  {avatarCard ? (
                    <div style={{ position: 'relative' }} title={avatarCard.name}>
                      <MiniCard c={avatarCard} enableHover />
                      <button
                        className="btn"
                        style={{ position: 'absolute', top: 4, right: 4 }}
                        onClick={() => setAvatarCard(null)}
                      >
                        ✕
                      </button>
                    </div>
                  ) : (
                    <div style={{ color: '#9fb0c2', fontSize: 12 }}>No avatar selected.</div>
                  )}
                </div>
              </div>
              <div
                className="card-tray"
                onDragOver={handleTrayDragOver}
                onDrop={(e) => handleTrayDrop(e, 'atlas')}
                style={{
                  minWidth: 260,
                  flex: '1 1 260px',
                  padding: 10,
                  borderRadius: 10,
                  border: '1px dashed #2b3647',
                  display: 'flex',
                  flexDirection: 'column',
                  alignSelf: 'stretch',
                }}
              >
                <div className="title">Atlas ({atlas.length})</div>
                <div style={{ fontSize: 11, color: '#9fb0c2', marginBottom: 6 }}>Drop sites here.</div>
                <div className="rowwrap" style={{ gap: 6, flexWrap: 'wrap', flex: 1, alignContent: 'flex-start' }}>
                  {atlasStacks.map(({ card, count }) => (
                    <div key={`${card.id}-atlas-stack`} style={{ position: 'relative' }} title={`${card.name} ×${count}`}>
                      <MiniCard c={card} enableHover />
                      {count > 1 && (
                        <div
                          style={{
                            position: 'absolute',
                            bottom: 4,
                            right: 4,
                            background: 'rgba(15,23,42,0.9)',
                            color: '#e5eefc',
                            border: '1px solid #334155',
                            borderRadius: 999,
                            padding: '2px 6px',
                            fontSize: 11,
                            fontWeight: 700,
                          }}
                        >
                          ×{count}
                        </div>
                      )}
                      <button className="btn" style={{ position: 'absolute', top: 4, right: 4 }} onClick={() => removeCard(card.id)}>✕</button>
                    </div>
                  ))}
                  {atlas.length === 0 && <div style={{ color: '#9fb0c2', fontSize: 12 }}>Empty</div>}
                </div>
              </div>

              <div
                className="card-tray"
                onDragOver={handleTrayDragOver}
                onDrop={(e) => handleTrayDrop(e, 'spellbook')}
                style={{
                  minWidth: 260,
                  flex: '1 1 260px',
                  padding: 10,
                  borderRadius: 10,
                  border: '1px dashed #2b3647',
                  display: 'flex',
                  flexDirection: 'column',
                  alignSelf: 'stretch',
                }}
              >
                <div className="title">Spellbook ({spells.length})</div>
                <div style={{ fontSize: 11, color: '#9fb0c2', marginBottom: 6 }}>Drop non-sites here.</div>
                <div className="rowwrap" style={{ gap: 6, flexWrap: 'wrap', flex: 1, alignContent: 'flex-start' }}>
                  {spellStacks.map(({ card, count }) => (
                    <div key={`${card.id}-spell-stack`} style={{ position: 'relative' }} title={`${card.name} ×${count}`}>
                      <MiniCard c={card} enableHover />
                      {count > 1 && (
                        <div
                          style={{
                            position: 'absolute',
                            bottom: 4,
                            right: 4,
                            background: 'rgba(15,23,42,0.9)',
                            color: '#e5eefc',
                            border: '1px solid #334155',
                            borderRadius: 999,
                            padding: '2px 6px',
                            fontSize: 11,
                            fontWeight: 700,
                          }}
                        >
                          ×{count}
                        </div>
                      )}
                      <button className="btn" style={{ position: 'absolute', top: 4, right: 4 }} onClick={() => removeCard(card.id)}>✕</button>
                    </div>
                  ))}
                  {spells.length === 0 && <div style={{ color: '#9fb0c2', fontSize: 12 }}>Empty</div>}
                </div>
              </div>

              <div
                className="card-tray"
                onDragOver={handleTrayDragOver}
                onDrop={(e) => handleTrayDrop(e, 'collection')}
                style={{
                  minWidth: 260,
                  flex: '1 1 260px',
                  padding: 10,
                  borderRadius: 10,
                  border: '1px dashed #2b3647',
                  display: 'flex',
                  flexDirection: 'column',
                  alignSelf: 'stretch',
                }}
              >
                <div className="title">Collection ({collection.length}/10)</div>
                <div style={{ fontSize: 11, color: '#9fb0c2', marginBottom: 6 }}>Drop any card here (optional).</div>
                <div className="rowwrap" style={{ gap: 6, flexWrap: 'wrap', flex: 1, alignContent: 'flex-start' }}>
                  {collectionStacks.map(({ card, count }) => (
                    <div key={`${card.id}-collection-stack`} style={{ position: 'relative' }} title={`${card.name} ×${count}`}>
                      <MiniCard c={card} enableHover />
                      {count > 1 && (
                        <div
                          style={{
                            position: 'absolute',
                            bottom: 4,
                            right: 4,
                            background: 'rgba(15,23,42,0.9)',
                            color: '#e5eefc',
                            border: '1px solid #334155',
                            borderRadius: 999,
                            padding: '2px 6px',
                            fontSize: 11,
                            fontWeight: 700,
                          }}
                        >
                          ×{count}
                        </div>
                      )}
                      <button className="btn" style={{ position: 'absolute', top: 4, right: 4 }} onClick={() => removeCard(card.id)}>✕</button>
                    </div>
                  ))}
                  {collection.length === 0 && <div style={{ color: '#9fb0c2', fontSize: 12 }}>Empty (optional up to 10)</div>}
                </div>
              </div>
            </div>
          </div>

          <div
            className="panel"
            style={{
              padding: 18,
              background: 'radial-gradient(circle at 20% 20%, rgba(125,211,252,0.08), transparent 35%), radial-gradient(circle at 80% 0%, rgba(246,197,111,0.08), transparent 35%), linear-gradient(135deg, #0b111a 0%, #0a0f17 60%, #0c131d 100%)',
              border: '1px solid #1f2937',
              boxShadow: '0 18px 38px rgba(0,0,0,0.45)',
            }}
          >
            <div className="rowwrap" style={{ justifyContent: 'space-between', alignItems: 'center', gap: 12, flexWrap: 'wrap' }}>
              <div className="stack" style={{ gap: 4 }}>
                <div className="title" style={{ margin: 0 }}>Card Browser</div>
                <div style={{ color: '#9fb0c2', fontSize: 12 }}>Search across all sets. Click to add multiples, swipe/drag to add a single copy.</div>
              </div>
              <div style={{ color: '#7dd3fc', fontSize: 12, fontWeight: 700, letterSpacing: 0.3 }}>
                {binderCards.length} cards shown
              </div>
            </div>

            <div className="rowwrap" style={{ gap: 8, alignItems: 'center', flexWrap: 'wrap', marginTop: 12 }}>
              <input
                value={binderQuery}
                onChange={(e) => { setBinderQuery(e.target.value); }}
                placeholder="Search all sets by name, text, or element…"
                style={{ padding: '10px 12px', background: '#0c1117', border: '1px solid #283241', borderRadius: 8, color: '#e5eefc', minWidth: 260 }}
              />
              <div className="rowwrap" style={{ gap: 6 }}>
                {(['Site', 'Spell', 'Unit', 'Avatar', 'ArtifactCard', 'AuraCard'] as Card['kind'][]).map((k) => (
                  <button
                    key={k}
                    className="btn"
                    onClick={() => setBinderKinds(prev => ({ ...prev, [k]: !prev[k] }))}
                    style={{
                      padding: '6px 10px',
                      borderRadius: 999,
                      fontSize: 11,
                      background: binderKinds[k] ? '#1f2937' : '#0f1724',
                      border: binderKinds[k] ? '1px solid #7dd3fc' : '1px solid #283241',
                    }}
                  >
                    {k}
                  </button>
                ))}
              </div>
              <div className="rowwrap" style={{ gap: 6 }}>
                {(['Air', 'Earth', 'Fire', 'Water'] as Elem[]).map((e) => (
                  <button
                    key={e}
                    className="btn"
                    onClick={() => setBinderElems(prev => ({ ...prev, [e]: !prev[e] }))}
                    style={{
                      padding: '6px 10px',
                      borderRadius: 999,
                      fontSize: 11,
                      background: binderElems[e] ? '#1f2937' : '#0f1724',
                      border: binderElems[e] ? '1px solid #f6c56f' : '1px solid #283241',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 6,
                    }}
                  >
                    <ElemIconImg e={e} size={12} /> {e}
                  </button>
                ))}
              </div>
            </div>

            <div
              style={{
                position: 'relative',
                marginTop: 16,
                borderRadius: 20,
                padding: '28px 36px 28px 54px',
                background: 'linear-gradient(145deg, #0d1521 0%, #0a0f19 60%, #0c131d 100%)',
                border: '1px solid #1f2937',
                boxShadow: '0 20px 40px rgba(0,0,0,0.45)',
                overflow: 'hidden',
              }}
            >
              <div
                style={{
                  position: 'absolute',
                  top: 18,
                  bottom: 18,
                  left: 18,
                  width: 22,
                  background: 'linear-gradient(180deg, #0a0f17 0%, #0b111a 50%, #0a0f17 100%)',
                  borderRight: '1px solid #1f2937',
                  boxShadow: 'inset -4px 0 10px rgba(0,0,0,0.35)',
                }}
              />
              {binderCards.length === 0 ? (
                <div style={{ color: '#9fb0c2', fontSize: 12, paddingLeft: 6 }}>
                  No cards match this search.
                </div>
              ) : (
                <div
                  style={{
                    position: 'relative',
                    zIndex: 1,
                    paddingLeft: 6,
                    overflowX: 'auto',
                    paddingBottom: 6,
                    scrollSnapType: 'x mandatory',
                  }}
                >
                  <div style={{ display: 'flex', gap: 14, minWidth: '100%' }}>
                    {binderCards.map((card) => (
                      <div
                        key={card.id}
                        style={{
                          flex: '0 0 calc((100% - 42px) / 4)',
                          scrollSnapAlign: 'start',
                        }}
                      >
                        <BinderPocket
                          card={card}
                          onAdd={(mode) => handleCarouselAdd(card, mode)}
                          disableHover
                        />
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
          <div className="panel" style={{ padding: 12 }}>
            <div className="title">Import by List</div>
            <textarea
              value={listText}
              onChange={(e) => setListText(e.target.value)}
              placeholder={`One per line, e.g.\nGothic Tower x6\nLightning Bolt x8\nAlbespine Pikemen x4`}
              style={{ width: '100%', minHeight: 110, padding: 10, background: '#0c1117', border: '1px solid #283241', borderRadius: 8, color: '#e5eefc' }}
            />
            <div className="rowwrap" style={{ gap: 8, marginTop: 6 }}>
              <button className="btn" onClick={importList}>Add from List</button>
            </div>
          </div>
          <div className="panel" style={{ padding: 12 }}>
            <div className="title">Import from URL</div>
            <div style={{ fontSize: 12, color: '#9fb0c2', marginBottom: 6 }}>
              Paste a deck URL (e.g. curiosa.io) to import its list.
            </div>
            <div className="rowwrap" style={{ gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
              <input
                value={importUrl}
                onChange={(e) => setImportUrl(e.target.value)}
                placeholder="https://curiosa.io/decks/..."
                style={{ padding: '10px 12px', background: '#0c1117', border: '1px solid #283241', borderRadius: 8, color: '#e5eefc', minWidth: 320 }}
              />
              <button className="btn" onClick={importDeckFromUrl} disabled={importingUrl || !importUrl.trim()}>
                {importingUrl ? 'Importing…' : 'Import from URL'}
              </button>
            </div>
          </div>
          <div className="panel" style={{ padding: 12 }}>
            <div className="title">Brewing (v1)</div>
            {!deckStats && <div style={{ color: '#9fb0c2', fontSize: 12 }}>Add cards to see analytics.</div>}
            {deckStats && (
              <div className="rowwrap" style={{ gap: 16, flexWrap: 'wrap' }}>
                <div style={{ minWidth: 260, flex: '1 1 260px' }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#e5eefc', marginBottom: 6 }}>Mana / Cost Curve</div>
                  <svg width="100%" height={140} viewBox="0 0 320 140" preserveAspectRatio="xMidYMid meet" style={{ background: '#0d1118', border: '1px solid #1f2937', borderRadius: 8 }}>
                    {deckStats.costCurve.map((b, i) => {
                      const max = Math.max(...deckStats.costCurve.map(c => c.count), 1);
                      const barW = 24;
                      const gap = 8;
                      const x = 12 + i * (barW + gap);
                      const h = (b.count / max) * 100;
                      const y = 120 - h;
                      return (
                        <g key={b.label}>
                          <rect x={x} y={y} width={barW} height={h} fill="#60a5fa" opacity={0.9} rx={3} />
                          <text x={x + barW / 2} y={132} textAnchor="middle" fontSize="10" fill="#cbd5e1">{b.label}</text>
                          <text x={x + barW / 2} y={y - 4} textAnchor="middle" fontSize="10" fill="#cbd5e1">{b.count}</text>
                        </g>
                      );
                    })}
                  </svg>
                  <div style={{ marginTop: 8, fontSize: 12, color: '#9fb0c2', lineHeight: 1.4 }}>
                    <div>Sites: {deckStats.composition.sites}</div>
                    <div>Units: {deckStats.composition.units} • Spells: {deckStats.composition.spells} • Artifacts: {deckStats.composition.artifacts} • Auras: {deckStats.composition.auras}</div>
                    <div>Unique names: {deckStats.composition.uniqueNames}</div>
                  </div>
                </div>
                <div style={{ minWidth: 240, flex: '1 1 240px' }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#e5eefc', marginBottom: 6 }}>Thresholds</div>
                  <div style={{ display: 'grid', gap: 6 }}>
                    {(['Air','Earth','Fire','Water'] as Elem[]).map((e) => (
                      <div key={e} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: '#cbd5e1', background: '#0d1118', border: '1px solid #1f2937', borderRadius: 8, padding: '6px 8px' }}>
                        <span>{elemIcon(e)} {e}</span>
                        <span>Demand: {deckStats.thresholds.demand[e]} | Max req: {deckStats.thresholds.maxRequired[e]} | Site sources: {deckStats.thresholds.siteSources[e]}</span>
                      </div>
                    ))}
                  </div>
                </div>
                <div style={{ minWidth: 260, flex: '1 1 260px' }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#e5eefc', marginBottom: 6, display: 'flex', alignItems: 'center', gap: 8 }}>
                    Simulation
                    <input
                      type="number"
                      min={10}
                      max={5000}
                      value={simGames}
                      onChange={(e) => setSimGames(Math.max(10, Math.min(5000, parseInt(e.target.value || '0', 10))))}
                      style={{ width: 80, padding: '4px 6px', background: '#0c1117', border: '1px solid #283241', borderRadius: 6, color: '#e5eefc', fontSize: 12 }}
                      title="Simulated games"
                    />
                  </div>
                  {!simResult && <div style={{ color: '#9fb0c2', fontSize: 12 }}>Add cards to simulate.</div>}
                  {simResult && (
                    <div style={{ fontSize: 12, color: '#cbd5e1', display: 'grid', gap: 6 }}>
                      <div>Games: {simResult.games} • Mulligan rate: {(simResult.mulliganRate * 100).toFixed(1)}%</div>
                      <div>
                        Avg playable by turn:
                        {' '}
                        {simResult.averagePlayableByTurn.map((v, i) => `T${i + 1}:${v.toFixed(1)}`).join('  ')}
                      </div>
                      <div>
                        Threshold met prob:
                        {(['Air','Earth','Fire','Water'] as Elem[]).map(e => {
                          const arr = simResult.thresholdMetByTurn[e];
                          if (!arr || arr.length === 0) return null;
                          return (
                            <div key={e} style={{ marginLeft: 8 }}>
                              {elemIcon(e)} {arr.map((p, i) => `T${i + 1}:${(p * 100).toFixed(0)}%`).join('  ')}
                            </div>
                          );
                        })}
                      </div>
                      <div>
                        Sample hand:
                        <div className="rowwrap" style={{ gap: 6, marginTop: 4, flexWrap: 'wrap' }}>
                          {simResult.sampleHand.map((c, idx) => (
                            <MiniCard key={`${c.id}-hand-${idx}`} c={c} scale={0.75} showNameOverlay />
                          ))}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
                <div style={{ minWidth: 240, flex: '1 1 240px' }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#e5eefc', marginBottom: 6 }}>Suggestions</div>
                  {suggestions.length === 0 && <div style={{ fontSize: 12, color: '#9fb0c2' }}>No suggestions — numbers look balanced.</div>}
                  {suggestions.length > 0 && (
                    <ul style={{ paddingLeft: 16, margin: 0, display: 'grid', gap: 6 }}>
                      {suggestions.map((s, i) => (
                        <li key={i} style={{ color: '#cbd5e1', fontSize: 12, lineHeight: 1.4 }}>{s.message}</li>
                      ))}
                    </ul>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      ) : null}
      {showcasePickerOpen && (
        <ModalShell
          title="Showcase Card"
          onClose={() => closeShowcasePicker(null)}
          footer={
            <div className="rowwrap" style={{ gap: 8 }}>
              <button className="btn" onClick={() => closeShowcasePicker(null)}>Cancel</button>
            </div>
          }
        >
          <div className="stack" style={{ gap: 8 }}>
            <input
              value={showcaseSearch}
              onChange={(e) => setShowcaseSearch(e.target.value)}
              placeholder="Search cards..."
              className="textbox"
              style={{ padding: '8px 10px' }}
            />
            <div style={{ maxHeight: '45vh', overflowY: 'auto', display: 'grid', gap: 6 }}>
              {showcaseFiltered.map((c: Card) => (
                <button
                  key={c.id}
                  className="btn"
                  onClick={() => closeShowcasePicker({ name: c.name, image: c.image })}
                  style={{ justifyContent: 'space-between', display: 'flex', gap: 8 }}
                >
                  <span>{c.name}</span>
                  <span style={{ opacity: 0.7, fontSize: 11 }}>{c.kind}</span>
                </button>
              ))}
              {showcaseFiltered.length === 0 && (
                <div style={{ color: '#9fb0c2', fontSize: 12 }}>No cards match this search.</div>
              )}
            </div>
          </div>
        </ModalShell>
      )}
    </div>
  )
}

function DeckPreview({ decks }: { decks: Decks }) {
  const summarizeDeck = (cards: Card[]): string[] => {
    const map = new Map<string, { c: Card; n: number }>()
    for (const c of cards) { const k = c.name + '|' + c.kind; if (!map.has(k)) map.set(k, { c, n: 0 }); map.get(k)!.n++ }
    return Array.from(map.values()).sort((a, b) => a.c.name.localeCompare(b.c.name)).map(({ c, n }) => `${c.name} ×${n}`)
  }
  return (
    <div className="rowwrap" style={{ gap: 12 }}>
      <div style={{ minWidth: 200 }}>
        <div className="title">Avatar</div>
        {decks.avatar ? (
          <div style={{ fontSize: 12, color: '#9fb0c2' }}>{decks.avatar.name}</div>
        ) : (
          <div style={{ fontSize: 12, color: '#9fb0c2' }}>None</div>
        )}
      </div>
      <div style={{ minWidth: 220 }}>
        <div className="title">Atlas ({decks.atlas.length})</div>
        <div style={{ display: 'grid', gap: 4 }}>{summarizeDeck(decks.atlas).map((line, i) => <div key={i} style={{ fontSize: 12, color: '#9fb0c2' }}>{line}</div>)}</div>
      </div>
      <div style={{ minWidth: 280 }}>
        <div className="title">Spellbook ({decks.spellbook.length})</div>
        <div style={{ display: 'grid', gap: 4 }}>{summarizeDeck(decks.spellbook).map((line, i) => <div key={i} style={{ fontSize: 12, color: '#9fb0c2' }}>{line}</div>)}</div>
      </div>
      <div style={{ minWidth: 220 }}>
        <div className="title">Collection ({(decks.collection ?? []).length})</div>
        <div style={{ display: 'grid', gap: 4 }}>
          {summarizeDeck(decks.collection ?? []).map((line, i) => (
            <div key={i} style={{ fontSize: 12, color: '#9fb0c2' }}>{line}</div>
          ))}
          {(decks.collection ?? []).length === 0 && <div style={{ fontSize: 12, color: '#9fb0c2' }}>Empty</div>}
        </div>
      </div>
    </div>
  )
}

function MiniCard({
  c,
  scale = 1,
  showNameOverlay = false,
  enableHover = false,
  style,
}: {
  c: Card;
  scale?: number;
  showNameOverlay?: boolean;
  enableHover?: boolean;
  style?: React.CSSProperties;
}) {
  const W = 64 * scale, H = 86 * scale
  const imageSrcs = useMemo(() => buildAssetFallbacks((c as any).image), [((c as any).image as string | undefined)]);
  const hb = enableHover
    ? useHoverBindingsForCard({ src: (c as any).image, name: c.name, cardKind: c.kind, baseWidth: 216, zoom: 1.9 })
    : null;
  const hoverProps = enableHover ? {
    tabIndex: 0,
    onPointerEnter: hb?.onPointerEnter,
    onPointerMove: hb?.onPointerMove,
    onPointerLeave: hb?.onPointerLeave,
    onPointerUp: hb?.onPointerUp,
    onFocus: hb?.onFocus,
    onBlur: hb?.onBlur,
  } : {};
  const overlayName = showNameOverlay && (c as any).image ? (
    <div
      style={{
        position: 'absolute',
        left: 0,
        right: 0,
        bottom: 0,
        padding: `4px 6px`,
        background: 'linear-gradient(180deg, transparent, rgba(0,0,0,0.85))',
        color: '#f8e6c3',
        fontWeight: 700,
        fontSize: 11,
        letterSpacing: 0.4,
        whiteSpace: 'nowrap',
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        textShadow: '0 1px 2px rgba(0,0,0,0.6)',
        textAlign: 'center',
        pointerEvents: 'none',
      }}
    >
      {c.name}
    </div>
  ) : null;

  if (imageSrcs.length > 0) {
    return (
      <div
        {...hoverProps}
        style={{
          width: W,
          height: H,
          borderRadius: 6,
          border: '1px solid #283241',
          position: 'relative',
          overflow: 'hidden',
          background: '#0e1318',
          ...(style ?? {}),
        }}
      >
        <img
          src={imageSrcs[0]}
          data-fallbacks={imageSrcs.slice(1).join('|')}
          alt={`${c.name} art`}
          onError={advanceImageFallback}
          style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover' }}
        />
        {overlayName}
      </div>
    )
  }
  return (
    <div
      {...hoverProps}
      style={{
        width: W,
        height: H,
        borderRadius: 6,
        background: '#0e1318',
        border: '1px solid #283241',
        display: 'grid',
        gridTemplateRows: '18px 1fr 14px',
        padding: 6,
        ...(style ?? {}),
      }}
    >
      <div style={{ fontSize: 10*scale, fontWeight: 700, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{c.name}</div>
      <div style={{ fontSize: 10*scale, lineHeight: 1.2, color: '#9fb0c2', textAlign: 'center', alignSelf: 'center' }}>
        {c.kind === 'Unit' ? `ATK ${(c as any).atk ?? (c as any).power ?? 0} / DEF ${(c as any).def ?? (c as any).power ?? 0}` :
         c.kind === 'Spell' ? c.text ?? 'Spell' :
         c.kind === 'ArtifactCard' ? 'Artifact' :
         c.kind === 'AuraCard' ? 'Aura' :
         c.kind === 'Avatar' ? (c.text ?? 'Avatar') : 'Site'}
      </div>
      <div style={{ fontSize: 9*scale, opacity: 0.7, justifySelf: 'end' }}>{c.kind}</div>
    </div>
  )
}

type HandOverlayCardProps = {
  card: Card
  highlight: boolean
  canPlay: boolean
  reducedMotion: boolean
  onPlay: (card: Card) => void
  onInspect: (card: Card) => void
  onHoverChange: (card: Card | null, pos: { x: number; y: number } | null) => void
  playSfx: (kind: UiSfxKind) => void
}

function HandOverlayCard({
  card,
  highlight,
  canPlay,
  reducedMotion,
  onPlay,
  onInspect,
  onHoverChange,
  playSfx,
}: HandOverlayCardProps) {
  const hostRef = useRef<HTMLDivElement | null>(null)
  const rejectTimerRef = useRef<number | null>(null)
  const [isHovered, setIsHovered] = useState(false)
  const [isRejecting, setIsRejecting] = useState(false)
  const [tilt, setTilt] = useState({ x: 0, y: 0 })
  const [drag, setDrag] = useState({
    pointerId: -1,
    active: false,
    started: false,
    startX: 0,
    startY: 0,
    dx: 0,
    dy: 0,
    anchorX: 0,
    anchorY: 0,
    validDrop: false,
  })

  useEffect(() => {
    return () => {
      if (rejectTimerRef.current != null) {
        window.clearTimeout(rejectTimerRef.current)
        rejectTimerRef.current = null
      }
    }
  }, [])

  const updateTilt = useCallback((clientX: number, clientY: number) => {
    if (reducedMotion) {
      setTilt({ x: 0, y: 0 })
      return
    }
    const host = hostRef.current
    if (!host) return
    const rect = host.getBoundingClientRect()
    if (!rect.width || !rect.height) return
    const nx = (clientX - rect.left) / rect.width - 0.5
    const ny = (clientY - rect.top) / rect.height - 0.5
    setTilt({
      x: Math.max(-MOTION.hover.tiltDeg, Math.min(MOTION.hover.tiltDeg, -ny * MOTION.hover.tiltDeg * 1.2)),
      y: Math.max(-MOTION.hover.tiltDeg, Math.min(MOTION.hover.tiltDeg, nx * MOTION.hover.tiltDeg * 1.2)),
    })
  }, [reducedMotion])

  const resetDrag = useCallback(() => {
    setDrag({
      pointerId: -1,
      active: false,
      started: false,
      startX: 0,
      startY: 0,
      dx: 0,
      dy: 0,
      anchorX: 0,
      anchorY: 0,
      validDrop: false,
    })
  }, [])

  const triggerReject = useCallback(() => {
    setIsRejecting(true)
    if (rejectTimerRef.current != null) {
      window.clearTimeout(rejectTimerRef.current)
    }
    rejectTimerRef.current = window.setTimeout(() => {
      setIsRejecting(false)
      rejectTimerRef.current = null
    }, 280)
  }, [])

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (e.button !== 0) return
    const target = e.target as HTMLElement | null
    if (target?.closest('button')) return
    const host = hostRef.current
    if (!host) return
    const rect = host.getBoundingClientRect()
    try {
      host.setPointerCapture(e.pointerId)
    } catch {
      // ignore
    }
    playSfx('card_pickup')
    setDrag({
      pointerId: e.pointerId,
      active: true,
      started: false,
      startX: e.clientX,
      startY: e.clientY,
      dx: 0,
      dy: 0,
      anchorX: rect.left + rect.width / 2,
      anchorY: rect.top + rect.height / 2,
      validDrop: false,
    })
    updateTilt(e.clientX, e.clientY)
  }

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!drag.active || drag.pointerId !== e.pointerId) {
      if (!drag.active) updateTilt(e.clientX, e.clientY)
      return
    }
    const dx = e.clientX - drag.startX
    const dy = e.clientY - drag.startY
    const started = false
    const validDrop = false
    setDrag((prev) => ({
      ...prev,
      dx,
      dy,
      started,
      validDrop,
    }))
    onHoverChange(card, { x: e.clientX, y: e.clientY })
    updateTilt(e.clientX, e.clientY)
    if (started) e.preventDefault()
  }

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (drag.pointerId !== e.pointerId) return
    try {
      hostRef.current?.releasePointerCapture(e.pointerId)
    } catch {
      // ignore
    }
    const wasDrag = drag.started
    const validDrop = drag.validDrop
    const moved = Math.hypot(drag.dx, drag.dy) >= MOTION.drag.thresholdPx
    resetDrag()
    setIsHovered(false)
    setTilt({ x: 0, y: 0 })
    onHoverChange(null, null)
    if (moved) return
    if (wasDrag) {
      if (validDrop) {
        playSfx('target_valid')
        playSfx('card_drop')
        onPlay(card)
      } else {
        playSfx('target_invalid')
        triggerReject()
      }
      return
    }
    playSfx('ui_click')
    onPlay(card)
  }

  const handlePointerEnter = (e: React.PointerEvent<HTMLDivElement>) => {
    setIsHovered(true)
    onHoverChange(card, { x: e.clientX, y: e.clientY })
    playSfx('ui_hover')
    updateTilt(e.clientX, e.clientY)
  }

  const handlePointerLeave = () => {
    setIsHovered(false)
    onHoverChange(null, null)
    setTilt({ x: 0, y: 0 })
  }

  const handlePointerCancel = (e: React.PointerEvent<HTMLDivElement>) => {
    if (drag.pointerId !== e.pointerId) return
    resetDrag()
    setIsHovered(false)
    onHoverChange(null, null)
    setTilt({ x: 0, y: 0 })
  }

  const className = [
    'so-hand-card-shell',
    isHovered ? 'is-hover' : '',
    drag.started ? 'is-acting' : '',
    drag.started && drag.validDrop ? 'is-valid-drop' : '',
    drag.started && !drag.validDrop ? 'is-invalid-drop' : '',
    isRejecting ? 'is-reject' : '',
  ]
    .filter(Boolean)
    .join(' ')

  const hostStyle: React.CSSProperties = {
    border: highlight ? '2px solid rgba(246, 197, 111, 0.92)' : '1px solid #283241',
    boxShadow: highlight
      ? '0 0 0 2px rgba(246, 197, 111, 0.25), 0 8px 16px rgba(0,0,0,0.35)'
      : undefined,
    background: '#0e131a',
    padding: 6,
    position: 'relative',
    opacity: drag.started ? 0.22 : 1,
    transition: `opacity ${MOTION.duration.fast}s ${MOTION.easing.ui}`,
    touchAction: 'none',
  }

  const surfaceStyle: React.CSSProperties = {
    ['--so-card-x' as any]: `${drag.started ? drag.dx : 0}px`,
    ['--so-card-y' as any]: `${drag.started ? drag.dy : isHovered ? -MOTION.hover.liftPx : 0}px`,
    ['--so-card-tilt-x' as any]: `${tilt.x.toFixed(2)}deg`,
    ['--so-card-tilt-y' as any]: `${tilt.y.toFixed(2)}deg`,
    ['--so-card-scale' as any]: drag.started ? 1.06 : 1,
  }
  const tooltipText = handTooltipRulesText(card)

  const actingCard = drag.started && typeof document !== 'undefined'
    ? createPortal(
        <div
          className="so-acting-card-layer"
          style={{
            left: drag.anchorX + drag.dx,
            top: drag.anchorY + drag.dy,
          }}
        >
          <div className={`so-acting-card-chip ${drag.validDrop ? 'valid' : 'invalid'}`}>
            {drag.validDrop ? 'Release to Play' : canPlay ? 'Drag Up to Play' : 'Invalid Target'}
          </div>
          <div
            className="so-hand-card-surface"
            style={{
              ['--so-card-x' as any]: '0px',
              ['--so-card-y' as any]: '0px',
              ['--so-card-tilt-x' as any]: `${tilt.x.toFixed(2)}deg`,
              ['--so-card-tilt-y' as any]: `${tilt.y.toFixed(2)}deg`,
              ['--so-card-scale' as any]: 1.06,
            }}
          >
            <MiniCard c={card} scale={1.5 * HAND_CARD_SIZE_MULTIPLIER} />
          </div>
        </div>,
        document.body
      )
    : null
  const tooltipPortal =
    isHovered && !drag.started && typeof document !== 'undefined' && typeof window !== 'undefined' && hostRef.current
      ? (() => {
          const rect = hostRef.current!.getBoundingClientRect()
          const maxWidth = Math.min(460, Math.max(260, window.innerWidth - 24))
          const left = Math.max(12 + maxWidth / 2, Math.min(window.innerWidth - 12 - maxWidth / 2, rect.left + rect.width / 2))
          const preferAbove = rect.top > 120
          const top = preferAbove ? rect.top - 10 : rect.bottom + 10
          const transform = preferAbove ? 'translate(-50%, -100%)' : 'translate(-50%, 0)'
          return createPortal(
            <div
              style={{
                position: 'fixed',
                left,
                top,
                transform,
                padding: '8px 10px',
                borderRadius: 10,
                background: 'rgba(7, 12, 20, 0.98)',
                border: '1px solid rgba(148, 163, 184, 0.55)',
                color: '#e8eef7',
                fontSize: 11,
                fontWeight: 600,
                lineHeight: 1.28,
                whiteSpace: 'normal',
                maxWidth,
                pointerEvents: 'none',
                zIndex: 16000,
                boxShadow: '0 10px 22px rgba(0,0,0,0.42)',
              }}
            >
              <div style={{ fontSize: 12, fontWeight: 800 }}>{card.name}</div>
              {tooltipText ? (
                <div
                  style={{
                    marginTop: 4,
                    fontSize: 11,
                    fontWeight: 500,
                    lineHeight: 1.35,
                    color: '#c7d6eb',
                    whiteSpace: 'pre-wrap',
                  }}
                >
                  {tooltipText}
                </div>
              ) : null}
            </div>,
            document.body
          )
        })()
      : null

  return (
    <>
      <div
        ref={hostRef}
        className={className}
        style={hostStyle}
        onPointerEnter={handlePointerEnter}
        onPointerMove={handlePointerMove}
        onPointerLeave={handlePointerLeave}
        onPointerCancel={handlePointerCancel}
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
      >
        <button
          className="btn"
          onClick={(e) => {
            e.stopPropagation()
            onInspect(card)
          }}
          title={`Inspect ${card.name}`}
          style={{
            position: 'absolute',
            top: 4,
            right: 4,
            minWidth: 0,
            padding: '2px 6px',
            borderRadius: 999,
            fontSize: 11,
            lineHeight: 1,
            zIndex: 4,
            opacity: 0.92,
          }}
        >
          i
        </button>
        <div className="so-hand-card-surface" style={surfaceStyle}>
          <MiniCard c={card} scale={1.5 * HAND_CARD_SIZE_MULTIPLIER} />
        </div>
      </div>
      {actingCard}
      {tooltipPortal}
    </>
  )
}

type PersistentHandCardProps = {
  card: Card
  canPlay: boolean
  highlight: boolean
  reducedMotion: boolean
  playSfx: (kind: UiSfxKind) => void
  onPlay: (card: Card) => void
  onInspect: (card: Card) => void
  isBoardDropPoint: (x: number, y: number) => boolean
  onDropToBoard: (card: Card, point: { x: number; y: number }) => Promise<boolean> | boolean
}

function PersistentHandCard({
  card,
  canPlay,
  highlight,
  reducedMotion,
  playSfx,
  onPlay,
  onInspect,
  isBoardDropPoint,
  onDropToBoard,
}: PersistentHandCardProps) {
  const hostRef = useRef<HTMLDivElement | null>(null)
  const rejectTimerRef = useRef<number | null>(null)
  const [isHovered, setIsHovered] = useState(false)
  const [isRejecting, setIsRejecting] = useState(false)
  const [tilt, setTilt] = useState({ x: 0, y: 0 })
  const [drag, setDrag] = useState({
    pointerId: -1,
    active: false,
    started: false,
    startX: 0,
    startY: 0,
    dx: 0,
    dy: 0,
    anchorX: 0,
    anchorY: 0,
    validDrop: false,
  })

  useEffect(() => {
    return () => {
      if (rejectTimerRef.current != null) {
        window.clearTimeout(rejectTimerRef.current)
        rejectTimerRef.current = null
      }
    }
  }, [])

  const updateTilt = useCallback((clientX: number, clientY: number) => {
    if (reducedMotion) {
      setTilt({ x: 0, y: 0 })
      return
    }
    const host = hostRef.current
    if (!host) return
    const rect = host.getBoundingClientRect()
    if (!rect.width || !rect.height) return
    const nx = (clientX - rect.left) / rect.width - 0.5
    const ny = (clientY - rect.top) / rect.height - 0.5
    setTilt({
      x: Math.max(-MOTION.hover.tiltDeg, Math.min(MOTION.hover.tiltDeg, -ny * MOTION.hover.tiltDeg * 1.2)),
      y: Math.max(-MOTION.hover.tiltDeg, Math.min(MOTION.hover.tiltDeg, nx * MOTION.hover.tiltDeg * 1.2)),
    })
  }, [reducedMotion])

  const resetDrag = useCallback(() => {
    setDrag({
      pointerId: -1,
      active: false,
      started: false,
      startX: 0,
      startY: 0,
      dx: 0,
      dy: 0,
      anchorX: 0,
      anchorY: 0,
      validDrop: false,
    })
  }, [])

  const triggerReject = useCallback(() => {
    setIsRejecting(true)
    if (rejectTimerRef.current != null) {
      window.clearTimeout(rejectTimerRef.current)
    }
    rejectTimerRef.current = window.setTimeout(() => {
      setIsRejecting(false)
      rejectTimerRef.current = null
    }, 280)
  }, [])

  const handlePointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    if (e.button !== 0) return
    const target = e.target as HTMLElement | null
    if (target?.closest('button')) return
    const host = hostRef.current
    if (!host) return
    const rect = host.getBoundingClientRect()
    try {
      host.setPointerCapture(e.pointerId)
    } catch {
      // ignore
    }
    playSfx('card_pickup')
    setDrag({
      pointerId: e.pointerId,
      active: true,
      started: false,
      startX: e.clientX,
      startY: e.clientY,
      dx: 0,
      dy: 0,
      anchorX: rect.left + rect.width / 2,
      anchorY: rect.top + rect.height / 2,
      validDrop: false,
    })
    updateTilt(e.clientX, e.clientY)
  }

  const handlePointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (!drag.active || drag.pointerId !== e.pointerId) {
      if (!drag.active) updateTilt(e.clientX, e.clientY)
      return
    }
    const dx = e.clientX - drag.startX
    const dy = e.clientY - drag.startY
    const started = false
    const validDrop = false
    setDrag((prev) => ({
      ...prev,
      dx,
      dy,
      started,
      validDrop,
    }))
    updateTilt(e.clientX, e.clientY)
    if (started) e.preventDefault()
  }

  const handlePointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
    if (drag.pointerId !== e.pointerId) return
    try {
      hostRef.current?.releasePointerCapture(e.pointerId)
    } catch {
      // ignore
    }
    const wasDrag = drag.started
    const point = { x: e.clientX, y: e.clientY }
    const validDrop = canPlay && isBoardDropPoint(point.x, point.y)
    const moved = Math.hypot(drag.dx, drag.dy) >= MOTION.drag.thresholdPx
    resetDrag()
    setIsHovered(false)
    setTilt({ x: 0, y: 0 })
    if (moved) return

    if (wasDrag) {
      if (!validDrop) {
        playSfx('target_invalid')
        triggerReject()
        return
      }
      void Promise.resolve(onDropToBoard(card, point)).then((accepted) => {
        if (accepted) {
          playSfx('target_valid')
          playSfx('card_drop')
        } else {
          playSfx('target_invalid')
          triggerReject()
        }
      })
      return
    }

    playSfx('ui_click')
    onPlay(card)
  }

  const handlePointerEnter = (e: React.PointerEvent<HTMLDivElement>) => {
    setIsHovered(true)
    updateTilt(e.clientX, e.clientY)
    playSfx('ui_hover')
  }

  const handlePointerLeave = () => {
    setIsHovered(false)
    setTilt({ x: 0, y: 0 })
  }

  const handlePointerCancel = (e: React.PointerEvent<HTMLDivElement>) => {
    if (drag.pointerId !== e.pointerId) return
    resetDrag()
    setIsHovered(false)
    setTilt({ x: 0, y: 0 })
  }

  const className = [
    'so-hand-card-shell',
    'so-persistent-card-shell',
    isHovered ? 'is-hover' : '',
    drag.started ? 'is-acting' : '',
    drag.started && drag.validDrop ? 'is-valid-drop' : '',
    drag.started && !drag.validDrop ? 'is-invalid-drop' : '',
    isRejecting ? 'is-reject' : '',
  ]
    .filter(Boolean)
    .join(' ')

  const hostStyle: React.CSSProperties = {
    ['--so-hand-peek' as any]: '80%',
    ['--so-hand-reveal' as any]: '10%',
    border: highlight ? '2px solid rgba(246, 197, 111, 0.92)' : '1px solid #283241',
    boxShadow: highlight
      ? '0 0 0 2px rgba(246, 197, 111, 0.25), 0 8px 16px rgba(0,0,0,0.35)'
      : undefined,
    background: '#0e131a',
    padding: 4,
    borderRadius: 10,
    position: 'relative',
    opacity: drag.started ? 0.22 : 1,
    transition: `opacity ${MOTION.duration.fast}s ${MOTION.easing.ui}`,
    touchAction: 'none',
    pointerEvents: 'auto',
  }

  const surfaceStyle: React.CSSProperties = {
    ['--so-card-x' as any]: `${drag.started ? drag.dx : 0}px`,
    ['--so-card-y' as any]: `${drag.started ? drag.dy : isHovered ? -MOTION.hover.liftPx * 0.4 : 0}px`,
    ['--so-card-tilt-x' as any]: `${tilt.x.toFixed(2)}deg`,
    ['--so-card-tilt-y' as any]: `${tilt.y.toFixed(2)}deg`,
    ['--so-card-scale' as any]: drag.started ? 1.06 : 1,
  }
  const tooltipText = handTooltipRulesText(card)

  const actingCard = drag.started && typeof document !== 'undefined'
    ? createPortal(
        <div
          className="so-acting-card-layer"
          style={{
            left: drag.anchorX + drag.dx,
            top: drag.anchorY + drag.dy,
          }}
        >
          <div className={`so-acting-card-chip ${drag.validDrop ? 'valid' : 'invalid'}`}>
            {drag.validDrop ? 'Release on Tile' : canPlay ? 'Drop on Board Tile' : 'Invalid Card'}
          </div>
          <div
            className="so-hand-card-surface"
            style={{
              ['--so-card-x' as any]: '0px',
              ['--so-card-y' as any]: '0px',
              ['--so-card-tilt-x' as any]: `${tilt.x.toFixed(2)}deg`,
              ['--so-card-tilt-y' as any]: `${tilt.y.toFixed(2)}deg`,
              ['--so-card-scale' as any]: 1.06,
            }}
          >
            <MiniCard c={card} scale={1.28 * HAND_CARD_SIZE_MULTIPLIER} />
          </div>
        </div>,
        document.body
      )
    : null
  const tooltipPortal =
    isHovered && !drag.started && typeof document !== 'undefined' && typeof window !== 'undefined' && hostRef.current
      ? (() => {
          const rect = hostRef.current!.getBoundingClientRect()
          const maxWidth = Math.min(460, Math.max(260, window.innerWidth - 24))
          const left = Math.max(12 + maxWidth / 2, Math.min(window.innerWidth - 12 - maxWidth / 2, rect.left + rect.width / 2))
          const preferAbove = rect.top > 120
          const top = preferAbove ? rect.top - 10 : rect.bottom + 10
          const transform = preferAbove ? 'translate(-50%, -100%)' : 'translate(-50%, 0)'
          return createPortal(
            <div
              style={{
                position: 'fixed',
                left,
                top,
                transform,
                padding: '8px 10px',
                borderRadius: 10,
                background: 'rgba(7, 12, 20, 0.98)',
                border: '1px solid rgba(148, 163, 184, 0.55)',
                color: '#e8eef7',
                fontSize: 11,
                fontWeight: 600,
                lineHeight: 1.28,
                whiteSpace: 'normal',
                maxWidth,
                pointerEvents: 'none',
                zIndex: 16000,
                boxShadow: '0 10px 22px rgba(0,0,0,0.42)',
              }}
            >
              <div style={{ fontSize: 12, fontWeight: 800 }}>{card.name}</div>
              {tooltipText ? (
                <div
                  style={{
                    marginTop: 4,
                    fontSize: 11,
                    fontWeight: 500,
                    lineHeight: 1.35,
                    color: '#c7d6eb',
                    whiteSpace: 'pre-wrap',
                  }}
                >
                  {tooltipText}
                </div>
              ) : null}
            </div>,
            document.body
          )
        })()
      : null

  return (
    <>
      <div
        ref={hostRef}
        className={className}
        style={hostStyle}
        onPointerEnter={handlePointerEnter}
        onPointerMove={handlePointerMove}
        onPointerLeave={handlePointerLeave}
        onPointerCancel={handlePointerCancel}
        onPointerDown={handlePointerDown}
        onPointerUp={handlePointerUp}
      >
        <button
          className="btn"
          onClick={(e) => {
            e.stopPropagation()
            onInspect(card)
          }}
          title={`Inspect ${card.name}`}
          style={{
            position: 'absolute',
            top: 2,
            right: 2,
            minWidth: 0,
            padding: '2px 5px',
            borderRadius: 999,
            fontSize: 10,
            lineHeight: 1,
            zIndex: 4,
            opacity: 0.9,
          }}
        >
          i
        </button>
        <div className="so-hand-card-surface" style={surfaceStyle}>
          <MiniCard c={card} scale={1.28 * HAND_CARD_SIZE_MULTIPLIER} />
        </div>
      </div>
      {actingCard}
      {tooltipPortal}
    </>
  )
}

type PersistentHandBarProps = {
  cards: Card[]
  unitHands: UnitSideHand[]
  reducedMotion: boolean
  boardTargetingActive: boolean
  playSfx: (kind: UiSfxKind) => void
  canPlayCard: (card: Card) => boolean
  canPlayUnitHandCard: (entry: PersistentUnitHandCardRef) => boolean
  highlightCard: (card: Card) => boolean
  onPlayCard: (card: Card) => void
  onPlayUnitHandCard: (entry: PersistentUnitHandCardRef) => void
  onInspectCard: (card: Card) => void
  isBoardDropPoint: (x: number, y: number) => boolean
  onDropToBoard: (card: Card, point: { x: number; y: number }) => Promise<boolean> | boolean
  avatarVitals: Array<{ pid: PlayerId; life: number; power: number; mana: number; active: boolean }>
}

type PersistentUnitHandCardRef = {
  source: UnitSideHandSource
  unitId: string
  unitName: string
  card: MorganaSpellCard
}

function UnitSideHandCard({
  entry,
  canPlay,
  playSfx,
  onPlay,
  onInspect,
}: {
  entry: PersistentUnitHandCardRef
  canPlay: boolean
  playSfx: (kind: UiSfxKind) => void
  onPlay: (entry: PersistentUnitHandCardRef) => void
  onInspect: (card: Card) => void
}) {
  const [isHover, setIsHover] = useState(false)
  return (
    <div
      className={['so-unit-hand-card', isHover ? 'is-hover' : '', canPlay ? '' : 'is-disabled'].filter(Boolean).join(' ')}
      onPointerEnter={() => setIsHover(true)}
      onPointerLeave={() => setIsHover(false)}
      onClick={() => {
        if (!canPlay) {
          playSfx('ui_cancel')
          return
        }
        playSfx('ui_click')
        onPlay(entry)
      }}
      role="button"
      tabIndex={0}
      onKeyDown={(event) => {
        if (event.key !== 'Enter' && event.key !== ' ') return
        event.preventDefault()
        if (!canPlay) {
          playSfx('ui_cancel')
          return
        }
        playSfx('ui_click')
        onPlay(entry)
      }}
      title={`${entry.card.name} — ${entry.unitName}`}
    >
      <button
        className="btn"
        onClick={(event) => {
          event.stopPropagation()
          onInspect(entry.card)
        }}
        title={`Inspect ${entry.card.name}`}
        style={{
          position: 'absolute',
          top: 2,
          right: 2,
          minWidth: 0,
          padding: '1px 5px',
          borderRadius: 999,
          fontSize: 10,
          lineHeight: 1,
          zIndex: 4,
          opacity: 0.9,
        }}
      >
        i
      </button>
      <div className="so-unit-hand-card-surface">
        <MiniCard c={entry.card} scale={0.98 * HAND_CARD_SIZE_MULTIPLIER} />
      </div>
    </div>
  )
}

function PersistentHandBar({
  cards,
  unitHands,
  reducedMotion,
  boardTargetingActive,
  playSfx,
  canPlayCard,
  canPlayUnitHandCard,
  highlightCard,
  onPlayCard,
  onPlayUnitHandCard,
  onInspectCard,
  isBoardDropPoint,
  onDropToBoard,
  avatarVitals,
}: PersistentHandBarProps) {
  const stopHandScroll = (event: React.WheelEvent<HTMLDivElement>) => {
    event.preventDefault();
    event.stopPropagation();
  };
  const compactMain = cards.length > 5;
  const mainOverlapPx = compactMain ? 30 : 0;

  return (
    <div
      className={['so-persistent-hand', boardTargetingActive ? 'is-targeting-board' : ''].filter(Boolean).join(' ')}
      data-reduced-motion={reducedMotion ? 'true' : 'false'}
      onWheel={stopHandScroll}
    >
      {avatarVitals.length > 0 && (
        <div className="so-hand-avatar-vitals" aria-hidden="true">
          {avatarVitals.map((stat) => (
            <div
              key={`hand-avatar-vitals-${stat.pid}`}
              className={[
                'so-hand-avatar-vitals-pill',
                `pid-${stat.pid}`,
                stat.active ? 'is-active' : '',
              ].filter(Boolean).join(' ')}
            >
              <span className="pid-label">{`P${stat.pid}`}</span>
              <span>{ICON.life} {stat.life}</span>
              <span>{ICON.power} {stat.power}</span>
              <span>{ICON.mana ?? '🔮'} {stat.mana}</span>
            </div>
          ))}
        </div>
      )}
      <div className="so-persistent-hand-body" onWheel={stopHandScroll}>
        {unitHands.length > 0 && (
          <div className="so-unit-hand-rail">
            {unitHands.map((group) => {
              const compact = group.cards.length > 5;
              const overlapPx = compact ? 24 : 0;
              const sourceLabel = group.source === 'morgana' ? 'Secret Hand' : 'Bound Hand';
              return (
                <div className="so-unit-hand-group" key={group.key}>
                  <div className="so-unit-hand-title">{`${group.unitName} • ${sourceLabel}`}</div>
                  <div className="so-unit-hand-cards">
                    {group.cards.map((card, index) => {
                      const ref: PersistentUnitHandCardRef = {
                        source: group.source,
                        unitId: group.unitId,
                        unitName: group.unitName,
                        card,
                      };
                      return (
                        <div
                          key={`${group.key}:${card.id}`}
                          className="so-persistent-hand-slot"
                          style={{ marginLeft: index === 0 ? 0 : -overlapPx, zIndex: 20 + index }}
                        >
                          <UnitSideHandCard
                            entry={ref}
                            canPlay={canPlayUnitHandCard(ref)}
                            playSfx={playSfx}
                            onPlay={onPlayUnitHandCard}
                            onInspect={onInspectCard}
                          />
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
        <div className="so-persistent-hand-inner" onWheel={stopHandScroll}>
          {cards.length === 0 ? (
            <div className="so-persistent-hand-empty">Hand empty</div>
          ) : cards.map((card, index) => (
            <div
              key={`persistent-slot-${card.id}`}
              className="so-persistent-hand-slot"
              style={{ marginLeft: index === 0 ? 0 : -mainOverlapPx, zIndex: 30 + index }}
            >
              <PersistentHandCard
                key={`persistent-${card.id}`}
                card={card}
                canPlay={canPlayCard(card)}
                highlight={highlightCard(card)}
                reducedMotion={reducedMotion}
                playSfx={playSfx}
                onPlay={onPlayCard}
                onInspect={onInspectCard}
                isBoardDropPoint={isBoardDropPoint}
                onDropToBoard={onDropToBoard}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

const HAND_CARD_SCALE = 1.7

function handCardDimensions(big: boolean) {
  const baseWidth = big ? 216 : 72
  const baseHeight = big ? 288 : 96
  return { width: baseWidth * HAND_CARD_SCALE, height: baseHeight * HAND_CARD_SCALE }
}

function handCardPadding(big: boolean, selected: boolean) {
  return (big ? (selected ? 9 : 10) : (selected ? 5 : 6)) * HAND_CARD_SCALE
}

function HandCardFace({ card, big = false, selected = false, onClick, concealed = false, backImage }: { card: Card; big?: boolean; selected?: boolean; onClick?: () => void; concealed?: boolean; backImage?: string }) {
  const { width, height } = handCardDimensions(big)
  const paddingValue = handCardPadding(big, selected)
  const imageSrcs = useMemo(() => buildAssetFallbacks((card as any).image), [((card as any).image as string | undefined)]);
  const hiddenBackSrcs = useMemo(
    () => buildAssetFallbacks(backImage ?? '/assets/Sorcery_Spellbook.png'),
    [backImage],
  );
  const baseStyle: React.CSSProperties = {
    width,
    height,
    borderRadius: 8 * HAND_CARD_SCALE,
    background: '#0e1318',
    border: selected ? '2px solid #7dd3fc' : '1px solid #283241',
    padding: concealed ? 0 : paddingValue,
    boxShadow: selected
      ? undefined
      : big
        ? '0 12px 30px rgba(0,0,0,.35)'
        : undefined,
    overflow: 'hidden',
    transform: selected ? 'translateY(-2px)' : undefined,
    transition: 'transform .08s ease',
    position: 'relative',
    display: 'grid',
    placeItems: 'center',
    cursor: onClick ? 'pointer' : 'default',
  }

  if (concealed) {
    const isAtlasBack = backImage?.includes('Sorcery_Atlas');
    return (
      <div style={{ ...baseStyle, padding: 0 }} onClick={onClick}>
        <img
          src={hiddenBackSrcs[0] ?? backImage ?? '/assets/Sorcery_Spellbook.png'}
          data-fallbacks={hiddenBackSrcs.slice(1).join('|')}
          alt="Concealed card"
          onError={advanceImageFallback}
          style={{
            position: 'absolute',
            left: '50%',
            top: '50%',
            width: isAtlasBack ? '100%' : '100%',
            height: isAtlasBack ? '100%' : '100%',
            objectFit: 'contain',
            opacity: 0.92,
            transform: isAtlasBack ? 'translate(-50%, -50%) rotate(0deg)' : 'translate(-50%, -50%)',
            transformOrigin: 'center',
          }}
          draggable={false}
        />
      </div>
    )
  }

  if (imageSrcs.length > 0) {
    return (
      <div style={baseStyle} onClick={onClick}>
        <img
          src={imageSrcs[0]}
          data-fallbacks={imageSrcs.slice(1).join('|')}
          alt={`${card.name} art`}
          onError={advanceImageFallback}
          style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', objectFit: 'cover' }}
        />
      </div>
    )
  }

  const titleSize = (big ? 16 : 9) * HAND_CARD_SCALE
  const bodySize = (big ? 13 : 9.5) * HAND_CARD_SCALE
  const fineSize = (big ? 12 : 8) * HAND_CARD_SCALE
  const elem = (card as any).element as Elem | undefined

  return (
    <div
      style={{ ...baseStyle, display: 'grid', gridTemplateRows: `${18 * HAND_CARD_SCALE}px 1fr ${16 * HAND_CARD_SCALE}px` }}
      onClick={onClick}
    >
      <div style={{ fontSize: titleSize, fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
        {card.name} {elem ? elemIcon(elem) : ''}
      </div>
      <div
        style={{
          fontSize: bodySize,
          alignSelf: 'center',
          justifySelf: 'center',
          textAlign: 'center',
          lineHeight: 1.25,
          wordBreak: 'break-word',
          color: '#cde2ff',
          opacity: 0.9,
        }}
      >
        {card.kind === 'Site' ? (
          <div style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
            {(card as any).elements?.map((e: Elem, i: number) => (
              <ElemIconImg key={i} e={e} size={12 * HAND_CARD_SCALE * 1.1} />
            ))}
            <span>Site</span>
          </div>
        ) : (card as any).text}
      </div>
      <div style={{ fontSize: fineSize, opacity: 0.7, justifySelf: 'end' }}>{card.kind}</div>
    </div>
  )
}

type HandHoverOptions = Parameters<typeof useHoverBindingsForCard>[0]

function HandCard({
  card,
  hoverOptions,
  selected,
  onClick,
  concealed,
  backImage,
}: {
  card: Card
  hoverOptions?: HandHoverOptions
  selected: boolean
  onClick?: () => void
  concealed: boolean
  backImage: string
}) {
  const hb = hoverOptions ? useHoverBindingsForCard(hoverOptions) : null
  const { width: smallWidth, height: smallHeight } = handCardDimensions(false)
  const effectiveSelected = !concealed && selected

  return (
    <div
      className="card"
      tabIndex={concealed ? -1 : 0}
      onPointerEnter={hb ? hb.onPointerEnter : undefined}
      onPointerMove={hb ? hb.onPointerMove : undefined}
      onPointerLeave={hb ? hb.onPointerLeave : undefined}
      onPointerUp={hb ? hb.onPointerUp : undefined}
      onFocus={hb ? hb.onFocus : undefined}
      onBlur={hb ? hb.onBlur : undefined}
      onClick={concealed ? undefined : onClick}
      style={{
        width: smallWidth,
        height: smallHeight,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 0,
        pointerEvents: concealed ? 'none' : 'auto',
      }}
    >
      <HandCardFace
        card={card}
        selected={effectiveSelected}
        onClick={concealed ? undefined : onClick}
        concealed={concealed}
        backImage={backImage}
      />
    </div>
  )
}

function Hands({
  game,
  pid,
  revealed,
  onCardSelected,
  onGameChanged,
}: {
  game: Game;
  pid: PlayerId;
  revealed: boolean;
  onCardSelected?: () => void;
  onGameChanged?: (next: Game) => void;
}) {
  const combinedHand = [...game.handAtlas[pid], ...game.handSpells[pid]]
  const concealed = !revealed
  const { height: cardHeight } = handCardDimensions(false)
  const finalizeSelection = () => { onCardSelected?.() }

  return (
    <div style={{ display: 'flex', justifyContent: 'center', padding: '4px 0' }}>
      <div
        className="hand"
        style={{
          justifyContent: 'center',
          alignItems: 'center',
          minHeight: cardHeight,
          gap: 8,
        }}
      >
        {combinedHand.map((card) => {
          const hoverOptions: HandHoverOptions | undefined = revealed
            ? {
              src: (card as any).image,
              name: card.name,
              cardKind: card.kind,
              baseWidth: 216,
              zoom: 1.5,
              side: pid === 2 ? 'left' : 'right',
              context: 'hand',
            }
            : undefined
          const backImage = card.kind === 'Site' ? '/assets/Sorcery_Atlas.png' : '/assets/Sorcery_Spellbook.png'

          if (card.kind === 'Site') {
            const isFireballing = game.fireballMode[pid] && card.kind === 'Site'
            const click = !concealed
              ? () => {
                  let actionTaken = false
                  if (isFireballing) {
                    (game as any)._pendingFireball = { pid, cardId: card.id }
                    game.log.unshift(`Select a target tile to cast Fireball using ${card.name}.`)
                    actionTaken = true
                  } else {
                    const pendingMode = (game as any)._pendingSiteMode
                    if (pendingMode?.pid === pid) {
                      const prev = pendingMode.cardId
                      pendingMode.cardId = card.id
                      if (prev !== card.id) {
                        game.log.unshift(`P${pid} selects ${card.name} from the atlas.`)
                        actionTaken = true
                      }
                    }
                  }
                  if (actionTaken) finalizeSelection()
                }
              : undefined
            const selected =
              !concealed && (game as any)._pendingSiteMode?.pid === pid && (game as any)._pendingSiteMode.cardId === card.id

            return (
              <HandCard
                key={card.id}
                card={card}
                hoverOptions={hoverOptions}
                selected={selected}
                onClick={click}
                concealed={concealed}
                backImage={backImage}
              />
            )
          }

  const pending = (game as any)._pendingPlay as PendingPlayState | undefined
          const isSelected = !concealed && pending?.pid === pid && pending.cardId === card.id
          const onCardClick = !concealed
            ? () => {
                void (async () => {
                  let actionTaken = false
                  if (card.kind === 'Unit') {
                    if (/^Sir Gareth$/i.test(card.name ?? '')) {
                      const used = await maybeUseSirGarethRevealFromHand(game, pid, card as Extract<Card, { kind: 'Unit' }>);
                      if (used) {
                        onGameChanged?.(structuredClone(game));
                        requestGameSync?.();
                        actionTaken = true;
                      }
                    }
                    if (!actionTaken && isUnitSummonable(game, pid, card)) {
                      const pendingUnit: any = (game as any)._pendingUnitMode
                      let prev: string | undefined = undefined
                      if (pendingUnit && typeof pendingUnit.cardId === 'string') {
                        prev = pendingUnit.cardId as string
                      }
                      (game as any)._pendingUnitMode = { pid, cardId: card.id, region: 'surface', source: 'hand' }
                      if (prev !== card.id) {
                        game.log.unshift(`P${pid} selects ${card.name} — click a legal location to place it.`)
                        actionTaken = true
                      }
                    }
                  } else if (card.kind === 'Spell' || card.kind === 'AuraCard' || card.kind === 'ArtifactCard') {
                    const canPlay =
                      card.kind === 'Spell'
                        ? canCastSpell(game, pid, card)
                        : card.kind === 'AuraCard'
                        ? canCastAura(game, pid, card)
                        : canConjureArtifact(game, pid, card)
                    if (canPlay) {
                      void beginCastFromHand(game, pid, card.id)
                      actionTaken = true
                    }
                  }
                  if (actionTaken) finalizeSelection()
                })();
              }
            : undefined

          return (
            <HandCard
              key={card.id}
              card={card}
              hoverOptions={hoverOptions}
              selected={isSelected}
              onClick={onCardClick}
              concealed={concealed}
              backImage={backImage}
            />
          )
        })}
      </div>
    </div>
  )
}
